parameters.jsCode:
// Validation & Confidence Gate — Sprint 2
// Goal:
// 1) Block obviously broken underwriting from publishing
// 2) Separate hard blockers from softer confidence warnings
// 3) Preserve internal logging while tightening external publish safety

function safeNode(name, fallback = {}) {
  try {
    const v = $(name).first().json;
    return v ?? fallback;
  } catch {
    return fallback;
  }
}

function num(v) {
  if (v === null || v === undefined) return null;
  if (typeof v === 'number') return Number.isFinite(v) ? v : null;

  const cleaned = String(v).replace(/[^\d.-]/g, '').trim();

  if (!cleaned || cleaned === '.' || cleaned === '-' || cleaned === '-.') {
    return null;
  }

  const n = Number(cleaned);
  return Number.isFinite(n) ? n : null;
}

function txt(v) {
  return String(v ?? '').trim();
}

function hasUnitSuffix(address) {
  return /(?:\bapt\b|\bunit\b|#|\bsuite\b|\bste\b)/i.test(address || '');
}

function sameBucketType(a, b) {
  const ta = txt(a).toLowerCase();
  const tb = txt(b).toLowerCase();
  if (!ta || !tb) return true;

  const bucket = (x) => {
    if (/multi|duplex|triplex|fourplex|quad|apartment/.test(x)) return 'multi';
    if (/condo|condominium/.test(x)) return 'condo';
    if (/townhouse|townhome/.test(x)) return 'townhome';
    if (/single|sfr|single family/.test(x)) return 'single';
    if (/mobile|manufactured/.test(x)) return 'manufactured';
    return x;
  };

  return bucket(ta) === bucket(tb);
}

function round2(n) {
  return Number((n || 0).toFixed(2));
}

const MIN_CONFIDENCE_TO_PUBLISH = 60;

const stageNode = safeNode('Evaluation & Stage Router');
const output = stageNode.output || stageNode || {};

const metricsNode = safeNode('Compute Metrics v2');
const metrics =   output.metrics || metricsNode.metrics || {};

const property = output.property || metricsNode.property || {};
const dealMath = safeNode('OFFER ENGINE1');
const ds = output.deal_structure || {};

const primary = ds['Primary Offer'] || {};
const backup = ds['Backup Offer'] || {};
const cash = ds['Updated Cash Offer'] || {};

const publicRecord = safeNode('HTTP Request6');
const normalizeNode = safeNode('Normalize Subject + Mode');
const dedupeNode = safeNode('Deduplicate Opportunities');
const transcriptNode = safeNode('Phone Transcript analyzer');

const resolved = normalizeNode.resolved || dedupeNode.resolved || {};
const transcriptOutput = transcriptNode.output || output.transcript || {};

const validation = {
  version: 'validator-s2.0',
  can_publish: true,
  errors: [],
  warnings: [],
  info: [],
  checks: {},
  confidence: {
    score: 100,
    tier: 'high',
    threshold_to_publish: MIN_CONFIDENCE_TO_PUBLISH,
    reasons: []
  }
};

function addError(msg) {
  validation.errors.push(msg);
  validation.confidence.score -= 20;
  validation.confidence.reasons.push(`ERROR: ${msg}`);
}

function addWarning(msg) {
  validation.warnings.push(msg);
  validation.confidence.score -= 5;
  validation.confidence.reasons.push(`WARN: ${msg}`);
}

function addInfo(msg) {
  validation.info.push(msg);
}

function finalizeConfidence() {
  validation.confidence.score = Math.max(0, Math.min(100, validation.confidence.score));
  if (validation.confidence.score >= 85) validation.confidence.tier = 'high';
  else if (validation.confidence.score >= 60) validation.confidence.tier = 'medium';
  else validation.confidence.tier = 'low';
}

const address =
  txt(property.address) ||
  txt(resolved.address_for_value_full) ||
  txt(resolved.raw_address);

const propTypeMetrics = txt(metrics.propertyType);
const propTypeProperty = txt(property.propertyType);
const propTypeResolved = txt(resolved.property_type_for_value);

const arv = num(metrics.arv ?? property.arv_value ?? output.arv_value ?? dealMath.output?.property?.arv_value);
const asIs = num(metrics.as_is_value ?? property.est_value);
const listPrice = num(metrics.list_price ?? property.list_price ?? metrics.price);
const grossRent = num(metrics.grossRent ?? metrics.gross_rent_monthly);
const taxes = num(metrics.taxes);
const insurance = num(metrics.insurance);
const opex = num(metrics.opex);
const noi = num(metrics.noi);
const tiMonthly = num(metrics.tiMonthly);
const equityPct = num(metrics.equity_pct);
const loanBal = num(metricsNode.existing_loan?.balance ?? output.existing_loan?.balance ?? dealMath.existing_loan?.balance) ?? 0;
const loanRate = num(metricsNode.existing_loan?.rate ?? output.existing_loan?.rate ?? dealMath.existing_loan?.rate) ?? 0;

validation.checks.address = address;
validation.checks.arv = arv;
validation.checks.as_is_value = asIs;
validation.checks.list_price = listPrice;
validation.checks.gross_rent = grossRent;
validation.checks.noi = noi;
validation.checks.opex = opex;
validation.checks.ti_monthly = tiMonthly;
validation.checks.equity_pct = equityPct;

// ------------------------------
// 1) Core subject/data sanity
// ------------------------------
if (!address) addError('Missing subject address.');
if (arv === null || arv <= 0) addError(`ARV is missing or non-positive: ${arv}`);
if (asIs !== null && asIs < 0) addError(`As-is value is negative: ${asIs}`);
if (listPrice !== null && listPrice < 0) addError(`List price is negative: ${listPrice}`);
if (grossRent !== null && grossRent < 0) addError(`Gross rent is negative: ${grossRent}`);
if (taxes !== null && taxes < 0) addError(`Taxes are negative: ${taxes}`);
if (insurance !== null && insurance < 0) addError(`Insurance is negative: ${insurance}`);
if (opex !== null && opex < 0) addError(`Operating expenses are negative: ${opex}`);
if (noi !== null && noi < 0) addError(`NOI is negative: ${noi}`);
if (tiMonthly !== null && tiMonthly < 0) addError(`TI monthly is negative: ${tiMonthly}`);

if (equityPct === null) {
  addError('equity_pct is missing or non-numeric.');
} else {
  if (equityPct < -100 || equityPct > 100) addError(`equity_pct out of range for percent convention: ${equityPct}`);
  else if (equityPct > 0 && equityPct < 1) addWarning(`equity_pct looks fraction-scaled (${equityPct}). Expected 0–100 percent convention.`);
}

if (propTypeMetrics && propTypeResolved && !sameBucketType(propTypeMetrics, propTypeResolved)) {
  addError(`Property type drift between metrics (${propTypeMetrics}) and resolved subject (${propTypeResolved}).`);
}
if (propTypeProperty && propTypeResolved && !sameBucketType(propTypeProperty, propTypeResolved)) {
  addError(`Property type drift between property output (${propTypeProperty}) and resolved subject (${propTypeResolved}).`);
}

// ------------------------------
// 2) Cash offer consistency
// ------------------------------
const cashAmt = num(cash['Final Cash Offer'] ?? cash.finalCashOffer);
const cashPct = num(cash['Final Cash Offer % of ARV'] ?? cash.finalCashOfferPct);

validation.checks.cash_offer_amount = cashAmt;
validation.checks.cash_offer_pct = cashPct;

if (cashAmt !== null && cashPct !== null && arv !== null && arv > 0) {
  const impliedPct = round2((cashAmt / arv) * 100);
  validation.checks.cash_offer_implied_pct = impliedPct;

  if (Math.abs(impliedPct - cashPct) > 1.0) {
    addError(`Updated Cash Offer mismatch: amount implies ${impliedPct}% of ARV but field says ${cashPct}%.`);
  }

  if (cashAmt > arv) {
    addError(`Cash offer exceeds ARV: cash ${cashAmt}, ARV ${arv}.`);
  }
} else {
  addWarning('Updated Cash Offer could not be fully validated (missing amount, percent, or ARV).');
}

// ------------------------------
// 3) Multifamily / subject-scope
// ------------------------------
const publicUnitCount =
  num(publicRecord.features?.unitCount) ??
  num(publicRecord.subjectProperty?.features?.unitCount) ??
  0;

const sqft =
  num(metrics.sqft) ??
  num(property.sqft) ??
  num(resolved.building_sqft) ??
  0;

if (
  /multi|duplex|triplex|fourplex|quad|apartment/i.test(`${propTypeMetrics} ${propTypeProperty} ${propTypeResolved}`) &&
  hasUnitSuffix(address) &&
  (sqft > 1500 || publicUnitCount > 1)
) {
  addError(`Multifamily subject-scope conflict: unit-style address appears paired with building-level data for "${address}".`);
}

// ------------------------------
// 4) Offer validation
// ------------------------------
function validateOffer(label, offer) {
  const offerType = txt(offer['Type'] || offer.type);
  const purchasePrice = num(offer['Purchase Price'] || offer.purchasePrice);
  const down = num(offer['Down Payment ($)'] || offer.downPayment);
  const downPct = num(offer['Down Payment (%)'] || offer.downPaymentPct);
  const rate = num(offer['Loan Rate (%)'] || offer['Interest Rate (%)'] || offer.interestRate || offer.ratePct);
  const payment = num(offer['Monthly Payment (PI)'] || offer['Monthly Payment'] || offer.monthlyPayment || offer.monthPI);
  const ads = num(offer['ADS'] || offer.ads);
  const dscr = num(offer['DSCR'] || offer.dscr);
  const monthlyCF = num(offer['Monthly Cash-flow'] || offer.monthlyCF || offer.monthly_cash_flow);
  const coc = num(offer['Cash-on-Cash Return'] || offer.coc || offer.coc_pct);
  const balloon = num(offer['Balloon Term (Years)'] || offer.balloonYrs);

  validation.checks[`${label.toLowerCase()}_type`] = offerType;

  const result = {
    type: offerType,
    viable: false,
    reasons: []
  };

  if (!offerType) {
    addError(`${label} offer has no Type.`);
    result.reasons.push('missing_type');
    return result;
  }

  if (purchasePrice === null || purchasePrice <= 0) {
    addError(`${label} offer missing Purchase Price.`);
    result.reasons.push('missing_purchase_price');
  }

  if (down !== null && down < 0) {
    addError(`${label} offer has invalid negative down payment.`);
    result.reasons.push('negative_down');
  }

  if (payment !== null && payment < 0) {
    addError(`${label} offer has invalid monthly payment.`);
    result.reasons.push('negative_payment');
  }

  if (/seller finance/i.test(offerType)) {
    if (rate === null || rate <= 0) {
      addError(`${label} Seller Finance offer missing rate.`);
      result.reasons.push('missing_rate');
    } else if (rate > 4.0) {
      addError(`${label} Seller Finance rate ${rate}% exceeds 4.0% max.`);
      result.reasons.push('rate_too_high');
    }

    if (downPct !== null && downPct > 20) {
      addError(`${label} Seller Finance down payment ${downPct}% exceeds 10% max.`);
      result.reasons.push('down_pct_too_high');
    }

    if (balloon !== null && balloon < 5) {
      addError(`${label} Seller Finance balloon ${balloon} years is below 5-year minimum.`);
      result.reasons.push('balloon_too_short');
    }
  }

  if (/subject-to|subject to/i.test(offerType)) {
    if (loanBal <= 0) {
      addError(`${label} Subject-To offer is incompatible with no existing loan.`);
      result.reasons.push('no_loan_for_subto');
    }

    if (loanBal > 150000 && loanRate > 6.8) {
      addError(`${label} Subject-To loan rate ${loanRate}% exceeds 6.8% max for loans over $150k.`);
      result.reasons.push('loan_rate_too_high');
    }

    if (loanBal > 0 && loanBal <= 150000 && loanRate > 8) {
      addError(`${label} Subject-To loan rate ${loanRate}% exceeds 8% max for loans under $150k.`);
      result.reasons.push('loan_rate_too_high');
    }
  }

  if (/hybrid/i.test(offerType)) {
    if (loanBal <= 0) {
      addError(`${label} Hybrid offer is incompatible with no existing loan.`);
      result.reasons.push('no_loan_for_hybrid');
    }

    if (downPct !== null && downPct > 10) {
      addError(`${label} Hybrid down payment ${downPct}% exceeds 10% max.`);
      result.reasons.push('down_pct_too_high');
    }
  }

  // DSCR consistency check
  let impliedADS = ads;
  if ((impliedADS === null || impliedADS <= 0) && payment !== null && payment >= 0 && tiMonthly !== null && tiMonthly >= 0) {
    impliedADS = (payment + tiMonthly) * 12;
  }

  if (dscr !== null && impliedADS !== null && impliedADS > 0 && noi !== null && noi > 0) {
    const impliedDSCR = round2(noi / impliedADS);
    validation.checks[`${label.toLowerCase()}_implied_dscr`] = impliedDSCR;
    if (Math.abs(impliedDSCR - dscr) > 0.05) {
      addError(`${label} DSCR mismatch: field says ${dscr}, implied is ${impliedDSCR}.`);
      result.reasons.push('dscr_mismatch');
    }
  }

  // Viability screen
  if (/seller finance|hybrid/i.test(offerType)) {
    if ((dscr ?? -999) >= 1.2 && (monthlyCF ?? -999) >= 200 && (coc ?? -999) >= 13) {
      result.viable = true;
    } else {
      result.reasons.push('fails_sf_hybrid_viability');
    }
  } else if (/subject-to|subject to/i.test(offerType)) {
    const lowRateException = loanRate > 0 && loanRate <= 3.5;
    const cfPass = lowRateException ? (monthlyCF ?? -999) >= -50 : (monthlyCF ?? -999) >= 150;
    if ((dscr ?? -999) >= 1.0 && cfPass) {
      result.viable = true;
    } else {
      result.reasons.push('fails_subto_viability');
    }
  }

  return result;
}

const primaryEval = validateOffer('Primary', primary);
const backupEval = validateOffer('Backup', backup);

validation.checks.primary_offer_viable = primaryEval.viable;
validation.checks.backup_offer_viable = backupEval.viable;

// ------------------------------
// 5) Cash viability
// ------------------------------
let cashViable = false;
if (cashAmt !== null && cashAmt > 0 && arv !== null && arv > 0) {
  if (cashAmt <= arv * 0.75) {
    cashViable = true;
  }
}
validation.checks.cash_offer_viable = cashViable;

// ------------------------------
// 6) Transcript / confidence
// ------------------------------
const transcriptSummary =
  txt(transcriptOutput?.sellerUrgency) ||
  txt(transcriptOutput?.output?.sellerUrgency) ||
  txt(output.transcript?.output?.sellerUrgency) ||
  txt(output.transcript_insights?.sellerUrgency);

if (!transcriptSummary || /no transcript provided/i.test(transcriptSummary)) {
  addWarning('No transcript provided. Underwriting may proceed, but seller-fit confidence is low.');
}

// ------------------------------
// 7) Publish gating
// ------------------------------
if (!primaryEval.viable && !backupEval.viable && !cashViable) {
  addError('No economically viable offer path passed validation.');
}

finalizeConfidence();

validation.checks.error_count = validation.errors.length;
validation.checks.warning_count = validation.warnings.length;

validation.can_publish =
  validation.errors.length === 0 &&
  validation.confidence.score >= MIN_CONFIDENCE_TO_PUBLISH;

validation.publish_decision = validation.can_publish
  ? 'publish_safe'
  : (validation.errors.length > 0
      ? 'blocked_by_errors'
      : 'blocked_by_low_confidence');

return [{
  json: {
    validation
  }
}];

// ==============================
// PACK AGENT v4 - Stage Router Passthrough
// ==============================

function get(node, fallback = {}) {
  try {
    const v = $(node).first().json;
    return v ? v : fallback;
  } catch {
    return fallback;
  }
}

// Pull from upstream
const dealMathNode = get('OFFER ENGINE v1');
const metricsNode = get('Compute Metrics v2');
const propertyData = get('HTTP Request6');
const publicRecord = propertyData;

const fetchSale = get('Fetch Sale Data');
const fetchRent = get('Fetch rental comps');
const fetchComps = get('Selected Comps');
const webhook = get('Start Webhook1');
const workflow = get('Execute Workflow');
const analyzer = get('Phone Transcript analyzer');
const resolveRent = get('Resolve Rental Model');
const stageRouter = get('Evaluation & Stage Router');
const marketDataExtracted = get('Information Extractor').output || {};
const normalized = get('Normalize Subject + Mode') || {};
const dedup = get('Deduplicate Opportunities') || {};
const resolved = normalized.resolved || dedup.resolved || {};

const customData = webhook.body?.customData || {};
const loanData = dealMathNode.existing_loan || metricsNode.existing_loan || {};

const buyerMatches = stageRouter.buyer_matches || [];

let soldCompsList = [];
if (fetchComps?.selected_comps && Array.isArray(fetchComps.selected_comps)) {
  soldCompsList = fetchComps.selected_comps.map(c => ({
    address: c.formattedAddress,
    price: c.price,
    propType: c.propType,
    bedrooms: c.bedrooms,
    bathrooms: c.bathrooms,
    squareFootage: c.squareFootage,
    yrBuilt: c.yearBuilt,
    lotSqft: c.lotSqft,
    pricePerSqFt: c.pricePerSqFt,
    DOM: c.daysOnMarket,
    distance: c.distance,
    correlation: c.correlation
  }));
}

const payload = {
  deal_structure: dealMathNode.deal_structure || dealMathNode.output?.deal_structure || {},
  investors_analysis: dealMathNode.investors_analysis || dealMathNode.output?.investors_analysis || {},
  loi: dealMathNode.loi || dealMathNode.output?.loi || "",

  public_property_data: publicRecord,
  property: dealMathNode.property || metricsNode.property || {},
  metrics: dealMathNode.metrics || metricsNode.metrics || {},
  config: dealMathNode.config || metricsNode.config || {},

  existing_loan: loanData,
  market_data_trends: marketDataExtracted,
  standard_monthly_rent: resolveRent.standard_rent_monthly,
  rent_calculations: resolveRent.rent_calculations || {},
  rental_estimates: resolveRent.rental_estimates || {},

  normalized_subject: resolved || {}, 

  buyer_matches: buyerMatches,
  buyer_match_summary: stageRouter.buyer_match_summary,
  comps_source: {
    arv: fetchComps.estARV || null,
    comp_low: fetchComps.priceRangeLow || null,
    comp_high: fetchComps.priceRangeHigh || null,
    comparables: soldCompsList
  },

  // Stage router passthrough
  leadScore: stageRouter.leadScore ?? stageRouter.lead_score ?? null,
  lead_score: stageRouter.lead_score ?? stageRouter.leadScore ?? null,
  lead_score_version: stageRouter.lead_score_version || null,
  lead_score_explanation: stageRouter.lead_score_explanation || "",
  recommendation: stageRouter.recommendation || {},

  execution_context: stageRouter.execution_context || stageRouter.output?.execution_context || "unknown",
  precall_priority_score: stageRouter.precall_priority_score ?? null,
  postcall_actionability_score: stageRouter.postcall_actionability_score ?? null,

  seller_stance: stageRouter.seller_stance || {},
  seller_acceptance: stageRouter.seller_acceptance || {},
  score_breakdown: stageRouter.score_breakdown || {},
  pricing_reality: stageRouter.seller_acceptance?.pricing_reality || stageRouter.recommendation?.pricingReality || {},

  sale_listing_source: fetchSale || {},
  rental_comps_source: fetchRent || {},
  webhook_custom_data: customData,
  transcript: analyzer || ""
};

return [{ json: payload }];

function safeNode(name, fallback) {
  if (fallback === undefined) fallback = {};
  try {
    var v = $(name).first().json;
    return v || fallback;
  } catch (e) {
    return fallback;
  }
}

function firstValue() {
  for (var i = 0; i < arguments.length; i++) {
    var v = arguments[i];
    if (v === 0 || v === false) return v;
    if (v === null || v === undefined) continue;
    if (typeof v === 'string' && v.trim() === '') continue;
    return v;
  }
  return null;
}

function nonEmptyObject() {
  for (var i = 0; i < arguments.length; i++) {
    var v = arguments[i];
    if (v && typeof v === 'object' && !Array.isArray(v) && Object.keys(v).length) return v;
  }
  return {};
}

function hasAnyKey(obj, keys) {
  if (!obj || typeof obj !== 'object') return false;
  return keys.some(function(k) {
    return obj[k] !== undefined && obj[k] !== null;
  });
}

function toMoneyNumber(x) {
  if (x === null || x === undefined || x === '') return null;
  if (typeof x === 'number') return Number.isFinite(x) ? x : null;
  var n = parseFloat(String(x).replace(/[^\d.\-]/g, ''));
  return Number.isFinite(n) ? n : null;
}

function money(x, digits) {
  if (digits === undefined) digits = 2;
  var n = toMoneyNumber(x);
  if (n === null) return '—';
  return '$' + n.toLocaleString('en-US', {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits
  });
}

function pct(x, digits) {
  if (digits === undefined) digits = 1;
  if (x === null || x === undefined || x === '') return '—';
  if (typeof x === 'string' && x.indexOf('%') >= 0) return x;
  var n = toMoneyNumber(x);
  if (n === null) return '—';
  return n.toFixed(digits) + '%';
}

function clean(s) {
  return String(s == null ? '' : s).replace(/\s+\n/g, '\n').trim();
}

function lower(s) {
  return String(s == null ? '' : s).trim().toLowerCase();
}

function escapeHtml(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function nlToBr(s) {
  return escapeHtml(s || '').replace(/\n/g, '<br>');
}

function isPresent(v) {
  if (v === 0 || v === false) return true;
  if (v === null || v === undefined) return false;
  if (typeof v === 'string') {
    var s = v.trim();
    return s !== '' && s !== 'N/A' && s !== 'null' && s !== 'undefined';
  }
  return true;
}

function pushLine(lines, label, value, formatter) {
  if (!isPresent(value)) return;
  var out = formatter ? formatter(value) : value;
  if (!isPresent(out)) return;
  lines.push('• ' + label + ': ' + out);
}

function offerField(offer) {
  for (var i = 1; i < arguments.length; i++) {
    var key = arguments[i];
    if (offer && offer[key] !== undefined && offer[key] !== null && offer[key] !== '') return offer[key];
  }
  return null;
}

function toDiscord(s) {
  return String(s || '')
    .replace(/^🏠/gm, '**🏠**')
    .replace(/^🏦/gm, '**🏦**')
    .replace(/^📊/gm, '**📊**')
    .replace(/^💼/gm, '**💼**')
    .replace(/^🧭/gm, '**🧭**')
    .replace(/^📬/gm, '**📬**')
    .replace(/^📌/gm, '**📌**')
    .replace(/^👤/gm, '**👤**')
    .replace(/^🗒️/gm, '**🗒️**')
    .replace(/^🧰/gm, '**🧰**')
    .replace(/^💵/gm, '**💵**')
    .replace(/^🤖/gm, '**🤖**');
}

function scoreText(v, max) {
  if (max === undefined) max = 10;
  if (v === null || v === undefined || v === '') return 'N/A';
  return String(v) + '/' + String(max);
}

function evalColor(evaluation) {
  var v = lower(evaluation);
  if (v.indexOf('hot') >= 0) return '#16a34a';
  if (v.indexOf('warm') >= 0) return '#d97706';
  if (v.indexOf('follow') >= 0) return '#2563eb';
  if (v.indexOf('cold') >= 0) return '#64748b';
  if (v.indexOf('dead') >= 0) return '#dc2626';
  if (v.indexOf('manual') >= 0) return '#7c3aed';
  return '#334155';
}

function scoreBadgeHtml(score) {
  var n = toMoneyNumber(score);

  if (n === null) {
    return '<span style="display:inline-block;padding:5px 10px;border-radius:999px;background:#e5e7eb;color:#374151;font-weight:800;">N/A</span>';
  }

  var bg = '#dc2626';
  if (n >= 9) bg = '#16a34a';
  else if (n >= 7) bg = '#d97706';
  else if (n >= 5) bg = '#2563eb';
  else if (n >= 3) bg = '#64748b';

  return '<span style="display:inline-block;padding:5px 10px;border-radius:999px;background:' + bg + ';color:white;font-weight:900;">' + String(n) + '/10</span>';
}

function explainEvaluation(bestScore) {
  var s = toMoneyNumber(bestScore);
  if (s === null) return 'Manual review because one or more scoring inputs were missing, conflicting, or unreliable.';
  if (s >= 9) return 'Hot because at least one offer path appears highly likely to be seller-acceptable.';
  if (s >= 7) return 'Warm because at least one offer path is plausible, but may still require negotiation.';
  if (s >= 5) return 'Follow-Up because there may be a path, but seller acceptance is uncertain.';
  if (s >= 3) return 'Cold because both offer paths appear unlikely without a major seller concession.';
  return 'Dead because neither the cash nor creative path appears realistically acceptable.';
}

function getOfferByName(deal, name) {
  if (!deal || typeof deal !== 'object') return {};
  return deal[name] || {};
}

function buildContext(a) {
  var aiNode = safeNode('AI Agent', {});
  var oeNode = safeNode('OFFER ENGINE v1', {});

  var current = a || {};
  var currentOut = current.output || {};

  var aiOut = nonEmptyObject(
    aiNode.output,
    current.ai_agent && current.ai_agent.output,
    current.aiAgent && current.aiAgent.output,
    {}
  );

  var oeOut = nonEmptyObject(
    oeNode.output,
    current.offer_engine && current.offer_engine.output,
    current.offerEngine && current.offerEngine.output,
    current.offer_generator && current.offer_generator.output,
    {}
  );

  var currentDeal = firstValue(currentOut.deal_structure, current.deal_structure, {});
  var aiDeal = firstValue(aiOut.deal_structure, {});
  var oeDeal = firstValue(oeOut.deal_structure, currentDeal, {});

  function mergeOffer(name) {
    var base = firstValue(getOfferByName(oeDeal, name), getOfferByName(currentDeal, name), {});
    var ai = firstValue(getOfferByName(aiDeal, name), {});
    var merged = Object.assign({}, base);
    if (isPresent(ai.Justification)) merged.Justification = ai.Justification;
    return merged;
  }

  var acceptanceScoring = firstValue(
    current.acceptance_scoring,
    currentOut.acceptance_scoring,
    oeOut.acceptance_scoring,
    aiOut.acceptance_scoring,
    {}
  );

  var recommendation = firstValue(
    current.recommendation,
    currentOut.recommendation,
    oeOut.recommendation,
    aiOut.recommendation,
    {}
  );

  var sellerStance = firstValue(
    current.seller_stance,
    currentOut.seller_stance,
    acceptanceScoring.seller_stance,
    recommendation.seller_stance,
    {}
  );

  var sellerFloor = firstValue(
    current.seller_floor,
    currentOut.seller_floor,
    acceptanceScoring.seller_floor,
    recommendation.seller_floor,
    {}
  );

  return {
    raw: current,
    currentOut: currentOut,
    aiOut: aiOut,
    oeOut: oeOut,

    property: firstValue(currentOut.property, current.property, oeOut.property, aiOut.property, {}),
    metrics: firstValue(currentOut.metrics, current.metrics, oeOut.metrics, aiOut.metrics, {}),
    existingLoan: firstValue(currentOut.existing_loan, current.existing_loan, oeOut.existing_loan, aiOut.existing_loan, {}),
    config: firstValue(currentOut.config, current.config, oeOut.config, aiOut.config, {}),
    transcript: firstValue(current.transcript, currentOut.transcript, oeOut.transcript, {}),

    leadScore: firstValue(currentOut.lead_score, current.lead_score, current.leadScore, oeOut.lead_score, null),
    leadScoreExplanation: firstValue(current.lead_score_explanation, currentOut.lead_score_explanation, aiOut.lead_score_explanation, oeOut.lead_score_explanation, null),

    acceptanceScoring: acceptanceScoring,
    recommendation: recommendation,

    cashProbability: firstValue(current.cash_probability, currentOut.cash_probability, acceptanceScoring.cash_probability, recommendation.cash_probability, null),
    creativeProbability: firstValue(current.creative_probability, currentOut.creative_probability, acceptanceScoring.creative_probability, recommendation.creative_probability, null),

    underwritingEvaluation: firstValue(current.underwriting_evaluation, currentOut.underwriting_evaluation, acceptanceScoring.underwriting_evaluation, recommendation.underwritingEvaluation, null),
    underwritingEvaluationLabel: firstValue(current.underwriting_evaluation_label, currentOut.underwriting_evaluation_label, acceptanceScoring.underwriting_evaluation_label, recommendation.evaluation, null),

    bestAcceptanceScore: firstValue(current.best_acceptance_score, currentOut.best_acceptance_score, acceptanceScoring.best_acceptance_score, recommendation.best_acceptance_score, null),
    bestAcceptancePath: firstValue(current.best_acceptance_path, currentOut.best_acceptance_path, acceptanceScoring.best_acceptance_path, recommendation.best_acceptance_path, null),

    executionContext: firstValue(current.execution_context, currentOut.execution_context, acceptanceScoring.execution_context, recommendation.execution_context, null),
    sellerStance: sellerStance,
    sellerFloor: sellerFloor,

    investorsAnalysis: firstValue(oeOut.investors_analysis, currentOut.investors_analysis, current.investors_analysis, {}),
    investorsAnalysisInsights: firstValue(aiOut.investors_analysis_insights, oeOut.investors_analysis_insights, currentOut.investors_analysis_insights, null),

    compsSummary: firstValue(aiOut.comps_summary, currentOut.comps_summary, current.comps_summary, null),
    compPropertiesReport: firstValue(currentOut.comp_properties_report, current.comp_properties_report, oeOut.comp_properties_report, []),

    buyerMatches: firstValue(currentOut.buyer_matches, current.buyer_matches, oeOut.buyer_matches, []),
    buyerMatchSummary: firstValue(aiOut.buyer_match_summary, currentOut.buyer_match_summary, current.buyer_match_summary, null),

    dispoStrategy: firstValue(aiOut.dispoStrategy, currentOut.dispoStrategy, current.dispoStrategy, {}),
    finalRecommendationsAndInsights: firstValue(aiOut.finalRecommendationsAndInsights, currentOut.finalRecommendationsAndInsights, null),
    loi: firstValue(aiOut.loi, currentOut.loi, null),

    dealStructure: {
      'Primary Offer': mergeOffer('Primary Offer'),
      'Backup Offer': mergeOffer('Backup Offer'),
      'Updated Cash Offer': mergeOffer('Updated Cash Offer')
    },

    cashOffer: firstValue(oeOut.cash_offer, currentOut.cash_offer, current.cash_offer, {}),
    mao: firstValue(oeOut.mao, currentOut.mao, current.mao),
    wholesaleFee: firstValue(oeOut.wholesale_fee, currentOut.wholesale_fee, current.wholesale_fee),
    repairEstimate: firstValue(oeOut.repair_estimate, currentOut.repair_estimate, current.repair_estimate),
    ctsEngine: firstValue(oeOut.cts_engine, currentOut.cts_engine, current.cts_engine, {}),
    assignmentFeeRange: firstValue(oeOut.assignment_fee_range, currentOut.assignment_fee_range, current.assignment_fee_range),
    estimatedArv: firstValue(currentOut.estimated_arv, current.estimated_arv, oeOut.estimated_arv, aiOut.estimated_arv)
  };
}

