function buildAcceptanceScoringText(ctx) {
  var acc = ctx.acceptanceScoring || {};
  var rec = ctx.recommendation || {};

  var cashScore = firstValue(ctx.cashProbability, acc.cash_probability, rec.cash_probability);
  var creativeScore = firstValue(ctx.creativeProbability, acc.creative_probability, rec.creative_probability);
  var bestScore = firstValue(ctx.bestAcceptanceScore, acc.best_acceptance_score, rec.best_acceptance_score);
  var bestPath = firstValue(ctx.bestAcceptancePath, acc.best_acceptance_path, rec.best_acceptance_path, 'unknown');
  var underwritingEvaluation = firstValue(ctx.underwritingEvaluationLabel, ctx.underwritingEvaluation, acc.underwriting_evaluation_label, rec.evaluation, 'N/A');
  var executionContext = firstValue(ctx.executionContext, acc.execution_context, rec.execution_context, 'unknown');
  var sellerFloor = firstValue(ctx.sellerFloor, acc.seller_floor, rec.seller_floor, {});
  var stance = firstValue(ctx.sellerStance, acc.seller_stance, rec.seller_stance, {});
  var cashBreakdown = acc.cash_probability_breakdown || {};
  var creativeBreakdown = acc.creative_probability_breakdown || {};
  var manualReasons = acc.manual_review_reasons || rec.manual_review_reasons || [];

  var lines = [];

  lines.push('🤖 Underwriting Acceptance Scoring');
  lines.push('• Execution Context: ' + executionContext);
  lines.push('• Cash Probability: ' + scoreText(cashScore));
  lines.push('• Creative Probability: ' + scoreText(creativeScore));
  lines.push('• Best Path: ' + (bestPath || 'N/A'));
  lines.push('• Underwriting Evaluation: ' + underwritingEvaluation);
  lines.push('• Seller Floor: ' + (sellerFloor.formatted || money(sellerFloor.value, 0)));
  lines.push('• Seller Floor Source: ' + (sellerFloor.source || 'N/A') + ' (' + (sellerFloor.confidence || 'unknown') + ' confidence)');
  lines.push('• Seller Urgency: ' + (stance.urgency_band || 'unknown'));
  lines.push('• Price Flexibility: ' + (stance.price_flexibility || 'unknown'));
  lines.push('• Creative Openness: ' + (stance.terms_openness || 'unknown'));

  if (executionContext === 'pre_call') lines.push('• Context Note: Pre-call scoring uses public/inferred seller signals only. Seller motivation is not confirmed yet.');
  if (executionContext === 'post_call') lines.push('• Context Note: Post-call scoring uses transcript/seller/agent evidence.');

  lines.push('• Why: ' + explainEvaluation(bestScore));

  if (Array.isArray(cashBreakdown.reasons) && cashBreakdown.reasons.length) {
    lines.push('• Cash Score Notes:');
    cashBreakdown.reasons.slice(0, 5).forEach(function(r) {
      lines.push('•   - ' + r);
    });
  }

  if (Array.isArray(creativeBreakdown.reasons) && creativeBreakdown.reasons.length) {
    lines.push('• Creative Score Notes:');
    creativeBreakdown.reasons.slice(0, 6).forEach(function(r) {
      lines.push('•   - ' + r);
    });
  }

  if (Array.isArray(manualReasons) && manualReasons.length) {
    lines.push('• Manual Review Reasons:');
    manualReasons.forEach(function(r) {
      lines.push('•   - ' + r);
    });
  }

  if (isPresent(ctx.leadScoreExplanation)) lines.push('• Router Explanation: ' + clean(ctx.leadScoreExplanation));

  return lines.join('\n');
}

