  pushLine(lines, 'DSCR', ia['DSCR']);
  pushLine(lines, 'Monthly Cash-flow', ia['Monthly Cash-flow']);
  pushLine(lines, 'Annual Cash-flow', ia['Annual Cash-flow']);
  pushLine(lines, 'Break-even Rent', ia['Break-even Rent']);
  pushLine(lines, 'Rent Gap to Break-even', ia['Rent Gap to Break-even']);
  pushLine(lines, 'Cash Flow Profile', ia['Cash Flow Profile']);
  pushLine(lines, 'Years to Recapture Cash In', ia['Years to Recapture Cash In']);
  pushLine(lines, 'Total Cash In', ia['Total Cash In']);
  pushLine(lines, 'Cash-on-Cash Return', ia['Cash-on-Cash Return']);
  pushLine(lines, '2% Rule', ia['2% Rule']);
  pushLine(lines, '50% Rule', ia['50% Rule']);

  if (isPresent(ctx.investorsAnalysisInsights)) {
    lines.push('• Insight: ' + clean(ctx.investorsAnalysisInsights));
  }

  return lines.join('\n');
}

function buildOfferSection(title, offer) {
  if (!offer || !isPresent(offer.Type || offer.offer_type)) return title + '\n• —';

  var type = firstValue(offer.offer_type, offer.Type, 'Offer');
  var typeKey = lower(type);
  var lines = [];

  lines.push(title);
  lines.push('• Type: ' + type);

  pushLine(lines, 'Purchase Price', offerField(offer, 'Purchase Price'));
  pushLine(lines, 'Requested Price', offerField(offer, 'Requested Price'));
  pushLine(lines, 'Target DSCR', offerField(offer, 'Target DSCR'));
  pushLine(lines, 'DSCR-Adjusted Price', offerField(offer, 'DSCR-Adjusted Price'));
  pushLine(lines, 'Price Adjusted for DSCR', offerField(offer, 'Price Adjusted for DSCR'));

  if (typeKey.indexOf('subject') >= 0) {
    pushLine(lines, 'CTS', offerField(offer, 'cts', 'CTS ($)', 'Cash to Seller'));
    pushLine(lines, 'CTS %', offerField(offer, 'cts_pct', 'CTS (%)'));
    pushLine(lines, 'Existing Loan Balance', offerField(offer, 'existing_loan_balance', 'Existing Loan Balance'));
    pushLine(lines, 'Existing Loan Rate', offerField(offer, 'existing_loan_rate', 'Existing Loan Interest Rate', 'Loan Rate (%)', 'Interest Rate (%)'));
    pushLine(lines, 'Existing Loan Monthly PI', offerField(offer, 'existing_loan_monthly_pi', 'Existing Loan Monthly Payment (PI)', 'Monthly Payment (PI)'));
    pushLine(lines, 'Combined Monthly PI', offerField(offer, 'combined_monthly_pi', 'Combined Monthly Payment (PI)'));
  } else if (typeKey.indexOf('hybrid') >= 0) {
    pushLine(lines, 'CTS', offerField(offer, 'cts', 'CTS ($)', 'Cash to Seller'));
    pushLine(lines, 'CTS %', offerField(offer, 'cts_pct', 'CTS (%)'));
    pushLine(lines, 'Existing Loan Balance', offerField(offer, 'existing_loan_balance', 'Existing Loan Balance'));
    pushLine(lines, 'Existing Loan Rate', offerField(offer, 'existing_loan_rate', 'Existing Loan Interest Rate'));
    pushLine(lines, 'Existing Loan Monthly PI', offerField(offer, 'existing_loan_monthly_pi', 'Existing Loan Monthly Payment (PI)'));
    pushLine(lines, 'Seller Carry Principal', offerField(offer, 'seller_carry_principal', 'Seller Carryback Loan'));
    pushLine(lines, 'Seller Carry Rate', offerField(offer, 'seller_carry_rate', 'Seller Carryback Interest Rate'));
    pushLine(lines, 'Seller Carry Amort Years', offerField(offer, 'seller_carry_amort_years'));
    pushLine(lines, 'Seller Carry Balloon Years', offerField(offer, 'seller_carry_balloon_years', 'Balloon Term (Years)'));
    pushLine(lines, 'Seller Carry Monthly PI', offerField(offer, 'seller_carry_monthly_pi', 'Seller Carryback Monthly Payment (PI)'));
    pushLine(lines, 'Combined Monthly PI', offerField(offer, 'combined_monthly_pi', 'Combined Monthly Payment (PI)'));
  } else {
    pushLine(lines, 'Down Payment', offerField(offer, 'down_payment', 'Down Payment ($)'));
    pushLine(lines, 'Down Payment %', offerField(offer, 'down_payment_pct', 'Down Payment (%)'));
    pushLine(lines, 'Seller Carry Principal', offerField(offer, 'seller_carry_principal', 'Seller Carryback Loan', 'Financed Amount'));
    pushLine(lines, 'Seller Carry Rate', offerField(offer, 'seller_carry_rate', 'Seller Carryback Interest Rate', 'Loan Rate (%)', 'Interest Rate (%)'));
    pushLine(lines, 'Seller Carry Amort Years', offerField(offer, 'seller_carry_amort_years', 'Amortization (Years)'));
    pushLine(lines, 'Seller Carry Balloon Years', offerField(offer, 'seller_carry_balloon_years', 'Balloon Term (Years)'));
    pushLine(lines, 'Seller Carry Monthly PI', offerField(offer, 'seller_carry_monthly_pi', 'Seller Carryback Monthly Payment (PI)', 'Monthly Payment (PI)'));
  }

  pushLine(lines, 'Monthly Taxes and Insurance (TI)', offerField(offer, 'Monthly Taxes and Insurance (TI)', 'Monthly Taxes & Insurance'));
  pushLine(lines, 'ADS', offerField(offer, 'ADS'));
  pushLine(lines, 'DSCR', offerField(offer, 'DSCR'));
  pushLine(lines, 'Monthly Cash-flow', offerField(offer, 'Monthly Cash-flow'));
  pushLine(lines, 'Annual Cash-flow', offerField(offer, 'Annual Cash-flow'));
  pushLine(lines, 'Break-even Rent', offerField(offer, 'Break-even Rent'));
  pushLine(lines, 'Rent Gap to Break-even', offerField(offer, 'Rent Gap to Break-even'));
  pushLine(lines, 'Rent Needed for Target DSCR', offerField(offer, 'Rent Needed for Target DSCR'));
  pushLine(lines, 'Rent Gap to Target DSCR', offerField(offer, 'Rent Gap to Target DSCR'));
  pushLine(lines, 'Cash Flow Profile', offerField(offer, 'Cash Flow Profile'));
  pushLine(lines, 'Years to Recapture Cash In', offerField(offer, 'Years to Recapture Cash In'));
  pushLine(lines, 'Total Entry Fee', offerField(offer, 'total_entry_fee', 'Total Entry Fee'));
  pushLine(lines, 'Cash-on-Cash Return', offerField(offer, 'Cash-on-Cash Return'));

  if (isPresent(offer.Justification)) lines.push('• Justification: ' + clean(offer.Justification));

  return lines.join('\n');
}

function buildCashUnderwritingNote(ctx) {
  var cash = ctx.cashOffer || {};
  var mao = firstValue(cash.cash_offer, ctx.mao, 0);

  return 'Cash MAO is ' + money(mao, 0) + '. This MAO is based on the ARV cash-offer table and does not automatically deduct estimated repairs, buyer closing costs, seller agent fees, or wholesale fee. Those numbers are displayed as closer reference points only. Repairs should only be deducted from the seller-facing offer if the transcript, agent notes, inspection comments, or listing remarks specifically confirm repair issues. Closing costs, seller agent fees, and wholesale fees are negotiation levers, not automatic deductions from the initial MAO.';
}

function buildCashOfferSection(ctx) {
  var updated = ctx.dealStructure['Updated Cash Offer'] || {};
  var cash = ctx.cashOffer || {};
  var lines = [];

  lines.push('💵 All Cash Offer');

  pushLine(lines, 'Final Cash Offer / MAO', firstValue(updated['Final Cash Offer'], cash.cash_offer, ctx.mao), function(v) {
    if (typeof v === 'string' && v.indexOf('$') >= 0) return v;
    return money(v, 0);
  });

  pushLine(lines, 'Final Cash Offer % of ARV', firstValue(updated['Final Cash Offer % of ARV'], cash.cash_offer_pct_of_arv));
  pushLine(lines, 'Cash Offer Table Used', firstValue(updated['Cash Offer Table Used'], cash.cash_offer_table));
  pushLine(lines, 'ARV', cash.arv, function(v) { return money(v, 0); });
  pushLine(lines, 'Cash Offer % Used', firstValue(cash.cash_offer_pct_used, cash.buy_box_pct));
  pushLine(lines, 'Base Cash Offer Before Repair Deduction', firstValue(updated['Base Cash Offer Before Repair Deduction'], cash.base_cash_offer_before_repair_deduction), function(v) { return money(v, 0); });

  lines.push('');
  lines.push('Closer Reference Numbers - Not Automatically Deducted');

  pushLine(lines, 'Repair Estimate Reference', firstValue(cash.repair_estimate, ctx.repairEstimate), function(v) { return money(v, 0); });
  pushLine(lines, 'Repair Deduction Used In MAO', firstValue(updated['Repair Deduction Used'], cash.repair_deduction_used), function(v) { return money(v, 0); });
  pushLine(lines, 'Repair Deduction Reason', firstValue(updated['Repair Deduction Reason'], cash.repair_deduction_reason));
  pushLine(lines, 'Low Rehab Reference', firstValue(updated['Low Rehab Reference'], cash.low_rehab_reference), function(v) { return money(v, 0); });
  pushLine(lines, 'Medium Rehab Reference', firstValue(updated['Medium Rehab Reference'], cash.medium_rehab_reference), function(v) { return money(v, 0); });
  pushLine(lines, 'Full Rehab Reference', firstValue(updated['Full Rehab Reference'], cash.full_rehab_reference), function(v) { return money(v, 0); });
  pushLine(lines, 'Buyer Closing / Acquisition Cost Reference', firstValue(updated['Buyer Acquisition Costs Reference'], cash.buyer_acquisition_costs_reference, cash.buyer_closing_costs), function(v) { return money(v, 0); });
  pushLine(lines, 'Seller Agent Fee Reference', firstValue(updated['Seller Agent Fee Reference'], cash.seller_agent_fee_reference), function(v) { return money(v, 0); });
  pushLine(lines, 'Seller Closing Costs Reference', firstValue(updated['Seller Closing Costs Reference'], cash.seller_closing_costs_reference), function(v) { return money(v, 0); });
  pushLine(lines, 'Wholesale Fee Reference', firstValue(cash.wholesale_fee, ctx.wholesaleFee), function(v) { return money(v, 0); });
  pushLine(lines, 'Spread vs List Price', cash.spread_vs_list_price, function(v) { return money(v, 0); });
  pushLine(lines, 'Deal Viable', cash.deal_viable);

  lines.push('');
  lines.push('• Underwriting Note: ' + buildCashUnderwritingNote(ctx));

  if (isPresent(updated.Justification)) lines.push('• Engine Note: ' + clean(updated.Justification));

  return lines.join('\n');
}

function buildCtsEngineSection(ctx) {
  var c = ctx.ctsEngine || {};
  if (!hasAnyKey(c, ['seller_retail_net', 'recommended_cts'])) return null;

  var lines = [];
  lines.push('🧭 CTS Engine');
  pushLine(lines, 'Seller Retail Net', c.seller_retail_net, function(v) { return money(v, 0); });
  pushLine(lines, 'Agent Commission', c.agent_commission, function(v) { return money(v, 0); });
  pushLine(lines, 'Seller Closing Costs', c.seller_closing_costs, function(v) { return money(v, 0); });
  pushLine(lines, 'CTS Conservative', c.cts_conservative, function(v) { return money(v, 0); });
  pushLine(lines, 'CTS Standard', c.cts_standard, function(v) { return money(v, 0); });
  pushLine(lines, 'CTS Aggressive', c.cts_aggressive, function(v) { return money(v, 0); });
  pushLine(lines, 'Recommended CTS', c.recommended_cts, function(v) { return money(v, 0); });
  pushLine(lines, 'Motivation Bracket', c.motivation_bracket);
  pushLine(lines, 'Hard Cap 15%', c.hard_cap_15pct, function(v) { return money(v, 0); });

  if (isPresent(ctx.assignmentFeeRange)) lines.push('• Assignment Fee Range: ' + ctx.assignmentFeeRange);

  return lines.join('\n');
}

function buildCompsSection(ctx) {
  var comps = Array.isArray(ctx.compPropertiesReport) ? ctx.compPropertiesReport.slice(0, 5) : [];
  var lines = [];

  lines.push('📌 Comps');

  if (isPresent(ctx.compsSummary)) lines.push('• Summary: ' + clean(ctx.compsSummary));

  if (!comps.length) {
    lines.push('• —');
    return lines.join('\n');
  }

  comps.forEach(function(c, i) {
    var bits = [];
    bits.push(c.address || '—');

    if (isPresent(c.price)) bits.push(money(c.price, 0));
    if (isPresent(c.beds) || isPresent(c.bedrooms)) bits.push(firstValue(c.beds, c.bedrooms) + 'bd');
    if (isPresent(c.baths) || isPresent(c.bathrooms)) bits.push(firstValue(c.baths, c.bathrooms) + 'ba');
    if (isPresent(c.squareFootage)) bits.push(c.squareFootage + ' sf');
    if (isPresent(c.daysOnMarket)) bits.push('DOM ' + c.daysOnMarket);
    if (isPresent(c.distance)) bits.push('Dist ' + c.distance);
    if (isPresent(c.correlation)) bits.push('Corr ' + c.correlation);

    lines.push('• Comp ' + (i + 1) + ': ' + bits.join(', '));
  });

  return lines.join('\n');
}

function buildBuyerMatchesSection(ctx, showContact) {
  var buyers = Array.isArray(ctx.buyerMatches) ? ctx.buyerMatches.slice(0, 5) : [];
  var lines = [];

  lines.push('👤 Buyer Matches');

  if (isPresent(ctx.buyerMatchSummary)) lines.push('• Summary: ' + clean(ctx.buyerMatchSummary));

  if (!buyers.length) {
    lines.push('• —');
    return lines.join('\n');
  }

  buyers.forEach(function(b) {
    var head = (b.buyer || '—') + ' (' + (b.score != null ? b.score : '—') + ') [' + (b.level || '—') + ']' + (b.rationale ? ' — ' + b.rationale : '');
    lines.push('• ' + head);

    if (showContact) {
      var contact = b.contact || {};
      var parts = [];

      if (isPresent(contact.name)) parts.push(contact.name);
      if (isPresent(contact.company)) parts.push(contact.company);
      if (isPresent(contact.email)) parts.push(contact.email);
      if (isPresent(contact.phone)) parts.push(String(contact.phone));

      if (parts.length) lines.push('•   Contact: ' + parts.join(' | '));
    }
  });

  return lines.join('\n');
}

function buildDispoSection(ctx) {
  var d = ctx.dispoStrategy || {};
  if (!hasAnyKey(d, ['recommendedDispoStrategy', 'bestEndBuyerType', 'projectedAssignmentFee'])) return null;

  var lines = [];
  lines.push('🧭 Disposition Strategy');

  pushLine(lines, 'Recommended Strategy', d.recommendedDispoStrategy);
  pushLine(lines, 'Best End Buyer Type', d.bestEndBuyerType);
  pushLine(lines, 'Projected Assignment Fee', d.projectedAssignmentFee);

  if (Array.isArray(d.endBuyerExitStrategyProfitProjections) && d.endBuyerExitStrategyProfitProjections.length) {
    lines.push('• End Buyer Exit Strategy Profit Projections:');
    d.endBuyerExitStrategyProfitProjections.forEach(function(x) {
      lines.push('•   • ' + x);
    });
  }

  return lines.join('\n');
}

function buildRecommendationsSection(ctx) {
  if (!isPresent(ctx.finalRecommendationsAndInsights)) return null;
  return '📬 Final Recommendations and Insights\n• ' + clean(ctx.finalRecommendationsAndInsights);
}

function buildTranscriptSection(ctx) {
  var t = firstValue(ctx.transcript && ctx.transcript.output, ctx.transcript, {});
  if (!hasAnyKey(t, ['sellerUrgency', 'sellerHardship', 'conditionOfProperty', 'price', 'additionalInsights'])) return null;

  var lines = [];
  lines.push('🗒️ Transcript Insights');
  pushLine(lines, 'Seller Urgency', t.sellerUrgency);
  pushLine(lines, 'Seller Hardship', t.sellerHardship);
  pushLine(lines, 'Condition', t.conditionOfProperty);
  pushLine(lines, 'Price / Terms', t.price);
  pushLine(lines, 'Additional', t.additionalInsights);

  return lines.join('\n');
}

function buildLeadSection(ctx) {
  return buildAcceptanceScoringText(ctx);
}

function buildLoanSection(ctx) {
  var ex = ctx.existingLoan || {};
  if (!hasAnyKey(ex, ['balance', 'rate', 'sellerMonthlyPaymentPI', 'original_principal', 'ltv'])) return null;

  var lines = [];
  lines.push('🏦 Existing Loan');

  pushLine(lines, 'Balance', ex.balance, function(v) { return money(v, 0); });
  pushLine(lines, 'Rate', ex.rate, function(v) { return pct(v, 2); });
  pushLine(lines, 'Monthly PI', ex.sellerMonthlyPaymentPI, function(v) { return money(v, 2); });
  pushLine(lines, 'Original Principal', ex.original_principal, function(v) { return money(v, 0); });
  pushLine(lines, 'LTV', ex.ltv, function(v) { return pct(Number(v) <= 1.5 ? Number(v) * 100 : v, 2); });

  return lines.join('\n');
}

function buildOffersSection(ctx, includeCtsEngine) {
  var sections = [];

  sections.push('💼 Deal Structure');
  sections.push(buildOfferSection('Primary Offer', ctx.dealStructure['Primary Offer']));
  sections.push(buildOfferSection('Backup Offer', ctx.dealStructure['Backup Offer']));
  sections.push(buildCashOfferSection(ctx));

  if (includeCtsEngine) {
    var cts = buildCtsEngineSection(ctx);
    if (cts) sections.push(cts);
  }

  return sections.join('\n\n');
}

function buildCloserCashReferenceChecklist(ctx) {
  return [
    '💵 Cash MAO Interpretation',
    '• ' + buildCashUnderwritingNote(ctx),
    '• Do not reduce the initial cash offer just because reference repairs or fees are shown.',
    '• Use repair references only if the seller/agent/listing confirms actual condition issues.',
    '• Use closing costs, seller agent fee, and wholesale fee as negotiation context, not automatic deductions.'
  ].join('\n');
}

function buildPrequalifier(ctx) {
  return [
    buildHeader(ctx),
    buildLeadSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, false),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, false),
    buildTranscriptSection(ctx)
  ].filter(Boolean).join('\n\n');
}

function buildCloser(ctx) {
  return [
    buildHeader(ctx),
    buildLoanSection(ctx),
    buildLeadSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, true),
    buildCloserCashReferenceChecklist(ctx),
    buildDispoSection(ctx),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, false),
    buildRecommendationsSection(ctx),
    '🧰 Closer Checklist\n' + [
      '• Verify payoff, PI, escrow, arrears, HOA, liens, solar, and any loss-mit status',
      '• Reconfirm CTS / cash to seller and who is covering closing costs',
      '• Reconfirm move-out timing and title / attorney / escrow path',
      '• Use the AI justification as the narrative and the OFFER ENGINE numbers as the hard math',
      '• Cash MAO excludes unconfirmed repairs and excludes closing costs unless closer chooses to negotiate them in'
    ].join('\n')
  ].filter(Boolean).join('\n\n');
}

function buildTC(ctx) {
  return [
    buildHeader(ctx),
    buildLeadSection(ctx),
    buildLoanSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, true),
    buildCloserCashReferenceChecklist(ctx),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, true),
    buildRecommendationsSection(ctx)
  ].filter(Boolean).join('\n\n');
}

function buildDispoManager(ctx) {
  return [
    buildHeader(ctx),
    buildLeadSection(ctx),
    buildLoanSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, true),
    buildCloserCashReferenceChecklist(ctx),
    buildDispoSection(ctx),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, true),
    buildRecommendationsSection(ctx)
  ].filter(Boolean).join('\n\n');
}

function buildOwner(ctx) {
  return [
    buildHeader(ctx),
    buildLeadSection(ctx),
    buildLoanSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, true),
    buildCloserCashReferenceChecklist(ctx),
    buildDispoSection(ctx),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, true),
    buildRecommendationsSection(ctx)
  ].filter(Boolean).join('\n\n');
}

function buildOwnerHtml(ctx) {
  var bodyText = [
    buildLoanSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, true),
    buildCloserCashReferenceChecklist(ctx),
    buildDispoSection(ctx),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, true),
    buildRecommendationsSection(ctx)
  ].filter(Boolean).join('\n\n');

  return [
    buildHeaderHtml(ctx),
    buildAcceptanceScoringHtml(ctx),
    '<div style="font-family:Arial,Helvetica,sans-serif;border:1px solid #dbe3ef;border-radius:16px;background:#ffffff;padding:16px 18px;margin-top:16px;color:#0f172a;font-size:13px;line-height:1.45;">' + nlToBr(bodyText) + '</div>'
  ].filter(Boolean).join('\n');
}

function buildEndBuyer(ctx) {
  return [
    buildHeader(ctx),
    buildLeadSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOfferSection('Primary Offer', ctx.dealStructure['Primary Offer']),
    buildCashOfferSection(ctx),
    buildCompsSection(ctx),
    buildDispoSection(ctx)
  ].filter(Boolean).join('\n\n');
}

function buildRoleNotes(ctx) {
  var notes = {
    prequalifier: buildPrequalifier(ctx),
    closer: buildCloser(ctx),
    tc: buildTC(ctx),
    dispo_manager: buildDispoManager(ctx),
    owner: buildOwner(ctx),
    end_buyer: buildEndBuyer(ctx)
  };

  var out = {};

  Object.keys(notes).forEach(function(key) {
    out[key] = {
      text: notes[key],
      html: key === 'owner' ? buildOwnerHtml(ctx) : nlToBr(notes[key]),
      discord: toDiscord(notes[key])
    };
  });

  return out;
}

function buildFallbackLoi(ctx) {
  var p = ctx.property || {};
  var addr = [p.address, p.city, p.state, p.postal_code].filter(Boolean).join(', ') || 'the subject property';
  var primary = ctx.dealStructure['Primary Offer'] || {};
  var cash = ctx.dealStructure['Updated Cash Offer'] || {};

  return [
    '<html><body>',
    '<h2>Letter of Intent - ' + escapeHtml(addr) + '</h2>',
    '<p>Please consider the following purchase options:</p>',
    '<h3>Option 1: All Cash</h3>',
    '<p>Purchase Price: ' + escapeHtml(firstValue(cash['Final Cash Offer'], '—')) + '</p>',
    '<h3>Option 2: Creative Offer</h3>',
    '<p>Type: ' + escapeHtml(firstValue(primary.Type, primary.offer_type, '—')) + '</p>',
    '<p>Purchase Price: ' + escapeHtml(firstValue(primary['Purchase Price'], '—')) + '</p>',
    '<p>Cash to Seller / CTS: ' + escapeHtml(firstValue(primary.cts, primary['CTS ($)'], primary['Cash to Seller'], primary['Down Payment ($)'], '—')) + '</p>',
    '<p>Justification: ' + escapeHtml(clean(primary.Justification || '') || '—') + '</p>',
    '</body></html>'
  ].join('');
}

function buildOutput(a) {
  var ctx = buildContext(a);
  var role_notes = buildRoleNotes(ctx);
  var ownerOneLine = role_notes.owner.text.replace(/\n+/g, ' | ').replace(/\s+/g, ' ').trim();

  return {
    role_notes: role_notes,
    pretty_summary_one_line: ownerOneLine,
    pretty_json: JSON.stringify(a, null, 2),

    ai_underwriting_note: role_notes.owner.html,
    pretty_note_ghl: role_notes.owner.text,

    direct_to_agent_loi: firstValue(ctx.loi, buildFallbackLoi(ctx))
  };
}

if (typeof item !== 'undefined') {
  return [{ json: buildOutput(item && item.json ? item.json : {}) }];
}

var allItems = (typeof items !== 'undefined') ? items : $input.all();

return allItems.map(function(it) {
  return { json: buildOutput(it && it.json ? it.json : {}) };
});

const items = $input.all();

let targetEmail = null;
let users = null;

// Step 1: Find targetEmail and users[] from passed inputs
for (const item of items) {
  const j = item.json;

  if (!targetEmail && typeof j?.targetEmail === 'string') {
    targetEmail = j.targetEmail;
  }

  if (!users && Array.isArray(j?.users)) {
    users = j.users;
  }
}

// Step 2: Validate
if (!targetEmail) {
  return [{ json: { error: true, message: "Target email missing from inputs." } }];
}

if (!Array.isArray(users)) {
  return [{ json: { error: true, message: "Users array missing or invalid." } }];
}

// Step 3: Match
const emailNorm = targetEmail.trim().toLowerCase();

const matched = users.filter(u =>
  typeof u?.email === 'string' &&
  u.email.trim().toLowerCase() === emailNorm
);

if (matched.length === 0) {
  return [{
    json: {
      error: true,
      message: `No user found for email: ${targetEmail}`,
      usersCount: users.length
    }
  }];
}

return matched.map(user => ({ json: user }));

try {
  let nextSteps = $input.first().json.output.nextSteps;

  // Handle stringified or single-object cases
  if (typeof nextSteps === 'string') {
    try { nextSteps = JSON.parse(nextSteps); } catch {}
  }
  if (nextSteps && typeof nextSteps === 'object' && !Array.isArray(nextSteps)) {
    nextSteps = [nextSteps];
  }

  if (!Array.isArray(nextSteps)) {
    return [{
      json: {
        error: true,
        message: "Pack Agent Input → transcript_insights.nextSteps not found or not an array"
      }
    }];
  }

  return nextSteps
    .filter(s => s && typeof s === 'object')
    .map(s => ({ json: s }));

} catch (err) {
  return [{ json: { error: true, message: err?.message || "Unexpected error" } }];
}

