#/******************************************************
 🧮 RECOMPUTE NODE — v2.9 "Pace-Mode" (Final)
 -----------------------------------------------------
 Purpose:
  - Merge upstream agent + pack data
  - Resolve rent (with strong fallback) and recompute NOI/metrics
  - Construct creative structures with investor + seller guardrails:
      • Seller Financing (must clear payoff; option to cover seller fees)
      • SubTo (no balloon; cash-to-seller strategy vs retail net)
      • Hybrid = SubTo + Seller Carry (2nd) for equity
  - Enforce down/entry caps with CF-based wiggle room
  - Add Seller Interest Delta for Seller Finance
  - Compute Updated Cash Offer with bracket + list delta
  - Lead scoring (with no-transcript override) + pipeline stage (RESTORED)
  - LOI is seller-facing, no jargon, tailored to primary structure
******************************************************/

/***** ---------- [0] Helpers ---------- *****/
function parseNum(x) {
  if (x == null) return 0;
  if (typeof x === 'number') return Number.isFinite(x) ? x : 0;
  const n = parseFloat(String(x).replace(/[^\d.\-]/g, ''));
  return Number.isFinite(n) ? n : 0;
}
function pmt(rateAnnualPct, years, principal) {
  const r = (rateAnnualPct / 100) / 12;
  const n = years * 12;
  if (n <= 0 || principal <= 0) return 0;
  if (r === 0) return principal / n;
  return (r * principal) / (1 - Math.pow(1 + r, -n));
}
function safeParse(x) { try { return (typeof x === 'string') ? JSON.parse(x) : x; } catch { return null; } }
function money(n) { const v = Number.isFinite(n) ? n : 0; return `$${(Math.round(v * 100) / 100).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}`; }
function pct(v) { const n = parseNum(v); return `${n.toFixed(2)} %`; }
function cashPctForARV(arv) { if (arv < 150000) return 0.53; if (arv < 200000) return 0.56; if (arv < 300000) return 0.66; if (arv < 400000) return 0.71; if (arv < 500000) return 0.72; return 0.73; }
function median(arr){ const a=arr.slice().sort((x,y)=>x-y); const n=a.length; if(!n) return 0; const m=Math.floor(n/2); return n%2? a[m] : Math.round((a[m-1]+a[m])/2); }
function text(s){ return String(s || '').toLowerCase(); }
function hasSignal(s, rx){ return !!(s && rx.test(s)); }
function topBuyerScore(matches){ return Array.isArray(matches) && matches.length ? (parseNum(matches[0].score) || 0) : 0; }
const clamp = (v, min, max) => Math.min(max, Math.max(min, v));

/***** ---------- [0.1] Config Defaults (seller fees) ---------- *****/
// Buyer closing you already track via config.closingCostRate (often 8%)
const DEFAULT_AGENT_FEE_RATE     = 0.06;   // seller’s agent side + listing side (simplified)
const DEFAULT_SELLER_CLOSE_RATE  = 0.02;   // seller-side closing estimate
const DEFAULT_RET_CARRY_RATE     = 5.5;    // default seller-carry rate for hybrid trials
const DEFAULT_BANK_RATE          = 6.5;    // bank piece for hybrid (if used)

/***** ---------- [1] Merge Inputs ---------- *****/
try {
  const inputs = $input.all().map(i => i.json || {});
  const pack   = inputs.find(i => i.metrics || i.config || i.property || i.buyer_matches) || {};
  const agentH = inputs.find(i => Object.prototype.hasOwnProperty.call(i,'output')) || {};
  const agent  = safeParse(agentH.output) || agentH || {};

  // Bring context forward (prefer upstream when agent omitted)
  const M  = pack.metrics || {};
  const C  = pack.config  || {};
  const P  = pack.property || {};
  const T  = pack.transcript_insights || {};
  agent.transcript_insights = T || agent.transcript_insights || null;
  for (const k of ['property','rental_estimates','existing_loan']) if (pack[k]) agent[k] = pack[k];
  if (!agent.buyer_matches && Array.isArray(pack.buyer_matches)) {
    agent.buyer_matches = pack.buyer_matches;
    if (pack.buyer_match_summary) agent.buyer_match_summary = pack.buyer_match_summary;
  }
  if (pack.config)  agent.config  = pack.config;
  if (pack.metrics) agent.metrics = pack.metrics;

  /***** ---------- [2] ARV & Price Baseline ---------- *****/
  const comps = agent.comp_properties_report || pack.comp_properties_report || [];
  const compPrices = comps.map(c => parseNum(c.price)).filter(Boolean);
  const arvFromComps = median(compPrices);
  const arvAgent     = parseNum(agent.estimated_arv);
  const arvProp      = parseNum(P.est_value);
  const ARV          = arvAgent || arvProp || arvFromComps || 0;
  if (ARV) agent.estimated_arv = ARV;

  const priceFromPO  = parseNum(agent.deal_structure?.['Primary Offer']?.['Purchase Price']);
  const basePrice    = priceFromPO || parseNum(M.price) || parseNum(P.list_price) || (ARV || 0);
  const listPriceNum = parseNum(P.list_price) || parseNum(M.price) || basePrice;

  /***** ---------- [3] Rent Resolution & NOI Recompute ---------- *****/
  const R = agent.rental_estimates || {};
  // Resolve monthly rent (strong fallback cascade)
  const rentMonthly =
    (parseNum(M.grossRent) > 0 ? parseNum(M.grossRent) : 0) ||
    parseNum(R.from_webhook_monthly_income) ||
    parseNum(R.from_comp_pull_high) ||
    parseNum(R.from_deal_sauce_high) ||
    parseNum(R.from_comp_pull_low) ||
    parseNum(R.from_deal_sauce_low) || 0;

  // If upstream left annualRent alone, recompute from monthly
  const annualRent = rentMonthly * 12;

  // If opex components zeroed, reconstruct from config rates (mgmt/maint/vacancy) + explicit T&I
  const taxes      = parseNum(M.taxes);
  const insurance  = parseNum(M.insurance);
  const mgmtRate   = (C.mgmtRate != null) ? C.mgmtRate : 0.08;
  const maintRate  = (C.maintRate != null) ? C.maintRate : 0.05;
  const vacRate    = (C.vacancyRate != null) ? C.vacancyRate : 0.05;

  const mgmt   = (parseNum(M.mgmt)   || (annualRent * mgmtRate));
  const maint  = (parseNum(M.maint)  || (annualRent * maintRate));
  const vac    = (parseNum(M.vacancy)|| (annualRent * vacRate));
  const opex   = taxes + insurance + mgmt + maint + vac;

  const NOI    = Math.max(annualRent - opex, 0);
  const moTI   = (taxes + insurance) / 12;   // tracking info only

  /***** ---------- [4] Existing Loan Merge (safe) ---------- *****/
  const packLoan  = pack.existing_loan || {};
  const agentLoan = agent.existing_loan || {};
  const EL = {
    balance: parseNum(packLoan.balance || agentLoan.balance),
    payment: parseNum(packLoan.payment || agentLoan.payment),
    rate:    parseNum(packLoan.rate    || agentLoan.rate),
    source:  packLoan.source || agentLoan.source || "unknown"
  };

  /***** ---------- [5] Seller Profile & Rehab Heuristic (light-touch) ---------- *****/
  const Turg = text(T.sellerUrgency);
  const Thrd = text(T.sellerHardship);
  const Tcond= text(T.conditionOfProperty);
  // Seller state: aggressive if neutral/patient; standard if urgency/hardship; conservative if both strong
  const urgStrong  = hasSignal(Turg, /\b(asap|urgent|immediately|must\s*sell|quick\s*close|holding\s*costs)\b/);
  const hardStrong = hasSignal(Thrd, /\b(foreclos|pre[-\s]*foreclos|divorce|job\s*loss|medical|probate|relocat)\b/);
  let sellerState = 'aggressive';
  if (urgStrong || hardStrong) sellerState = 'standard';
  if (urgStrong && hardStrong) sellerState = 'conservative';

  // Rehab estimate (only if transcript hints at issues; else 0)
  let rehabEst = 0;
  if (hasSignal(Tcond, /\b(needs|deferred|roof|hvac|plumb|electric|foundation|major|repairs?)\b/)) rehabEst = Math.round(basePrice * 0.03);

  /***** ---------- [6] Fees & Caps ---------- *****/
  const BUYER_CLOSE_RATE    = (C.closingCostRate != null) ? C.closingCostRate : 0.08; // your existing assumption
  const AGENT_FEE_RATE      = (C.listAgentFeeRate != null) ? C.listAgentFeeRate : DEFAULT_AGENT_FEE_RATE;
  const SELLER_CLOSE_RATE   = (C.sellerClosingRate != null) ? C.sellerClosingRate : DEFAULT_SELLER_CLOSE_RATE;
  const SELLER_SIDE_RATE    = AGENT_FEE_RATE + SELLER_CLOSE_RATE;
  const ASSIGN_RATE         = (C.assignmentPctOfDown != null) ? C.assignmentPctOfDown : 0.25;

  // % caps: prefer ≤10% down & ≤15% total entry; allow up to 15% down / 20% entry if CF ≥ $500
  const BASE_DP_CAP_PCT     = 10;
  const MAX_DP_CAP_PCT      = 15;
  const BASE_ENTRY_CAP_PCT  = 15;
  const MAX_ENTRY_CAP_PCT   = 20;

  /***** ---------- [7] Utility: cash-to-seller recommendation (SubTo/Hybrid) ---------- *****/
  function recommendCashToSeller(retailNet, state){
    // brackets as discussed
    const s = state || 'aggressive';
    let out = 0;
    if (retailNet <= -20000) {
      out = 0;
    } else if (retailNet <= 0) {
      out = (s==='aggressive') ? 4000 : (s==='standard' ? 1500 : 0);
    } else if (retailNet <= 5000) {
      out = (s==='aggressive') ? 7000 : (s==='standard' ? 2250 : 1500);
    } else if (retailNet <= 15000) {
      out = (s==='aggressive') ? 10000 : (s==='standard' ? 4000 : 2000);
    } else if (retailNet <= 30000) {
      out = (s==='aggressive') ? 15000 : (s==='standard' ? 7000 : 3000);
    } else {
      out = (s==='aggressive') ? 20000 : (s==='standard' ? 10000 : 5000);
    }
    return Math.max(0, Math.round(out));
  }

  /***** ---------- [8] Scoring function for candidate structures ---------- *****/
  function scoreCandidate(c){
    if (!c) return -1e12;
    const passBoost = (c.pass ? 1e6 : 0);
    return passBoost + (c.monthlyCF || -1e9) * 10 + (c.DSCR || 0) * 100 - (c.totalIn || 1e9);
  }

  /***** ---------- [9] Seller Finance Builder (must clear payoff) ---------- *****/
  function buildSellerFinanceCombos(price0){
    const results = [];
    const priceTrials = [price0, Math.round(price0 * 0.95), Math.round(price0 * 0.90)]; // two 5% reductions

    for (const price of priceTrials){
      const sellerFees = price * SELLER_SIDE_RATE;
      const buyerClosing = price * BUYER_CLOSE_RATE;

      for (const coverSellerFees of [true, false]) {
        // Required immediate cash to clear seller obligations
        const payoffNeeded = EL.balance || 0;
        const requiredCash = coverSellerFees ? payoffNeeded : Math.max(0, payoffNeeded + sellerFees);

        // Down % candidates: must be >= requiredCash/price; try 10/12.5/15
        const dpNeededPct = (price > 0) ? (requiredCash / price) * 100 : 1000;
        const dpChoices = [10, 12.5, 15].filter(p => p >= dpNeededPct && p <= 15);
        if (!dpChoices.length) continue; // price still too high to clear payoff under caps

        for (const downPct of dpChoices){
          const down$  = Math.round(price * downPct / 100);
          const prin   = Math.max(price - down$, 0);

          // Rate/Amort tries bounded by constraints (rate ≤ 4%)
          for (const ratePct of [4.0, 3.5, 3.0]){
            for (const years of [40, 30]){
              const monthPI = Math.round(pmt(ratePct, years, prin));
              const ADS     = monthPI * 12;
              const DSCR    = Number((NOI / (ADS || 1)).toFixed(2));
              const annualCF= Math.round(NOI - ADS);
              const monthlyCF = Math.round(annualCF / 12);

              const assignment = Math.round(ASSIGN_RATE * down$);
              const sellerside = coverSellerFees ? Math.round(sellerFees) : 0;
              const totalIn    = Math.round(down$ + assignment + buyerClosing + sellerside);

              // Enforce caps dynamically (allow wiggle if CF ≥ 500)
              const entryPct   = price ? (totalIn / price) * 100 : 1000;
              const dpCapOK    = (downPct <= BASE_DP_CAP_PCT) || (downPct <= MAX_DP_CAP_PCT && monthlyCF >= 500);
              const entryCapOK = (entryPct <= BASE_ENTRY_CAP_PCT) || (entryPct <= MAX_ENTRY_CAP_PCT && monthlyCF >= 500);

              // Seller Finance hard constraints
              const pass = (DSCR >= 1.20) && (monthlyCF >= 200) && (totalIn > 0) && dpCapOK && entryCapOK;

              results.push({
                type: 'Seller Financing',
                purchasePrice: price,
                down$: down$, downPct,
                ratePct, years, balloonYrs: 5,
                monthPI, ADS, DSCR, annualCF, monthlyCF, totalIn,
                coverSellerFees,
                sellerFeesPaid: sellerside,
                buyerClosing,
                payoffCleared: requiredCash,
                pass
              });
            }
          }
        }
      }
    }
    // pick best
    results.sort((a,b)=> scoreCandidate(b)-scoreCandidate(a));
    return results[0] || null;
  }

  /***** ---------- [10] SubTo Builder (no balloon) ---------- *****/
  function buildSubTo(price){
    const payoff = EL.balance || 0;
    const agentFees = price * AGENT_FEE_RATE;
    const sellerClose = price * SELLER_CLOSE_RATE;
    const sellerFees = agentFees + sellerClose;
    const buyerClosing = price * BUYER_CLOSE_RATE;

    // Retail-net estimate if seller were to go conventional
    const retailNet = Math.round(price - payoff - sellerFees - rehabEst);

    // Choose cash-to-seller per retailNet & sellerState (reversed tactic: aggressive for neutral/patient)
    let cashToSeller = recommendCashToSeller(retailNet, sellerState);

    // Two modes: cover seller fees or not — whichever yields better economics under caps
    const modes = [true, false].map(coverSellerFees => {
      const firstPI = EL.payment || (EL.rate && payoff ? Math.round(pmt(EL.rate, 30, payoff)) : 0);
      const ADS     = (firstPI || 0) * 12;
      const DSCR    = ADS ? Number((NOI / ADS).toFixed(2)) : 0;
      const annualCF= Math.round(NOI - ADS);
      const monthlyCF = Math.round(annualCF / 12);

      // Entry budget caps (allow wiggle for CF ≥ 500)
      const entryCap = (monthlyCF >= 500) ? MAX_ENTRY_CAP_PCT : BASE_ENTRY_CAP_PCT;
      const cap$     = Math.round(price * (entryCap / 100));

      // Total entry = down + assignment + buyerClosing + (optional seller fees we cover)
      const other$   = Math.round(buyerClosing + (coverSellerFees ? sellerFees : 0));
      const denom    = (1 + ASSIGN_RATE);
      const maxDown$ = Math.max(0, Math.round((cap$ - other$) / denom));

      // Clamp cash-to-seller within entry budget
      const down$    = Math.max(0, Math.min(cashToSeller, maxDown$));
      const downPct  = price ? Number(((down$ / price) * 100).toFixed(2)) : 0;

      const assignment = Math.round(ASSIGN_RATE * down$);
      const totalIn    = Math.round(down$ + assignment + other$);

      // SubTo constraints
      const rateReqOK = (payoff < 150000) ? (EL.rate <= 8.0 || !EL.rate) : (EL.rate <= 5.0 || !EL.rate);
      const dpCapOK   = (downPct <= BASE_DP_CAP_PCT) || (downPct <= MAX_DP_CAP_PCT && monthlyCF >= 500);
      const entryOK   = totalIn <= cap$;
      const cfOK      = monthlyCF >= 150;
      const pass      = rateReqOK && dpCapOK && entryOK && cfOK;

      return {
        type: 'SUBTO (Assume Existing Loan)',
        purchasePrice: price,
        down$: down$, downPct,
        ratePct: EL.rate || null, years: null, balloonYrs: null, // no balloon on SubTo
        monthPI: firstPI || 0, ADS, DSCR, annualCF, monthlyCF, totalIn,
        coverSellerFees, sellerFeesPaid: (coverSellerFees ? Math.round(sellerFees) : 0),
        buyerClosing, payoffCleared: payoff,
        cashToSellerInitial: cashToSeller,
        retailNet,
        pass
      };
    });

    modes.sort((a,b)=> scoreCandidate(b)-scoreCandidate(a));
    return modes[0] || null;
  }

  /***** ---------- [11] Hybrid Builder = SubTo + Seller Carry (2nd) ---------- *****/
  function buildHybrid(price){
    const payoff  = EL.balance || 0;
    const equity  = Math.max(price - payoff, 0);
    const firstPI = EL.payment || (EL.rate && payoff ? Math.round(pmt(EL.rate, 30, payoff)) : 0);

    const agentFees  = price * AGENT_FEE_RATE;
    const sellerClose= price * SELLER_CLOSE_RATE;
    const sellerFees = agentFees + sellerClose;
    const buyerClosing = price * BUYER_CLOSE_RATE;

    const retailNet = Math.round(price - payoff - sellerFees - rehabEst);
    let cashToSeller = recommendCashToSeller(retailNet, sellerState);
    cashToSeller = Math.min(cashToSeller, equity); // cannot exceed equity

    // Try with/without covering seller fees, and multiple carry rates/terms
    const results = [];
    for (const coverSellerFees of [true, false]) {
      const other$   = Math.round(buyerClosing + (coverSellerFees ? sellerFees : 0));
      const denom    = (1 + ASSIGN_RATE);

      // Start with requested cashToSeller; clamp to entry caps
      // We will iterate carry rate/years, but entry budget affects only the cashToSeller component.
      // Budget:
      const provisionalMonthPI = firstPI; // second PI unknown yet; we’ll score after
      const provisionalADS = (provisionalMonthPI || 0) * 12;
      const provisionalDSCR = provisionalADS ? Number((NOI / provisionalADS).toFixed(2)) : 0;
      const provisionalAnnualCF = Math.round(NOI - provisionalADS);
      const provisionalMonthlyCF = Math.round(provisionalAnnualCF / 12);

      const entryCapPct = (provisionalMonthlyCF >= 500) ? MAX_ENTRY_CAP_PCT : BASE_ENTRY_CAP_PCT;
      const cap$ = Math.round(price * (entryCapPct / 100));
      const maxDown$ = Math.max(0, Math.round((cap$ - other$) / denom));
      const down$ = Math.max(0, Math.min(cashToSeller, maxDown$));
      const downPct = price ? Number(((down$ / price) * 100).toFixed(2)) : 0;
      const assignment = Math.round(ASSIGN_RATE * down$);

      // Seller carry principal = remaining equity
      const carryPrin = Math.max(equity - down$, 0);

      for (const ratePct of [4.5, 4.0, 3.5, 3.0]) {
        for (const years of [40, 30]) {
          const carryPI = (carryPrin > 0) ? Math.round(pmt(ratePct, years, carryPrin)) : 0;
          const monthPI = (firstPI || 0) + carryPI;
          const ADS     = monthPI * 12;
          const DSCR    = ADS ? Number((NOI / ADS).toFixed(2)) : 0;
          const annualCF= Math.round(NOI - ADS);
          const monthlyCF= Math.round(annualCF / 12);

          const totalIn  = Math.round(down$ + assignment + other$);

          const entryPct = price ? (totalIn / price) * 100 : 1000;
          const dpCapOK  = (downPct <= BASE_DP_CAP_PCT) || (downPct <= MAX_DP_CAP_PCT && monthlyCF >= 500);
          const entryOK  = (entryPct <= BASE_ENTRY_CAP_PCT) || (entryPct <= MAX_ENTRY_CAP_PCT && monthlyCF >= 500);

          // Hybrid thresholds
          const pass = (DSCR >= 1.20) && (monthlyCF >= 200) && (entryOK) && (dpCapOK);

          results.push({
            type: 'Hybrid (SubTo + Seller Carry 2nd)',
            purchasePrice: price,
            down$: down$, downPct,
            ratePct: null, years: null, balloonYrs: 7, // balloon on 2nd, not on first
            carryRatePct: (carryPrin>0?ratePct:null),
            carryYears: (carryPrin>0?years:null),
            firstRatePct: EL.rate || null,
            firstBalance: payoff,
            firstPI: firstPI || 0,
            carryPrin,
            monthPI, ADS, DSCR, annualCF, monthlyCF, totalIn,
            coverSellerFees, sellerFeesPaid: (coverSellerFees ? Math.round(sellerFees) : 0),
            buyerClosing, payoffCleared: payoff,
            cashToSellerInitial: cashToSeller,
            retailNet,
            pass
          });
        }
      }
    }
    results.sort((a,b)=> scoreCandidate(b)-scoreCandidate(a));
    return results[0] || null;
  }

  /***** ---------- [12] Build Candidates Based on Equity Routing ---------- *****/
  const equityPct = (ARV > 0) ? ((ARV - (EL.balance || 0)) / ARV) * 100 : 100;
  let sfCandidate   = null;
  let subtoCandidate= null;
  let hybridCandidate= null;

  // Try all; we’ll choose routing-preferred primary & best backup
  sfCandidate    = buildSellerFinanceCombos(basePrice);
  if (EL.balance > 0) subtoCandidate  = buildSubTo(basePrice);
  if (EL.balance > 0) hybridCandidate = buildHybrid(basePrice);

  // Choose primary per routing rule of thumb
  let primaryPref = 'Seller Financing';
  if (equityPct < 15) primaryPref = 'SUBTO (Assume Existing Loan)';
  else if (equityPct <= 80) primaryPref = 'Hybrid (SubTo + Seller Carry 2nd)';

  const byType = {
    'Seller Financing': sfCandidate,
    'SUBTO (Assume Existing Loan)': subtoCandidate,
    'Hybrid (SubTo + Seller Carry 2nd)': hybridCandidate
  };

  let primary = byType[primaryPref] || sfCandidate || hybridCandidate || subtoCandidate || null;

  // Backup = best of remaining creatives (that isn’t the primary)
  const remaining = [sfCandidate, subtoCandidate, hybridCandidate].filter(x => x && x !== primary);
  remaining.sort((a,b)=> scoreCandidate(b)-scoreCandidate(a));
  let backup = remaining[0] || null;

  // If nothing viable, set backup to Wholesale/Move-on
  const wholesaleBackup = {
    'Type': 'Wholesale / Move on from this one',
    'Purchase Price': null,
    'Down Payment ($)': null,
    'Down Payment (%)': null,
    'Loan Rate (%)': null,
    'Amortization (Years)': null,
    'Balloon Term (Years)': null,
    'Monthly Payment': null,
    'ADS': null,
    'DSCR': null,
    'Monthly Cash-flow': null,
    'Cash-on-Cash Return': null,
    'Total Entry Fee': null,
    'Justification': 'No creative structure meets investor thresholds at current rents and costs. Recommend wholesale or move on unless price/terms improve.'
  };

  /***** ---------- [13] Seller-Interest Delta (SF only) ---------- *****/
  function sellerInterestDeltaForSF(c){
    if (!c || c.type !== 'Seller Financing') return 0;
    const principal = Math.max((c.purchasePrice || 0) - (c.down$ || 0), 0);
    const totalPaid = (c.ADS || 0) * (c.years || 30);
    return Math.max(0, totalPaid - principal);
  }

  /***** ---------- [14] Cash Offer per Table (with bracket + list delta) ---------- *****/
  function cashBracketLabel(arv){
    if (arv < 150000) return "< $150k → 53%";
    if (arv < 200000) return "$150–200k → 56%";
    if (arv < 300000) return "$200–300k → 66%";
    if (arv < 400000) return "$300–400k → 71%";
    if (arv < 500000) return "$400–500k → 72%";
    return "$500k+ → 73%";
  }
  const cashPct  = cashPctForARV(ARV || basePrice);
  const cashCap  = (ARV ? Math.round(ARV * cashPct) : Math.round(basePrice * (cashPct || 0.66))) || 0;
  const delta    = listPriceNum ? (listPriceNum - cashCap) : null;
  const aboveStr = delta!=null ? (delta >= 0 ? `${money(delta)} above` : `${money(-delta)} below`) : null;
  const bracketStr = ARV ? `Bracket ${cashBracketLabel(ARV)}.` : `Cash per table.`;
  const capStr     = `Max cash = ${money(cashCap)}.`;
  const listStr    = listPriceNum ? `List ${money(listPriceNum)} is ${aboveStr} the cap.` : ``;
  const tailStr    = (delta!=null && delta > 0) ? ` Recommend **Wholesale / Move on from this one** or negotiate down.` : ` Within cap.`;

  /***** ---------- [15] Compose deal_structure (authoritative) ---------- *****/
  agent.deal_structure = agent.deal_structure || {};

  // Primary — if null, show wholesale immediately
  if (!primary) {
    agent.deal_structure['Primary Offer'] = wholesaleBackup;
  } else {
    const isSF = primary.type === 'Seller Financing';
    const interestDelta = isSF ? sellerInterestDeltaForSF(primary) : 0;

    agent.deal_structure['Primary Offer'] = {
      'Type': primary.type,
      'Purchase Price': primary.purchasePrice,
      'Down Payment ($)': primary.down$,
      'Down Payment (%)': primary.downPct,
      'Loan Rate (%)': primary.ratePct,
      'Amortization (Years)': primary.years,
      'Balloon Term (Years)': primary.balloonYrs, // null for SubTo
      'Monthly Payment': primary.monthPI,
      'ADS': primary.ADS,
      'DSCR': primary.DSCR,
      'Monthly Cash-flow': primary.monthlyCF,
      'Cash-on-Cash Return': (primary.totalIn ? Number(((primary.annualCF / primary.totalIn) * 100).toFixed(2)) : null),
      'Total Entry Fee': primary.totalIn,
      ...(isSF ? { 'Interest Delta ($)': Number(interestDelta.toFixed(2)) } : {}),
      'Justification':
        (primary.pass
          ? `Meets investor gates under current rents and costs.`
          : `Does not fully meet investor gates at current rents/costs.`)
        + (isSF ? ` Over the term, this structure pays the seller ≈ ${money(interestDelta)} more in interest than a cash sale.` : ``)
    };
  }

  // Backup
  if (!backup) {
    agent.deal_structure['Backup Offer'] = wholesaleBackup;
  } else {
    agent.deal_structure['Backup Offer'] = {
      'Type': backup.type,
      'Purchase Price': backup.purchasePrice,
      'Down Payment ($)': backup.down$,
      'Down Payment (%)': backup.downPct,
      'Loan Rate (%)': backup.ratePct,
      'Amortization (Years)': backup.years,
      'Balloon Term (Years)': backup.balloonYrs,
      'Monthly Payment': backup.monthPI,
      'ADS': backup.ADS,
      'DSCR': backup.DSCR,
      'Monthly Cash-flow': backup.monthlyCF,
      'Cash-on-Cash Return': (backup.totalIn ? Number(((backup.annualCF / backup.totalIn) * 100).toFixed(2)) : null),
      'Total Entry Fee': backup.totalIn,
      'Justification': backup.pass ? `Viable alternate creative path.` : (backup.DSCR!=null ? `DSCR ${backup.DSCR}, CF $${backup.monthlyCF}/mo.` : `Alternate creative example for training.`)
    };
  }

  // Updated Cash Offer
  agent.deal_structure['Updated Cash Offer'] = {
    'Final Cash Offer': money(cashCap),
    'Final Cash Offer % of ARV': ARV ? `${(Math.round((cashCap/ARV)*10000)/100).toFixed(2)} %` : '—',
    'Justification': `${bracketStr} ${capStr} ${listStr}${tailStr}`
  };

  /***** ---------- [16] Investors Analysis (strings, based on PRIMARY) ---------- *****/
  const PA = agent.deal_structure['Primary Offer'];
  const ADS_primary       = parseNum(PA.ADS);
  const DSCR_primary      = (PA.DSCR == null) ? null : parseNum(PA.DSCR);
  const annualCF_primary  = parseNum(PA['Monthly Cash-flow']) * 12;
  const monthlyCF_primary = parseNum(PA['Monthly Cash-flow']);
  const totalIn_primary   = parseNum(PA['Total Entry Fee']);

  const rule2pct = (rentMonthly / (parseNum(PA['Purchase Price']) || 1)) >= 0.02 ? '✅' : '❌';
  const rule50   = (opex <= 0.5 * annualRent) ? '✅' : '❌';

  const cocPct  = totalIn_primary ? Number(((annualCF_primary/totalIn_primary)*100).toFixed(2)) : 0;

  const invStrings = [];
  invStrings.push(`Gross Rent: ${money(rentMonthly)}/mo`);
  invStrings.push(`Annual Rent: ${money(annualRent)}`);
  invStrings.push(`Operating Expenses: ${money(opex)}`);
  invStrings.push(`NOI: ${money(NOI)}`);
  invStrings.push(`Annual Debt Service (ADS): ${money(ADS_primary)}`);
  invStrings.push(`DSCR: ${DSCR_primary!=null ? DSCR_primary.toFixed(2) : 'n/a'} ${DSCR_primary!=null ? (DSCR_primary>=1.20?'✅ (meets 1.20 minimum)':'❌ (below 1.20 minimum)') : ''}`);
  invStrings.push(`Monthly Cash-flow: ${money(monthlyCF_primary)}`);
  invStrings.push(`Annual Cash-flow: ${money(annualCF_primary)}`);
  invStrings.push(`Total Cash In: ${money(totalIn_primary)}`);
  invStrings.push(`Cash-on-Cash Return: ${cocPct.toFixed(2)} % ${ (cocPct>=13?'✅':'❌') }`);
  invStrings.push(`2% Rule: ${rule2pct}${rule2pct==='❌'?' → Lower price or raise rent.':''}`);
  invStrings.push(`50% Rule: ${rule50}${rule50==='❌'?' → Lower expenses or reassess rent.':''}`);

  agent.investors_analysis = invStrings;

  // Insights (brief)
  agent.investors_analysis_insights =
    (PA.Type || '').startsWith('Seller Financing')
      ? (PA['Justification'] || 'Seller carry modeled under investor thresholds; see DSCR/CF/CoC for viability.')
      : (PA['Justification'] || 'Modeled under current rents and costs; see DSCR/CF/CoC for viability.');

  /***** ---------- [17] LOI (seller-facing) ---------- *****/
  function buildLOI(agentObj, primaryObj, cashCap$) {
    const addr = [P.address, P.city, P.state, P.postal_code].filter(Boolean).join(', ') || 'this property';
    const type = String(primaryObj.Type || '').trim();
    const price = money(primaryObj['Purchase Price']);
    const down  = money(primaryObj['Down Payment ($)']);
    const downPct = pct(primaryObj['Down Payment (%)']);
    const rate  = (primaryObj['Loan Rate (%)'] == null) ? '—' : pct(primaryObj['Loan Rate (%)']);
    const amort = primaryObj['Amortization (Years)'] || '—';
    const balloon= (primaryObj['Balloon Term (Years)'] == null) ? '—' : primaryObj['Balloon Term (Years)'];
    const moPI  = money(primaryObj['Monthly Payment'] || 0);

    // Seller-finance interest delta line if present
    const sfDelta = (primaryObj['Interest Delta ($)'] != null && parseNum(primaryObj['Interest Delta ($)'])>0)
      ? ` Over the term, this structure pays you about ${money(parseNum(primaryObj['Interest Delta ($)']))} more in interest than a traditional cash sale.`
      : ``;

    // Structure-specific framing
    let structureBlock = '';
    if (/^subto/i.test(type)) {
      structureBlock =
`Structure: Purchase subject-to the existing first mortgage. We will make the current payment directly and keep taxes/insurance current. No balloon is needed—this remains in place until payoff.`;
    } else if (/^Hybrid/i.test(type) || /subto.+carry/i.test(type)) {
      // If we captured carry info on backup/hybrid candidate
      const carryRate = agent.deal_structure['Backup Offer']?.carryRatePct || null;
      const carryYears= agent.deal_structure['Backup Offer']?.carryYears || null;
      structureBlock =
`Structure: Take over existing first mortgage (we make the payment) + seller-financed second for remaining equity, paid in monthly installments.`;
    } else if (/Seller Financing/i.test(type)) {
      structureBlock =
`Structure: Seller financing with low, steady monthly payments and a ${amort}-year amortization at ${rate}.`;
    }

    return `Letter of Intent (LOI)

Property: ${addr}

Primary Offer – ${type}
- Purchase Price: ${price}
- Down Payment: ${down} (${downPct})
- Terms: ${rate} interest, ${amort}-year amortization${(/^subto/i.test(type) ? '' : `, ${balloon}-year balloon`)}
- Monthly Payment: ${moPI}

Why this works for you: This approach offers a smooth, as-is sale with a flexible closing and steady monthly income.${sfDelta}

Cash Option: ${money(cashCap$)} for a quick, as-is close.

We’re flexible on timelines and details and happy to discuss.`;
  }

  agent.loi = buildLOI(agent, agent.deal_structure['Primary Offer'], cashCap);

  /***** ---------- [18] Lead Scoring (with no-transcript override) ---------- *****/
  const noTranscript = ['no transcript','not provided','unable to determine'].some(s => text(T.sellerUrgency).includes(s) || text(T.sellerHardship).includes(s) || text(T.conditionOfProperty).includes(s) || text(T.price).includes(s));
  const topFit = topBuyerScore(agent.buyer_matches);

  // Market-only scoring mode if no transcript (per Enhancement v4.3)
  if (noTranscript) {
    // Economics subscore (0–40): DSCR (0/8/15), CF (0/5/10 for ≥$200), CoC (0/5/10)
    let dscrPts = 0;
    if (DSCR_primary >= 1.50) dscrPts = 15;
    else if (DSCR_primary >= 1.30) dscrPts = 12;
    else if (DSCR_primary >= 1.20) dscrPts = 10;
    else if (DSCR_primary >= 1.10) dscrPts = 6;
    else if (DSCR_primary >= 1.00) dscrPts = 3;

    let cfPts = 0;
    if (monthlyCF_primary >= 400) cfPts = 10;
    else if (monthlyCF_primary >= 300) cfPts = 8;
    else if (monthlyCF_primary >= 200) cfPts = 5;

    let cocPts = 0;
    if (cocPct >= 12) cocPts = 10;
    else if (cocPct >= 10) cocPts = 8;
    else if (cocPct >= 8)  cocPts = 6;
    else if (cocPct >= 6)  cocPts = 4;
    else if (cocPct >= 4)  cocPts = 2;

    // Buyer Fit (0–35)
    const buyerPts = Math.round(Math.min(35, (topFit/100) * 35));

    // Price vs ARV (0–15)
    const lpa = (ARV>0) ? (listPriceNum/ARV) : 999;
    let pvaPts = 0;
    if (lpa <= 0.80) pvaPts = 15;
    else if (lpa <= 0.90) pvaPts = 10;
    else if (lpa <= 1.00) pvaPts = 5;

    // Market & Condition (0–10)
    const dom = parseNum(P.dom);
    const marketPts = (dom >= 60 ? 5 : dom >= 30 ? 3 : 0) + 5; // +5 default for unknown/fair condition

    let score = Math.min(100, Math.round(buyerPts + (dscrPts+cfPts+cocPts) + pvaPts + marketPts));
    agent.lead_score = score;
    agent.lead_score_version = "v3.0-balanced-2025-10-16";
    agent.lead_score_explanation = `Market-only scoring: Buyer fit ${topFit}/100, DSCR ${DSCR_primary??'n/a'}, CF ${money(monthlyCF_primary)}, CoC ${cocPct.toFixed(2)} %, list/ARV ${(lpa*100).toFixed(1)}%, DOM ${dom||'n/a'}.`;
  } else {
    // Your prior balanced v2 approach
    const SCORE_WEIGHTS = { buyer:25, dscr:20, cf:20, coc:10, uh:15, data:10 };
    // Economics (DSCR max 20, CF max 20, CoC max 10)
    let dscrPts = 0;
    if (DSCR_primary === null) dscrPts = 10;
    else if (DSCR_primary >= 1.50) dscrPts = 20;
    else if (DSCR_primary >= 1.30) dscrPts = 16;
    else if (DSCR_primary >= 1.20) dscrPts = 14;
    else if (DSCR_primary >= 1.10) dscrPts = 8;
    else if (DSCR_primary >= 1.00) dscrPts = 4;

    let cfPts = 0;
    if (monthlyCF_primary >= 400) cfPts = 20;
    else if (monthlyCF_primary >= 300) cfPts = 16;
    else if (monthlyCF_primary >= 200) cfPts = 14;
    else if (monthlyCF_primary >= 100) cfPts = 8;
    else if (monthlyCF_primary > 0)    cfPts = 4;

    let cocPts = 0;
    if (cocPct >= 12) cocPts = 10;
    else if (cocPct >= 10) cocPts = 8;
    else if (cocPct >= 8)  cocPts = 6;
    else if (cocPct >= 6)  cocPts = 4;
    else if (cocPct >= 4)  cocPts = 2;

    // Urgency/Hardship (max 15)
    const urgPts  = urgStrong ? 10 : (Turg ? 6 : 0);
    const hardPts = hardStrong ? 5 : (Thrd ? 2 : 0);
    const uhPts   = Math.min(SCORE_WEIGHTS.uh, urgPts + hardPts);

    // Data quality (max 10)
    const hasAddr = !!(P.address && P.city && P.state);
    const compsOk = Array.isArray(comps) && comps.length >= 2;
    const rentOk  = (rentMonthly > 0);
    let dataCount = 0; if (hasAddr) dataCount++; if (compsOk) dataCount++; if (rentOk) dataCount++;
    const dataPts = [0,4,7,10][dataCount] || 0;

    const buyerPts = Math.round(Math.min(SCORE_WEIGHTS.buyer, (topFit/100)*SCORE_WEIGHTS.buyer));
    let score = Math.max(0, Math.min(100, buyerPts + dscrPts + cfPts + cocPts + uhPts + dataPts));

    agent.lead_score = score;
    agent.lead_score_version = "v2-balanced-2025-09-15";
    agent.lead_score_explanation = [
      `Buyer fit ${topFit} => +${buyerPts}`,
      `DSCR ${DSCR_primary==null?'n/a':DSCR_primary} => +${dscrPts}`,
      `Monthly CF ${money(monthlyCF_primary)} => +${cfPts}`,
      `CoC ${cocPct.toFixed(2)} % => +${cocPts}`,
      `Urgency/Hardship => +${uhPts}`,
      `Data quality (${dataCount}/3) => +${dataPts}`
    ].join(' | ');
  }

  /***** ---------- [19] Evaluation & Next Pipeline Stage (RESTORED) ---------- *****/
  const statusRaw = text(agent.status || pack.status || agent.pipeline_status);
  const blob = [Turg, Thrd, text(T.price), text(T.additionalInsights), statusRaw].join(' ');
  const isDNC   = /\b(dnc|do\s*not\s*contact)\b/.test(blob);
  const isSold  = /\b(already\.?sold|sold\b)\b/.test(blob);
  const isUnint = /\b(uninterested|not\s*interested|no\s*interest)\b/.test(blob);
  const isRelease = /\brelease\b/.test(blob);

  const dom = parseNum(P.dom);
  const priceToARV = (ARV ? (basePrice / ARV) : null);
  const clearFail  = ((DSCR_primary!=null && DSCR_primary < 1.0) || monthlyCF_primary < 0 || cocPct < 4);
  const tempMaybe  = hasSignal(text(T.price), /\b(open|consider|maybe|counter|negotiat|follow\s*up|after|later)\b/);

  let evaluation = '🥶Cold';
  if (isDNC) evaluation = '☠️Dead';
  else if (isRelease) evaluation = '🎈Release';
  else if (isSold) evaluation = '☠️Dead';
  else if (agent.lead_score >= 85) evaluation = '🔥Hot';
  else if (agent.lead_score >= 70) evaluation = '🌤Warm';
  else if (agent.lead_score >= 55) evaluation = '📞Follow-Up';

  let nextPipelineStage = '1.5 In-Work';
  const reasons = [];

  if (isDNC) {
    nextPipelineStage = '12. DNC: Do Not contact'; reasons.push('Hard stop: DNC/Do Not Contact');
  } else if (isSold) {
    nextPipelineStage = '10. Dead: Inactive'; reasons.push('Hard stop: Already Sold');
  } else if (isUnint && !tempMaybe) {
    nextPipelineStage = '11. Cold/Not Interested'; reasons.push('Seller uninterested and no sign of future movement');
  } else if (evaluation === '🎈Release') {
    nextPipelineStage = '11. Cold/Not Interested'; reasons.push('Release requested/appropriate');
  } else if (agent.lead_score >= 70) {
    nextPipelineStage = '3. Closer Call'; reasons.push(`Lead score ${agent.lead_score} >= 70`);
  } else if (clearFail) {
    if (tempMaybe || (priceToARV!=null && priceToARV > 0.85)) {
      nextPipelineStage = '9. Cold: Long-Term Nurture'; reasons.push('Economics fail now but may improve with price movement or time');
    } else {
      nextPipelineStage = '9. Cold: Long-Term Nurture'; reasons.push('Economics fail with no realistic path');
    }
  } else {
    nextPipelineStage = '1.5 In-Work'; reasons.push('Borderline economics; gather more info to unlock creative structure');
  }

  agent.recommendation = {
    evaluation,
    nextPipelineStage,
    stage_version: "underwriting-stage-v2.5",
    readyForCloserCall: (nextPipelineStage === '3. Closer Call'),
    dataQuality: { hasAddr: !!(P.address && P.city && P.state), compsOk: Array.isArray(comps)&&comps.length>=2, rentOk: (rentMonthly>0), count: (!!(P.address && P.city && P.state) ? 1:0) + (Array.isArray(comps)&&comps.length>=2?1:0) + (rentMonthly>0?1:0) },
    economics: { DSCR: DSCR_primary, monthlyCF: monthlyCF_primary, CoC: cocPct },
    reasons
  };

  /***** ---------- [20] Flags ---------- *****/
  agent.flags = {
    dscr_pass: DSCR_primary==null ? false : (DSCR_primary >= 1.20),
    cashflow_pass: monthlyCF_primary >= 200
  };

  /***** ---------- [21] Return ---------- *****/
  return [{ json: agent }];

} catch (e) {
  return [{ json: { _error: (e && e.message) ? e.message : String(e), _inputs: $input.all().map(i=>i.json) } }];
}

