// 🛡️ Rent Sentry — single-output, production-safe
function n(x) { return Number(String(x ?? '').replace(/[^\d.\-]/g, '')) || 0; }

const it = $json;
const m = it.metrics || {};
const r = it.rental_estimates || {};

// 🚨 GRAB THE NEW FLAWLESS RESOLVED OBJECT 🚨
const res = it.resolved || {};

// Forbidden contact-level field (always treated as 0)
const banned = n(r.from_webhook_monthly_income || 0);

// Upstream Nodes
const compsNode = (() => { try { return $('Fetch rental comps').first().json || {}; } catch { return {}; } })();
const marketNode = (() => { try { return $('Market Rental/Sale Data').first().json || {}; } catch { return {}; } })();

// Allowed sources only
const dealLow = n(r.from_deal_sauce_low);
const dealHigh = n(r.from_deal_sauce_high);
const compLow = n(r.from_comp_pull_low) || n(compsNode.rentRangeLow);
const compHigh = n(r.from_comp_pull_high) || n(compsNode.rentRangeHigh);
const metricsGross = n(m.grossRent);

// ---------------------------------------------------------
// NEW FALLBACK: Market Data by Property Type & Bedrooms
// ---------------------------------------------------------
let marketRent = 0;
try {
  if (marketNode.rentalData) {
     const pTypeStr = String(res.property_type_for_rent || 'Single Family').toLowerCase();
     const beds = n(res.building_beds || 3); // 🚨 Uses scalable beds

     // Find matching property type averages
     let pTypeMatch = (marketNode.rentalData.dataByPropertyType || []).find(d => String(d.propertyType).toLowerCase().includes(pTypeStr.replace('single family', 'single')));
     let typeRent = pTypeMatch ? n(pTypeMatch.averageRent) : 0;

     // Find matching bedroom averages
     let bedMatch = (marketNode.rentalData.dataByBedrooms || []).find(d => n(d.bedrooms) === beds);
     let bedRent = bedMatch ? n(bedMatch.averageRent) : 0;

     // Blend them, or pick whichever is valid
     if (typeRent > 0 && bedRent > 0) marketRent = Math.round((typeRent + bedRent) / 2);
     else if (typeRent > 0) marketRent = typeRent;
     else if (bedRent > 0) marketRent = bedRent;
     else marketRent = n(marketNode.rentalData.averageRent) || 0; // Absolute average if all else fails
  }
} catch (e) {
  // Silent fail
}

// ---------------------------------------------------------

// Pick monthly in a stable order (never use banned)
let chosenMonthly = 0;
if (metricsGross > 0) {
  chosenMonthly = metricsGross;
} else if (compLow && compHigh) {
  chosenMonthly = Math.round((compLow + compHigh) / 2);
} else if (dealLow && dealHigh) {
  chosenMonthly = Math.round((dealLow + dealHigh) / 2);
} else if (n(compsNode.rent) > 0) {
  chosenMonthly = n(compsNode.rent);
} else if (marketRent > 0) {
  chosenMonthly = marketRent;
}

// 🛡️ Bulletproof Fallback: The 0.8% Rule if all APIs fail
if (chosenMonthly === 0) {
  const listPrice = it.property?.list_price ? n(it.property.list_price) : (n(m.list_price) || n(m.price) || 0);
  if (listPrice > 0) {
    chosenMonthly = Math.round(listPrice * 0.008);
  } else {
    const asIsValue = n(it.property?.est_value) || n(m.as_is_value) || n(m.estValue) || 0;
    if (asIsValue > 0) {
      chosenMonthly = Math.round(asIsValue * 0.008);
    }
  }
}

const ok = chosenMonthly > 0;
const annual = ok ? chosenMonthly * 12 : 0;

// Write a clear watchdog annotation
it.watchdog = {
  rent_status: ok ? "OK" : "MISSING",
  severity: ok ? "INFO" : "ALERT",
  banned_rent_detected: banned > 0,
  chosen_rent: chosenMonthly,
  sources: {
    deal_low: dealLow,
    deal_high: dealHigh,
    comp_low: compLow,
    comp_high: compHigh,
    market_rent: marketRent,
    metrics_gross: metricsGross
  }
};

// Patch metrics only if missing; never zero-out a good value
it.metrics = {
  ...m,
  grossRent: ok ? chosenMonthly : (m.grossRent || 0),
  annualRent: ok ? annual : (m.annualRent || 0)
};

// Always return exactly one array of one object
return [{ json: it }];

// Alert Deduper — use workflow static data (persists across executions)
const alert = $json.alert;
const id = $json?.body?.customData?.opportunityId || $json?.property?.opportunityId || $json?.id || $json?.opportunityId || 'unknown';

// 24 hours
const WINDOW_MS = 24 * 60 * 60 * 1000;

const sd = this.getWorkflowStaticData('global');
sd.__rentAlerts = sd.__rentAlerts || {};

const last = sd.__rentAlerts[id];
const now = Date.now();

if (last && (now - last) < WINDOW_MS) {
  // Skip sending — already sent in the last 24h
  return [{ json: { ...$json, alert, dedupe: { sent: false, reason: "duplicate-within-24h" } } }];
}

// Mark sent
sd.__rentAlerts[id] = now;
return [{ json: { ...$json, alert, dedupe: { sent: true } } }];

// Format Rent Alert — normalize data for Discord/Slack
function n(x){ return Number(String(x ?? '').replace(/[^\d.\-]/g,'')) || 0; }
function money(x){ return `$${Number(x||0).toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}`; }
function pct(x){ return `${Number(x || 0).toFixed(2)}%`; }

const j = $json || {};
const prop = j.property || {};
const m = j.metrics || {};
const w = j.watchdog || {};
const cfg = j.config || {};
const buyers = Array.isArray(j.buyer_matches) ? j.buyer_matches : [];

const addr = prop.address || j?.body?.customData?.opportunityAddress || 'Unknown address';
const city = prop.city || j?.body?.customData?.city || '';
const state = prop.state || j?.body?.customData?.state || '';
const zip = prop.postal_code || j?.body?.customData?.zip || '';
const listPrice = money(n(prop.list_price || j?.body?.customData?.list_price));
const crmLink = j.crm_link || j?.body?.LinkToCRM || j?.body?.["Link to View Contact in Web App"] || null;

const sources = w.sources || {};
const bannedHit = Boolean(w.banned_rent_detected);

const alert = {
  title: "🚨 RENT MISSING / INVALID — Sentry Fail",
  severity: "high",
  reason: "Gross rent is missing, zero, or only available from disallowed source(s).",
  timestamp: new Date().toISOString(),
  address: `${addr}${city||state||zip ? `, ${city}${state?`, ${state}`:''}${zip?` ${zip}`:''}` : ''}`,
  listPrice,
  chosenRent: n(w.chosen_rent),
  allowedSources: {
    deal_low: n(sources.deal_low),
    deal_high: n(sources.deal_high),
    comp_low: n(sources.comp_low),
    comp_high: n(sources.comp_high),
    metrics_gross: n(sources.metrics_gross)
  },
  bannedSourceTriggered: bannedHit, // contact-level rent detected (never use)
  metricsSnapshot: {
    dscr: m.dscr ?? null,
    monthlyCF: n(m.monthlyCF),
    annualCF: n(m.annualCF),
    opex: n(m.opex),
    taxes: n(m.taxes),
    insurance: n(m.insurance),
    mgmtRate: cfg.mgmtRate ?? null,
    maintRate: cfg.maintRate ?? null,
    vacancyRate: cfg.vacancyRate ?? null,
  },
  topBuyer: buyers[0] ? {
    name: buyers[0].buyer || buyers[0].contact?.name,
    score: buyers[0].score,
    phone: buyers[0].contact?.phone || null
  } : null,
  crmLink
};

return [{ json: { ...j, alert } }];

// ---------- Helpers ----------
function parseMoney(x) {
  if (x === undefined || x === null) return 0;
  if (typeof x === 'number') return x;
  const s = String(x).replace(/[^\d.\-]/g, '');
  const n = parseFloat(s);
  return isNaN(n) ? 0 : n;
}


const compsNode = (() => {
  try { return $('Fetch Comps API').first().json || {}; }
  catch { return {}; }
})();

const subj = compsNode.subjectProperty || {};
const beds = Number(subj.bedrooms || 0);
const sqft = Number(subj.squareFootage || 0);
const propType = String(subj.propertyType || '').toLowerCase();

const standardRent = Number($json.standard_rent_monthly);




// ---------- PAD SPLIT CONFIG (from calculator) ----------
const PAD = {
  minBeds: 4,
  minSqft: 2000,
  targetMinRooms: 5,
  targetMaxRooms: 7,
  maxRoomsToAdd: 3,
  minSqftPerRoom: 260,          // conservative
  paybackYears: 5,
  renoPerRoomAdded: 15000,      // YOUR rule
  costPerBedroomAdded: 17500,
  costPerBathroomAdded: 15000,
  furnishingPerRoom: 2500,
  otherRehab: 5000
};

// ---------- PAD SPLIT ELIGIBILITY ----------
const padsplitAllowed =
  beds >= PAD.minBeds &&
  sqft >= PAD.minSqft &&
  ['single family', 'sfh', 'townhome'].includes(propType);

// ---------- PAD SPLIT PLAN ----------
let padsplitRent = null;
let padsplitPlan = { reason: 'Not eligible' };

if (padsplitAllowed && standardRent > 0) {
  // Target rooms: clamp to 5–7
  let targetRooms = Math.min(PAD.targetMaxRooms, Math.max(PAD.targetMinRooms, beds));
  let roomsToAdd = Math.max(0, targetRooms - beds);
  roomsToAdd = Math.min(roomsToAdd, PAD.maxRoomsToAdd);

  // Ensure sqft supports it
  const sqftPerRoom = r => (r > 0 ? sqft / r : 0);
  while (targetRooms > beds && sqftPerRoom(targetRooms) < PAD.minSqftPerRoom) {
    targetRooms -= 1;
    roomsToAdd = Math.max(0, targetRooms - beds);
  }

  // Bathroom logic: ideal = ceil(rooms / 2), cap +1
  const baths = Number(subj.bathrooms || 0);
  const requiredBaths = Math.ceil(targetRooms / 2);
  const bathsToAdd = Math.max(
    0,
    Math.min(1, Math.ceil(requiredBaths - baths))
  );


  // Renovation estimate (matches your calculator)
  const renoEstimate =
    (roomsToAdd * PAD.costPerBedroomAdded) +
    (bathsToAdd * PAD.costPerBathroomAdded) +
    (targetRooms * PAD.furnishingPerRoom) +
    PAD.otherRehab;

  // PadSplit rent model (still conservative)
  let roomRent = Math.round(standardRent / beds);
  roomRent = Math.min(1100, Math.max(850, roomRent)); // raise floor to avoid fake splits
  padsplitRent = targetRooms * roomRent;

  // Feasibility gate: does uplift support $15k per added room?
  const upliftMonthly = padsplitRent - standardRent;
  const upliftAnnual = upliftMonthly * 12;
  const supportedReno = upliftAnnual * PAD.paybackYears;
  const requiredRenoForGate = roomsToAdd * PAD.renoPerRoomAdded;

  const feasible =
    roomsToAdd === 0
      ? upliftMonthly >= 600 // if no build, require real uplift
      : supportedReno >= requiredRenoForGate;

  // ---------- Bathroom burden ratio (infrastructure risk, NOT a hard gate) ----------
  const bathRenoCost = bathsToAdd * PAD.costPerBathroomAdded;
  const totalUpliftValue = upliftAnnual * PAD.paybackYears;

  const bathroomBurdenRatio =
    totalUpliftValue > 0
      ? bathRenoCost / totalUpliftValue
      : null;

  let bathroomInfrastructureRisk = 'low';
  if (bathroomBurdenRatio !== null) {
    if (bathroomBurdenRatio > 0.5) bathroomInfrastructureRisk = 'high';
    else if (bathroomBurdenRatio > 0.3) bathroomInfrastructureRisk = 'moderate';
  }


  if (!feasible) {
    padsplitRent = null; // DO NOT promote fake upside
  }

  padsplitPlan = {
    currentRooms: beds,
    targetRooms,
    roomsToAdd,
    currentBaths: baths,
    requiredBaths,
    bathsToAdd,
    sqftPerRoom: Number(sqftPerRoom(targetRooms).toFixed(1)),
    roomRent,
    standardRent,
    padsplitRentCandidate: targetRooms * roomRent,
    upliftMonthly,
    renoEstimate,
    supportedReno,
    requiredRenoForGate,
    totalRenoEstimate: renoEstimate,
    feasible,
    // NEW — infrastructure diagnostics
    bathroomBurdenRatio: bathroomBurdenRatio !== null
      ? Number(bathroomBurdenRatio.toFixed(2))
      : null,
    bathroomInfrastructureRisk
  };
}

// ---------- CANONICAL SELECTION ----------

const PAD_SPLIT_PROMOTION_MULTIPLE = 1.40; // Increased gate margin requirements
let canonical = 'standard'

if (
  padsplitAllowed &&
  padsplitPlan?.feasible &&
  padsplitRent &&
  padsplitRent >= standardRent * PAD_SPLIT_PROMOTION_MULTIPLE
) {
  canonical = 'padsplit'
}

// ---------- OUTPUT ----------
return [{
  json: {
    ...$json,
    rental_estimates: $json.rental_estimates ?? null,
    rental_models: {
      standard: {
        grossRentMonthly: standardRent,
        assumptions: {
          vacancyRate: 0.05,
          mgmtRate: 0.08,
          maintRate: 0.05,
          utilitiesIncluded: false
        }
      },
      padsplit: {
        allowed: padsplitAllowed,
        feasible: padsplitPlan?.feasible ?? false,
        grossRentMonthly: padsplitRent,
        assumptions: {
          vacancyRate: 0.12,
          mgmtRate: 0.18,
          maintRate: 0.09,
          utilitiesIncluded: true
        },
        debug: padsplitPlan
      }

    },

    canonical_rental_model: canonical
  }
}]

// ==========================
// BUILD STANDARD RENT
// Resolves ONE market rent + preserves rent signals
// ==========================

function parseMoney(x) {
  if (x === undefined || x === null) return 0;
  if (typeof x === 'number') return x;
  const s = String(x).replace(/[^\d.\-]/g, '');
  const n = parseFloat(s);
  return isNaN(n) ? 0 : n;
}

const rentalNode = (() => {
  try { return $('Fetch rental comps').first().json || {}; }
  catch { return {}; }
})();

const rent_low  = parseMoney(rentalNode.rentRangeLow);
const rent_high = parseMoney(rentalNode.rentRangeHigh);
const rent_val  = parseMoney(rentalNode.rent);

const cd = $json.customData || {};
const cdLowA  = parseMoney(cd.lowRentEst || cd.RentalEstimateLow);
const cdHighA = parseMoney(cd.highRentEst || cd.RentalEstimateHigh);

const marketDataExtracted = $('Information Extractor').first()?.json?.output || undefined;

let unit_rent_monthly = 0;

if (rent_val) {
  unit_rent_monthly = rent_val;
} else if (rent_low && rent_high) {
  unit_rent_monthly = Math.round((rent_low + rent_high) / 2);
} else if (cdLowA && cdHighA) {
  unit_rent_monthly = Math.round((cdLowA + cdHighA) / 2);
}

if (!unit_rent_monthly) {
  throw new Error('Build Standard Rent: unable to resolve standard rent');
}

// 🚨 FLASHLIGHT: BULLETPROOF RESOLVED EXTRACTION 🚨
// This forces n8n to fetch the unit count straight from the source normalizer
const res = (() => {
    try { const r = $('Normalize Subject + Mode').first().json; if (r && r.resolved) return r.resolved; } catch {}
    try { const r = $('Deduplicate Opportunities').first().json; if (r && r.resolved) return r.resolved; } catch {}
    return $json.resolved || {};
})();

const is_mf = res.is_multifamily || false;
const units = res.unit_count || 1;

// Scale to get Gross Building Rent
const gross_rent_monthly = is_mf && units > 1 ? (unit_rent_monthly * units) : unit_rent_monthly;

const standard_rent_monthly = gross_rent_monthly;

return [{
  json: {
    ...$json,
    market_data_extracted: marketDataExtracted,

    // Authoritative rent used by all downstream logic (Gross Building Rent)
    standard_rent_monthly,

    rent_calculations: {
      unit_rent_monthly,
      gross_building_rent: standard_rent_monthly,
      unit_count_multiplier_applied: units,
      was_scaled_for_multifamily: (is_mf && units > 1)
    },

    rental_estimates: {
      from_comp_pull_low: rent_low || 0,
      from_comp_pull_high: rent_high || 0,
      from_deal_sauce_low: cdLowA || 0,
      from_deal_sauce_high: cdHighA || 0,
      from_webhook_monthly_income: 0
    }
  }
}];

