## // ==========================================
// COMPUTE METRICS v9 (Selector Edition)
// AS-IS VALUE (independent), ARV (comps API), LIST PRICE (MLS)
// Deterministic rent, opex, NOI. No ADS/DSCR/CF/CoC here.
// ==========================================

// ---- Helpers ----
function parseMoney(x) {
    if (x === undefined || x === null) return 0;
    if (typeof x === 'number') return x;
    const s = String(x).replace(/[^\d.\-]/g, '');
    const n = parseFloat(s);
    return isNaN(n) ? 0 : n;
}

function firstNonEmpty(...vals) {
    for (const v of vals) {
        if (v === 0) return 0;
        if (v == null) continue;
        if (typeof v === 'string' && v.trim() !== '') return v;
        if (typeof v === 'number') return v;
    }
    return null;
}

// -------------------------------------------------------------
// Canonical Rental Model (UPSTREAM)
// -------------------------------------------------------------
const rentalModels = $json.rental_models || {};
const canonicalKey = $json.canonical_rental_model || 'standard';
const rental = rentalModels[canonicalKey];

if (!rental || rental.grossRentMonthly == null) {
    throw new Error('Compute Metrics: Missing canonical rental model or rent');
}

const grossRent = Number(rental.grossRentMonthly);
const annualRent = grossRent * 12;


// ---- Upstream nodes (selectors) ----
const webhook = (() => { try { return $('Start Webhook1').first().json || {}; } catch { return {}; } })();
const cd = (webhook.body && Object.keys(webhook.body).length > 0) ? (webhook.body.customData || webhook.body) : {};

const rentalNode = (() => { try { return $('Fetch rental comps').first().json || {}; } catch { return {}; } })();
const saleNode = (() => { try { return $('Fetch Sale Data').first().json || {}; } catch { return {}; } })();
const compsNode = (() => { try { return $('Fetch Comps API').first().json || {}; } catch { return {}; } })();
const loanWrapper = (() => { try { return $('Code8').first().json || {}; } catch { return {}; } })();

// DYNAMIC PROPERTY DATA TARGET: HTTP Request6
const propNode = (() => { try { return $('HTTP Request6').first().json || {}; } catch { return {}; } })(); 

const existing_loan_upstream = loanWrapper.existing_loan || {};

const warnings = [];

// -------------------------------------------------------------
// LIST PRICE (MLS) - seller's ask
// -------------------------------------------------------------
const mls_list_price = parseMoney(firstNonEmpty(
    saleNode.price,
    cd.list_price,
    cd.ListPrice,
    0
));

// -------------------------------------------------------------
// AS-IS VALUE (Option B logic)
// -------------------------------------------------------------
let as_is_value = parseMoney(firstNonEmpty(
    cd.estValue,                                  // DealSauce as-is valuation
    saleNode.estValue,                            // Sale Data AVM estimate
    saleNode.est_value,                           // alt key
    compsNode.priceRangeLow,                      // fallback to low comp
    0
));

// -------------------------------------------------------------
// ARV (with SMART OUTLIER SCRUBBING)
// -------------------------------------------------------------
let arv = 0;

if (compsNode.comparables && Array.isArray(compsNode.comparables) && compsNode.comparables.length > 0) {
    // Extract all valid comp prices
    let prices = compsNode.comparables.map(c => parseMoney(c.price)).filter(p => p > 0);

    if (prices.length > 2) {
        prices.sort((a, b) => a - b);

        // IQR Outlier Filtering (Interquartile Range)
        const q1Idx = Math.floor(prices.length * 0.25);
        const q3Idx = Math.floor(prices.length * 0.75);
        const q1 = prices[q1Idx];
        const q3 = prices[q3Idx];
        const iqr = q3 - q1;

        // Any comp > 1.5x IQR above Q3 or below Q1 is an outlier
        // (Also cap the lower bound at $0 to avoid weirdness)
        const lowerBound = Math.max(0, q1 - (1.5 * iqr));
        const upperBound = q3 + (1.5 * iqr);

        // Strip extreme outliers
        const filtered = prices.filter(p => p >= lowerBound && p <= upperBound);

        if (filtered.length > 0) {
            // Average of the tight cluster
            const sum = filtered.reduce((a, b) => a + b, 0);
            arv = Math.round(sum / filtered.length);
        } else {
            // Fallback to median if IQR filtering wipes everything
            arv = prices[Math.floor(prices.length / 2)];
        }
    } else if (prices.length > 0) {
        // 1 or 2 comps? Just average them without filtering
        const sum = prices.reduce((a, b) => a + b, 0);
        arv = Math.round(sum / prices.length);
    }
}

// Fallback to RentCast's generic average if the array parsing fails
if (!arv || arv === 0) {
    arv = parseMoney(firstNonEmpty(
        compsNode.price,
        0
    ));
}

// 🛡️ Bulletproof Fallback: Built ARV if API missed
if (arv === 0) {
    if (as_is_value && as_is_value > 0) {
        // Fallback 1: As-Is + Estimated Rehab (e.g. As-Is * 1.3 for decent margin)
        arv = Math.round(as_is_value * 1.3);
    } else if (mls_list_price && mls_list_price > 0) {
        // Fallback 2: List Price + standard upside
        arv = Math.round(mls_list_price * 1.15);
    } else {
        // Absolute Floor Fallback
        arv = Math.max(mls_list_price, as_is_value, 10000);
    }
    warnings.push("ARV missing from API. Derived from As-Is/List Price fallbacks.");
}

const comp_low = parseMoney(compsNode.priceRangeLow);
const comp_high = parseMoney(compsNode.priceRangeHigh);

// -------------------------------------------------------------
// Property characteristics
// -------------------------------------------------------------
const address = String(firstNonEmpty(
    propNode.addressLine1,
    propNode.formattedAddress,
    saleNode.addressLine1,
    compsNode.subjectProperty?.addressLine1,
    rentalNode.subjectProperty?.addressLine1,
    cd.opportunityAddress,
    cd.address,
    ''
)).trim();

const city = String(firstNonEmpty(
    propNode.city,
    saleNode.city,
    compsNode.subjectProperty?.city,
    rentalNode.subjectProperty?.city,
    cd.city,
    ''
)).trim();

const state = String(firstNonEmpty(
    propNode.state,
    saleNode.state,
    compsNode.subjectProperty?.state,
    rentalNode.subjectProperty?.state,
    cd.state,
    ''
)).trim().toUpperCase();

const postal = String(firstNonEmpty(
    propNode.zipCode,
    saleNode.zipCode,
    compsNode.subjectProperty?.zipCode,
    rentalNode.subjectProperty?.zipCode,
    cd.zip,
    cd.postal_code,
    ''
)).trim();

const beds = Number(firstNonEmpty(
    propNode.bedrooms,
    saleNode.bedrooms,
    compsNode.subjectProperty?.bedrooms,
    rentalNode.subjectProperty?.bedrooms,
    cd.beds,
    null
));

const baths = Number(firstNonEmpty(
    propNode.bathrooms,
    saleNode.bathrooms,
    compsNode.subjectProperty?.bathrooms,
    rentalNode.subjectProperty?.bathrooms,
    cd.baths,
    null
));

const sqft = Number(firstNonEmpty(
    propNode.squareFootage,
    saleNode.squareFootage,
    compsNode.subjectProperty?.squareFootage,
    rentalNode.subjectProperty?.squareFootage,
    cd.sqft,
    0
));

let yearBuilt = firstNonEmpty(
    propNode.yearBuilt,
    saleNode.yearBuilt,
    compsNode.subjectProperty?.yearBuilt,
    rentalNode.subjectProperty?.yearBuilt,
    cd.year_built_mls,
    cd['👤MLS_Curr_YearBuilt'],
    null
);
// 🛡️ Stricter sanitization for yearBuilt APIs passing "Unknown" or random strings
if (typeof yearBuilt === 'string') {
    yearBuilt = parseInt(yearBuilt.replace(/[^\d]/g, ''), 10);
}
yearBuilt = (isNaN(yearBuilt) || yearBuilt < 1700 || yearBuilt > 2100) ? null : yearBuilt;

const propType = String(firstNonEmpty(
    propNode.propertyType,
    saleNode.propertyType,
    compsNode.subjectProperty?.propertyType,
    rentalNode.subjectProperty?.propertyType,
    cd.prop_type,
    'single family'
)).toLowerCase();

const mlsDesc = String(firstNonEmpty(
    cd.mlsDescription,
    ''
)).trim();

// 🚐 RV Park / Mobile Home Park Detection
const isRVPark = /\b(rv park|mobile home park|campground|mhp|rv resort)\b/.test(propType) || /\b(rv park|mobile home park|campground)\b/i.test(mlsDesc);
if (isRVPark && !warnings.includes("Detected RV/Mobile Home Park format")) {
    warnings.push("Detected RV/Mobile Home Park format. Operating expenses structured accordingly.");
}

const dom = Number(firstNonEmpty(
    saleNode.daysOnMarket,
    cd.dom,
    null
));

// -------------------------------------------------------------
// Taxes & Insurance (Dynamic RentCast Integration)
// -------------------------------------------------------------

// (City and state already defined globally above)

const HIGH_RISK_INS_STATES = new Set(['FL', 'TX', 'LA', 'OK', 'AL', 'MS', 'SC', 'NC', 'GA', 'CA']);
const insuranceRate = HIGH_RISK_INS_STATES.has(state) ? 0.012 : 0.006;
const defaultTaxRate = 0.0115;

// 1. DYNAMIC TAX CAPTURE (From RentCast via HTTP Request6 / propNode)
// Using the direct property fetch API as the primary source for taxes
let rentcastTaxes = 0;
try {
  // Check HTTP Request6 (propNode) first, fallback to comps subject properties
  const propertyData = (propNode && propNode.propertyTaxes) ? propNode : (compsNode.subjectProperty || {});
  if (propertyData.propertyTaxes) {
      const tax2024 = propertyData.propertyTaxes?.["2024"]?.total;
      const tax2023 = propertyData.propertyTaxes?.["2023"]?.total;
      rentcastTaxes = tax2024 || tax2023 || 0;
  }
} catch(e) {}

// 2. FALLBACK TAX CASCADE
let taxes = parseMoney(cd['annual taxes']);
if (!taxes || taxes === 0) {
  if (rentcastTaxes > 0) {
    taxes = rentcastTaxes; // RentCast Data is primary fallback
  } else if (mls_list_price) {
    taxes = Math.round(mls_list_price * defaultTaxRate);
  }
}

// 3. INSURANCE CASCADE
let insurance = parseMoney(cd.insuranceAnnual);
if (!insurance && parseMoney(cd.insuranceMonthly)) {
  insurance = Math.round(parseMoney(cd.insuranceMonthly) * 12);
}
if (!insurance) {
  // If we found a real tax value, derive insurance proportionately, else use list price
  if (taxes > 0 && !mls_list_price) {
    // Standard ratio: Insurance is roughly 80% to 120% of taxes in non-high risk.
    insurance = Math.round(taxes * (HIGH_RISK_INS_STATES.has(state) ? 1.2 : 0.8));
  } else if (mls_list_price) {
    insurance = Math.round(mls_list_price * insuranceRate);
  }
}

// Expense multipliers
const isSmallMulti = /(duplex|triplex|fourplex|quad|multi)/.test(propType);

// 🚐 RV/Mobile Home Parks have much higher standard OPEX (35-45%)
let mgmtRate = rental.assumptions?.mgmtRate ?? (isSmallMulti ? 0.09 : (isRVPark ? 0.12 : 0.08));
let maintRate = rental.assumptions?.maintRate ?? (isSmallMulti ? 0.07 : (isRVPark ? 0.15 : 0.05));
let vacancyRate = rental.assumptions?.vacancyRate ?? (isSmallMulti ? 0.07 : (isRVPark ? 0.10 : 0.05));
if (yearBuilt && yearBuilt < 1980 && !isRVPark) maintRate += 0.02;

// Core opex
const mgmt = Math.round(mgmtRate * annualRent);
const maint = Math.round(maintRate * annualRent);
const vacancy = Math.round(vacancyRate * annualRent);

const utilitiesRate = rental.assumptions?.utilitiesIncluded ? 0.10 : (isRVPark ? 0.10 : 0);
const utilities = Math.round(utilitiesRate * annualRent);


const opex = mgmt + maint + vacancy + utilities + taxes + insurance;
const noi = Math.max(annualRent - opex, 0);

// TI monthly (display only)
const tiMonthly = (taxes + insurance) / 12;

// ---- Existing Loan ----
const loanBalance = parseMoney(cd['Loan 1 Balance']);
const loanRate = parseMoney(cd['Loan 1 rate']);
const sellerMonthlyPaymentPI = parseMoney(cd['Loan 1 Monthly payment']); // <-- PI only
const originalPrincipal = parseMoney(cd['loan 1 original principal']);

let rawLtv = parseMoney(cd.l_to_v_ratio);  // "67" or maybe "0.67"
let ltv = null;
if (rawLtv) {
    ltv = rawLtv > 1 ? rawLtv / 100 : rawLtv;
}
if (ltv && ltv > 1.25) {
    // Cap absurd values to max 125% to prevent NaN explosions
    ltv = 1.25;
}

// ---- Equity pct ----
let equity_pct = null;

if (ltv !== null) {
    equity_pct = (1 - ltv) * 100;
} else if (as_is_value && loanBalance > 0) {
    const frac = (as_is_value - loanBalance) / as_is_value;
    equity_pct = frac * 100;
}

// Sanitize equity
if (equity_pct !== null) {
    equity_pct = Math.max(-100, Math.min(100, equity_pct)); // cap between -100% and +100%
}



// -------------------------------------------------------------
// Build outputs
// -------------------------------------------------------------
const property = {
    address,
    city,
    state,
    postal_code: postal,
    list_price: mls_list_price ? `$${mls_list_price.toLocaleString(undefined, { maximumFractionDigits: 0 })}.00` : null,
    est_value: as_is_value,
    arv_value: arv,
    beds,
    baths,
    year_built_mls: yearBuilt,
    dom,
    mls_description: mlsDesc,
    mls: {
        number: saleNode.mlsNumber || null,
        name: saleNode.mlsName || null,
        status: saleNode.status || null,
        listedDate: saleNode.listedDate || null,
        lastSeenDate: saleNode.lastSeenDate || null,
        price_num: mls_list_price
    }
};

const existing_loan = {
    balance: loanBalance || 0,
    sellerMonthlyPaymentPI: sellerMonthlyPaymentPI || 0,
    rate: loanRate || 0,
    original_principal: originalPrincipal || 0,
    ltv: ltv !== null ? Number(ltv.toFixed(4)) : null   // e.g. 0.6700, not 67
};

const metrics = {
    list_price: mls_list_price,
    as_is_value,
    arv,
    comp_low,
    comp_high,

    price: mls_list_price,
    city,
    state,
    bedrooms: beds,
    bathrooms: baths,
    propertyType: propType,
    sqft,
    yearBuilt,

    grossRent,
    annualRent,
    taxes,
    insurance,
    mgmt,
    maint,
    vacancy,
    opex,
    noi,

    estValue: as_is_value,
    equity_pct, // e.g. ~0.33 for 67% LTV
    tiMonthly
};

const config = {
    insuranceRate,
    mgmtRate,
    maintRate,
    vacancyRate,
    assignmentPctOfDown: 0.25,
    closingCostRate: 0.08,
    taxRate: defaultTaxRate
};

const rental_estimates = $json.rental_estimates || null;
const padsplit_current_vs_target = $json.rental_models.padsplit.debug || {};
const canonical = {
    rental_model: canonicalKey,   // <-- ADD THIS
    economics: {
        grossRentMonthly: grossRent,
        annualRent,
        opexAnnual: opex,
        NOI: noi,
        ADS: null,
        DSCR: null,
        monthlyCF: null,
        annualCF: null,
        totalCashIn: null,
        CoC_pct: null
    }
};


// ---- Return ----
return [{
    json: {
        property,
        rental_estimates,
        existing_loan,
        metrics,
        config,
        canonical,
        padsplit_current_vs_target,
        warnings
    }
}];

