## 
// DETERMINISTIC MATH ENGINE (Replaces AI Hallucinations)
const data = $json;
const metrics = data.metrics || {};
const loan = data.existing_loan || {};
const config = data.config || {};

// We cleanly pull the mapped metrics calculated upstream!
const annualTaxes = metrics.taxes || 0;
const annualInsurance = metrics.insurance || 0;
const tiMonthly = (annualTaxes / 12) + (annualInsurance / 12);

// Fallback logic for property value
const basePrice = metrics.as_is_value || metrics.list_price || metrics.arv || 0;

// 1. BASE ECONOMICS (Perfect Math)
const grossRent = metrics.grossRent || 0;
const annualRent = metrics.annualRent || 0;
const totalOpex = metrics.opex || 0; 

// Calculate accurate NOI (Properly inherits negative values now)
const noi = annualRent - totalOpex;

const piMonthly = loan.sellerMonthlyPaymentPI || 0;
const ads = piMonthly * 12; 

const dscr = ads > 0 ? (noi / ads).toFixed(2) : "0.00";
const monthlyCF = (noi / 12) - piMonthly;
const annualCF = monthlyCF * 12;

let totalCashIn = 0;
if (loan.balance > 0) {
    const equity = Math.max(basePrice - loan.balance, 0);
    const closingCosts = basePrice * (config.closingCostRate || 0.08);
    totalCashIn = equity + closingCosts;
} else {
    totalCashIn = basePrice;
}

const coc = totalCashIn > 0 ? ((annualCF / totalCashIn) * 100).toFixed(1) : "0.0";
const rule50 = totalOpex <= (annualRent * 0.5) ? "✅" : "❌";
const rule2 = grossRent >= (totalCashIn * 0.02) ? "✅" : "❌";

data.output = data.output || {};

data.output.investors_analysis = {
    "Gross Rent": "$" + grossRent.toLocaleString(), 
    "Annual Rent": "$" + annualRent.toLocaleString(),
    "Operating Expenses": "$" + totalOpex.toLocaleString(),
    "NOI": "$" + noi.toLocaleString(),
    "Annual Debt Service (ADS)": "$" + ads.toLocaleString(),
    "DSCR": dscr,
    "Monthly Cash-flow": "$" + monthlyCF.toFixed(0),
    "Annual Cash-flow": "$" + annualCF.toFixed(0),
    "Total Cash In": "$" + totalCashIn.toLocaleString(),
    "Cash-on-Cash Return": coc + "%",
    "2% Rule": rule2,
    "50% Rule": rule50
};

// 2. DEAL STRUCTURE ENGINE
let primary = {};
let backup = {};

const purchasePrice = basePrice;
const existingBalance = loan.balance || 0;
let equityPct = 1.0;
if (metrics.as_is_value > 0 && existingBalance > 0) {
    equityPct = (metrics.as_is_value - existingBalance) / metrics.as_is_value;
}

// Logic: Subject-To vs Hybrid vs Seller Finance
if (equityPct < 0.15 && existingBalance > 0) {
    primary = {
        "Type": "Subject-To",
        "Purchase Price": purchasePrice,
        "Cash to Seller": 2000,
        "Existing Loan Balance": existingBalance,
        "Monthly Payment (PI)": piMonthly
    };
    backup = {
        "Type": "Hybrid",
        "Purchase Price": purchasePrice,
        "Cash to Seller": 1000,
        "Existing Loan Balance": existingBalance,
        "Seller Carryback Loan": Math.max(purchasePrice - existingBalance - 1000, 0),
        "Monthly Payment (PI)": piMonthly + 150
    };
} else if (equityPct >= 0.15 && existingBalance > 0) {
    const carryAmount = Math.max(purchasePrice - existingBalance - 3000, 0);
    const carryPI = (carryAmount * (0.04 / 12)) / (1 - Math.pow(1 + (0.04 / 12), -360));
    primary = {
        "Type": "Hybrid",
        "Purchase Price": purchasePrice,
        "Cash to Seller": 3000,
        "Existing Loan Balance": existingBalance,
        "Seller Carryback Loan": carryAmount,
        "Monthly Payment (PI)": piMonthly + carryPI
    };
    backup = {
        "Type": "Subject-To (Max Cash)",
        "Purchase Price": purchasePrice,
        "Cash to Seller": 15000, 
        "Existing Loan Balance": existingBalance,
        "Monthly Payment (PI)": piMonthly
    };
} else {
    // Default Seller Finance (Free and Clear)
    const downPayment = purchasePrice * 0.10;
    const financed = purchasePrice - downPayment;
    const pi = (financed * (0.04 / 12)) / (1 - Math.pow(1 + (0.04 / 12), -360));
    primary = {
        "Type": "Seller Finance",
        "Purchase Price": purchasePrice,
        "Down Payment ($)": downPayment,
        "Down Payment (%)": 10.0,
        "Loan Rate (%)": 4.0,
        "Amortization (Years)": 30,
        "Balloon Term (Years)": 5, 
        "Financed Amount": financed,
        "Monthly Payment (PI)": pi
    };

    const backupDown = purchasePrice * 0.20;
    const backupFin = purchasePrice - backupDown;
    const backupPi = (backupFin * (0.02 / 12)) / (1 - Math.pow(1 + (0.02 / 12), -360));
    backup = {
        "Type": "Seller Finance (Cash Flow Focus)",
        "Purchase Price": purchasePrice,
        "Down Payment ($)": backupDown,
        "Down Payment (%)": 20.0,
        "Loan Rate (%)": 2.0,
        "Amortization (Years)": 30,
        "Balloon Term (Years)": 5, 
        "Financed Amount": backupFin,
        "Monthly Payment (PI)": backupPi
    };
}

function processStructure(offerData) {
    const pPI = offerData["Combined Monthly Payment (PI)"] || offerData["Monthly Payment (PI)"];

    // 🚨 BUG FIX: T&I strictly omitted from ADS formula.
    const pADS = pPI * 12; 
    const pDSCR = pADS > 0 ? (noi / pADS).toFixed(2) : "0.00";
    const pCF = (noi / 12) - pPI;

    const cashOut = offerData["Cash to Seller"] || offerData["Down Payment ($)"] || 0;
    const totalEntry = cashOut + (purchasePrice * (config.closingCostRate || 0.08));
    const pCoC = totalEntry > 0 ? (((pCF * 12) / totalEntry) * 100).toFixed(1) + "%" : "0%";

    return {
        ...offerData,
        "Monthly Taxes and Insurance (TI)": "$" + tiMonthly.toFixed(0),
        "ADS": "$" + pADS.toFixed(0),
        "DSCR": pDSCR,
        "Monthly Cash-flow": "$" + pCF.toFixed(0),
        "Cash-on-Cash Return": pCoC,
        "Total Entry Fee": "$" + totalEntry.toFixed(0),
        "Justification": "Calculated deterministically based on upstream property and loan metrics without AI hallucination."
    };
}

data.output.deal_structure = {
    "Primary Offer": processStructure(primary),
    "Backup Offer": processStructure(backup),
    "Updated Cash Offer": {
        "Final Cash Offer": "$" + ((metrics.arv || basePrice) * 0.7).toFixed(0),
        "Final Cash Offer % of ARV": "70.0%",
        "Justification": "70% of ARV minus expected condition adjustments."
    }
};

data.output.recommendation = data.output.recommendation || {};
data.output.recommendation.economics = {
    DSCR: parseFloat(data.output.deal_structure["Primary Offer"]["DSCR"]),
    monthlyCF: parseFloat(data.output.deal_structure["Primary Offer"]["Monthly Cash-flow"].replace('$', '')),
    CoC: parseFloat(data.output.deal_structure["Primary Offer"]["Cash-on-Cash Return"].replace('%', ''))
};

// =========================================================
// LOI GENERATION MATH FIX (Resents exact balloon interest)
// =========================================================
if (data.output.deal_structure["Primary Offer"]["Type"] === "Seller Finance") {
    const pOffer = data.output.deal_structure["Primary Offer"];
    const price = pOffer["Purchase Price"];
    const downObj = pOffer["Down Payment ($)"];
    const financed = pOffer["Financed Amount"];
    const rate = pOffer["Loan Rate (%)"];
    const amort = pOffer["Amortization (Years)"];
    const balloon = pOffer["Balloon Term (Years)"] || 5;
    const payment = parseFloat(pOffer["Monthly Payment (PI)"]) || 0;

    const r = (rate / 100) / 12;
    const n = balloon * 12; 
    const N = amort * 12;
    let remBalance = 0;
    if (r > 0) {
        remBalance = financed * ( (Math.pow(1+r, N) - Math.pow(1+r, n)) / (Math.pow(1+r, N) - 1) );
    } else {
        remBalance = financed - (payment * n);
    }

    // Interest Paid = Total Payments - Principal Knocked Out
    const principalPaid = financed - remBalance;
    const totalInterestPaid = (payment * n) - principalPaid;

    const fullCashPrice = ((metrics.arv || basePrice) * 0.7);

    data.output.loi = `Letter of Intent (LOI)\n\nProperty: ${metrics.address || data.property?.address}, ${metrics.city || data.property?.city}, ${metrics.state || data.property?.state}, ${metrics.postal_code || data.property?.postal_code}\n\nPrimary Offer – Seller Financing\n- Purchase Price: $${price.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}\n- Down Payment: $${downObj.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})} (${pOffer["Down Payment (%)"] || 10} %)\n- Terms: ${rate} % interest, ${amort}-year amortization, ${balloon}-year balloon\n- Monthly Payment: $${payment.toFixed(2)}\n\nWhy this works for you: This approach offers a smooth, as-is sale with a flexible closing and steady monthly income. Over the ${balloon}-year term before the balloon payment, this structure pays you about $${totalInterestPaid.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})} more in interest than a traditional cash sale.\n\nCash Option: $${fullCashPrice.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})} for a quick, as-is close.\n\nWe’re flexible on timelines and details and happy to discuss.`;
}

// 🚨 PERFECTION FIX: Overwrite Investor Analysis to precisely match the Primary Offer!
const primaryEconomics = data.output.deal_structure["Primary Offer"];
data.output.investors_analysis = {
    "Gross Rent": "$" + grossRent.toLocaleString(),
    "Annual Rent": "$" + annualRent.toLocaleString(),
    "Operating Expenses": "$" + totalOpex.toLocaleString(),
    "NOI": "$" + noi.toLocaleString(),
    "Annual Debt Service (ADS)": primaryEconomics["ADS"],
    "DSCR": primaryEconomics["DSCR"],
    "Monthly Cash-flow": primaryEconomics["Monthly Cash-flow"],
    "Annual Cash-flow": "$" + (parseFloat(primaryEconomics["Monthly Cash-flow"].replace(/[^0-9.-]/g, '')) * 12).toFixed(0),
    "Total Cash In": primaryEconomics["Total Entry Fee"],
    "Cash-on-Cash Return": primaryEconomics["Cash-on-Cash Return"],
    "2% Rule": rule2,
    "50% Rule": rule50
};

// 🚨 Override variables up to the root level.
data.deal_structure = data.output.deal_structure;
data.investors_analysis = data.output.investors_analysis;

// Resync the freshly un-capped upstream NOI with our final verified object so it updates globally
metrics.noi = noi; 
data.metrics = metrics;

if (data.output.loi) {
    data.loi = data.output.loi; 
}

return data;

/**
 * Stage Router — v3.8
 *
 * - Uses canonical.economics ONLY for DSCR / CF / CoC.
 * - CoC normalized: if 0 < CoC <= 1, treated as fraction → *100.
 * - UH points:
 *      - If four_pillars exist → derive from Urgency + Motivation.
 *      - Else → use transcript-based or fallback UH engine.
 * - Economics fail (DSCR < 1.0 or CF < 0) → always Cold/Nurture (no override).
 */

function T(v) { return String(v ?? '').trim(); }
function pNum(v) {
  const n = Number(String(v ?? '').replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : 0;
}
function money(n) { return `$${(Number(n) || 0).toFixed(2)}`; }
function pct(n) { return `${(Number(n) || 0).toFixed(2)} %`; }
function has(s, re) { return re.test(T(s).toLowerCase()); }
const STAGE_VERSION = "stage-v3.3";


// --------------------------------------------------------
// Root / source
// --------------------------------------------------------
const root = $json;
const src = root.canonical ?? root;
const econ = src.economics || {};
const comps = root.comp_properties_report || [];
const buyers = root.buyer_matches || [];
const transcript = root.transcript_insights || {};
const property = root.property || {};
const metrics = root.metrics || {};
const pillars = root.four_pillars || {};
// ---- Transcript fields (must be declared before scoring uses them) ----
const Turg = T(transcript.sellerUrgency);
const Thard = T(transcript.sellerHardship);
const Tprice = T(transcript.price);
const Tadd = T(transcript.additionalInsights);
// status must also be declared BEFORE any scoring logic uses it
const statusRaw = T(root.status || src.status || root.pipeline_status);



// --------------------------------------------------------
// Economics — canonical ONLY
// --------------------------------------------------------
const DSCR = pNum(econ.DSCR);
const monthlyCF = pNum(econ.monthlyCF);

// Normalize CoC: if it looks like a fraction (<=1), convert to percent
let CoC = Number(econ.CoC_pct || 0);
if (Number.isFinite(CoC) && CoC > 0 && CoC <= 1) {
  CoC = CoC * 100;
}

// --------------------------------------------------------
// Buyer fit
// --------------------------------------------------------
function topBuyer(list) {
  if (!Array.isArray(list) || !list.length) return 0;
  return Math.max(...list.map(b => Number(b.score) || 0));
}
const topFit = topBuyer(buyers);
const buyerPts = Math.round(Math.min(25, (topFit / 100) * 25)); // max 25

// --------------------------------------------------------
// DSCR scoring (max 20)
// --------------------------------------------------------
let dscrPts = 0;
if (DSCR >= 1.50) dscrPts = 20;
else if (DSCR >= 1.30) dscrPts = 16;
else if (DSCR >= 1.20) dscrPts = 14;
else if (DSCR >= 1.10) dscrPts = 8;
else if (DSCR >= 1.00) dscrPts = 4;

// --------------------------------------------------------
// Cashflow scoring (max 20)
// --------------------------------------------------------
let cfPts = 0;
if (monthlyCF >= 400) cfPts = 20;
else if (monthlyCF >= 300) cfPts = 16;
else if (monthlyCF >= 200) cfPts = 14;
else if (monthlyCF >= 100) cfPts = 8;
else if (monthlyCF > 0) cfPts = 4;

// --------------------------------------------------------
// CoC scoring (max 10) — on normalized percent
// --------------------------------------------------------
let cocPts = 0;
if (CoC >= 12) cocPts = 10;
else if (CoC >= 10) cocPts = 8;
else if (CoC >= 8) cocPts = 6;
else if (CoC >= 6) cocPts = 4;
else if (CoC >= 4) cocPts = 2;

// --------------------------------------------------------
// Urgency / Hardship score v3.8
// Priority: four_pillars → transcript → fallback
// Max 15 pts total
// --------------------------------------------------------
let uhPts = 0;

// A) If four_pillars present → use Urgency + Motivation
const pillarUrg = Number(pillars.Urgency ?? 0);
const pillarMot = Number(pillars.Motivation ?? 0);
if (pillarUrg || pillarMot) {
  // Sum (0–20) mapped to 0–15 pts
  const sum = Math.max(0, Math.min(20, pillarUrg + pillarMot));
  uhPts = (sum / 20) * 15;
} else {
  // B) No pillars → use transcript or fallback

  const Turg = T(transcript.sellerUrgency);
  const Thard = T(transcript.sellerHardship);
  const Tprice = T(transcript.price);
  const Tadd = T(transcript.additionalInsights);

  const transcriptAvailable = !!(Turg || Thard || Tprice || Tadd);

  if (transcriptAvailable) {
    const urgencyStrong = has(Turg, /\b(vacant|asap|urgent|quick\s*close|immediately|must\s*sell|holding\s*costs)\b/);
    const hardshipStrong = has(Thard, /\b(foreclos|pre[-\s]*foreclos|divorce|job\s*loss|medical|probate|relocat)\b/);

    const urgPoints = urgencyStrong ? 10 : (Turg ? 6 : 0);
    const hardPoints = hardshipStrong ? 5 : (Thard ? 2 : 0);

    uhPts = Math.min(15, urgPoints + hardPoints);
  } else {
    // C) Full fallback when no transcript & no pillars
    let fallbackUrg = 0;
    let fallbackHard = 0;

    const DOM = Number(property.dom ?? 0);

    // DOM-driven urgency
    if (DOM >= 90) fallbackUrg += 8;
    else if (DOM >= 60) fallbackUrg += 6;
    else if (DOM >= 30) fallbackUrg += 3;

    // Vacancy from MLS narrative
    const mlsDesc = T(property.mls_description);
    if (/vacant|empty|no one living/i.test(mlsDesc)) {
      fallbackUrg += 6;
    }

    // Out-of-state owner hint
    const sellerLoc = T(root.seller_location || root.ownerLocation);
    if (sellerLoc && !/nv|nevada/i.test(sellerLoc)) {
      fallbackUrg += 4;
    }

    // Price reduction
    const priceText = mlsDesc + " " + Tprice;
    if (/reduced|price drop|motivated/i.test(priceText)) {
      fallbackUrg += 4;
    }

    // Equity + DOM stress
    const eq = Number(metrics.equity_pct ?? 0);
    if (eq >= 30 && DOM >= 60) {
      fallbackHard += 3;
    }

    uhPts = Math.min(15, fallbackUrg + fallbackHard);
  }
}

// --------------------------------------------------------
// Data quality scoring
// --------------------------------------------------------
const hasAddr = !!(property.address && property.city && property.state);
const compsOK = comps.length >= 2;
const rentOK = !!pNum(metrics.grossRent) || !!pNum(metrics.annualRent);

let dataCount = 0;
if (hasAddr) dataCount++;
if (compsOK) dataCount++;
if (rentOK) dataCount++;

const dataPts = [0, 4, 7, 10][dataCount] || 0;


// ---- Comp Strength Bonus ----
// Measures how tight, consistent, and reliable the comps are.
// Uses correlation, price tightness, DOM variance.

let compStrength = 0;

if (Array.isArray(comps) && comps.length >= 3) {
  const prices = comps.map(c => pNum(c.price)).filter(n => n > 0);
  const cors = comps.map(c => Number(c.correlation) || 0);

  if (prices.length >= 3) {
    const avg = prices.reduce((a, b) => a + b, 0) / prices.length;
    const max = Math.max(...prices);
    const min = Math.min(...prices);
    const spreadPct = (max - min) / avg; // 0.10 = tight, 0.30 = loose

    // Tighter price clustering → stronger comps
    if (spreadPct < 0.12) compStrength += 5;
    else if (spreadPct < 0.20) compStrength += 3;
    else if (spreadPct < 0.30) compStrength += 1;

    // Average correlation strength
    const avgCor = cors.reduce((a, b) => a + b, 0) / cors.length;
    if (avgCor >= 0.96) compStrength += 5;
    else if (avgCor >= 0.94) compStrength += 3;
    else if (avgCor >= 0.92) compStrength += 1;
  }
}

// ---- Price Drop Acceleration ----
// Detects pricing pain: multiple drops or large recent cut.
// Works even if minimal data is available.

let priceDropPts = 0;
const priceData = root.priceHistory || root.price_changes || root.mls_price_changes || [];

if (Array.isArray(priceData) && priceData.length >= 1) {
  // Normalize
  const drops = priceData
    .map(x => ({
      old: pNum(x.oldPrice ?? x.old ?? x.from),
      new: pNum(x.newPrice ?? x.new ?? x.to),
      date: x.date || null
    }))
    .filter(p => p.old > 0 && p.new > 0 && p.new < p.old);

  if (drops.length > 0) {
    const last = drops[drops.length - 1];
    const pct = (last.old - last.new) / last.old;

    if (pct >= 0.10) priceDropPts += 6;  // 10%+ cut
    else if (pct >= 0.06) priceDropPts += 4;  // 6-9% cut
    else if (pct >= 0.03) priceDropPts += 2;  // 3-5% cut

    // Multiple drops = pain
    if (drops.length >= 3) priceDropPts += 4;
    else if (drops.length === 2) priceDropPts += 2;
  }
}


// --------------------------------------------------------
// DOM scoring (max +7 / -7)
// --------------------------------------------------------
const DOM = Number(property.dom ?? 0);
let domPts = 0;
if (DOM >= 61 && DOM <= 90) domPts = 7;
else if ((DOM >= 40 && DOM <= 60) || (DOM >= 91 && DOM <= 120)) domPts = 4;
else if (DOM < 40 && DOM > 0) {
  const t = 1 - DOM / 40;
  domPts = Math.round(-7 * t);
} else if (DOM > 120) {
  const span = Math.min(80, DOM - 120);
  const t = span / 80;
  domPts = Math.round(-7 * t);
}

// --------------------------------------------------------
// Price vs ARV scoring (max +12 / -12)
// --------------------------------------------------------
const listPrice = pNum(property.list_price);
const ARV = pNum(src.estimated_arv ?? root.estimated_arv);
let pricePts = 0;

if (ARV > 0 && listPrice > 0) {
  const ratio = listPrice / ARV;
  if (ratio <= 0.80) pricePts = +12;
  else if (ratio <= 0.90) pricePts = +9;
  else if (ratio <= 1.00) pricePts = +5;
  else if (ratio <= 1.10) pricePts = -4;
  else if (ratio <= 1.20) pricePts = -8;
  else pricePts = -12;
}

// --------------------------------------------------------
// Condition scoring (+5 max)
// --------------------------------------------------------
// 7) Condition boost from four pillars
const condScore = Number(root.four_pillars?.Condition ?? 0);

// map 0–10 pillar scale → 0–5 stage-router points
let condBoost = 0;
if (condScore >= 9) condBoost = 5;         // excellent
else if (condScore >= 7) condBoost = 4;    // very good
else if (condScore >= 5) condBoost = 2;    // decent
else condBoost = 0;                         // poor or unknown


// --------------------------------------------------------
// FINAL SCORE
// --------------------------------------------------------
let score =
  buyerPts +
  dscrPts +
  cfPts +
  cocPts +
  uhPts +
  dataPts +
  compStrength +
  priceDropPts +
  domPts +
  pricePts +
  condBoost;


score = Math.max(0, Math.min(100, score));

// --- Stage Routing Patch v3.7 ---
// Economics Fail = DSCR < 1.0 OR negative CF
const blob = [Turg, Thard, Tprice, Tadd, statusRaw].join(' ');

// 🧩 These MUST be defined right here
const isDNC = /\b(dnc|do\s*not\s*contact)\b/i.test(blob);
const isSold = /\b(already\.?sold|sold\b)\b/i.test(blob);
const isUnint = /\b(uninterested|not\s*interested|no\s*interest)\b/i.test(blob);

// New classifications for hesitant and deferred intent
const isHesitant = /\b(hesitant|unsure|maybe|needs\s*time|thinking\s*about\s*it|not\s*sure\s*yet|possibly)\b/i.test(blob);
const isDeferred = /\b(talk\s*to\s*wife|talk\s*to\s*husband|talk\s*to\s*spouse|talk\s*to\s*partner|partner|attorney|lawyer|decision\s*maker|family|kids)\b/i.test(blob);
const tempMaybe = has(blob, /\b(open|consider|maybe|counter|negotiat|follow\s*up|after|later)\b/);

const econFail = (DSCR < 1.0 || monthlyCF < 0);

let evaluation = "";
let nextStage = "";
const reasons = [];

// --- 1) HARD STOPS ---
if (isDNC) {
  nextStage = "12. DNC: Do Not contact";
  evaluation = "☠️Dead";
  reasons.push("Hard stop: DNC");
}
else if (isSold) {
  nextStage = "10. Dead: Inactive";
  evaluation = "☠️Dead";
  reasons.push("Hard stop: Already Sold");
}
else if (isDeferred) {
  nextStage = "1.5 Prequal Answered: Following Up";
  evaluation = "📞Follow-Up";
  reasons.push("Deferred decision maker (needs to consult partner/family/attorney)");
}
else if (isHesitant || (isUnint && tempMaybe)) {
  nextStage = "9. Cold: Long-Term Nurture";
  evaluation = "🤔Hesitant";
  reasons.push("Seller is hesitant, unsure, or might consider later");
}
else if (isUnint) {
  nextStage = "11. Cold/Not Interested";
  evaluation = "🥶Cold";
  reasons.push("Uninterested with no sign of movement");
}

// --- 2) ECON FAIL HANDLING ---
else if (econFail && score < 50) {
  nextStage = "9. Cold: Long-Term Nurture";
  evaluation = "🥶Cold";
  reasons.push("Economics fail AND score < 50 → Long-Term Nurture");
}

// --- 3) HIGH SCORE ALWAYS ESCALATES ---
// Determine economics

const econPass = !econFail;




// ----------------------------
// SCORE 90–100
// ----------------------------
if (score >= 90) {
  evaluation = "🔥Hot";
  nextStage = "3. Closer Call";
  reasons.push(`High-score lead. DSCR ${DSCR}, CF $${monthlyCF}. Auto-Hot.`);
}

// ----------------------------
// SCORE 80–89
// ----------------------------
else if (score >= 80) {
  if (econPass) {
    evaluation = "🔥Hot";
    reasons.push(`Economics pass → Hot (DSCR ${DSCR}, CF $${monthlyCF}).`);
  } else {
    evaluation = "🌤️Warm";
    reasons.push(`Economics fail → Warm (DSCR ${DSCR}, CF $${monthlyCF}).`);
  }
  nextStage = "3. Closer Call";
}

// ----------------------------
// SCORE 65–79
// ----------------------------
else if (score >= 65) {
  if (econPass) {
    evaluation = "🌤️Warm";
    reasons.push(`Warm: Economics pass (DSCR ${DSCR}, CF $${monthlyCF}).`);
    nextStage = "3. Closer Call";
  } else {
    evaluation = "Closer 🫳Manual Review";
    reasons.push(`Economics fail → Manual Review (DSCR ${DSCR}, CF $${monthlyCF}).`);
    nextStage = "3. Closer Call";
  }
}


// --- 4) DEFAULT FOLLOW-UP ---
else {
  nextStage = "1.5 Prequal Answered: Following Up";
  evaluation = "📞Follow-Up for better 📝 Score";
  reasons.push("Borderline economics; gather more info");
}




// --------------------------------------------------------
// Write back onto root
// --------------------------------------------------------
root.lead_score = score;
root.lead_score_version = "uws-v3.8";

root.lead_score_explanation =
  `Buyer fit => +${buyerPts} | ` +
  `DSCR => +${dscrPts} | ` +
  `Monthly CF (${money(monthlyCF)}) => +${cfPts} | ` +
  `CoC (${pct(CoC)}) => +${cocPts} | ` +
  `Urgency/Hardship => +${uhPts.toFixed(1)} | ` +
  `Data quality (${dataCount}/3) => +${dataPts} | ` +
  `DOM (${DOM} days) => +${domPts} | ` +
  `Price/ARV => +${pricePts} | ` +
  `Condition => ${condBoost >= 0 ? '+' : ''}${condBoost}`,
  `Comp Strength => +${compStrength}`,
  `Price Drop Accel => +${priceDropPts}`


// --- Final Assignment ---
root.recommendation = {
  evaluation,
  nextPipelineStage: nextStage,
  stage_version: STAGE_VERSION,
  readyForCloserCall: (nextStage === "3. Closer Call"),
  dataQuality: { hasAddr, compsOK, rentOK, dataCount },
  economics: { DSCR: DSCR, monthlyCF: monthlyCF, CoC: CoC },
  reasons
};

return [{ json: root }];

