// Get the incoming lead data to know what Property Type and Bedrooms to look for
const lead = $('HTTP Request6').first().json;
const webhook = $('Start Webhook1').first().json.body.customData;
const propertyType = lead.propertyType || webhook.prop_type || "single_family"; // default to Single Family if missing
const bedrooms = parseInt(lead.bedrooms || webhook.beds || 3); // default to 3 if missing
const zip = lead.zipCode || webhook.zip;
// Get the raw AI analysis blocks
const aiAnalysis = $('Information Extractor').first().json.output;

// Get the raw RentCast arrays so we can extract the EXACT numbers for this property type
const rcSalesProps = $('Market Rental/Sale Data').item.json.saleData.dataByPropertyType || [];
const rcSalesBeds = $('Market Rental/Sale Data').item.json.saleData.dataByBedrooms || [];
const rcRentProps = $('Market Rental/Sale Data').item.json.rentalData.dataByPropertyType || [];
const rcRentBeds = $('Market Rental/Sale Data').item.json.rentalData.dataByBedrooms || [];

// 1. EXTRACT DATA BY PROPERTY TYPE
// We compare in a case-insensitive way just to be safe
const normalizedPropTypeRaw = String(propertyType).trim().toLowerCase();
const specificSalesProp = rcSalesProps.find(p => String(p.propertyType).toLowerCase() === normalizedPropTypeRaw) || {};
const specificRentProp = rcRentProps.find(p => String(p.propertyType).toLowerCase() === normalizedPropTypeRaw) || {};

// 2. EXTRACT DATA BY BEDROOMS
const specificSalesBed = rcSalesBeds.find(b => parseInt(b.bedrooms) === bedrooms) || {};
const specificRentBed = rcRentBeds.find(b => parseInt(b.bedrooms) === bedrooms) || {};

// -------------------------------------------------------------
// HELPER FUNCTIONS
// -------------------------------------------------------------

// Helper to reliably map any format of Property Type to GHL's single_options keys
function getGhlPropertyKey(rawType) {
    if (!rawType) return "";
    const lower = String(rawType).trim().toLowerCase();
    if (lower === "single family" || lower === "sf" || lower === "single_family") return "single_family";
    if (lower === "multi-family" || lower === "multifamily" || lower === "mf") return "multifamily";
    if (lower === "condo" || lower === "condominium") return "condo";
    if (lower === "townhouse" || lower === "townhome") return "townhouse";
    if (lower === "apartment" || lower === "apart") return "apartment";
    if (lower === "manufactured" || lower === "mobile") return "manufactured";
    if (lower === "land" || lower === "lot") return "land";
    return lower.replace(/[^a-z0-9]/g, "_"); // fallback
}

// Helper for GHL MONETORY type. 
// GHL Custom Objects expect MONETORY fields to be an object with the default currency code and value: { "currency": "default", "value": 100 }
function toMonetary(val) {
    if (val === undefined || val === null || val === "") return { currency: "default", value: 0 };
    const num = Number(String(val).replace(/[^0-9.-]/g, ""));
    return { currency: "default", value: isNaN(num) ? 0 : num };
}

// Helper for GHL NUMERICAL type.
function toNumerical(val) {
    if (val === undefined || val === null || val === "") return 0;
    const num = Number(String(val).replace(/[^0-9.-]/g, ""));
    return isNaN(num) ? 0 : num;
}

// -------------------------------------------------------------
// FINAL MAPPING OBJECT
// -------------------------------------------------------------
return {
  json: {
    zip_code: zip,
    id: toNumerical(zip),
    sales_market_data_by_property_type: aiAnalysis["Sales Market Data By Property Type"] || "",
    sales_market_data_by_bedrooms: aiAnalysis["Sales Market Data by Bedrooms"] || "",
    historical_sales_market_data: aiAnalysis["Historical Sales Market Data"] || "",
    rental_market_data_by_property_type: aiAnalysis["Rental Market Data By Property Type"] || "",
    rental_market_data_by_bedrooms: aiAnalysis["Rental Market Data by Bedrooms"] || "",
    historical_rental_market_data: aiAnalysis["Historical Rental Market Data"] || "",
    overal_market_data_analysis: aiAnalysis["Overal Market Data Analysis"] || "",
    market_analysis_for_a_padsplit_option: aiAnalysis["Market Analysis for a Padsplit Option"] || "",
    salesdata_by_property_type: getGhlPropertyKey(specificSalesProp.propertyType),
    rentaldata_by_property_type: getGhlPropertyKey(specificRentProp.propertyType),
    salesdata_by_bedrooms: toNumerical(specificSalesBed.bedrooms),
    rentaldata_by_bedrooms: toNumerical(specificRentBed.bedrooms),
    salesstats_averageprice: toMonetary(specificSalesProp.averagePrice),
    salesstats_medianprice: toMonetary(specificSalesProp.medianPrice),
    salesstats_minprice: toMonetary(specificSalesProp.minPrice),
    salesstats_maxprice: toMonetary(specificSalesProp.maxPrice),

    salesstats_averagepricepersquarefoot: toMonetary(specificSalesProp.averagePricePerSquareFoot),
    salesstats_medianpricepersquarefoot: toMonetary(specificSalesProp.medianPricePerSquareFoot),
    salesstats_minpricepersquarefoot: toMonetary(specificSalesProp.minPricePerSquareFoot),
    salesstats_maxpricepersquarefoot: toMonetary(specificSalesProp.maxPricePerSquareFoot),

    salesstats_averagesquarefootage: toNumerical(specificSalesProp.averageSquareFootage),
    salesstats_mediansquarefootage: toNumerical(specificSalesProp.medianSquareFootage),
    salesstats_minsquarefootage: toNumerical(specificSalesProp.minSquareFootage),
    salesstats_maxsquarefootage: toNumerical(specificSalesProp.maxSquareFootage),

    salesstats_averagedaysonmarket: toNumerical(specificSalesProp.averageDaysOnMarket),
    salesstats_mediandaysonmarket: toNumerical(specificSalesProp.medianDaysOnMarket),
    salesstats_mindaysonmarket: toNumerical(specificSalesProp.minDaysOnMarket),
    salesstats_maxdaysonmarket: toNumerical(specificSalesProp.maxDaysOnMarket),

    salesstats_newlistings: toNumerical(specificSalesProp.newListings),
    salesstats_totallistings: toNumerical(specificSalesProp.totalListings),

    // Rental Data specific to the Property Type
    rentstats_averagerent: toMonetary(specificRentProp.averageRent),
    rentstats_minrent: toMonetary(specificRentProp.minRent),
    rentstats_maxrent: toMonetary(specificRentProp.maxRent),

    rentstats_averagerentpersquarefoot: toMonetary(specificRentProp.averageRentPerSquareFoot),
    rentalstats_minrentpersquarefoot: toMonetary(specificRentProp.minRentPerSquareFoot),
    rentstats_maxrentpersquarefoot: toMonetary(specificRentProp.maxRentPerSquareFoot),

    rentstats_averagesquarefootage: toNumerical(specificRentProp.averageSquareFootage),
    rentstats_maxsquarefootage: toNumerical(specificRentProp.maxSquareFootage),
    rentstats_minsquarefootage: toNumerical(specificRentProp.minSquareFootage),

    rentstats_averagedaysonmarket: toNumerical(specificRentProp.averageDaysOnMarket),
    rentstats_mindaysonmarket: toNumerical(specificRentProp.minDaysOnMarket),
    rentstats_maxdaysonmarket: toNumerical(specificRentProp.maxDaysOnMarket),

    rentstats_newlistings: toNumerical(specificRentProp.newListings),
    rentstats_totallistings: toNumerical(specificRentProp.totalListings)
  }
};

