parameters.jsCode:
  /******************************************************
 SELECTED COMPS + SAFE ARV ENGINE
 -----------------------------------------------------
 What this fixes:
 - Does NOT only select sold comps
 - Allows sold / pending / active / unknown-status comps
 - Applies quality filters to every comp
 - Uses adaptive filtering for large/luxury homes
 - Adds rejection diagnostics
 - Adds BatchLeads / external estimate support
 - Adds lot-size / estate-lot guardrails
 - Prevents small-lot subdivision comps from pretending
   they fully support acreage / estate valuations
******************************************************/

function num(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  if (typeof v === 'boolean') return v ? 1 : 0;
  const n = Number(String(v).replace(/[^\d.-]/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function txt(v) {
  return String(v ?? '').trim();
}

function lower(v) {
  return txt(v).toLowerCase();
}

function get(obj, keys) {
  for (const k of keys) {
    if (
      obj &&
      obj[k] !== undefined &&
      obj[k] !== null &&
      obj[k] !== ''
    ) {
      return obj[k];
    }
  }
  return null;
}

function avg(arr) {
  return arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : 0;
}

function median(arr) {
  if (!arr.length) return 0;
  const sorted = [...arr].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2
    ? sorted[mid]
    : (sorted[mid - 1] + sorted[mid]) / 2;
}

function clamp(n, min, max) {
  return Math.min(max, Math.max(min, n));
}

function ratio(a, b) {
  const x = num(a);
  const y = num(b);
  if (x <= 0 || y <= 0) return 0;
  return x / y;
}

function firstNonZero(values) {
  for (const v of values) {
    const n = num(v);
    if (n > 0) return n;
  }
  return 0;
}

function normalizeType(v) {
  const s = lower(v);

  if (!s) return '';

  if (s.includes('multi')) return 'multi-family';
  if (s.includes('duplex')) return 'multi-family';
  if (s.includes('triplex')) return 'multi-family';
  if (s.includes('fourplex')) return 'multi-family';
  if (s.includes('apartment')) return 'apartment';
  if (s.includes('single')) return 'single-family';
  if (s.includes('sfr')) return 'single-family';
  if (s.includes('residential')) return 'single-family';
  if (s.includes('detached')) return 'single-family';
  if (s.includes('town')) return 'townhouse';
  if (s.includes('condo')) return 'condo';

  return s;
}

function propertyTypeMatches(compType, subjectType) {
  const c = normalizeType(compType);
  const s = normalizeType(subjectType);

  if (!c || !s) return true;
  if (c === s) return true;

  if (s === 'multi-family' && /(multi|duplex|triplex|fourplex|apartment)/i.test(c)) return true;
  if (s === 'single-family' && /(single|sfr|residential|detached)/i.test(c)) return true;

  return false;
}

function parseLotSqft(v) {
  if (v === null || v === undefined || v === '') return 0;

  const raw = String(v).toLowerCase();
  const n = num(v);

  if (n <= 0) return 0;

  // Explicit acreage string.
  if (raw.includes('acre') || raw.includes(' ac')) {
    return Math.round(n * 43560);
  }

  // Explicit square footage string.
  if (
    raw.includes('sqft') ||
    raw.includes('sq ft') ||
    raw.includes('square feet') ||
    raw.includes('sf')
  ) {
    return Math.round(n);
  }

  // Heuristic:
  // 250000 = sqft.
  // 5.7 = likely acres.
  if (n > 1000) return Math.round(n);
  if (n > 0 && n < 100) return Math.round(n * 43560);

  return Math.round(n);
}

function getLotSqftFrom(obj) {
  if (!obj) return 0;

  const sqftVal = get(obj, [
    'lotSqft',
    'lot_sqft',
    'lotSizeSqft',
    'lot_size_sqft',
    'lotSizeSquareFeet',
    'lot_size_square_feet',
    'lotAreaSqft',
    'lot_area_sqft',
    'lotSquareFeet',
    'lot_square_feet'
  ]);

  if (sqftVal !== null && sqftVal !== undefined && sqftVal !== '') {
    return parseLotSqft(sqftVal);
  }

  const genericLotVal = get(obj, [
    'lotSize',
    'lot_size',
    'lotArea',
    'lot_area',
    'landArea',
    'land_area'
  ]);

  if (genericLotVal !== null && genericLotVal !== undefined && genericLotVal !== '') {
    return parseLotSqft(genericLotVal);
  }

  const acresVal = get(obj, [
    'acres',
    'lotAcres',
    'lot_acres',
    'acreage',
    'lotAcreage',
    'lot_acreage'
  ]);

  if (acresVal !== null && acresVal !== undefined && acresVal !== '') {
    const acres = num(acresVal);
    return acres > 0 ? Math.round(acres * 43560) : 0;
  }

  return 0;
}

function classifyCompStatus(c) {
  const status = lower(get(c, [
    'status',
    'listingStatus',
    'mlsStatus',
    'propertyStatus',
    'standardStatus',
    'listing_status',
    'mls_status',
    'standard_status'
  ]));

  const soldDate = get(c, [
    'soldDate',
    'dateSold',
    'removedDate',
    'closedDate',
    'lastSaleDate',
    'sold_date',
    'date_sold',
    'removed_date',
    'closed_date',
    'last_sale_date'
  ]);

  if (soldDate) return 'sold';

  if (/(sold|closed)/i.test(status)) return 'sold';

  if (/(pending|under contract|under_contract|contingent|active under contract)/i.test(status)) {
    return 'pending';
  }

  if (/(active|for sale|listed|coming soon)/i.test(status)) {
    return 'active';
  }

  if (/(withdrawn|cancelled|canceled|expired)/i.test(status)) {
    return 'excluded';
  }

  // RentCast often uses Inactive for removed/closed-ish records.
  // Do not kill it automatically unless we know it is bad.
  if (/inactive|off market|off-market/i.test(status)) {
    return 'unknown';
  }

  return 'unknown';
}

function isAllowedCompStatus(c) {
  const group = classifyCompStatus(c);
  return ['sold', 'pending', 'active', 'unknown'].includes(group);
}

function getCompPrice(c) {
  const group = classifyCompStatus(c);

  if (group === 'sold') {
    return num(get(c, [
      'soldPrice',
      'closePrice',
      'salePrice',
      'lastSalePrice',
      'price',
      'listPrice',
      'sold_price',
      'close_price',
      'sale_price',
      'last_sale_price',
      'list_price'
    ]));
  }

  return num(get(c, [
    'listPrice',
    'price',
    'askingPrice',
    'currentPrice',
    'listingPrice',
    'list_price',
    'asking_price',
    'current_price',
    'listing_price'
  ]));
}

function getPriceBasis(c) {
  const group = classifyCompStatus(c);

  if (group === 'sold') return 'sold_price';
  if (group === 'pending') return 'pending_or_contract_price';
  if (group === 'active') return 'list_price';
  return 'unknown_price_basis';
}

function normalizeComp(c) {
  const statusGroup = classifyCompStatus(c);

  return {
    ...c,
    _price: getCompPrice(c),
    _priceBasis: getPriceBasis(c),
    _statusGroup: statusGroup,

    _sqft: num(get(c, [
      'squareFootage',
      'livingArea',
      'sqft',
      'buildingSqft',
      'buildingArea',
      'grossLivingArea',
      'square_footage',
      'living_area',
      'building_sqft',
      'building_area',
      'gross_living_area'
    ])),

    _beds: num(get(c, [
      'bedrooms',
      'beds',
      'bed',
      'numBedrooms',
      'bed_count',
      'bedroom_count'
    ])),

    _baths: num(get(c, [
      'bathrooms',
      'baths',
      'bath',
      'totalBathrooms',
      'numBathrooms',
      'bath_count',
      'bathroom_count',
      'total_bathrooms'
    ])),

    _distance: num(get(c, [
      'distance',
      'distanceMiles',
      'distance_miles',
      'distanceMi',
      'distance_mi',
      'miles'
    ])),

    _yearBuilt: num(get(c, [
      'yearBuilt',
      'yrBuilt',
      'year_built',
      'yr_built'
    ])),

    _propertyType: get(c, [
      'propertyType',
      'propType',
      'type',
      'property_type',
      'prop_type'
    ]),

    _lotSqft: getLotSqftFrom(c)
  };
}

function rejectionReason(c, subject, rules) {
  if (!isAllowedCompStatus(c)) return 'bad_status';

  if (c._price <= 0) return 'missing_or_zero_price';
  if (c._sqft <= 0) return 'missing_or_zero_sqft';

  if (rules.requireBeds && c._beds <= 0) return 'missing_or_zero_beds';
  if (rules.requireBaths && c._baths <= 0) return 'missing_or_zero_baths';

  if (rules.requireTypeMatch && !propertyTypeMatches(c._propertyType, subject.propType)) {
    return 'property_type_mismatch';
  }

  if (rules.maxDistance > 0 && c._distance > rules.maxDistance) {
    return 'distance_too_far';
  }

  if (subject.beds > 0 && c._beds > 0 && Math.abs(c._beds - subject.beds) > rules.bedTolerance) {
    return 'bed_mismatch';
  }

  if (subject.baths > 0 && c._baths > 0 && Math.abs(c._baths - subject.baths) > rules.bathTolerance) {
    return 'bath_mismatch';
  }

  if (subject.sqft > 0 && c._sqft > 0) {
    const sqftRatio = c._sqft / subject.sqft;

    if (sqftRatio < rules.minSqftRatio) return 'sqft_too_small';
    if (sqftRatio > rules.maxSqftRatio) return 'sqft_too_large';
  }

  if (subject.yearBuilt > 0 && c._yearBuilt > 0 && rules.yearTolerance > 0) {
    if (Math.abs(c._yearBuilt - subject.yearBuilt) > rules.yearTolerance) {
      return 'year_built_mismatch';
    }
  }

  return null;
}

function summarizeRejections(normalizedComps, subject, rules) {
  const summary = {};

  for (const c of normalizedComps) {
    const reason = rejectionReason(c, subject, rules);
    if (reason) summary[reason] = (summary[reason] || 0) + 1;
  }

  return summary;
}

function applyRules(normalizedComps, subject, rules) {
  return normalizedComps.filter(c => !rejectionReason(c, subject, rules));
}

function sortComps(comps) {
  const rank = {
    sold: 1,
    pending: 2,
    active: 3,
    unknown: 4
  };

  return comps.sort((a, b) => {
    const ar = rank[a._statusGroup] || 9;
    const br = rank[b._statusGroup] || 9;

    if (ar !== br) return ar - br;

    const ac = num(a.correlation);
    const bc = num(b.correlation);

    if (bc !== ac) return bc - ac;

    if (a._distance !== b._distance) return a._distance - b._distance;

    return num(get(a, ['daysOld', 'days_old'])) - num(get(b, ['daysOld', 'days_old']));
  });
}

function filterComps(comps, subject) {
  if (!Array.isArray(comps) || !comps.length) {
    return {
      safeComps: [],
      passUsed: 'none',
      rejectionSummary: {},
      debugRejectedSamples: []
    };
  }

  const normalizedComps = comps.map(normalizeComp);

  const isLuxuryOrLarge =
    subject.sqft >= 3500 ||
    subject.baths >= 5 ||
    subject.beds >= 5 ||
    subject.lotSqft >= 43560;

  const passes = [
    {
      name: 'strict',
      maxDistance: 2,
      minSqftRatio: 0.65,
      maxSqftRatio: 1.35,
      bedTolerance: 2,
      bathTolerance: 2,
      yearTolerance: 25,
      requireBeds: true,
      requireBaths: true,
      requireTypeMatch: true
    },
    {
      name: isLuxuryOrLarge ? 'relaxed_luxury' : 'relaxed',
      maxDistance: isLuxuryOrLarge ? 5 : 3,
      minSqftRatio: isLuxuryOrLarge ? 0.45 : 0.55,
      maxSqftRatio: isLuxuryOrLarge ? 1.75 : 1.50,
      bedTolerance: isLuxuryOrLarge ? 3 : 2,
      bathTolerance: isLuxuryOrLarge ? 3.5 : 2.5,
      yearTolerance: 40,
      requireBeds: true,
      requireBaths: true,
      requireTypeMatch: true
    },
    {
      name: 'salvage_market_context',
      maxDistance: isLuxuryOrLarge ? 10 : 5,
      minSqftRatio: isLuxuryOrLarge ? 0.35 : 0.45,
      maxSqftRatio: isLuxuryOrLarge ? 2.25 : 1.75,
      bedTolerance: isLuxuryOrLarge ? 99 : 3,
      bathTolerance: isLuxuryOrLarge ? 99 : 3.5,
      yearTolerance: 0,
      requireBeds: false,
      requireBaths: false,
      requireTypeMatch: false
    }
  ];

  let selected = [];
  let passUsed = 'none';
  let rejectionSummary = {};

  for (const rules of passes) {
    selected = applyRules(normalizedComps, subject, rules);
    rejectionSummary = summarizeRejections(normalizedComps, subject, rules);

    if (selected.length >= 3) {
      passUsed = rules.name;
      break;
    }

    if (rules.name === 'salvage_market_context' && selected.length > 0) {
      passUsed = rules.name;
      break;
    }
  }

  const finalRules =
    passes.find(p => p.name === passUsed) ||
    passes[passes.length - 1];

  selected = sortComps(selected);

  const debugRejectedSamples = normalizedComps
    .map(c => ({
      address: c.formattedAddress || c.address || c.formatted_address || null,
      price: c._price,
      sqft: c._sqft,
      beds: c._beds,
      baths: c._baths,
      lotSqft: c._lotSqft || null,
      lotAcres: c._lotSqft > 0 ? Number((c._lotSqft / 43560).toFixed(2)) : null,
      distance: c._distance,
      statusGroup: c._statusGroup,
      rawStatus: get(c, [
        'status',
        'listingStatus',
        'mlsStatus',
        'propertyStatus',
        'standardStatus',
        'listing_status',
        'mls_status',
        'standard_status'
      ]) || null,
      propertyType: c._propertyType || null,
      rejectionReason: rejectionReason(c, subject, finalRules)
    }))
    .filter(x => x.rejectionReason)
    .slice(0, 15);

  return {
    safeComps: selected,
    passUsed,
    rejectionSummary,
    debugRejectedSamples
  };
}

function getStartWebhookCustomData() {
  try {
    const j = $('Start Webhook1').first().json;
    return j?.body?.customData || {};
  } catch {
    return {};
  }
}

function getListPrice(s, res, cd) {
  return num(
    get(s, [
      'listPrice',
      'listingPrice',
      'askingPrice',
      'mlsListPrice',
      'list_price',
      'listing_price',
      'asking_price',
      'mls_list_price'
    ]) ||
    get(res, [
      'listPrice',
      'listingPrice',
      'askingPrice',
      'mlsListPrice',
      'list_price',
      'listing_price',
      'asking_price',
      'mls_list_price'
    ]) ||
    get(cd, [
      'listPrice',
      'listingPrice',
      'askingPrice',
      'mlsListPrice',
      'list_price',
      'listing_price',
      'asking_price',
      'mls_list_price',
      'price',
      'asking'
    ]) ||
    s?.listing?.list_price ||
    s?.listing?.listPrice ||
    s?.property?.listPrice ||
    s?.property?.price
  );
}

function getRentcastMidpoint(s) {
  const low = num(s.priceRangeLow);
  const high = num(s.priceRangeHigh);

  if (low > 0 && high > 0 && high >= low) {
    return Math.round((low + high) / 2);
  }

  return num(get(s, [
    'rentcastValue',
    'rentcast_value',
    'estimatedValue',
    'estimated_value',
    'value',
    'avm',
    'avmValue',
    'avm_value'
  ]));
}

function getTrustedExternalEstimate(s, res, cd) {
  // Prefer explicit BatchLeads-style names.
  const explicit = num(
    get(s, [
      'batchLeadsEstimatedValue',
      'batchleadsEstimatedValue',
      'batchleads_estimated_value',
      'batchLeadsValue',
      'batchleads_value',
      'batchLeadsAVM',
      'batchleads_avm',
      'estimatedValueBatchLeads',
      'propertyEstimatedValue',
      'property_estimated_value'
    ]) ||
    get(res, [
      'batchLeadsEstimatedValue',
      'batchleadsEstimatedValue',
      'batchleads_estimated_value',
      'batchLeadsValue',
      'batchleads_value',
      'batchLeadsAVM',
      'batchleads_avm',
      'estimatedValueBatchLeads',
      'propertyEstimatedValue',
      'property_estimated_value'
    ]) ||
    get(cd, [
      'batchLeadsEstimatedValue',
      'batchleadsEstimatedValue',
      'batchleads_estimated_value',
      'batchLeadsValue',
      'batchleads_value',
      'batchLeadsAVM',
      'batchleads_avm',
      'estimatedValueBatchLeads',
      'propertyEstimatedValue',
      'property_estimated_value',
      'estimated_value',
      'estimatedValue'
    ]) ||
    s?.batchleads?.estimated_value ||
    s?.batchleads?.estimatedValue ||
    s?.batchLeads?.estimated_value ||
    s?.batchLeads?.estimatedValue ||
    s?.property?.batchLeadsEstimatedValue ||
    s?.property?.propertyEstimatedValue
  );

  return explicit > 0 ? explicit : 0;
}

function getCompFitStats(safeComps, subject) {
  const sqftRatios = safeComps
    .filter(c => c._sqft > 0 && subject.sqft > 0)
    .map(c => c._sqft / subject.sqft);

  const correlations = safeComps
    .map(c => {
      const raw = num(c.correlation);
      return raw <= 1 ? raw * 100 : raw;
    })
    .filter(v => v > 0);

  return {
    avgSqftRatio: Number(avg(sqftRatios).toFixed(3)),
    medianSqftRatio: Number(median(sqftRatios).toFixed(3)),
    avgCorrelation: Number(avg(correlations).toFixed(1)),
    medianCorrelation: Number(median(correlations).toFixed(1))
  };
}

function getLotStats(safeComps, subject) {
  const compLots = safeComps
    .map(c => num(c._lotSqft))
    .filter(v => v > 0);

  const subjectLotSqft = num(subject.lotSqft);
  const medianCompLotSqft = median(compLots);
  const avgCompLotSqft = avg(compLots);

  const lotRatio =
    subjectLotSqft > 0 && medianCompLotSqft > 0
      ? subjectLotSqft / medianCompLotSqft
      : 0;

  const compLotDataCoverage =
    safeComps.length > 0
      ? compLots.length / safeComps.length
      : 0;

  const isLargeLot = subjectLotSqft >= 43560;     // 1 acre+
  const isEstateLot = subjectLotSqft >= 100000;   // 2.29 acres+
  const massiveLotMismatch = lotRatio >= 3;
  const missingCompLotData = isEstateLot && compLotDataCoverage < 0.5;

  return {
    subjectLotSqft,
    subjectLotAcres: subjectLotSqft > 0 ? Number((subjectLotSqft / 43560).toFixed(2)) : 0,
    medianCompLotSqft: Math.round(medianCompLotSqft),
    medianCompLotAcres: medianCompLotSqft > 0 ? Number((medianCompLotSqft / 43560).toFixed(2)) : 0,
    avgCompLotSqft: Math.round(avgCompLotSqft),
    avgCompLotAcres: avgCompLotSqft > 0 ? Number((avgCompLotSqft / 43560).toFixed(2)) : 0,
    compLotDataCoverage: Number(compLotDataCoverage.toFixed(2)),
    lotRatio: Number(lotRatio.toFixed(2)),
    isLargeLot,
    isEstateLot,
    massiveLotMismatch,
    missingCompLotData
  };
}

function computeSafeARV({ safeComps, subject, s, res, cd, filterPassUsed }) {
  const rentcastLow = num(s.priceRangeLow);
  const rentcastHigh = num(s.priceRangeHigh);
  const rentcastMidpoint = getRentcastMidpoint(s);

  const trustedExternalEstimate = getTrustedExternalEstimate(s, res, cd);
  const listPrice = getListPrice(s, res, cd);

  const ppsfValues = safeComps
    .filter(c => c._price > 0 && c._sqft > 0)
    .map(c => c._price / c._sqft);

  const avgPPSF = avg(ppsfValues);
  const medianPPSF = median(ppsfValues);

  const compBasedARV =
    subject.sqft > 0 && medianPPSF > 0
      ? Math.round(medianPPSF * subject.sqft)
      : 0;

  const fit = getCompFitStats(safeComps, subject);
  const lotStats = getLotStats(safeComps, subject);

  const weakCompFit =
    filterPassUsed === 'salvage_market_context' ||
    safeComps.length < 3 ||
    fit.medianSqftRatio < 0.50 ||
    fit.medianCorrelation < 75;

  const rentcastRangeExists =
    rentcastLow > 0 &&
    rentcastHigh > 0 &&
    rentcastHigh >= rentcastLow;

  const rentcastContradictedByTrustedEstimate =
    rentcastRangeExists &&
    trustedExternalEstimate > 0 &&
    trustedExternalEstimate > rentcastHigh * 1.35;

  const rentcastContradictedByListPrice =
    rentcastRangeExists &&
    listPrice > 0 &&
    listPrice > rentcastHigh * 2.0;

  const rentcastRangeLowConfidence =
    rentcastContradictedByTrustedEstimate ||
    rentcastContradictedByListPrice;

  const compMatchesTrustedEstimate =
    compBasedARV > 0 &&
    trustedExternalEstimate > 0 &&
    ratio(compBasedARV, trustedExternalEstimate) >= 0.85 &&
    ratio(compBasedARV, trustedExternalEstimate) <= 1.15;

  const compViolatesRentcastRange =
    rentcastRangeExists &&
    compBasedARV > 0 &&
    (
      compBasedARV < rentcastLow * 0.85 ||
      compBasedARV > rentcastHigh * 1.15
    );

  let estARV = 0;
  let arvSource = '';
  let valuationConfidence = 'low';
  const valuationWarnings = [];

  if (compMatchesTrustedEstimate) {
    estARV = Math.round((compBasedARV + trustedExternalEstimate) / 2);
    arvSource = 'comp_median_ppsf_confirmed_by_batchleads';
    valuationConfidence = weakCompFit ? 'medium' : 'high';
  } else if (trustedExternalEstimate > 0 && weakCompFit) {
    estARV = trustedExternalEstimate;
    arvSource = 'batchleads_estimate_due_to_weak_comp_fit';
    valuationConfidence = 'medium';
  } else if (compBasedARV > 0 && !weakCompFit) {
    estARV = compBasedARV;
    arvSource = 'filtered_market_comps_median_ppsf';
    valuationConfidence = 'medium';
  } else if (compBasedARV > 0 && rentcastRangeLowConfidence) {
    estARV = compBasedARV;
    arvSource = 'comp_median_ppsf_used_rentcast_range_rejected';
    valuationConfidence = 'medium';
  } else if (trustedExternalEstimate > 0) {
    estARV = trustedExternalEstimate;
    arvSource = 'batchleads_estimate';
    valuationConfidence = 'medium';
  } else if (rentcastMidpoint > 0) {
    estARV = rentcastMidpoint;
    arvSource = 'rentcast_price_range_midpoint';
    valuationConfidence = 'low';
  } else {
    estARV = 0;
    arvSource = 'no_reliable_value_source';
    valuationConfidence = 'none';
  }

  const supportedValueBasis =
    estARV > 0
      ? estARV
      : compBasedARV || trustedExternalEstimate || rentcastMidpoint || 0;

  const listToSupportedValueRatio =
    listPrice > 0 && supportedValueBasis > 0
      ? listPrice / supportedValueBasis
      : 0;

  const listPriceUnsupported =
    listPrice > 0 &&
    supportedValueBasis > 0 &&
    listToSupportedValueRatio >= 1.35;

  const requiresLandAdjustedValuation =
    lotStats.isEstateLot &&
    (
      lotStats.massiveLotMismatch ||
      lotStats.missingCompLotData ||
      listToSupportedValueRatio >= 1.5
    );

  if (weakCompFit) {
    valuationWarnings.push(
      'Comp fit is weak because selected comps are materially smaller, lower-correlation, or required salvage filtering.'
    );
  }

  if (rentcastRangeLowConfidence) {
    valuationWarnings.push(
      'RentCast low/high range appears inconsistent with BatchLeads estimate and/or list price; range was not used as a hard clamp.'
    );
  }

  if (compViolatesRentcastRange && !rentcastRangeLowConfidence) {
    valuationWarnings.push(
      'Comp-derived ARV is outside RentCast range tolerance; review valuation manually.'
    );
  }

  if (listPriceUnsupported) {
    valuationWarnings.push(
      `List price appears unsupported by current comp/estimate anchors. List-to-supported-value ratio is ${listToSupportedValueRatio.toFixed(2)}x.`
    );
  }

  if (lotStats.isEstateLot) {
    valuationWarnings.push(
      `Subject has an estate-sized lot of ${lotStats.subjectLotAcres} acres. Standard SFR subdivision comps may not capture excess land value.`
    );
  }

  if (lotStats.massiveLotMismatch) {
    valuationWarnings.push(
      `Subject lot is ${lotStats.lotRatio}x the median comp lot size. Residential PPSF comps alone are not sufficient.`
    );
  }

  if (lotStats.missingCompLotData) {
    valuationWarnings.push(
      'Most selected comps are missing lot-size data, so land adjustment cannot be verified.'
    );
  }

  if (requiresLandAdjustedValuation) {
    valuationConfidence = 'manual_review_required';
    arvSource = `${arvSource}_land_adjustment_required`;
    valuationWarnings.push(
      'Manual land-adjusted valuation required. Use estate/acreage comps, land comps, zoning, usable acreage, and development potential before treating ARV as production-grade.'
    );
  }

  if (listPrice > 0 && estARV > 0 && listPrice > estARV * 2) {
    valuationWarnings.push(
      'Seller/list price is more than 2x supported estimated value. Treat as retail fantasy unless acreage/luxury comps prove otherwise.'
    );
  }

  return {
    estARV: Math.round(estARV),
    arvSource,
    valuationConfidence,
    valuationWarnings,
    averagePpsqft: Number(avgPPSF.toFixed(2)),
    medianPpsqft: Number(medianPPSF.toFixed(2)),
    compBasedARV,
    trustedExternalEstimate,
    rentcastMidpoint,
    rentcastLow,
    rentcastHigh,
    listPrice,
    listToSupportedValueRatio: Number(listToSupportedValueRatio.toFixed(2)),
    weakCompFit,
    rentcastRangeLowConfidence,
    rentcastContradictedByTrustedEstimate,
    rentcastContradictedByListPrice,
    compMatchesTrustedEstimate,
    compViolatesRentcastRange,
    listPriceUnsupported,
    requiresLandAdjustedValuation,
    compFit: fit,
    lotStats
  };
}

