// ==========================================
// 1. HELPER FUNCTIONS
// ==========================================
function firstNonEmpty(...vals) {
  for (const v of vals) {
    if (v === 0) return 0;
    if (v === false) return false;
    if (v == null) continue;

    if (typeof v === 'string') {
      const trimmed = v.trim();
      if (trimmed !== '' && trimmed.toLowerCase() !== 'empty') return trimmed;
    } else {
      return v;
    }
  }
  return null;
}

function parseMoney(x) {
  if (x == null || x === '') return null;
  if (typeof x === 'number') return Number.isFinite(x) ? x : null;
  const n = parseFloat(String(x).replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : null;
}

function parseNum(x) {
  if (x == null || x === '') return null;
  if (typeof x === 'number') return Number.isFinite(x) ? x : null;
  const n = parseFloat(String(x).replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : null;
}

function cleanSpaces(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}

function normalizeZip(zip) {
  const s = cleanSpaces(zip);
  const m = s.match(/^(\d{5})(?:-\d{4})?$/);
  return m ? m[1] : s;
}

function hasUnitMarker(address) {
  const s = cleanSpaces(address).toLowerCase();
  return /(?:\b(?:apt|apartment|unit|ste|suite)\b|#)\s*[a-z0-9-]+\b/.test(s);
}

function stripUnit(address) {
  return cleanSpaces(address)
    .replace(/(?:\b(?:apt|apartment|unit|ste|suite)\b|#)\s*[a-z0-9-]+\b/ig, '')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

function parseStreetFromOppName(name) {
  const s = cleanSpaces(name);
  if (!s.includes('-')) return '';
  return s.split('-').slice(1).join('-').trim();
}

function toBoolLike(v) {
  const s = cleanSpaces(v).toLowerCase();
  if (!s) return null;
  if (['yes', 'y', 'true', '1'].includes(s)) return true;
  if (['no', 'n', 'false', '0'].includes(s)) return false;
  return null;
}

function toPct(v) {
  const n = parseNum(v);
  if (n == null) return null;
  return n <= 1 ? n * 100 : n;
}

function toRatio(v) {
  const n = parseNum(v);
  if (n == null) return null;
  return n > 1 ? n / 100 : n;
}

function joinAddress(addressLine, city, state, zip) {
  return cleanSpaces([addressLine, city, state, zip].filter(Boolean).join(', '));
}

// RentCast strict property type enforcement
function canonicalPropertyType(rawPropType, rawHouseStyle, rawPropertyTypeField) {
  const s = [rawPropType, rawHouseStyle, rawPropertyTypeField]
    .filter(Boolean)
    .join(' | ')
    .toLowerCase();

  if (/(5\+|apartment)/.test(s)) return 'Apartment';
  if (/(multi|duplex|triplex|quad|fourplex|4-plex|plex|2-4)/.test(s)) return 'Multi-Family';

  if (/(condo|condominium)/.test(s)) return 'Condo';
  if (/(townhome|townhouse|attached)/.test(s)) return 'Townhouse';

  if (/(manufactured|mobile|modular)/.test(s)) return 'Manufactured';
  if (/(vacant land|land|vacant)/.test(s)) return 'Land';
  if (/(commercial|industrial|office|retail)/.test(s)) return 'Commercial';

  return 'Single Family';
}

function inferUnitCount(propModeStr, notesStr, addressHasUnit, sqft) {
  const s = String(propModeStr || '').toLowerCase() + ' ' + String(notesStr || '').toLowerCase();

  const explicitMatch = s.match(/(?:(\d+)\s*units?|(?:number of units|units?)[#:\s]+(\d+))/i);
  if (explicitMatch) {
    const explicitCount = parseInt(explicitMatch[1] || explicitMatch[2], 10);
    if (explicitCount > 0) return explicitCount;
  }

  if (/quad|fourplex|4-plex|4 units|four units/.test(s)) return 4;
  if (/triplex|3-plex|3 units|three units/.test(s)) return 3;
  if (/duplex|2-plex|2 units|two units/.test(s)) return 2;

  if (addressHasUnit && sqft >= 2500) return 4;
  return null;
}

function amortizedPI(balance, annualRatePct, years = 30) {
  const P = parseMoney(balance);
  const rate = parseMoney(annualRatePct);
  if (!P || !rate || P <= 0 || rate <= 0) return null;

  const r = (rate / 100) / 12;
  const n = years * 12;
  return P * ((r * Math.pow(1 + r, n)) / (Math.pow(1 + r, n) - 1));
}

