  if (!match) return null;

  if (match.fieldValue !== undefined && match.fieldValue !== null) return match.fieldValue;
  if (match.fieldValueString !== undefined && match.fieldValueString !== null) return match.fieldValueString;
  if (match.fieldValueNumber !== undefined && match.fieldValueNumber !== null) return match.fieldValueNumber;
  return null;
}

function parseNum(val) {
  if (val === undefined || val === null || val === "") return null;
  const num = Number(String(val).replace(/[^0-9.-]+/g, ""));
  return Number.isFinite(num) ? num : null;
}

function parseMoney(val) {
  if (val === undefined || val === null || val === "") return null;
  const num = Number(String(val).replace(/[^0-9.-]+/g, ""));
  return Number.isFinite(num) ? num : null;
}

function cleanSpaces(s) {
  return String(s || "").replace(/\s+/g, " ").trim();
}

function normalizeZip(zip) {
  const s = cleanSpaces(zip);
  const m = s.match(/^(\d{5})(?:-\d{4})?$/);
  return m ? m[1] : s;
}

function parseStreetFromOpportunityName(name) {
  const s = cleanSpaces(name);
  if (!s.includes("-")) return "";
  return s.split("-").slice(1).join("-").trim();
}

function identifyPropertyType(propType, houseStyle, beds, baths) {
