  if (/(condo|condominium)/.test(s)) return { propType: "Condo", isSFH: false };
  if (/(townhome|townhouse|attached)/.test(s)) return { propType: "Townhouse", isSFH: false };
  if (/(commercial|industrial|office|retail)/.test(s)) return { propType: "Commercial", isSFH: false };
  if (/(manufactured|mobile|modular)/.test(s)) return { propType: "Manufactured", isSFH: true };

  const actualBeds = parseNum(beds) || 0;
  const actualBaths = parseNum(baths) || 0;

  if (/(land|lot|vacant)/.test(s) || (actualBeds === 0 && actualBaths === 0 && (s === "" || s.includes("unimproved")))) {
    return { propType: "Land", isSFH: false };
  }

