    total_open_loans_amount: 0,
    est_monthly_payment: 0
  };

  // If there are ANY notes mapped (which includes transcripts), it's postcall
  const precall_mode = !res.notes;

  const addressHasUnit = hasUnitMarker(rawAddress);
  const strippedAddress = stripUnit(rawAddress);

  // Calculate Multi-family specific splits (Now passing in res.notes!)
  let unit_count = is_multifamily ? inferUnitCount(propertyType, res.notes, addressHasUnit, sqft) : 1;

  // HEURISTIC FALLBACK: If we know it's a multifamily but could not infer unit_count from text:
  if (is_multifamily && !unit_count) {
    if (beds >= 4) {
      // If we have a lot of beds, assume roughly 2 beds per unit
      unit_count = Math.max(2, Math.round(beds / 2));
    } else if (sqft >= 1500) {
      // Otherwise assume ~1000 sqft per unit
      unit_count = Math.max(2, Math.round(sqft / 1000));
    } else {
      // Absolute fallback is a duplex
      unit_count = 2;
    }
  }

  // Proper variable initialization to prevent "building_beds is not defined" crashes
  let building_sqft = sqft || 0;
  let unit_sqft = sqft || 0;
  let building_beds = beds || 0;
  let unit_beds = beds || 0;
  let building_baths = baths || 0;
  let unit_baths = baths || 0;

  if (is_multifamily && unit_count) {
    // 1. Decoupled Bed / Bath Logic 
    // If beds <= 3 on a multifamily property, it is almost certainly unit-level data
    const is_unit_level_rooms = (beds > 0 && beds <= 3);

    if (is_unit_level_rooms) {
      unit_beds = beds;
      building_beds = beds * unit_count;
      unit_baths = baths;
      building_baths = baths * unit_count;
    } else {
      building_beds = beds;
      unit_beds = beds > 0 ? Math.round(beds / unit_count) : 0;
      building_baths = baths;
      unit_baths = baths > 0 ? (baths / unit_count) : 0;
    }

    // 2. Decoupled Square Footage Logic
    // If sqft <= 1500 or it has a unit marker, it's typically unit-level data
    if (addressHasUnit || (sqft > 0 && sqft <= 1500)) {
      unit_sqft = sqft;
      building_sqft = sqft * unit_count;
    } else {
      building_sqft = sqft;
      unit_sqft = sqft > 0 ? Math.round(sqft / unit_count) : 0;
    }
  }

  // Rent AVM is unit-level for MF, value AVM is building-level for MF.
  const address_for_value_line = is_multifamily && addressHasUnit ? strippedAddress : rawAddress;
  const address_for_rent_line = rawAddress;

  // Confidence Flagging
  let address_scope_confidence = 'high';
  if (is_multifamily && addressHasUnit) address_scope_confidence = 'medium';
  if (is_multifamily && !unit_count) address_scope_confidence = 'medium';
  if (!rawAddress || !rawCity || !rawState || !rawZip) address_scope_confidence = 'low';

  // Package sale contamination flag
  let package_sale_flag = false;
  const ppsf = (lastSaleAmount > 0 && sqft > 0) ? lastSaleAmount / sqft : 0;

  if (
    is_multifamily &&
    lastSaleAmount > 0 &&
    (
      (assessedTotal > 0 && lastSaleAmount > assessedTotal * 2.5) ||
      ppsf > 450 ||
      lastSaleAmount >= 750000
    )
  ) {
    package_sale_flag = true;
  }

  // Build the final underwriting payload
  const finalResolved = {
    underwriting_mode: precall_mode ? 'precall' : 'postcall',
    is_multifamily,
    address_has_unit_marker: addressHasUnit,
    address_scope_confidence,
    package_sale_flag,

    raw_address: rawAddress,
    raw_city: rawCity,
    raw_state: rawState,
    raw_zip: rawZip,

    address_for_value: address_for_value_line,
    address_for_value_full: joinAddress(address_for_value_line, rawCity, rawState, rawZip),

    address_for_rent: address_for_rent_line,
    address_for_rent_full: joinAddress(address_for_rent_line, rawCity, rawState, rawZip),

    property_type_for_value: propertyType,
    property_type_for_rent: propertyType,

    unit_count,
    building_sqft,
    unit_sqft,

    building_beds: building_beds || null,
    building_baths: building_baths || null,
    unit_beds: unit_beds || null,
    unit_baths: unit_baths || null,

    loan_data,
    source_assumptions: {
      sqft_input: sqft || null,
      beds_input: beds || null,
      baths_input: baths || null,
      house_style: rawHouseStyle || null,
      property_type_input: propertyType || null,
      assessed_total_value: assessedTotal || null,
      last_sale_amount: lastSaleAmount || null
    }
  };

  // Replace the old 'resolved' object with the fully computed underwriting one
  opp.resolved = finalResolved;

  results.push({ json: opp });
}

return results;

