    // ------------------------------------------
    let estimatedRepairCost = parseMoney(firstNonEmpty(cd.repair_costs, cd.repairs, cd.EstimatedRepairs, null));
    if (estimatedRepairCost === 0 || estimatedRepairCost === null) {
        estimatedRepairCost = sqft > 0 ? sqft * 20 : 30000; // Flat $20/sqft otherwise $30K default 
    }

    // ------------------------------------------
    // Rent Metrics (Market Rent vs 1% Pro Forma)
    // ------------------------------------------
    let marketRent = grossRent;
    if (rentalNode.comparables && Array.isArray(rentalNode.comparables) && rentalNode.comparables.length > 0) {
        // Filter rental comps exactly as we filtered sales
        let validRents = rentalNode.comparables.filter(c => c.price > 0);
        validRents = validRents.filter(c => {
             if (c.distance > 2) return false;
             if (beds > 0 && Math.abs(c.bedrooms - beds) > 1) return false;
             if (baths > 0 && Math.abs(c.bathrooms - baths) > 1) return false;
             return true;
        });

        if (validRents.length > 0) {
            marketRent = Math.round(validRents.map(c => c.price).reduce((a,b) => a+b, 0) / validRents.length);
        }
    }
    const proFormaRent = Math.round(arv * 0.01); // 1% of ARV logic

    let yearBuilt = firstNonEmpty(propNode.yearBuilt, saleNode.yearBuilt, compsNode.subjectProperty?.yearBuilt, rentalNode.subjectProperty?.yearBuilt, cd.year_built_mls, cd['🚨MLS_Curr_YearBuilt'], null);
    if (typeof yearBuilt === 'string') { yearBuilt = parseInt(yearBuilt.replace(/[^\d]/g, ''), 10); }
    yearBuilt = (isNaN(yearBuilt) || yearBuilt < 1700 || yearBuilt > 2100) ? null : yearBuilt;

    const propType = String(res.property_type_for_value || 'single family').toLowerCase();
    const mlsDesc = String(firstNonEmpty(cd.mlsDescription, '')).trim();

    const isRVPark = /\b(rv park|mobile home park|campground|mhp|rv resort)\b/.test(propType) || /\b(rv park|mobile home park|campground)\b/i.test(mlsDesc);
    if (isRVPark && !warnings.includes("Detected RV/Mobile Home Park format")) {
        warnings.push("Detected RV/Mobile Home Park format. Operating expenses structured accordingly.");
    }

    const dom = Number(firstNonEmpty(saleNode.daysOnMarket, cd.dom, null));

    // ------------------------------------------
    // Taxes & Insurance
    // ------------------------------------------
    const HIGH_RISK_INS_STATES = new Set(['FL', 'TX', 'LA', 'OK', 'AL', 'MS', 'SC', 'NC', 'GA', 'CA']);
    const insuranceRate = HIGH_RISK_INS_STATES.has(state) ? 0.012 : 0.006;
    const defaultTaxRate = 0.0115;

    let rentcastTaxes = 0;
    try {
        const propData = propNode.taxAssessments ? propNode : (compsNode.subjectProperty || {});
        if (propData && propData.propertyTaxes) {
            rentcastTaxes = propData.propertyTaxes?.["2024"]?.total || propData.propertyTaxes?.["2023"]?.total || 0;
        }
    } catch (e) { }

    let taxes = parseMoney(cd['annual taxes']);
    if (!taxes || taxes === 0) {
        if (rentcastTaxes > 0) taxes = rentcastTaxes; 
        else if (mls_list_price) taxes = Math.round(mls_list_price * defaultTaxRate);
        else if (as_is_value) taxes = Math.round(as_is_value * defaultTaxRate);
        else if (arv) taxes = Math.round(arv * defaultTaxRate);
    }

    let insurance = parseMoney(cd.insuranceAnnual);
    if (!insurance && parseMoney(cd.insuranceMonthly)) insurance = Math.round(parseMoney(cd.insuranceMonthly) * 12);
    if (!insurance) {
        if (taxes > 0) insurance = Math.round(taxes * (HIGH_RISK_INS_STATES.has(state) ? 1.2 : 0.8));
        else insurance = Math.round((mls_list_price || as_is_value || arv || 100000) * insuranceRate);
    }

    const isSmallMulti = /(duplex|triplex|fourplex|quad|multi)/.test(propType);
    let mgmtRate = rental.assumptions?.mgmtRate ?? (isSmallMulti ? 0.09 : (isRVPark ? 0.12 : 0.08));
    let maintRate = rental.assumptions?.maintRate ?? (isSmallMulti ? 0.07 : (isRVPark ? 0.15 : 0.05));
    let vacancyRate = rental.assumptions?.vacancyRate ?? (isSmallMulti ? 0.07 : (isRVPark ? 0.10 : 0.05));
    if (yearBuilt && yearBuilt < 1980 && !isRVPark) maintRate += 0.02;

    const mgmt = Math.round(mgmtRate * annualRent);
    const maint = Math.round(maintRate * annualRent);
    const vacancy = Math.round(vacancyRate * annualRent);
    const utilitiesRate = rental.assumptions?.utilitiesIncluded ? 0.10 : (isRVPark ? 0.10 : 0);
    const utilities = Math.round(utilitiesRate * annualRent);

    const opex = mgmt + maint + vacancy + utilities + taxes + insurance;
