            ADS: null, DSCR: null, monthlyCF: null, annualCF: null, totalCashIn: null, CoC_pct: null
        }
    };

    results.push({
        json: { ...it, property, rental_estimates, existing_loan, metrics, config, canonical, padsplit_current_vs_target, warnings }
    });
}

