        if (ppsqfts.length > 2) {
            ppsqfts.sort((a, b) => a - b);
            const q1 = ppsqfts[Math.floor(ppsqfts.length * 0.25)];
            const q3 = ppsqfts[Math.floor(ppsqfts.length * 0.75)];
