const results = [];

// ==========================================
// 1. LOAD DATA
// ==========================================
const oppItems = $items("Fetch Opportunities");
const mappingItems = $input.all();
const mappingData = mappingItems.map(item => item.json);

if (!oppItems || oppItems.length === 0) {
  return [{ json: { info: "Could not find any data from the Fetch Opportunities node." } }];
}

// ==========================================
// 2. HELPERS
// ==========================================
function getCfVal(customFieldsArr, fieldId) {
  if (!fieldId || !Array.isArray(customFieldsArr)) return null;
  const match = customFieldsArr.find(f => f.id === fieldId);
  if (!match) return null;

  if (match.fieldValue !== undefined && match.fieldValue !== null) return match.fieldValue;
  if (match.fieldValueString !== undefined && match.fieldValueString !== null) return match.fieldValueString;
  if (match.fieldValueNumber !== undefined && match.fieldValueNumber !== null) return match.fieldValueNumber;
  return null;
}

function parseNum(val) {
  if (val === undefined || val === null || val === "") return null;
  const num = Number(String(val).replace(/[^0-9.-]+/g, ""));
  return Number.isFinite(num) ? num : null;
}

function parseMoney(val) {
  if (val === undefined || val === null || val === "") return null;
  const num = Number(String(val).replace(/[^0-9.-]+/g, ""));
  return Number.isFinite(num) ? num : null;
}

function cleanSpaces(s) {
  return String(s || "").replace(/\s+/g, " ").trim();
}

function normalizeZip(zip) {
  const s = cleanSpaces(zip);
  const m = s.match(/^(\d{5})(?:-\d{4})?$/);
  return m ? m[1] : s;
}

function parseStreetFromOpportunityName(name) {
  const s = cleanSpaces(name);
  if (!s.includes("-")) return "";
  return s.split("-").slice(1).join("-").trim();
}

function identifyPropertyType(propType, houseStyle, beds, baths) {
  const s = [String(propType), String(houseStyle)]
    .filter(Boolean)
    .join(' | ')
    .toLowerCase();

  // RentCast API Strict Multi-Family Splitting
  if (/(5\+|apartment)/.test(s)) {
    return { propType: "Apartment", isSFH: false };
  }
  if (/(multi|duplex|triplex|quad|fourplex|4-plex|plex|2-4)/.test(s)) {
    return { propType: "Multi-Family", isSFH: false };
  }

  // Condos and Townhomes
  if (/(condo|condominium)/.test(s)) {
    return { propType: "Condo", isSFH: false };
  }
  if (/(townhome|townhouse|attached)/.test(s)) {
    return { propType: "Townhouse", isSFH: false };
  }

  // Commercial / Land Edge cases
  if (/(commercial|industrial|office|retail)/.test(s)) {
    return { propType: "Commercial", isSFH: false };
  }
  if (/(manufactured|mobile|modular)/.test(s)) {
    return { propType: "Manufactured", isSFH: true }; // Commonly treated as SFR in APIs unless in a park
  }

  let actualBeds = parseNum(beds) || 0;
  let actualBaths = parseNum(baths) || 0;
  if (/(land|lot|vacant)/.test(s) || (actualBeds === 0 && actualBaths === 0 && (s === "" || s.includes("unimproved")))) {
    return { propType: "Land", isSFH: false };
  }

  // Fallback
  return { propType: "Single Family", isSFH: true }; 
}

// ==========================================
// 3. MAIN
// ==========================================
for (const item of oppItems) {
  const rootLocationId = item.json.locationId || (item.json.contact && item.json.contact.locationId);

