        if (jsVar && customFieldId) {
          CF[jsVar] = customFieldId;
        }
      }
    }

    const customFields = opp.customFields || [];

    const opportunityName = cleanSpaces(opp.name || "");
    const parsedStreetFromName = parseStreetFromOpportunityName(opportunityName);

    // STRICT opportunity-only address hierarchy
    let rawStreet = cleanSpaces(
      getCfVal(customFields, CF.oppStreetAddress) ||
      getCfVal(customFields, CF.opportunityAddress) ||
      parsedStreetFromName ||
      ""
    );

    // If opportunityAddress field is a full address blob, reduce to street line
    if (rawStreet.includes(",")) {
      rawStreet = rawStreet.split(",")[0].trim();
    }

    const rawCity = cleanSpaces(getCfVal(customFields, CF.city) || "");
    const rawState = cleanSpaces(getCfVal(customFields, CF.state) || "").toUpperCase();
    const rawZip = normalizeZip(getCfVal(customFields, CF.zip) || "");

    const rawPropType = cleanSpaces(getCfVal(customFields, CF.prop_type) || "");
    const rawHouseStyle = cleanSpaces(getCfVal(customFields, CF["opp.propertyStyle"]) || "");

    const beds = parseNum(getCfVal(customFields, CF.beds));
    const baths = parseNum(getCfVal(customFields, CF.baths));
    const sqft = parseNum(getCfVal(customFields, CF.squarefootage));

    const assessedTotal = parseMoney(
      getCfVal(customFields, CF["opp.assessedTotalValue"]) ??
      getCfVal(customFields, CF.assessedTotal)
    );

    const lastSaleAmount = parseMoney(
      getCfVal(customFields, CF["opp.lastSaleAmount"]) ??
      getCfVal(customFields, CF.lastSaleAmount)
    );

    const listPrice = parseMoney(getCfVal(customFields, CF["opp.listPrice"]));
    const estValue = parseMoney(getCfVal(customFields, CF["opp.estValue"]));
    const estEquity = parseMoney(getCfVal(customFields, CF["opp.estEquity"]));
    const units = parseNum(getCfVal(customFields, CF["opp.units"]));
    const lotArea = parseNum(getCfVal(customFields, CF["opp.lotArea"]));
    const yearBuilt = parseNum(getCfVal(customFields, CF.yearBuilt));
    const listStatus = cleanSpaces(getCfVal(customFields, CF["opp.listStatus"]) || "");
    const ownerOccupied = cleanSpaces(getCfVal(customFields, CF["opp.ownerOccupied"]) || "");
    const vacancy = cleanSpaces(getCfVal(customFields, CF["opp.vacancy"]) || "");
    const isOutreachProperty = cleanSpaces(getCfVal(customFields, CF["opp.is_outreach_property"]) || "");
    const highRentEst = cleanSpaces(getCfVal(customFields, CF["highRentEst"]) || "");
    const lowRentEst = cleanSpaces(getCfVal(customFields, CF["lowRentEst"]) || "");

    const consolidatedNotes = [
      getCfVal(customFields, CF.clsAdditionalNotes),
      getCfVal(customFields, CF.pqAdditionalNotes),
      getCfVal(customFields, CF.uwAdditionalNotes),
      getCfVal(customFields, CF.aiNotes),
      getCfVal(customFields, CF.mlsDescription)
    ].filter(Boolean).join(" | ");

    const loan_1_balance = parseMoney(getCfVal(customFields, CF["Loan 1 Balance"]));
    const loan_1_monthly_payment = parseMoney(getCfVal(customFields, CF["Loan 1 Monthly payment"]));
    const loan_1_rate = parseMoney(getCfVal(customFields, CF["Loan 1 rate"]));
    const loan_1_original_principal = parseMoney(getCfVal(customFields, CF["loan 1 original principal"]));
    const total_open_loans_amount = parseMoney(
      getCfVal(customFields, CF["opp.totalAmountOfOpenLoans"]) ??
      getCfVal(customFields, CF.open_loans)
    );
    const ltv_ratio = parseNum(getCfVal(customFields, CF.l_to_v_ratio));

    const isSFH = propertyType === "Single Family";

    const { propType: propertyType, isSFH } = identifyPropertyType(rawPropType, rawHouseStyle, beds, baths);

    let loan_status = "none";
    const debtSignalExists =
      loan_1_balance != null ||
      loan_1_monthly_payment != null ||
      loan_1_rate != null ||
      loan_1_original_principal != null ||
      total_open_loans_amount != null ||
      ltv_ratio != null;

    if (debtSignalExists) {
      if (loan_1_balance != null && loan_1_monthly_payment != null) {
        loan_status = "usable";
      } else {
        loan_status = "incomplete";
      }
    }

    results.push({
      json: {
        ...opp,
        resolved: {
          subject: cleanSpaces([rawStreet, rawCity, rawState, rawZip].filter(Boolean).join(", ")),
          addressRaw: rawStreet,
          city: rawCity,
          state: rawState,
          zip: rawZip,
          mode: propertyType,
          isSFH,
          beds,
          baths,
          sqft,
          assessedTotal,
          lastSaleAmount,
          listPrice,
          estValue,
          estEquity,
          units,
          lotArea,
          yearBuilt,
          listStatus,
          ownerOccupied,
          vacancy,
          isOutreachProperty,
          highRentEst,
          lowRentEst,
          notes: consolidatedNotes,
          opportunityName,
          parsedStreetFromOpportunityName: parsedStreetFromName,
          loan_data: {
            loan_1_balance,
            loan_1_monthly_payment,
            loan_1_rate,
            loan_1_original_principal,
            total_open_loans_amount,
            ltv_ratio,
            loan_status
          }
        }
      }
    });
  }
}

if (results.length === 0) {
  results.push({ json: { info: "No opportunities found within the Fetch Opportunities output." } });
}

return results;

