function safeNode(name, fallback = {}) {
  try {
    const v = $(name).first().json;
    return v ?? fallback;
  } catch {
    return fallback;
  }
}

function text(v, fallback = "") {
  if (v === undefined || v === null) return fallback;
  if (typeof v === "string") return v;
  try {
    return JSON.stringify(v);
  } catch {
    return String(v);
  }
}

function yesNo(v) {
  return v ? "true" : "false";
}

function moneyish(v) {
  if (v === undefined || v === null || v === "") return "";
  return String(v);
}

const validationNode = safeNode("Validation & Confidence Gate");
const stageNode = safeNode("Evaluation & Stage Router");
const normalizeNode = safeNode("Normalize Subject + Mode");
const dedupeNode = safeNode("Deduplicate Opportunities");
const webhookNode = safeNode("Start Webhook1");
const dealMathNode = safeNode("Deterministic Deal Math");
const transcriptNode = safeNode("Phone Transcript analyzer");

const validation = validationNode.validation || {};
const errors = Array.isArray(validation.errors) ? validation.errors : [];
const warnings = Array.isArray(validation.warnings) ? validation.warnings : [];
const checks = validation.checks || {};

const output = stageNode.output || stageNode || {};
const ds = output.deal_structure || {};
const primary = ds["Primary Offer"] || {};
const backup = ds["Backup Offer"] || {};
const cash = ds["Updated Cash Offer"] || {};

const resolved =
  normalizeNode.resolved ||
  dedupeNode.resolved ||
  {};

const webhookBody = webhookNode.body || {};
const customData = webhookBody.customData || webhookBody || {};

const edgeCase =
  resolved.address_for_value_full ||
  customData.opportunityAddress ||
  customData.address ||
  output.property?.address ||
  "unknown";

const contactId =
  webhookBody.contact_id ||
  webhookBody.contactId ||
  "";

const oppId =
  customData.opportunityId ||
  dedupeNode.id ||
  "";

const transcriptOutput = transcriptNode.output || "";
const sellerIntelPresent =
  !!transcriptOutput &&
  !/no transcript provided/i.test(text(transcriptOutput));

const row = {
  "Execution id": $execution.id,
  "Contact ID": contactId,
  "Opp Id": oppId,
  "Workflow Tested": $workflow.name,
  "Run Timestamp": $now,
  "Run Completed?": "true",
  "Validation Passed?": yesNo(errors.length === 0),
  "Publish Allowed?": yesNo(validation.can_publish === true),
  "Edge Case": edgeCase,
  "Webhook Data": text(customData),
  "Validator Errors / Warnings": JSON.stringify({
    errors,
    warnings
  }),
  "Underwriting Mode": resolved.underwriting_mode || "",
  "Seller Intel Present?": yesNo(sellerIntelPresent),

  "Prop_Type": resolved.property_type_for_value || output.property?.propertyType || "",
  "Beds (Building/Unit) Makeup": `${resolved.building_beds ?? ""}/${resolved.unit_beds ?? ""}`,
  "Baths (Building/Unit) Makeup": `${resolved.building_baths ?? ""}/${resolved.unit_baths ?? ""}`,
  "SQFT (Building/Unit) Makeup": `${resolved.building_sqft ?? ""}/${resolved.unit_sqft ?? ""}`,

  "ARV": moneyish(output.estimated_arv || output.metrics?.arv || checks.arv || ""),
  "As-Is Value": moneyish(output.metrics?.as_is_value || ""),
  "Cash Offer Amount": moneyish(cash["Final Cash Offer"] || checks.cash_offer_amount || ""),
  "Cash Offer Percent": moneyish(cash["Final Cash Offer % of ARV"] || checks.cash_offer_implied_pct || ""),

  "Primary Offer Type": primary["Type"] || checks.primary_type || checks.primary_offer_type || "",
  "Primary Purchase Price": moneyish(primary["Purchase Price"] || ""),
  "Primary Down Payment": moneyish(primary["Down Payment ($)"] || ""),
  "Primary Balloon": moneyish(primary["Balloon Term (Years)"] || ""),
  "Primary DSCR": moneyish(primary["DSCR"] || ""),
  "Primary Monthly CF": moneyish(primary["Monthly Cash-flow"] || ""),
  "Primary CoC": moneyish(primary["Cash-on-Cash Return"] || ""),

  "Backup Offer Type": backup["Type"] || checks.backup_type || checks.backup_offer_type || "",
  "Backup Purchase Price": moneyish(backup["Purchase Price"] || ""),
  "Backup Down Payment": moneyish(backup["Down Payment ($)"] || ""),
  "Backup Balloon": moneyish(backup["Balloon Term (Years)"] || ""),
  "Backup DSCR": moneyish(backup["DSCR"] || ""),
  "Backup Monthly CF": moneyish(backup["Monthly Cash-flow"] || ""),
  "Backup CoC": moneyish(backup["Cash-on-Cash Return"] || ""),

  "AI Lead Score": moneyish(output.lead_score || stageNode.output?.lead_score || ""),
  "Stage Evaluation Lead Score": moneyish(stageNode.leadScore || stageNode.lead_score || ""),
  "Recommended Stage": stageNode.recommendation?.nextPipelineStage || "",
  "Expected Outcome Met?": "",
  "Notes / What Looked Wrong": warnings.join(" | ")
};

return [{ json: row }];

