## // Validation & Confidence Gate — Sprint 1
// Purpose:
// 1) Catch contradictory numeric outputs before anything is published
// 2) Normalize obvious confidence / scope warnings into one place
// 3) Preserve transcriptless underwriting, but block clearly broken seller-facing output

function pNum(v) {
  const n = Number(String(v ?? '').replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : 0;
}
function pMoney(v) {
  return pNum(v);
}
function pPct(v) {
  return pNum(v);
}
function text(v) {
  return String(v ?? '').trim();
}

const finalData = $('Evaluation & Stage Router').first().json || {};
const output = finalData.output || finalData || {};
const metricsNode = $('Compute Metrics v2').first().json || {};
const metrics = metricsNode.metrics || output.metrics || {};
const property = output.property || metricsNode.property || {};
const dealMath = $('Deterministic Deal Math').first().json || {};
const ds = output.deal_structure || {};
const primary = ds['Primary Offer'] || {};
const backup = ds['Backup Offer'] || {};
const cash = ds['Updated Cash Offer'] || {};
const publicRecord = $('HTTP Request6').first().json || {};

const validation = {
  version: 'validator-s1.0',
  can_publish: true,
  errors: [],
  warnings: [],
  checks: {}
};

// ------------------------------
// Check 1: equity_pct convention
// ------------------------------
const equityPct = pNum(metrics.equity_pct);
validation.checks.equity_pct = equityPct;

if (!Number.isFinite(equityPct)) {
  validation.errors.push('equity_pct is missing or non-numeric.');
} else {
  if (equityPct < -100 || equityPct > 100) {
    validation.errors.push(`equity_pct out of range for percent convention: ${equityPct}`);
  }
  if (equityPct > 0 && equityPct < 1) {
    validation.warnings.push(`equity_pct looks fraction-scaled (${equityPct}). Expected percent convention 0-100.`);
  }
}

// -------------------------------------------
// Check 2: Updated Cash Offer amount vs percent
// -------------------------------------------
const cashAmt = pMoney(cash['Final Cash Offer'] ?? cash.finalCashOffer);
const cashPct = pPct(cash['Final Cash Offer % of ARV'] ?? cash.finalCashOfferPct);
const arv = pNum(metrics.arv || property.arv_value || output.arv_value || dealMath.output?.property?.arv_value);

validation.checks.cash_offer_amount = cashAmt;
validation.checks.cash_offer_pct = cashPct;
validation.checks.arv = arv;

if (cashAmt > 0 && cashPct > 0 && arv > 0) {
  const impliedPct = (cashAmt / arv) * 100;
  validation.checks.cash_offer_implied_pct = Number(impliedPct.toFixed(2));
  if (Math.abs(impliedPct - cashPct) > 1.0) {
    // FIX: Changed from errors to warnings so it no longer gates the opportunity
    validation.warnings.push(`Updated Cash Offer mismatch: amount implies ${impliedPct.toFixed(2)}% of ARV but field says ${cashPct.toFixed(2)}%.`);
  }
} else {
  validation.warnings.push('Updated Cash Offer could not be fully validated (missing amount, percent, or ARV).');
}

// ---------------------------------------------------
// Check 3: Primary / Backup structural completeness
// ---------------------------------------------------
function validateOffer(label, offer) {
  const offerType = text(offer['Type'] || offer.type);
  if (!offerType) {
    validation.warnings.push(`${label} offer has no Type.`);
    return;
  }

  const purchasePrice = pMoney(offer['Purchase Price'] || offer.purchasePrice);
  const down = pMoney(offer['Down Payment ($)'] || offer.downPayment);
  const rate = pNum(offer['Loan Rate (%)'] || offer['Interest Rate (%)'] || offer.interestRate);
  const payment = pMoney(offer['Monthly Payment (PI)'] || offer.monthlyPayment);
  const dscr = pNum(offer['DSCR'] || offer.dscr);

  validation.checks[`${label.toLowerCase()}_type`] = offerType;

  if (purchasePrice <= 0) {
    validation.errors.push(`${label} offer missing Purchase Price.`);
  }

  if (/Seller Finance|Hybrid|Subject-To/i.test(offerType)) {
    if (down < 0) {
      validation.errors.push(`${label} offer has invalid negative down payment.`);
    }
    if (/Seller Finance/i.test(offerType) && rate <= 0) {
      validation.errors.push(`${label} Seller Finance offer missing rate.`);
    }
    if (payment < 0) {
      validation.errors.push(`${label} offer has invalid monthly payment.`);
    }
    if (text(offer['DSCR'] || '').trim() && Number.isFinite(dscr) && dscr < 0) {
      validation.warnings.push(`${label} offer has negative DSCR.`);
    }
  }
}
validateOffer('Primary', primary);
validateOffer('Backup', backup);

// ---------------------------------------------------
// Check 4: obvious type/loan incompatibilities
// ---------------------------------------------------
const loanBal = pNum(metricsNode.existing_loan?.balance || output.existing_loan?.balance || 0);
const primaryType = text(primary['Type']);
if (loanBal <= 0 && /Subject-To|Hybrid/i.test(primaryType)) {
  validation.errors.push(`Primary offer type "${primaryType}" is incompatible with no existing loan.`);
}

// ---------------------------------------------------
// Check 5: obvious multifamily scope warning (lightweight)
// ---------------------------------------------------
const addr = text(property.address || metricsNode.property?.address || '');
const propType = text(metrics.propertyType || property.propertyType || '');
const sqft = pNum(metrics.sqft || property.sqft || 0);
const unitCount = pNum(publicRecord.features?.unitCount || publicRecord.subjectProperty?.features?.unitCount || 0);
const hasUnitSuffix = /(?:\bapt\b|\bunit\b|#)/i.test(addr);

if (/multi/i.test(propType) && hasUnitSuffix && (sqft > 1500 || unitCount > 1)) {
  // FIX: Changed from errors to warnings so it no longer gates the opportunity
  validation.warnings.push(`Multifamily subject-scope conflict suspected for address "${addr}". Unit-style address is paired with building-level characteristics.`);
}

// ---------------------------------------------------
// Check 6: transcriptless mode should warn, not block
// ---------------------------------------------------
const transcriptSummary = text(finalData.transcript?.output?.sellerUrgency || finalData.transcript_insights?.sellerUrgency || '');
if (!transcriptSummary || /No Transcript Provided/i.test(transcriptSummary)) {
  validation.warnings.push('No transcript provided. Underwriting may proceed, but seller-fit confidence is low.');
}

// --------------------------------
// Final publish decision
// --------------------------------
validation.can_publish = validation.errors.length === 0;

return [{
  json: {
    validation
  }
}];

##  /******************************************************
 ≡ƒº« RECOMPUTE NODE ΓÇö v2.9 "Pace-Mode" (Final)
 -----------------------------------------------------
 Purpose:
  - Merge upstream agent + pack data
  - Resolve rent (with strong fallback) and recompute NOI/metrics
  - Construct creative structures with investor + seller guardrails:
      ΓÇó Seller Financing (must clear payoff; option to cover seller fees)
      ΓÇó SubTo (no balloon; cash-to-seller strategy vs retail net)
      ΓÇó Hybrid = SubTo + Seller Carry (2nd) for equity
  - Enforce down/entry caps with CF-based wiggle room
  - Add Seller Interest Delta for Seller Finance
  - Compute Updated Cash Offer with bracket + list delta
  - Lead scoring (with no-transcript override) + pipeline stage (RESTORED)
  - LOI is seller-facing, no jargon, tailored to primary structure
******************************************************/

/***** ---------- [0] Helpers ---------- *****/
function parseNum(x) {
  if (x == null) return 0;
  if (typeof x === 'number') return Number.isFinite(x) ? x : 0;
  const n = parseFloat(String(x).replace(/[^\d.\-]/g, ''));
  return Number.isFinite(n) ? n : 0;
}
function pmt(rateAnnualPct, years, principal) {
  const r = (rateAnnualPct / 100) / 12;
  const n = years * 12;
  if (n <= 0 || principal <= 0) return 0;
  if (r === 0) return principal / n;
  return (r * principal) / (1 - Math.pow(1 + r, -n));
}
function safeParse(x) { try { return (typeof x === 'string') ? JSON.parse(x) : x; } catch { return null; } }
function money(n) { const v = Number.isFinite(n) ? n : 0; return `$${(Math.round(v * 100) / 100).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}`; }
function pct(v) { const n = parseNum(v); return `${n.toFixed(2)} %`; }
function cashPctForARV(arv) { if (arv < 150000) return 0.53; if (arv < 200000) return 0.56; if (arv < 300000) return 0.66; if (arv < 400000) return 0.71; if (arv < 500000) return 0.72; return 0.73; }
function median(arr){ const a=arr.slice().sort((x,y)=>x-y); const n=a.length; if(!n) return 0; const m=Math.floor(n/2); return n%2? a[m] : Math.round((a[m-1]+a[m])/2); }
function text(s){ return String(s || '').toLowerCase(); }
function hasSignal(s, rx){ return !!(s && rx.test(s)); }
function topBuyerScore(matches){ return Array.isArray(matches) && matches.length ? (parseNum(matches[0].score) || 0) : 0; }
const clamp = (v, min, max) => Math.min(max, Math.max(min, v));

/***** ---------- [0.1] Config Defaults (seller fees) ---------- *****/
// Buyer closing you already track via config.closingCostRate (often 8%)
const DEFAULT_AGENT_FEE_RATE     = 0.06;   // sellerΓÇÖs agent side + listing side (simplified)
const DEFAULT_SELLER_CLOSE_RATE  = 0.02;   // seller-side closing estimate
const DEFAULT_RET_CARRY_RATE     = 5.5;    // default seller-carry rate for hybrid trials
const DEFAULT_BANK_RATE          = 6.5;    // bank piece for hybrid (if used)

/***** ---------- [1] Merge Inputs ---------- *****/
try {
  const inputs = $input.all().map(i => i.json || {});
  const pack   = inputs.find(i => i.metrics || i.config || i.property || i.buyer_matches) || {};
  const agentH = inputs.find(i => Object.prototype.hasOwnProperty.call(i,'output')) || {};
  const agent  = safeParse(agentH.output) || agentH || {};

  // Bring context forward (prefer upstream when agent omitted)
  const M  = pack.metrics || {};
  const C  = pack.config  || {};
  const P  = pack.property || {};
  const T  = pack.transcript_insights || {};
  agent.transcript_insights = T || agent.transcript_insights || null;
  for (const k of ['property','rental_estimates','existing_loan']) if (pack[k]) agent[k] = pack[k];
  if (!agent.buyer_matches && Array.isArray(pack.buyer_matches)) {
    agent.buyer_matches = pack.buyer_matches;
    if (pack.buyer_match_summary) agent.buyer_match_summary = pack.buyer_match_summary;
  }
  if (pack.config)  agent.config  = pack.config;
  if (pack.metrics) agent.metrics = pack.metrics;

  /***** ---------- [2] ARV & Price Baseline ---------- *****/
  const comps = agent.comp_properties_report || pack.comp_properties_report || [];
  const compPrices = comps.map(c => parseNum(c.price)).filter(Boolean);
  const arvFromComps = median(compPrices);
  const arvAgent     = parseNum(agent.estimated_arv);
  const arvProp      = parseNum(P.est_value);
  const ARV          = arvAgent || arvProp || arvFromComps || 0;
  if (ARV) agent.estimated_arv = ARV;

  const priceFromPO  = parseNum(agent.deal_structure?.['Primary Offer']?.['Purchase Price']);
  const basePrice    = priceFromPO || parseNum(M.price) || parseNum(P.list_price) || (ARV || 0);
  const listPriceNum = parseNum(P.list_price) || parseNum(M.price) || basePrice;

  /***** ---------- [3] Rent Resolution & NOI Recompute ---------- *****/
  const R = agent.rental_estimates || {};
  // Resolve monthly rent (strong fallback cascade)
  const rentMonthly =
    (parseNum(M.grossRent) > 0 ? parseNum(M.grossRent) : 0) ||
    parseNum(R.from_webhook_monthly_income) ||
    parseNum(R.from_comp_pull_high) ||
    parseNum(R.from_deal_sauce_high) ||
    parseNum(R.from_comp_pull_low) ||
    parseNum(R.from_deal_sauce_low) || 0;

  // If upstream left annualRent alone, recompute from monthly
  const annualRent = rentMonthly * 12;

  // If opex components zeroed, reconstruct from config rates (mgmt/maint/vacancy) + explicit T&I
  const taxes      = parseNum(M.taxes);
  const insurance  = parseNum(M.insurance);
  const mgmtRate   = (C.mgmtRate != null) ? C.mgmtRate : 0.08;
  const maintRate  = (C.maintRate != null) ? C.maintRate : 0.05;
  const vacRate    = (C.vacancyRate != null) ? C.vacancyRate : 0.05;

  const mgmt   = (parseNum(M.mgmt)   || (annualRent * mgmtRate));
  const maint  = (parseNum(M.maint)  || (annualRent * maintRate));
  const vac    = (parseNum(M.vacancy)|| (annualRent * vacRate));
  const opex   = taxes + insurance + mgmt + maint + vac;

  const NOI    = Math.max(annualRent - opex, 0);
  const moTI   = (taxes + insurance) / 12;   // tracking info only

  /***** ---------- [4] Existing Loan Merge (safe) ---------- *****/
  const packLoan  = pack.existing_loan || {};
  const agentLoan = agent.existing_loan || {};
  const EL = {
    balance: parseNum(packLoan.balance || agentLoan.balance),
    payment: parseNum(packLoan.payment || agentLoan.payment),
    rate:    parseNum(packLoan.rate    || agentLoan.rate),
    source:  packLoan.source || agentLoan.source || "unknown"
  };

  /***** ---------- [5] Seller Profile & Rehab Heuristic (light-touch) ---------- *****/
  const Turg = text(T.sellerUrgency);
  const Thrd = text(T.sellerHardship);
  const Tcond= text(T.conditionOfProperty);
  // Seller state: aggressive if neutral/patient; standard if urgency/hardship; conservative if both strong
  const urgStrong  = hasSignal(Turg, /\b(asap|urgent|immediately|must\s*sell|quick\s*close|holding\s*costs)\b/);
  const hardStrong = hasSignal(Thrd, /\b(foreclos|pre[-\s]*foreclos|divorce|job\s*loss|medical|probate|relocat)\b/);
  let sellerState = 'aggressive';
  if (urgStrong || hardStrong) sellerState = 'standard';
  if (urgStrong && hardStrong) sellerState = 'conservative';

  // Rehab estimate (only if transcript hints at issues; else 0)
  let rehabEst = 0;
  if (hasSignal(Tcond, /\b(needs|deferred|roof|hvac|plumb|electric|foundation|major|repairs?)\b/)) rehabEst = Math.round(basePrice * 0.03);

  /***** ---------- [6] Fees & Caps ---------- *****/
  const BUYER_CLOSE_RATE    = (C.closingCostRate != null) ? C.closingCostRate : 0.08; // your existing assumption
  const AGENT_FEE_RATE      = (C.listAgentFeeRate != null) ? C.listAgentFeeRate : DEFAULT_AGENT_FEE_RATE;
  const SELLER_CLOSE_RATE   = (C.sellerClosingRate != null) ? C.sellerClosingRate : DEFAULT_SELLER_CLOSE_RATE;
  const SELLER_SIDE_RATE    = AGENT_FEE_RATE + SELLER_CLOSE_RATE;
  const ASSIGN_RATE         = (C.assignmentPctOfDown != null) ? C.assignmentPctOfDown : 0.25;

  // % caps: prefer Γëñ10% down & Γëñ15% total entry; allow up to 15% down / 20% entry if CF ΓëÑ $500
  const BASE_DP_CAP_PCT     = 10;
  const MAX_DP_CAP_PCT      = 15;
  const BASE_ENTRY_CAP_PCT  = 15;
  const MAX_ENTRY_CAP_PCT   = 20;

  /***** ---------- [7] Utility: cash-to-seller recommendation (SubTo/Hybrid) ---------- *****/
  function recommendCashToSeller(retailNet, state){
    // brackets as discussed
    const s = state || 'aggressive';
    let out = 0;
    if (retailNet <= -20000) {
      out = 0;
    } else if (retailNet <= 0) {
      out = (s==='aggressive') ? 4000 : (s==='standard' ? 1500 : 0);
    } else if (retailNet <= 5000) {
      out = (s==='aggressive') ? 7000 : (s==='standard' ? 2250 : 1500);
    } else if (retailNet <= 15000) {
      out = (s==='aggressive') ? 10000 : (s==='standard' ? 4000 : 2000);
    } else if (retailNet <= 30000) {
      out = (s==='aggressive') ? 15000 : (s==='standard' ? 7000 : 3000);
    } else {
      out = (s==='aggressive') ? 20000 : (s==='standard' ? 10000 : 5000);
    }
    return Math.max(0, Math.round(out));
  }

  /***** ---------- [8] Scoring function for candidate structures ---------- *****/
  function scoreCandidate(c){
    if (!c) return -1e12;
    const passBoost = (c.pass ? 1e6 : 0);
    return passBoost + (c.monthlyCF || -1e9) * 10 + (c.DSCR || 0) * 100 - (c.totalIn || 1e9);
  }

  /***** ---------- [9] Seller Finance Builder (must clear payoff) ---------- *****/
  function buildSellerFinanceCombos(price0){
    const results = [];
    const priceTrials = [price0, Math.round(price0 * 0.95), Math.round(price0 * 0.90)]; // two 5% reductions

    for (const price of priceTrials){
      const sellerFees = price * SELLER_SIDE_RATE;
      const buyerClosing = price * BUYER_CLOSE_RATE;

      for (const coverSellerFees of [true, false]) {
        // Required immediate cash to clear seller obligations
        const payoffNeeded = EL.balance || 0;
        const requiredCash = coverSellerFees ? payoffNeeded : Math.max(0, payoffNeeded + sellerFees);

        // Down % candidates: must be >= requiredCash/price; try 10/12.5/15
        const dpNeededPct = (price > 0) ? (requiredCash / price) * 100 : 1000;
        const dpChoices = [10, 12.5, 15].filter(p => p >= dpNeededPct && p <= 15);
        if (!dpChoices.length) continue; // price still too high to clear payoff under caps

        for (const downPct of dpChoices){
          const down$  = Math.round(price * downPct / 100);
          const prin   = Math.max(price - down$, 0);

          // Rate/Amort tries bounded by constraints (rate Γëñ 4%)
          for (const ratePct of [4.0, 3.5, 3.0]){
            for (const years of [40, 30]){
              const monthPI = Math.round(pmt(ratePct, years, prin));
              const ADS     = monthPI * 12;
              const DSCR    = Number((NOI / (ADS || 1)).toFixed(2));
              const annualCF= Math.round(NOI - ADS);
              const monthlyCF = Math.round(annualCF / 12);

              const assignment = Math.round(ASSIGN_RATE * down$);
              const sellerside = coverSellerFees ? Math.round(sellerFees) : 0;
              const totalIn    = Math.round(down$ + assignment + buyerClosing + sellerside);

              // Enforce caps dynamically (allow wiggle if CF ΓëÑ 500)
              const entryPct   = price ? (totalIn / price) * 100 : 1000;
              const dpCapOK    = (downPct <= BASE_DP_CAP_PCT) || (downPct <= MAX_DP_CAP_PCT && monthlyCF >= 500);
              const entryCapOK = (entryPct <= BASE_ENTRY_CAP_PCT) || (entryPct <= MAX_ENTRY_CAP_PCT && monthlyCF >= 500);

              // Seller Finance hard constraints
              const pass = (DSCR >= 1.20) && (monthlyCF >= 200) && (totalIn > 0) && dpCapOK && entryCapOK;

              results.push({
                type: 'Seller Financing',
                purchasePrice: price,
                down$: down$, downPct,
                ratePct, years, balloonYrs: 5,
                monthPI, ADS, DSCR, annualCF, monthlyCF, totalIn,
                coverSellerFees,
                sellerFeesPaid: sellerside,
                buyerClosing,
                payoffCleared: requiredCash,
                pass
              });
            }
          }
        }
      }
    }
    // pick best
    results.sort((a,b)=> scoreCandidate(b)-scoreCandidate(a));
    return results[0] || null;
  }

  /***** ---------- [10] SubTo Builder (no balloon) ---------- *****/
  function buildSubTo(price){
    const payoff = EL.balance || 0;
    const agentFees = price * AGENT_FEE_RATE;
    const sellerClose = price * SELLER_CLOSE_RATE;
    const sellerFees = agentFees + sellerClose;
    const buyerClosing = price * BUYER_CLOSE_RATE;

    // Retail-net estimate if seller were to go conventional
    const retailNet = Math.round(price - payoff - sellerFees - rehabEst);

    // Choose cash-to-seller per retailNet & sellerState (reversed tactic: aggressive for neutral/patient)
    let cashToSeller = recommendCashToSeller(retailNet, sellerState);

    // Two modes: cover seller fees or not ΓÇö whichever yields better economics under caps
    const modes = [true, false].map(coverSellerFees => {
      const firstPI = EL.payment || (EL.rate && payoff ? Math.round(pmt(EL.rate, 30, payoff)) : 0);
      const ADS     = (firstPI || 0) * 12;
      const DSCR    = ADS ? Number((NOI / ADS).toFixed(2)) : 0;
      const annualCF= Math.round(NOI - ADS);
      const monthlyCF = Math.round(annualCF / 12);

      // Entry budget caps (allow wiggle for CF ΓëÑ 500)
      const entryCap = (monthlyCF >= 500) ? MAX_ENTRY_CAP_PCT : BASE_ENTRY_CAP_PCT;
      const cap$     = Math.round(price * (entryCap / 100));

      // Total entry = down + assignment + buyerClosing + (optional seller fees we cover)
      const other$   = Math.round(buyerClosing + (coverSellerFees ? sellerFees : 0));
      const denom    = (1 + ASSIGN_RATE);
      const maxDown$ = Math.max(0, Math.round((cap$ - other$) / denom));

      // Clamp cash-to-seller within entry budget
      const down$    = Math.max(0, Math.min(cashToSeller, maxDown$));
      const downPct  = price ? Number(((down$ / price) * 100).toFixed(2)) : 0;

      const assignment = Math.round(ASSIGN_RATE * down$);
      const totalIn    = Math.round(down$ + assignment + other$);

      // SubTo constraints
      const rateReqOK = (payoff < 150000) ? (EL.rate <= 8.0 || !EL.rate) : (EL.rate <= 5.0 || !EL.rate);
      const dpCapOK   = (downPct <= BASE_DP_CAP_PCT) || (downPct <= MAX_DP_CAP_PCT && monthlyCF >= 500);
      const entryOK   = totalIn <= cap$;
      const cfOK      = monthlyCF >= 150;
      const pass      = rateReqOK && dpCapOK && entryOK && cfOK;

      return {
        type: 'SUBTO (Assume Existing Loan)',
        purchasePrice: price,
        down$: down$, downPct,
        ratePct: EL.rate || null, years: null, balloonYrs: null, // no balloon on SubTo
        monthPI: firstPI || 0, ADS, DSCR, annualCF, monthlyCF, totalIn,
        coverSellerFees, sellerFeesPaid: (coverSellerFees ? Math.round(sellerFees) : 0),
        buyerClosing, payoffCleared: payoff,
        cashToSellerInitial: cashToSeller,
        retailNet,
        pass
      };
    });

    modes.sort((a,b)=> scoreCandidate(b)-scoreCandidate(a));
    return modes[0] || null;
  }

  /***** ---------- [11] Hybrid Builder = SubTo + Seller Carry (2nd) ---------- *****/
  function buildHybrid(price){
    const payoff  = EL.balance || 0;
    const equity  = Math.max(price - payoff, 0);
    const firstPI = EL.payment || (EL.rate && payoff ? Math.round(pmt(EL.rate, 30, payoff)) : 0);

    const agentFees  = price * AGENT_FEE_RATE;
    const sellerClose= price * SELLER_CLOSE_RATE;
    const sellerFees = agentFees + sellerClose;
    const buyerClosing = price * BUYER_CLOSE_RATE;

    const retailNet = Math.round(price - payoff - sellerFees - rehabEst);
    let cashToSeller = recommendCashToSeller(retailNet, sellerState);
    cashToSeller = Math.min(cashToSeller, equity); // cannot exceed equity

    // Try with/without covering seller fees, and multiple carry rates/terms
    const results = [];
    for (const coverSellerFees of [true, false]) {
      const other$   = Math.round(buyerClosing + (coverSellerFees ? sellerFees : 0));
      const denom    = (1 + ASSIGN_RATE);

      // Start with requested cashToSeller; clamp to entry caps
      // We will iterate carry rate/years, but entry budget affects only the cashToSeller component.
      // Budget:
      const provisionalMonthPI = firstPI; // second PI unknown yet; weΓÇÖll score after
      const provisionalADS = (provisionalMonthPI || 0) * 12;
      const provisionalDSCR = provisionalADS ? Number((NOI / provisionalADS).toFixed(2)) : 0;
      const provisionalAnnualCF = Math.round(NOI - provisionalADS);
      const provisionalMonthlyCF = Math.round(provisionalAnnualCF / 12);

      const entryCapPct = (provisionalMonthlyCF >= 500) ? MAX_ENTRY_CAP_PCT : BASE_ENTRY_CAP_PCT;
      const cap$ = Math.round(price * (entryCapPct / 100));
      const maxDown$ = Math.max(0, Math.round((cap$ - other$) / denom));
      const down$ = Math.max(0, Math.min(cashToSeller, maxDown$));
      const downPct = price ? Number(((down$ / price) * 100).toFixed(2)) : 0;
      const assignment = Math.round(ASSIGN_RATE * down$);

      // Seller carry principal = remaining equity
      const carryPrin = Math.max(equity - down$, 0);

      for (const ratePct of [4.5, 4.0, 3.5, 3.0]) {
        for (const years of [40, 30]) {
          const carryPI = (carryPrin > 0) ? Math.round(pmt(ratePct, years, carryPrin)) : 0;
          const monthPI = (firstPI || 0) + carryPI;
          const ADS     = monthPI * 12;
          const DSCR    = ADS ? Number((NOI / ADS).toFixed(2)) : 0;
          const annualCF= Math.round(NOI - ADS);
          const monthlyCF= Math.round(annualCF / 12);

          const totalIn  = Math.round(down$ + assignment + other$);

          const entryPct = price ? (totalIn / price) * 100 : 1000;
          const dpCapOK  = (downPct <= BASE_DP_CAP_PCT) || (downPct <= MAX_DP_CAP_PCT && monthlyCF >= 500);
          const entryOK  = (entryPct <= BASE_ENTRY_CAP_PCT) || (entryPct <= MAX_ENTRY_CAP_PCT && monthlyCF >= 500);

          // Hybrid thresholds
          const pass = (DSCR >= 1.20) && (monthlyCF >= 200) && (entryOK) && (dpCapOK);

          results.push({
            type: 'Hybrid (SubTo + Seller Carry 2nd)',
            purchasePrice: price,
            down$: down$, downPct,
            ratePct: null, years: null, balloonYrs: 7, // balloon on 2nd, not on first
            carryRatePct: (carryPrin>0?ratePct:null),
            carryYears: (carryPrin>0?years:null),
            firstRatePct: EL.rate || null,
            firstBalance: payoff,
            firstPI: firstPI || 0,
            carryPrin,
            monthPI, ADS, DSCR, annualCF, monthlyCF, totalIn,
            coverSellerFees, sellerFeesPaid: (coverSellerFees ? Math.round(sellerFees) : 0),
            buyerClosing, payoffCleared: payoff,
            cashToSellerInitial: cashToSeller,
            retailNet,
            pass
          });
        }
      }
    }
    results.sort((a,b)=> scoreCandidate(b)-scoreCandidate(a));
    return results[0] || null;
  }

  /***** ---------- [12] Build Candidates Based on Equity Routing ---------- *****/
  const equityPct = (ARV > 0) ? ((ARV - (EL.balance || 0)) / ARV) * 100 : 100;
  let sfCandidate   = null;
