  }
  const cashPct  = cashPctForARV(ARV || basePrice);
  const cashCap  = (ARV ? Math.round(ARV * cashPct) : Math.round(basePrice * (cashPct || 0.66))) || 0;
  const delta    = listPriceNum ? (listPriceNum - cashCap) : null;
