  const bracketStr = ARV ? `Bracket ${cashBracketLabel(ARV)}.` : `Cash per table.`;
  const capStr     = `Max cash = ${money(cashCap)}.`;
  const listStr    = listPriceNum ? `List ${money(listPriceNum)} is ${aboveStr} the cap.` : ``;
  const tailStr    = (delta!=null && delta > 0) ? ` Recommend **Wholesale / Move on from this one** or negotiate down.` : ` Within cap.`;

  /***** ---------- [15] Compose deal_structure (authoritative) ---------- *****/
  agent.deal_structure = agent.deal_structure || {};

  // Primary ΓÇö if null, show wholesale immediately
  if (!primary) {
    agent.deal_structure['Primary Offer'] = wholesaleBackup;
  } else {
    const isSF = primary.type === 'Seller Financing';
    const interestDelta = isSF ? sellerInterestDeltaForSF(primary) : 0;

    agent.deal_structure['Primary Offer'] = {
      'Type': primary.type,
