  invStrings.push(`DSCR: ${DSCR_primary!=null ? DSCR_primary.toFixed(2) : 'n/a'} ${DSCR_primary!=null ? (DSCR_primary>=1.20?'Γ£à (meets 1.20 minimum)':'Γ¥î (below 1.20 minimum)') : ''}`);
  invStrings.push(`Monthly Cash-flow: ${money(monthlyCF_primary)}`);
  invStrings.push(`Annual Cash-flow: ${money(annualCF_primary)}`);
