  /***** ---------- [18] Lead Scoring (with no-transcript override) ---------- *****/
  const noTranscript = ['no transcript','not provided','unable to determine'].some(s => text(T.sellerUrgency).includes(s) || text(T.sellerHardship).includes(s) || text(T.conditionOfProperty).includes(s) || text(T.price).includes(s));
  const topFit = topBuyerScore(agent.buyer_matches);

  // Market-only scoring mode if no transcript (per Enhancement v4.3)
  if (noTranscript) {
    // Economics subscore (0ΓÇô40): DSCR (0/8/15), CF (0/5/10 for ΓëÑ$200), CoC (0/5/10)
    let dscrPts = 0;
    if (DSCR_primary >= 1.50) dscrPts = 15;
    else if (DSCR_primary >= 1.30) dscrPts = 12;
    else if (DSCR_primary >= 1.20) dscrPts = 10;
    else if (DSCR_primary >= 1.10) dscrPts = 6;
    else if (DSCR_primary >= 1.00) dscrPts = 3;

