        seller_carry_amort_years: candidate.sellerCarryAmortYears ?? null,
        seller_carry_balloon_years: candidate.sellerCarryBalloonYears ?? null,
        seller_carry_monthly_pi: moneyOrNull(candidate.sellerCarryMonthlyPI, 2),
        combined_monthly_pi: moneyOrNull(candidate.combinedMonthlyPI, 2),
        funded_amount: moneyOrNull(candidate.fundedAmount),
        purchase_gap: moneyOrNull(candidate.purchaseGap),
        total_entry_fee: moneyOrNull(candidate.totalIn),
        'Purchase Price': money(candidate.purchasePrice),
        'Cash to Seller': money(candidate.cashToSeller || 0),
        'Requested Price': money(candidate.requestedPrice || candidate.purchasePrice),
        'Target DSCR': candidate.targetDSCR ? String(candidate.targetDSCR) : '1.27',
        'DSCR-Adjusted Price': money(candidate.dscrAdjustedPrice || candidate.purchasePrice),
        'Price Adjusted for DSCR': !!candidate.priceAdjustedForDSCR,
        'Down Payment ($)': candidate.downPayment != null ? money(candidate.downPayment) : 'N/A',
        'Down Payment (%)': candidate.downPaymentPct != null ? pct(candidate.downPaymentPct, 1) : 'N/A',
        'CTS ($)': candidate.cts != null ? money(candidate.cts) : 'N/A',
        'CTS (%)': candidate.ctsPct != null ? pct(candidate.ctsPct, 1) : 'N/A',
        'Interest Rate (%)': candidate.sellerCarryRate != null ? String(candidate.sellerCarryRate) : (candidate.existingLoanRate != null ? String(candidate.existingLoanRate) : 'N/A'),
        'Amortization (Years)': candidate.sellerCarryAmortYears || null,
        'Balloon Term (Years)': candidate.sellerCarryBalloonYears || null,
        'Monthly Payment (PI)': money(candidate.combinedMonthlyPI || 0, 2),
        'Monthly Taxes and Insurance (TI)': money(econ.tiMonthly, 2),
        ADS: money(candidate.ADS || 0),
        DSCR: round(usePadsplit ? candidate.padsplitDSCR : candidate.DSCR, 2).toFixed(2),
        'Monthly Cash-flow': money(usePadsplit ? candidate.padsplitMonthlyCF : candidate.monthlyCF),
        'Annual Cash-flow': money(usePadsplit ? candidate.padsplitAnnualCF : candidate.annualCF),
        'Break-even Rent': money(breakEvenRent || 0, 2),
        'Rent Gap to Break-even': money(rentGap || 0, 2),
        'Cash-on-Cash Return': pct(usePadsplit ? candidate.padsplitCoC : candidate.coc, 1),
        'Funded Amount': money(candidate.fundedAmount || 0),
        'Purchase Gap': money(candidate.purchaseGap || 0),
        'Total Entry Fee': money(candidate.totalIn || 0),
        'Years to Recapture Cash In': candidate.paybackYears != null ? String(candidate.paybackYears) : 'N/A',
        'Cash Flow Profile': candidate.cashFlowProfile || 'N/A',
        'Instant Equity (%)': pct(candidate.instantEquityPct || 0, 1),
        'ARV Spread (%)': pct(candidate.arvSpreadPct || 0, 1),
        'Padsplit Upside (%)': pct(candidate.padsplitUpsidePct || 0, 1),
        'Deal Viable': !!candidate.pass,
        'Forced Fallback': !!candidate.forcedFallback,
        Justification: candidate.pass
            ? `Selected structure passed current ${mandate} mandate.`
            : candidate.forcedFallback
                ? 'Educational fallback only. Not seller-facing under current policy.'
                : `Best available structure, but not fully compliant with current ${mandate} mandate.`
    };
}

const items = $input.all();
