            policy.families = { ...policy.families, ...policyOverride.families };
            if (policyOverride.families.subto) policy.families.subto = { ...defaultPolicy.families.subto, ...policyOverride.families.subto };
            if (policyOverride.families.hybrid) policy.families.hybrid = { ...defaultPolicy.families.hybrid, ...policyOverride.families.hybrid };
            if (policyOverride.families.seller_finance) policy.families.seller_finance = { ...defaultPolicy.families.seller_finance, ...policyOverride.families.seller_finance };
        }

        if (policyOverride.mandates) {
