            const selectedMandate = profile.mandate || 'cashflow';
            const selected = evaluated.mandate_results[selectedMandate] || {
                pass: false,
                hard_fail_reasons: [],
                soft_fail_reasons: []
            };

            const fatalSoftFails = (selected.soft_fail_reasons || []).filter(r => r !== 'COC_BELOW_TARGET_BUT_DSCR_PASS');

            const combinedHardFails = [
                ...(evaluated.hard_fail_reasons || []),
                ...(selected.hard_fail_reasons || [])
            ];

            const combinedSoftFails = [
                ...(evaluated.soft_fail_reasons || []),
                ...(selected.soft_fail_reasons || [])
            ];

            return {
                ...evaluated,
                hard_fail_reasons: [...new Set(combinedHardFails)],
                soft_fail_reasons: [...new Set(combinedSoftFails)],
                pass: [...new Set(combinedHardFails)].length === 0 && fatalSoftFails.length === 0 && !!selected.pass
            };
