            root.output?.comps_summary ||
            '';

        const locationContext =
            root.location_context ||
            root.output?.location_context ||
            {};

        const marketData =
            root.market_data_trends ||
            root.output?.market_data_trends ||
            root.market_data_extracted ||
            {};

        const webhookCustomData =
            root.webhook_custom_data ||
            root.customData ||
            root.body?.customData ||
            root.body ||
            {};

        const warnings = Array.isArray(root.warnings) ? root.warnings : [];

        const result = {
            engine_status: engineStatus,
            estimated_arv: input.property.arv,
            comp_properties_report: compProperties,
            comps_summary: compsSummary,

            investors_analysis: investorsAnalysis,
            investors_analysis_insights: primary
                ? `${primary.type} is the current best path under ${profile.name}/${profile.mandate} underwriting. ` +
                `Viable for: ${(primary.viable_for || []).join(', ') || 'none'}. ` +
                `Quality tier is ${primaryQuality}.`
                : 'No structure could be built from current inputs.',

            deal_structure: dealStructure,
            cash_offer: cash.cash_offer,
            mao: cash.mao,
            wholesale_fee: cash.wholesaleFee,
            repair_estimate: cash.repairEstimate,
            cts_engine: cts,
            assignment_fee_range: assignmentFeeRange,

            property: input.property_raw,
            metrics: normalizedMetrics,
            config: passThroughConfig,
            existing_loan: normalizedLoan,
            canonical,

            normalized_subject: input.normalized_subject,
            transcript: input.transcript,
            output_transcript_raw: root.output || {},
            location_context: locationContext,
            market_data_trends: marketData,
            webhook_custom_data: webhookCustomData,

            buyer_matches: buyerMatches,
            buyer_match_summary: buyerMatchSummary,
            warnings,

            mandate_diagnostics: mandateDiagnostics,
            decision,
            offer_engine_debug: policy.output.include_debug ? offerEngineDebug : undefined
        };

        result.output = {
            ...result,
            output: undefined
        };
        delete result.output.output;

        if (!policy.output.include_debug) {
            delete result.offer_engine_debug;
            delete result.output.offer_engine_debug;
        }

        if (!policy.output.include_all_candidates && result.offer_engine_debug) {
            delete result.offer_engine_debug.top_candidates;
            delete result.output.offer_engine_debug.top_candidates;
        }

        results.push({ json: result });
    } catch (e) {
        results.push({
            json: {
                engine_status: {
                    version: ENGINE_VERSION,
                    status: 'error'
                },
                _error: e?.message || String(e),
                _stack: e?.stack || null,
                _input: item.json || {}
            }
        });
    }
}

return results;

