## // ==========================================
// COMPUTE METRICS v9 (Resolved + Loop Edition)
// ==========================================

function parseMoney(x) {
    if (x === undefined || x === null) return 0;
    if (typeof x === 'number') return x;
    const s = String(x).replace(/[^\d.\-]/g, '');
    const n = parseFloat(s);
    return isNaN(n) ? 0 : n;
}

function firstNonEmpty(...vals) {
    for (const v of vals) {
        if (v === 0) return 0;
        if (v == null) continue;
        if (typeof v === 'string' && v.trim() !== '') return v;
        if (typeof v === 'number') return v;
    }
    return null;
}

const items = $input.all();
const results = [];

// 🚨 BULLETPROOF RESOLVED EXTRACTION (Runs once to grab global context safely)
const res = (() => {
    try { const r = $('Normalize Subject + Mode').first().json; if (r && r.resolved) return r.resolved; } catch {}
    try { const r = $('Deduplicate Opportunities').first().json; if (r && r.resolved) return r.resolved; } catch {}
    return items[0].json.resolved || {};
})();

const webhook = (() => { try { return $('Start Webhook1').first().json || {}; } catch { return {}; } })();
const cd = (webhook.body && Object.keys(webhook.body).length > 0) ? (webhook.body.customData || webhook.body) : {};
const rentalNode = (() => { try { return $('Fetch rental comps').first().json || {}; } catch { return {}; } })();
const saleNode = (() => { try { return $('Fetch Sale Data').first().json || {}; } catch { return {}; } })();
const compsNode = (() => { try { return $('Fetch Comps API').first().json || {}; } catch { return {}; } })();
const propNode = (() => { try { return $('HTTP Request6').first().json || {}; } catch { return {}; } })(); 

for (const item of items) {
    const it = item.json;

    const rentalModels = it.rental_models || {};
    const canonicalKey = it.canonical_rental_model || 'standard';
    const rental = rentalModels[canonicalKey];

    if (!rental || rental.grossRentMonthly == null) {
        throw new Error('Compute Metrics: Missing canonical rental model or rent');
    }

    const grossRent = Number(rental.grossRentMonthly);
    const annualRent = grossRent * 12;
    const warnings = [];

    // ------------------------------------------
    // LIST PRICE & TAXES
    // ------------------------------------------
    // Only map list price if it is explicitly provided on the original lead data
    const mls_list_price = parseMoney(firstNonEmpty(
        saleNode.price, res.list_price, cd.list_price, cd.ListPrice, 0
    ));

    let taxAssessedValue = res.source_assumptions?.assessed_total_value || 0;
    if (!taxAssessedValue) {
        try {
            const propData = propNode.taxAssessments ? propNode : (compsNode.subjectProperty || {});
            if (propData && propData.taxAssessments) {
                taxAssessedValue = propData.taxAssessments?.["2026"]?.value || propData.taxAssessments?.["2025"]?.value || propData.taxAssessments?.["2024"]?.value || 0;
            }
        } catch (e) { }
    }

    // ------------------------------------------
    // AS-IS & ARV
    // ------------------------------------------
    let as_is_value = parseMoney(firstNonEmpty(
        cd.estValue, saleNode.estValue, saleNode.est_value, taxAssessedValue, compsNode.priceRangeLow, 0
    ));

    let arv = 0;
    const beds = Number(res.building_beds || res.unit_beds || res.source_assumptions?.beds_input || 0);
    const baths = Number(res.building_baths || res.unit_baths || res.source_assumptions?.baths_input || 0);
    const sqft = Number(res.building_sqft || res.unit_sqft || res.source_assumptions?.sqft_input || 0);

    if (compsNode.comparables && Array.isArray(compsNode.comparables) && compsNode.comparables.length > 0) {
        // Evaluate based on Price-Per-SqFt (PPSQFT)
        let validComps = compsNode.comparables.filter(c => c.price > 0 && c.squareFootage > 0);

        // Basic filtering to match subject properties
        validComps = validComps.filter(c => {
             if (c.distance > 2) return false;
             if (beds > 0 && Math.abs(c.bedrooms - beds) > 1) return false;
             if (baths > 0 && Math.abs(c.bathrooms - baths) > 1) return false;
             if (sqft > 0 && c.squareFootage > 0) {
                 const ratio = c.squareFootage / sqft;
                 if (ratio < 0.75 || ratio > 1.25) return false;
             }
             return true;
        });

        let ppsqfts = validComps.map(c => c.price / c.squareFootage);
        if (ppsqfts.length > 2) {
            ppsqfts.sort((a, b) => a - b);
            const q1 = ppsqfts[Math.floor(ppsqfts.length * 0.25)];
            const q3 = ppsqfts[Math.floor(ppsqfts.length * 0.75)];
            const lowerBound = Math.max(0, q1 - (1.5 * (q3 - q1)));
            const upperBound = q3 + (1.5 * (q3 - q1));
            const filtered = ppsqfts.filter(p => p >= lowerBound && p <= upperBound);
            let avgPpsqft = filtered.length > 0 
               ? filtered.reduce((a, b) => a + b, 0) / filtered.length
               : ppsqfts[Math.floor(ppsqfts.length / 2)];
            arv = Math.round(avgPpsqft * (sqft > 0 ? sqft : compsNode.subjectProperty?.squareFootage || 1500));
        } else if (ppsqfts.length > 0) {
            let avgPpsqft = ppsqfts.reduce((a, b) => a + b, 0) / ppsqfts.length;
            arv = Math.round(avgPpsqft * (sqft > 0 ? sqft : compsNode.subjectProperty?.squareFootage || 1500));
        }
    }

    if (!arv || arv === 0) { arv = parseMoney(firstNonEmpty(compsNode.price, 0)); }
    if (arv === 0) {
        if (as_is_value && as_is_value > 0) arv = Math.round(as_is_value * 1.3);
        else if (taxAssessedValue && taxAssessedValue > 0) arv = Math.round(taxAssessedValue * 1.15);
        else if (mls_list_price && mls_list_price > 0) arv = Math.round(mls_list_price * 1.15);
        else arv = Math.max(mls_list_price, as_is_value, 10000);
        warnings.push("ARV missing from API. Derived from As-Is/List/Tax fallbacks.");
    }

    if (taxAssessedValue > 0 && arv < taxAssessedValue) {
        warnings.push(`Warning: Calculated ARV ($${arv.toLocaleString()}) was less than County Tax Assessed Value ($${taxAssessedValue.toLocaleString()}). ARV boosted.`);
        arv = taxAssessedValue;
    }

    const comp_low = parseMoney(compsNode.priceRangeLow);
    const comp_high = parseMoney(compsNode.priceRangeHigh);

    // ------------------------------------------
    // Custom Rehab Estimator ($20/sqft default)
    // ------------------------------------------
    let estimatedRepairCost = parseMoney(firstNonEmpty(cd.repair_costs, cd.repairs, cd.EstimatedRepairs, null));
    if (estimatedRepairCost === 0 || estimatedRepairCost === null) {
        estimatedRepairCost = sqft > 0 ? sqft * 20 : 30000; // Flat $20/sqft otherwise $30K default 
    }

    // ------------------------------------------
    // Rent Metrics (Market Rent vs 1% Pro Forma)
    // ------------------------------------------
    let marketRent = res.extracted_rent_roll || res.extractedRentRoll || grossRent;
    if (!res.extracted_rent_roll && rentalNode.comparables && Array.isArray(rentalNode.comparables) && rentalNode.comparables.length > 0) {
        // Only run Rental API Comp scaling if the transcript didn't explicitly give us the rent
        let validRents = rentalNode.comparables.filter(c => c.price > 0);
        validRents = validRents.filter(c => {
             if (c.distance > 2) return false;
             if (beds > 0 && Math.abs(c.bedrooms - beds) > 1) return false;
             if (baths > 0 && Math.abs(c.bathrooms - baths) > 1) return false;
             return true;
        });

        if (validRents.length > 0) {
            marketRent = Math.round(validRents.map(c => c.price).reduce((a,b) => a+b, 0) / validRents.length);
        }

        // Multi-family auto-scalar for rental API data (APIs return per-unit rates)
        const unit_count = Number(res.unit_count || 0);
        const pType = String(res.property_type_for_value || 'single family').toLowerCase();
        const is_multi = /(apartment|duplex|triplex|fourplex|quad|multi)/.test(pType);

        if (is_multi && unit_count > 0 && marketRent < 2500) {
             marketRent = marketRent * unit_count;
        }
    }
    const proFormaRent = Math.round(arv * 0.01); // 1% of ARV logic

    // ------------------------------------------
    // Property characteristics
    // ------------------------------------------
    const address = String(res.raw_address || '').trim();
    const city = String(res.raw_city || '').trim();
    const state = String(res.raw_state || '').trim().toUpperCase();
    const postal = String(res.raw_zip || '').trim();


    let yearBuilt = firstNonEmpty(propNode.yearBuilt, saleNode.yearBuilt, compsNode.subjectProperty?.yearBuilt, rentalNode.subjectProperty?.yearBuilt, cd.year_built_mls, cd['🚨MLS_Curr_YearBuilt'], null);
    if (typeof yearBuilt === 'string') { yearBuilt = parseInt(yearBuilt.replace(/[^\d]/g, ''), 10); }
    yearBuilt = (isNaN(yearBuilt) || yearBuilt < 1700 || yearBuilt > 2100) ? null : yearBuilt;

    const propType = String(res.property_type_for_value || 'single family').toLowerCase();
    const mlsDesc = String(firstNonEmpty(cd.mlsDescription, '')).trim();

    const isRVPark = /\b(rv park|mobile home park|campground|mhp|rv resort)\b/.test(propType) || /\b(rv park|mobile home park|campground)\b/i.test(mlsDesc);
    if (isRVPark && !warnings.includes("Detected RV/Mobile Home Park format")) {
        warnings.push("Detected RV/Mobile Home Park format. Operating expenses structured accordingly.");
    }

    const dom = Number(firstNonEmpty(saleNode.daysOnMarket, cd.dom, null));

    // ------------------------------------------
    // Taxes & Insurance
    // ------------------------------------------
    const HIGH_RISK_INS_STATES = new Set(['FL', 'TX', 'LA', 'OK', 'AL', 'MS', 'SC', 'NC', 'GA', 'CA']);
    const insuranceRate = HIGH_RISK_INS_STATES.has(state) ? 0.012 : 0.006;
    const defaultTaxRate = 0.0115;

    let rentcastTaxes = 0;
    try {
        const propData = propNode.taxAssessments ? propNode : (compsNode.subjectProperty || {});
        if (propData && propData.propertyTaxes) {
            rentcastTaxes = propData.propertyTaxes?.["2026"]?.total || propData.propertyTaxes?.["2025"]?.total || propData.propertyTaxes?.["2024"]?.total || propData.propertyTaxes?.["2023"]?.total || 0;
        }
    } catch (e) { }

    let taxes = parseMoney(cd['annual taxes']);
    if (!taxes || taxes === 0) {
        if (rentcastTaxes > 0) taxes = rentcastTaxes; 
        else if (mls_list_price) taxes = Math.round(mls_list_price * defaultTaxRate);
        else if (as_is_value) taxes = Math.round(as_is_value * defaultTaxRate);
        else if (arv) taxes = Math.round(arv * defaultTaxRate);
    }

    let insurance = parseMoney(cd.insuranceAnnual);
    if (!insurance && parseMoney(cd.insuranceMonthly)) insurance = Math.round(parseMoney(cd.insuranceMonthly) * 12);
    if (!insurance) {
        if (taxes > 0) insurance = Math.round(taxes * (HIGH_RISK_INS_STATES.has(state) ? 1.2 : 0.8));
        else insurance = Math.round((mls_list_price || as_is_value || arv || 100000) * insuranceRate);
    }

    const isSmallMulti = /(duplex|triplex|fourplex|quad|multi)/.test(propType);
    let mgmtRate = rental.assumptions?.mgmtRate ?? (isSmallMulti ? 0.09 : (isRVPark ? 0.12 : 0.08));
    let maintRate = rental.assumptions?.maintRate ?? (isSmallMulti ? 0.07 : (isRVPark ? 0.15 : 0.05));
    let vacancyRate = rental.assumptions?.vacancyRate ?? (isSmallMulti ? 0.07 : (isRVPark ? 0.10 : 0.05));
    if (yearBuilt && yearBuilt < 1980 && !isRVPark) maintRate += 0.02;

    const mgmt = Math.round(mgmtRate * annualRent);
    const maint = Math.round(maintRate * annualRent);
    const vacancy = Math.round(vacancyRate * annualRent);
    const utilitiesRate = rental.assumptions?.utilitiesIncluded ? 0.10 : (isRVPark ? 0.10 : 0);
    const utilities = Math.round(utilitiesRate * annualRent);

    const opex = mgmt + maint + vacancy + utilities + taxes + insurance;
    const noi = annualRent - opex;
    const tiMonthly = (taxes + insurance) / 12;

    // ---- Existing Loan  ----
    const loanData = res.loan_data || {};
    const loanBalance = parseMoney(loanData.loan_1_balance || loanData.total_open_loans_amount);
    const loanRate = parseMoney(loanData.loan_1_rate);
    let sellerMonthlyPaymentPI = parseMoney(loanData.loan_1_monthly_payment); 
    const originalPrincipal = parseMoney(cd['loan 1 original principal']); 

    // Calculate missing P&I payment using standard 30-year amortization if rate and balance exist
    if (loanBalance > 0 && sellerMonthlyPaymentPI === 0 && loanRate > 0) {
        const r = (loanRate / 100) / 12;
        const n = 360; // Standard 30 yr default
        sellerMonthlyPaymentPI = loanBalance * ( (r * Math.pow(1+r, n)) / (Math.pow(1+r, n) - 1) );
    }

    let rawLtv = parseMoney(cd.l_to_v_ratio);   
    let ltv = null;
    if (rawLtv) ltv = rawLtv > 1 ? rawLtv / 100 : rawLtv;
    if (ltv && ltv > 1.25) ltv = 1.25;

    let equity_pct = null;
    if (ltv !== null) equity_pct = (1 - ltv) * 100;
    else if (as_is_value && loanBalance > 0) equity_pct = ((as_is_value - loanBalance) / as_is_value) * 100;
    if (equity_pct !== null) equity_pct = Math.max(-100, Math.min(100, equity_pct));

    // ------------------------------------------
    // Build outputs
    // ------------------------------------------
    const property = {
        address, city, state, postal_code: postal,
        list_price: mls_list_price ? `$${mls_list_price.toLocaleString(undefined, { maximumFractionDigits: 0 })}.00` : null,
        est_value: as_is_value, arv_value: arv,
        beds, baths, year_built_mls: yearBuilt, dom,
        mls_description: mlsDesc,
        mls: {
            number: saleNode.mlsNumber || null,
            name: saleNode.mlsName || null,
            status: saleNode.status || null,
            listedDate: saleNode.listedDate || null,
            lastSeenDate: saleNode.lastSeenDate || null,
            price_num: mls_list_price
        }
    };

    const existing_loan = {
        balance: loanBalance || 0,
        sellerMonthlyPaymentPI: sellerMonthlyPaymentPI || 0,
        rate: loanRate || 0,
        original_principal: originalPrincipal || 0,
        ltv: ltv !== null ? Number(ltv.toFixed(4)) : null
    };

    const metrics = {
        list_price: mls_list_price, as_is_value, arv, comp_low, comp_high,
        price: mls_list_price, city, state, bedrooms: beds, bathrooms: baths,
        propertyType: propType, sqft, yearBuilt,
        grossRent: marketRent, proFormaRent, annualRent: marketRent * 12, 
        estimatedRepairCost, taxes, insurance, mgmt, maint, vacancy, opex, noi: (marketRent * 12) - opex,
        estValue: as_is_value, equity_pct, tiMonthly
    };

    const config = {
        insuranceRate, mgmtRate, maintRate, vacancyRate,
        assignmentPctOfDown: 0.25, closingCostRate: 0.08, taxRate: defaultTaxRate
    };

    const rental_estimates = it.rental_estimates || null;
    const padsplit_current_vs_target = it.rental_models?.padsplit?.debug || {};
    const canonical = {
        rental_model: canonicalKey,      
        economics: {
            grossRentMonthly: grossRent, annualRent, opexAnnual: opex, NOI: noi,
            ADS: null, DSCR: null, monthlyCF: null, annualCF: null, totalCashIn: null, CoC_pct: null
        }
    };

    results.push({
        json: { ...it, property, rental_estimates, existing_loan, metrics, config, canonical, padsplit_current_vs_target, warnings }
    });
}

return results;

