    : [];

  const selectedCompsArv = parseMoney(selectedCompsNode.estARV);
  const selectedCompsAvgPpsf = parseMoney(selectedCompsNode.analysis?.averagePpsqft);
  const selectedCompsValidCount = parseMoney(selectedCompsNode.analysis?.validSoldCompsFound || selectedComps.length);

  const selectedPrices = selectedComps
    .map(c => parseMoney(c.price))
    .filter(v => v > 0);

  const selectedCompLow = selectedPrices.length ? Math.min(...selectedPrices) : 0;
  const selectedCompHigh = selectedPrices.length ? Math.max(...selectedPrices) : 0;

  const compLow = firstPositive(selectedCompsNode.priceRangeLow, selectedCompLow, compsNode.priceRangeLow);
  const compHigh = firstPositive(selectedCompsNode.priceRangeHigh, selectedCompHigh, compsNode.priceRangeHigh);
  const compMid = parseMoney(compsNode.price);

  const fallbackSaleComparables = Array.isArray(compsNode.comparables) ? compsNode.comparables : [];
  const saleComparables = selectedComps.length ? selectedComps : fallbackSaleComparables;

  let ppsfArv = 0;
  let ppsfArvSource = 'missing';

  if (selectedCompsArv > 0) {
