    ppsfArvSource = 'selected_comps_avg_ppsf_recalculated';
    warnings.push('Selected Comps did not provide estARV, so ARV was recalculated from Selected Comps average PPSF × subject sqft.');
  } else if (!selectedComps.length && fallbackSaleComparables.length) {
    const locationCtx = (() => {
      try {
        return $('Location Context v1').first().json.location_context || {};
      } catch {
