  }

  if (arv > 0 && as_is_value > 0 && as_is_value > arv) {
    warnings.push(`As-is value ($${Math.round(as_is_value).toLocaleString()}) is above ARV ($${Math.round(arv).toLocaleString()}). Check value inputs and condition assumptions.`);
