  let insurance = parseMoney(firstNonEmpty(cd.insuranceAnnual, cd.insuranceMonthly ? Math.round(parseMoney(cd.insuranceMonthly) * 12) : 0, it.metrics?.insurance, 0));

  if (!insurance) {
    if (taxes > 0) insurance = Math.round(taxes * (HIGH_RISK_INS_STATES.has(state) ? 0.56 : 0.80));
    else insurance = Math.round((listPrice || as_is_value || arv || 100000) * insuranceRate);
