  };

  const rental_estimates = it.rental_estimates || null;

  const padsplit_current_vs_target = {
    ...(it.rental_models?.padsplit?.debug || {}),
    currentRooms: padsplitCurrentRooms || null,
    targetRooms: padsplitTargetRooms || null,
    roomsToAdd: padsplitRoomsToAdd || 0,
    currentBaths: padsplitCurrentBaths || null,
    requiredBaths: padsplitRequiredBaths || null,
    bathsToAdd: padsplitBathroomsToAdd || 0,
    padsplitRentCandidate: finalPadsplitGrossRentMonthly || 0,
    upliftMonthly: padsplitUpliftMonthly || 0,
    totalRenoEstimate: padsplitRenoEstimate || 0,
    supportedReno: padsplitSupportedReno || 0,
    feasible: padsplitFeasible,
