      comp_properties_report,
      comps_summary,
      property,
      rental_estimates,
      rental_models,
      existing_loan,
      metrics,
      config,
      canonical,
      padsplit_room_mix,
      padsplit_expenses,
      padsplit_current_vs_target,
      warnings
    }
