##  


/******************************************************
 OFFER ENGINE v1
 -----------------------------------------------------
 Purpose:
  - Merge upstream pack + agent context
  - Normalize locked metrics / property / loan data
  - Recompute rent / opex / NOI deterministically
  - Build creative candidates:
      • Seller Finance
      • Subject-To
      • Hybrid
  - Build TRUE net cash MAO object
  - Select Primary + Backup offers from candidates
  - Output authoritative:
      • deal_structure
      • investors_analysis
      • cash_offer / mao / cts_engine
      • canonical economics
 -----------------------------------------------------
 Removed on purpose:
  - lead scoring
  - stage routing
  - LOI generation
******************************************************/

function parseNum(x) {
  if (x == null || x === '') return 0;
  if (typeof x === 'number') return Number.isFinite(x) ? x : 0;
  const n = Number(String(x).replace(/[^\d.-]/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function safeParse(x) {
  try {
    if (typeof x === 'string') return JSON.parse(x);
    return x;
  } catch {
    return x;
  }
}

function money(n, digits = 0) {
  const v = Number.isFinite(n) ? n : 0;
  return `$${v.toLocaleString('en-US', {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits
  })}`;
}

function pct(n, digits = 1) {
  const v = Number.isFinite(n) ? n : 0;
  return `${v.toFixed(digits)}%`;
}

function round(n, digits = 0) {
  const p = Math.pow(10, digits);
  return Math.round((Number(n) || 0) * p) / p;
}

function clamp(v, min, max) {
  return Math.min(max, Math.max(min, v));
}

function pmt(rateAnnualPct, years, principal) {
  const P = Number(principal) || 0;
  const y = Number(years) || 0;
  const r = (Number(rateAnnualPct) || 0) / 100 / 12;
  const n = y * 12;
  if (P <= 0 || n <= 0) return 0;
  if (r === 0) return P / n;
  return (P * r) / (1 - Math.pow(1 + r, -n));
}

function uniqRounded(nums) {
  const seen = new Set();
  const out = [];
  for (const raw of nums) {
    const v = Math.round(parseNum(raw));
    if (v > 0 && !seen.has(v)) {
      seen.add(v);
      out.push(v);
    }
  }
  return out;
}

function asText(v) {
  return String(v || '').trim();
}

function lower(v) {
  return String(v || '').toLowerCase();
}

function hasSignal(s, rx) {
  return rx.test(lower(s));
}

function maxBy(arr, fn) {
  if (!arr.length) return null;
  return arr.reduce((best, cur) => (fn(cur) > fn(best) ? cur : best), arr[0]);
}

function fallback(value, alt) {
  return (value !== undefined && value !== null && value !== '') ? value : alt;
}

try {
  /***** ---------- [1] Merge Inputs ---------- *****/
  const inputs = $input.all().map(i => i.json || {});
  const pack = inputs.find(i =>
    i.metrics || i.config || i.property || i.existing_loan || i.normalized_subject || i.transcript
  ) || {};

  const agentHolder = inputs.find(i =>
    Object.prototype.hasOwnProperty.call(i, 'output') ||
    i.estimated_arv ||
    i.comp_properties_report ||
    i.deal_structure
  ) || {};

  const parsedOutput = safeParse(agentHolder.output);
  const agent = (parsedOutput && typeof parsedOutput === 'object') ? parsedOutput : (agentHolder || {});

  const items = $input.all();
const results = [];



  /***** ---------- [2] Canonical Upstream Context ---------- *****/
  const packMetrics = pack.metrics || {};
  const packConfig = pack.config || {};
  const packProperty = pack.property || {};
  const packLoan = pack.existing_loan || {};
  const packNorm = pack.normalized_subject || pack.normalized_subject || {};
  const packTranscript =
    pack.transcript?.output ||
    pack.transcript_insights ||
    agent.transcript?.output ||
    agent.transcript_insights ||
    {};

  const property = {
    ...(agent.property || {}),
    ...packProperty
  };

  const metrics = {
    ...(agent.metrics || {}),
    ...packMetrics
  };

  const config = {
    closingCostRate: 0.08,
    mgmtRate: 0.08,
    maintRate: 0.05,
    vacancyRate: 0.05,
    assignmentPctOfDown: 0.25,
    taxRate: 0.0115,
    insuranceRate: 0.012,
    ...(agent.config || {}),
    ...packConfig
  };

  const existingLoan = {
    ...(agent.existing_loan || {}),
    ...packLoan
  };

 const buyerMatches =
  Array.isArray(pack.buyer_matches) ? pack.buyer_matches :
  Array.isArray(pack.matches) ? pack.matches :
  Array.isArray(agent.buyer_matches) ? agent.buyer_matches :
  Array.isArray(agent.matches) ? agent.matches :
  [];

const buyerMatchSummary =
  pack.buyer_match_summary ||
  pack.summary ||
  agent.buyer_match_summary ||
  agent.summary ||
  '';

const compProperties =
  Array.isArray(agent.comp_properties_report) ? agent.comp_properties_report :
  Array.isArray(pack.comp_properties_report) ? pack.comp_properties_report :
  Array.isArray(pack.sale_comparables) ? pack.sale_comparables :
  [];

const compsSummary =
  agent.comps_summary ||
  pack.comps_summary ||
  pack.sale_comps_summary ||
  '';

  /***** ---------- [3] Locked Baselines ---------- *****/
  const compPrices = compProperties.map(c => parseNum(c.price)).filter(v => v > 0);
  const compMedian = compPrices.length
    ? compPrices.sort((a, b) => a - b)[Math.floor(compPrices.length / 2)]
    : 0;

  const arv =
    parseNum(metrics.arv) ||
    parseNum(agent.estimated_arv) ||
    parseNum(property.arv_value) ||
    parseNum(property.est_value) ||
    compMedian ||
    0;

  const listPrice =
    parseNum(metrics.list_price) ||
    parseNum(metrics.price) ||
    parseNum(property.list_price) ||
    parseNum(property.mls?.price_num) ||
    0;

  const asIsValue =
    parseNum(metrics.as_is_value) ||
    parseNum(property.est_value) ||
    (listPrice > 0 ? listPrice : 0) ||
    (arv > 0 ? Math.round(arv * 0.9) : 0);

  const taxes =
    parseNum(metrics.taxes) ||
    parseNum(property.annual_taxes) ||
    0;

  const insurance =
    parseNum(metrics.insurance) ||
    parseNum(property.annual_insurance) ||
    (arv > 0 ? Math.round(arv * parseNum(config.insuranceRate || 0.012)) : 0);

  const rentMonthly =
    parseNum(metrics.grossRent) ||
    parseNum(metrics.gross_rent_monthly) ||
    parseNum(pack.rental_estimates?.from_webhook_monthly_income) ||
    parseNum(pack.rental_estimates?.from_comp_pull_high) ||
    parseNum(pack.rental_estimates?.from_comp_pull_low) ||
    0;

  const annualRent = parseNum(metrics.annualRent) || (rentMonthly * 12);

  const mgmt = parseNum(metrics.mgmt) || Math.round(annualRent * parseNum(config.mgmtRate || 0.08));
  const maint = parseNum(metrics.maint) || Math.round(annualRent * parseNum(config.maintRate || 0.05));
  const vacancy = parseNum(metrics.vacancy) || Math.round(annualRent * parseNum(config.vacancyRate || 0.05));
  const opex = parseNum(metrics.opex) || (taxes + insurance + mgmt + maint + vacancy);
  const noi = parseNum(metrics.noi) || Math.max(annualRent - opex, 0);
  const tiMonthly = parseNum(metrics.tiMonthly) || ((taxes + insurance) / 12);

  const loanBalance = parseNum(existingLoan.balance);
  const loanRate = parseNum(existingLoan.rate);
  const loanPI =
    parseNum(existingLoan.sellerMonthlyPaymentPI) ||
    parseNum(existingLoan.payment) ||
    ((loanBalance > 0 && loanRate > 0) ? Math.round(pmt(loanRate, 30, loanBalance)) : 0);

  let equityPct = parseNum(metrics.equity_pct);
  if (equityPct > 0 && equityPct <= 1) equityPct = equityPct * 100;

  if (!equityPct) {
    if (parseNum(existingLoan.ltv) > 0 && parseNum(existingLoan.ltv) <= 1) {
      equityPct = (1 - parseNum(existingLoan.ltv)) * 100;
    } else if (loanBalance > 0 && asIsValue > 0) {
      equityPct = ((asIsValue - loanBalance) / asIsValue) * 100;
    } else if (loanBalance <= 0) {
      equityPct = 100;
    } else {
      equityPct = 0;
    }
  }

  /***** ---------- [4] Transcript / Seller Signals ---------- *****/
  const sellerUrgency = asText(packTranscript.sellerUrgency);
  const sellerHardship = asText(packTranscript.sellerHardship);
  const sellerPrice = asText(packTranscript.price);
  const sellerInsights = asText(packTranscript.additionalInsights);
  const rawTranscript = [
    sellerUrgency,
    sellerHardship,
    sellerPrice,
    sellerInsights,
    asText(pack.webhook_custom_data?.prequalified_phone_transcript),
    asText(pack.webhook_custom_data?.contact_pq_transcript)
  ].join(' ');

  const dom = parseNum(property.dom || property.mls?.dom || metrics.dom);

  const motivationHigh =
    hasSignal(rawTranscript, /\b(hard money|refi|refinance|must sell|urgent|asap|one to two weeks|financial stress|probate|inherited|vacant|out of state)\b/i) ||
    dom >= 90;

  const competitionHigh =
    hasSignal(rawTranscript, /\b(multiple offers|offer in hand|bidding war|interested buyer)\b/i);

  let motivationBracket = 'neutral';
  if (competitionHigh) motivationBracket = 'aggressive';
  else if (motivationHigh) motivationBracket = 'conservative';

  /***** ---------- [5] Cash-to-Seller Engine ---------- *****/
  const askingPriceForCTS = listPrice || asIsValue || arv || 0;
  const agentCommission = Math.round(askingPriceForCTS * 0.06);
  const sellerClosingCosts = Math.round(askingPriceForCTS * 0.02);
  const rehabForRetail = 0;

  const sellerRetailNet = Math.round(
    askingPriceForCTS - loanBalance - agentCommission - sellerClosingCosts - rehabForRetail
  );

  let ctsConservative = 0;
  let ctsStandard = 0;
  let ctsAggressive = 0;

  if (sellerRetailNet < -20000) {
    ctsConservative = 0;
    ctsStandard = 0;
    ctsAggressive = 0;
  } else if (sellerRetailNet <= 0) {
    ctsConservative = 0;
    ctsStandard = 1500;
    ctsAggressive = 4000;
  } else if (sellerRetailNet <= 5000) {
    ctsConservative = 1500;
    ctsStandard = 2000;
    ctsAggressive = Math.min(7000, sellerRetailNet);
  } else {
    ctsConservative = Math.round(Math.min(sellerRetailNet * 0.10, sellerRetailNet));
    ctsStandard = Math.round(Math.min(sellerRetailNet * 0.20, sellerRetailNet));
    ctsAggressive = Math.round(Math.min(sellerRetailNet * 0.30, sellerRetailNet));
  }

  const hardCap15pct = Math.round(askingPriceForCTS * 0.15);

  let recommendedCTS = ctsStandard;
  if (motivationBracket === 'aggressive') recommendedCTS = ctsAggressive;
  if (motivationBracket === 'conservative') recommendedCTS = ctsConservative;
  recommendedCTS = Math.max(0, Math.min(recommendedCTS, hardCap15pct));

  const ctsEngine = {
    seller_retail_net: sellerRetailNet,
    agent_commission: agentCommission,
    seller_closing_costs: sellerClosingCosts,
    cts_conservative: ctsConservative,
    cts_standard: ctsStandard,
    cts_aggressive: ctsAggressive,
    recommended_cts: recommendedCTS,
    motivation_bracket: motivationBracket === 'aggressive' ? 'competition_high' : motivationBracket,
    hard_cap_15pct: hardCap15pct
  };

  /***** ---------- [6] True Net Cash MAO ---------- *****/
  const repairEstimate =
    parseNum(metrics.estimatedRepairCost) ||
    parseNum(metrics.repair_estimate) ||
    0;

  const buyerClosingCosts = Math.round(arv * parseNum(config.closingCostRate || 0.08));
  const wholesaleFee =
    parseNum(config.wholesaleAssignmentFee) ||
    parseNum(metrics.wholesaleFee) ||
    15000;

  const baseBuyBox = Math.round(arv * 0.70);
  const mao = Math.max(0, Math.round(baseBuyBox - repairEstimate - buyerClosingCosts - wholesaleFee));
  const cashPctOfArv = arv > 0 ? round((mao / arv) * 100, 1) : 0;
  const spreadVsList = listPrice > 0 ? Math.round(mao - listPrice) : 0;

  const acceptableNow =
    listPrice > 0
      ? mao >= listPrice || ((listPrice - mao) / listPrice) <= 0.05
      : false;

  let negotiationPotential = 'low';
  if (motivationHigh || dom >= 60 || hasSignal(rawTranscript, /\bflexibility|seller financing|creative|cash offer|hard money\b/i)) {
    negotiationPotential = 'high';
  } else if (dom >= 30 || hasSignal(rawTranscript, /\binterested|follow up|open\b/i)) {
    negotiationPotential = 'medium';
  }

  const pursueCashStrategy = mao > 0 && ['medium', 'high'].includes(negotiationPotential);

  const cashOfferObject = {
    type: 'Cash',
    arv,
    buy_box_pct: '70%',
    repair_estimate: repairEstimate,
    buyer_closing_costs: buyerClosingCosts,
    wholesale_fee: wholesaleFee,
    cash_offer: mao,
    cash_offer_pct_of_arv: `${cashPctOfArv}%`,
    spread_vs_list_price: spreadVsList,
    economic_viable: mao > 0,
    acceptable_now: acceptableNow,
    negotiation_potential: negotiationPotential,
    pursue_cash_strategy: pursueCashStrategy
  };

  /***** ---------- [7] Candidate Scoring ---------- *****/
  function candidateScore(c) {
    if (!c) return -1e12;
    const passBoost = c.pass ? 1000000 : 0;
    return passBoost + (c.monthlyCF * 20) + (c.DSCR * 100) + (c.coc * 5) - (c.totalIn * 0.01);
  }

  /***** ---------- [8] Seller Finance Candidates ---------- *****/
  function buildSellerFinanceCandidates() {
    const candidates = [];

    // Seller finance with existing debt only if down clears payoff.
    const priceBase = listPrice || asIsValue || arv || 0;
    const priceTrials = uniqRounded([
      priceBase,
      priceBase * 0.97,
      priceBase * 0.94,
      priceBase * 0.90,
      asIsValue,
      asIsValue * 0.97
    ]);

    for (const price of priceTrials) {
      for (const downPct of [10, 8, 5]) {
        const down$ = Math.round(price * downPct / 100);

        if (loanBalance > 0 && down$ < loanBalance) {
          continue;
        }

        for (const ratePct of [4.0, 3.5, 3.0]) {
          for (const balloonYrs of [5, 7]) {
            const years = 30;
            const financed = Math.max(price - down$, 0);
            const monthPI = Math.round(pmt(ratePct, years, financed));
            const totalDebtMonthly = monthPI + tiMonthly;
            const ADS = totalDebtMonthly * 12;
            const DSCR = ADS > 0 ? round(noi / ADS, 2) : 0;
            const monthlyCF = round(rentMonthly - totalDebtMonthly, 0);
            const annualCF = monthlyCF * 12;
            const assignment = Math.round(down$ * parseNum(config.assignmentPctOfDown || 0.25));
            const totalIn = Math.round(down$ + buyerClosingCosts + assignment);
            const coc = totalIn > 0 ? round((annualCF / totalIn) * 100, 1) : 0;

            const entryPct = price > 0 ? (totalIn / price) * 100 : 999;
            const pass =
              ratePct <= 4 &&
              downPct <= 10 &&
              balloonYrs >= 5 &&
              DSCR >= 1.20 &&
              monthlyCF >= 200 &&
              coc >= 13 &&
              (entryPct <= 15 || (entryPct <= 20 && monthlyCF >= 500));

            candidates.push({
              family: 'seller_finance',
              type: 'Seller Finance',
              purchasePrice: price,
              down$,
              downPct,
              ratePct,
              years,
              balloonYrs,
              financed,
              monthPI,
              ADS,
              DSCR,
              monthlyCF,
              annualCF,
              totalIn,
              coc,
              assignment,
              cashToSeller: down$,
              justification: pass
                ? 'Passes Seller Finance rules with compliant rate/down/balloon and acceptable DSCR, cash flow, and CoC.'
                : 'Closest Seller Finance structure under current pricing and rent, but does not fully meet investor thresholds.',
              pass
            });
          }
        }
      }
    }

    return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
  }

  /***** ---------- [9] Subject-To Candidates ---------- *****/
  function buildSubToCandidates() {
    const candidates = [];
    if (loanBalance <= 0) return candidates;

    const price = listPrice || asIsValue || arv || 0;
    const firstPI = loanPI;
    if (firstPI <= 0) return candidates;

    for (const coverSellerClosing of [false, true]) {
      const sellerCloseCovered = coverSellerClosing ? sellerClosingCosts : 0;
      const sellerAgentCovered = 0; // do not assume you cover commissions
      const buyerSide = buyerClosingCosts + sellerCloseCovered + sellerAgentCovered;

      for (const ctsTrial of uniqRounded([
        recommendedCTS,
        recommendedCTS * 0.75,
        recommendedCTS * 0.5,
        0
      ])) {
        const entryBase = ctsTrial + buyerSide;
        const assignment = Math.round(ctsTrial * parseNum(config.assignmentPctOfDown || 0.25));
        const totalIn = Math.round(entryBase + assignment);
        const entryPct = price > 0 ? (totalIn / price) * 100 : 999;

        const totalDebtMonthly = firstPI + tiMonthly;
        const ADS = totalDebtMonthly * 12;
        const DSCR = ADS > 0 ? round(noi / ADS, 2) : 0;
        const monthlyCF = round(rentMonthly - totalDebtMonthly, 0);
        const annualCF = monthlyCF * 12;
        const coc = totalIn > 0 ? round((annualCF / totalIn) * 100, 1) : 0;

        const lowRateException = loanRate > 0 && loanRate <= 3.5;
        const cfPass = lowRateException ? monthlyCF >= -50 : monthlyCF >= 150;
        const ratePass =
          (loanBalance > 150000 ? loanRate <= 5 : loanRate <= 8) || loanRate === 0;

        const pass =
          ratePass &&
          DSCR >= 1.0 &&
          cfPass &&
          entryPct <= 15;

        candidates.push({
          family: 'subto',
          type: 'Subject-To',
          purchasePrice: price,
          down$: ctsTrial,
          downPct: price > 0 ? round((ctsTrial / price) * 100, 2) : 0,
          ratePct: loanRate || null,
          years: null,
          balloonYrs: null,
          financed: loanBalance,
          firstPI,
          monthPI: firstPI,
          ADS,
          DSCR,
          monthlyCF,
          annualCF,
          totalIn,
          coc,
          assignment,
          cashToSeller: ctsTrial,
          coverSellerClosing,
          justification: pass
            ? 'Passes Subject-To screen with acceptable DSCR/cash flow and controlled entry.'
            : 'Closest Subject-To structure under current debt and entry assumptions, but not fully investor-compliant.',
          pass
        });
      }
    }

    return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
  }

  /***** ---------- [10] Hybrid Candidates ---------- *****/
  function buildHybridCandidates() {
    const candidates = [];
    if (loanBalance <= 0) return candidates;

    const priceBase = listPrice || asIsValue || arv || 0;
    const firstPI = loanPI;
    if (firstPI <= 0) return candidates;

    const priceTrials = uniqRounded([
      priceBase,
      priceBase * 0.97,
      priceBase * 0.94,
      asIsValue
    ]);

    for (const price of priceTrials) {
      for (const ctsTrial of uniqRounded([
        recommendedCTS,
        recommendedCTS * 0.75,
        recommendedCTS * 0.5,
        0
      ])) {
        const cts = Math.min(ctsTrial, Math.round(price * 0.10));
        const carryPrincipal = Math.max(price - loanBalance - cts, 0);

        for (const carryRate of [4.0, 3.5, 3.0]) {
          for (const balloonYrs of [5, 7]) {
            const carryYears = 30;
            const carryPI = carryPrincipal > 0 ? Math.round(pmt(carryRate, carryYears, carryPrincipal)) : 0;
            const combinedPI = firstPI + carryPI;
            const totalDebtMonthly = combinedPI + tiMonthly;
            const ADS = totalDebtMonthly * 12;
            const DSCR = ADS > 0 ? round(noi / ADS, 2) : 0;
            const monthlyCF = round(rentMonthly - totalDebtMonthly, 0);
            const annualCF = monthlyCF * 12;
            const assignment = Math.round(cts * parseNum(config.assignmentPctOfDown || 0.25));
            const totalIn = Math.round(cts + buyerClosingCosts + assignment);
            const coc = totalIn > 0 ? round((annualCF / totalIn) * 100, 1) : 0;
            const entryPct = price > 0 ? (totalIn / price) * 100 : 999;

            const pass =
              cts <= price * 0.10 &&
              DSCR >= 1.20 &&
              monthlyCF >= 200 &&
              coc >= 13 &&
              (entryPct <= 15 || (entryPct <= 20 && monthlyCF >= 500));

            candidates.push({
              family: 'hybrid',
              type: 'Hybrid',
              purchasePrice: price,
              down$: cts,
              downPct: price > 0 ? round((cts / price) * 100, 2) : 0,
              ratePct: carryRate,
              years: 30,
              balloonYrs,
              financed: loanBalance + carryPrincipal,
              firstPI,
              carryPrincipal,
              carryRate,
              carryYears,
              carryPI,
              monthPI: combinedPI,
              ADS,
              DSCR,
              monthlyCF,
              annualCF,
              totalIn,
              coc,
              assignment,
              cashToSeller: cts,
              justification: pass
                ? 'Passes Hybrid screen with controlled CTS, acceptable DSCR/cash flow, and compliant CoC.'
                : 'Closest Hybrid structure under current equity and debt, but not fully investor-compliant.',
              pass
            });
          }
        }
      }
    }

    return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
  }

  /***** ---------- [11] Build / Select Candidates ---------- *****/
  const sfCandidates = buildSellerFinanceCandidates();
  const subtoCandidates = buildSubToCandidates();
  const hybridCandidates = buildHybridCandidates();

  const allCandidates = [...sfCandidates, ...subtoCandidates, ...hybridCandidates];
  const passing = allCandidates.filter(c => c.pass);

  let preferredFamily = 'seller_finance';
  if (loanBalance > 0 && equityPct < 15) preferredFamily = 'subto';
  else if (loanBalance > 0 && equityPct <= 80) preferredFamily = 'hybrid';
  else preferredFamily = 'seller_finance';

  const preferredPassing = passing.filter(c => c.family === preferredFamily);
  const preferredAll = allCandidates.filter(c => c.family === preferredFamily);

  const primary =
    maxBy(preferredPassing, candidateScore) ||
    maxBy(preferredAll, candidateScore) ||
    maxBy(passing, candidateScore) ||
    maxBy(allCandidates, candidateScore);

  const backupPool = allCandidates.filter(c =>
    primary ? !(c.family === primary.family &&
      c.purchasePrice === primary.purchasePrice &&
      c.down$ === primary.down$ &&
      c.ratePct === primary.ratePct &&
      c.balloonYrs === primary.balloonYrs) : true
  );

  const backup =
    maxBy(backupPool.filter(c => c.family !== (primary ? primary.family : '')), candidateScore) ||
    maxBy(backupPool, candidateScore);

  /***** ---------- [12] Offer Formatter ---------- *****/
  function formatOffer(candidate, label) {
    if (!candidate) {
      return {
        Type: 'No viable creative offer',
        'Purchase Price': 'N/A',
        'Down Payment ($)': 'N/A',
        'Down Payment (%)': 'N/A',
        'Loan Rate (%)': 'N/A',
        'Amortization (Years)': null,
        'Balloon Term (Years)': null,
        'Monthly Payment (PI)': 'N/A',
        'Monthly Taxes and Insurance (TI)': money(tiMonthly),
        ADS: 'N/A',
        DSCR: 'N/A',
        'Monthly Cash-flow': 'N/A',
        'Cash-on-Cash Return': 'N/A',
        'Total Entry Fee': 'N/A',
        Justification: `${label} not available under current metrics.`
      };
    }

    const out = {
      Type: candidate.type,
      'Purchase Price': money(candidate.purchasePrice),
      'Cash to Seller': money(candidate.cashToSeller || 0),
      'Down Payment ($)': money(candidate.down$ || 0),
      'Down Payment (%)': pct(candidate.downPct || 0, 1),
      'Interest Rate (%)': candidate.ratePct != null ? String(candidate.ratePct) : 'N/A',
      'Loan Rate (%)': candidate.ratePct != null ? String(candidate.ratePct) : 'N/A',
      'Amortization (Years)': candidate.years || candidate.carryYears || null,
      'Balloon Term (Years)': candidate.balloonYrs ?? null,
      'Monthly Payment (PI)': money(candidate.monthPI || 0, 2),
      'Monthly Taxes and Insurance (TI)': money(tiMonthly),
      ADS: money(candidate.ADS || 0),
      DSCR: round(candidate.DSCR || 0, 2).toFixed(2),
      'Monthly Cash-flow': money(candidate.monthlyCF || 0),
      'Cash-on-Cash Return': pct(candidate.coc || 0, 1),
      'Total Entry Fee': money(candidate.totalIn || 0),
      Justification: candidate.justification
    };

    if (candidate.family === 'seller_finance') {
      out['Financed Amount'] = money(candidate.financed || 0);
      out['Seller Carryback Loan'] = money(candidate.financed || 0);
      out['Seller Carryback Interest Rate'] = candidate.ratePct != null ? String(candidate.ratePct) : 'N/A';
      out['Seller Carryback Monthly Payment (PI)'] = money(candidate.monthPI || 0, 2);
      out['Combined Monthly Payment (PI)'] = money(candidate.monthPI || 0, 2);
      out['Existing Loan Balance'] = money(0);
      out['Existing Loan Interest Rate'] = 'N/A';
      out['Existing Loan Monthly Payment (PI)'] = 'N/A';
    }

    if (candidate.family === 'subto') {
      out['Existing Loan Balance'] = money(loanBalance);
      out['Existing Loan Interest Rate'] = loanRate ? String(loanRate) : 'N/A';
      out['Existing Loan Monthly Payment (PI)'] = money(candidate.firstPI || 0, 2);
      out['Combined Monthly Payment (PI)'] = money(candidate.firstPI || 0, 2);
      out['Financed Amount'] = money(loanBalance);
      out['Seller Carryback Loan'] = money(0);
      out['Seller Carryback Interest Rate'] = 'N/A';
      out['Seller Carryback Monthly Payment (PI)'] = money(0, 2);
    }

    if (candidate.family === 'hybrid') {
      out['Existing Loan Balance'] = money(loanBalance);
      out['Existing Loan Interest Rate'] = loanRate ? String(loanRate) : 'N/A';
      out['Existing Loan Monthly Payment (PI)'] = money(candidate.firstPI || 0, 2);
      out['Seller Carryback Loan'] = money(candidate.carryPrincipal || 0);
      out['Seller Carryback Interest Rate'] = candidate.carryRate != null ? String(candidate.carryRate) : 'N/A';
      out['Seller Carryback Monthly Payment (PI)'] = money(candidate.carryPI || 0, 2);
      out['Combined Monthly Payment (PI)'] = money(candidate.monthPI || 0, 2);
      out['Financed Amount'] = money((loanBalance || 0) + (candidate.carryPrincipal || 0));
    }

    return out;
  }

  /***** ---------- [13] Deal Structure ---------- *****/
  const dealStructure = {
    'Primary Offer': formatOffer(primary, 'Primary Offer'),
    'Backup Offer': formatOffer(backup, 'Backup Offer'),
    'Updated Cash Offer': {
      'Final Cash Offer': money(mao),
      'Final Cash Offer % of ARV': `${cashPctOfArv}% of ARV`,
      'Justification':
        `True MAO used: (ARV ${money(arv)} × 70%) - Repairs ${money(repairEstimate)} - ` +
        `Buyer Closing Costs ${money(buyerClosingCosts)} - Wholesale Fee ${money(wholesaleFee)}. ` +
        `This produces a net cash MAO of ${money(mao)}.`
    }
  };

  /***** ---------- [14] Investors Analysis Mirrors Primary ---------- *****/
  const primaryMonthlyCF = primary ? primary.monthlyCF : 0;
  const primaryAnnualCF = primary ? primary.annualCF : 0;
  const primaryCoc = primary ? primary.coc : 0;
  const primaryADS = primary ? primary.ADS : 0;
  const primaryDSCR = primary ? primary.DSCR : 0;
  const primaryTotalIn = primary ? primary.totalIn : 0;
  const primaryPrice = primary ? primary.purchasePrice : 0;

  const rule2 = (primaryPrice > 0 && rentMonthly / primaryPrice >= 0.02) ? '✅' : '❌';
  const rule50 = (annualRent > 0 && opex <= annualRent * 0.5) ? '✅' : '❌';

  const investorsAnalysis = {
    'Gross Rent': money(rentMonthly),
    'Annual Rent': money(annualRent),
    'Operating Expenses': money(opex),
    NOI: money(noi),
    'Annual Debt Service (ADS)': money(primaryADS),
    DSCR: round(primaryDSCR || 0, 2).toFixed(2),
    'Monthly Cash-flow': money(primaryMonthlyCF),
    'Annual Cash-flow': money(primaryAnnualCF),
    'Total Cash In': money(primaryTotalIn),
    'Cash-on-Cash Return': pct(primaryCoc || 0, 1),
    '2% Rule': rule2,
    '50% Rule': rule50
  };

  let investorsAnalysisInsights = '';
  if (primary) {
    investorsAnalysisInsights =
      `${primary.type} is the current best creative path under locked metrics. ` +
      `DSCR is ${round(primaryDSCR || 0, 2).toFixed(2)}, monthly cash flow is ${money(primaryMonthlyCF)}, ` +
      `and cash-on-cash is ${pct(primaryCoc || 0, 1)}. ` +
      `${primary.pass ? 'This path clears the current rules.' : 'This path is the closest fit but still misses one or more investor targets.'}`;
  } else {
    investorsAnalysisInsights = 'No creative structure could be built from the current metrics.';
  }

  /***** ---------- [15] Assignment Fee Range ---------- *****/
  let assignmentFeeRange = '$3,000–$7,500';
  if (primaryMonthlyCF >= 500) assignmentFeeRange = '$8,000–$15,000';
  else if (primaryMonthlyCF >= 200) assignmentFeeRange = '$5,000–$12,000';

  /***** ---------- [16] Canonical Economics ---------- *****/
  const canonical = {
    economics: {
      grossRentMonthly: rentMonthly,
      annualRent,
      opexAnnual: opex,
      NOI: noi,
      ADS: primaryADS,
      DSCR: round(primaryDSCR || 0, 2),
      monthlyCF: primaryMonthlyCF,
      annualCF: primaryAnnualCF,
      totalCashIn: primaryTotalIn,
      CoC_pct: round(primaryCoc || 0, 1)
    }
  };

  /***** ---------- [17] Normalized Output Objects ---------- *****/
  const normalizedMetrics = {
    ...metrics,
    list_price: listPrice,
    price: listPrice || parseNum(metrics.price),
    as_is_value: asIsValue,
    arv,
    grossRent: rentMonthly,
    annualRent,
    taxes,
    insurance,
    mgmt,
    maint,
    vacancy,
    opex,
    noi,
    tiMonthly,
    equity_pct: round(equityPct, 2)
  };

  const normalizedLoan = {
    ...existingLoan,
    balance: loanBalance,
    sellerMonthlyPaymentPI: loanPI,
    rate: loanRate
  };

  /***** ---------- [18] Result ---------- *****/
  const result = {
    ...agent,
    estimated_arv: arv,
    comp_properties_report: compProperties,
    comps_summary: compsSummary,
    investors_analysis: investorsAnalysis,
    investors_analysis_insights: investorsAnalysisInsights,
    deal_structure: dealStructure,

    cash_offer: cashOfferObject,
    mao,
    wholesale_fee: wholesaleFee,
    repair_estimate: repairEstimate,
    cts_engine: ctsEngine,
    assignment_fee_range: assignmentFeeRange,

    property,
    metrics: normalizedMetrics,
    config,
    existing_loan: normalizedLoan,
    canonical,

    buyer_matches: buyerMatches,
    buyer_match_summary: buyerMatchSummary,

    // pass-through only; no new scoring / stage / LOI generated here
    lead_score: fallback(agent.lead_score, pack.lead_score),
    lead_score_explanation: fallback(agent.lead_score_explanation, pack.lead_score_explanation),
    recommendation: fallback(agent.recommendation, pack.recommendation),
    loi: fallback(agent.loi, pack.loi),

    output: {
      estimated_arv: arv,
      comp_properties_report: compProperties,
      comps_summary: compsSummary,
      investors_analysis: investorsAnalysis,
      investors_analysis_insights: investorsAnalysisInsights,
      deal_structure: dealStructure,
      cash_offer: cashOfferObject,
      mao,
      wholesale_fee: wholesaleFee,
      repair_estimate: repairEstimate,
      cts_engine: ctsEngine,
      assignment_fee_range: assignmentFeeRange,
      res,
      property,
      metrics: normalizedMetrics,
      config,
      existing_loan: normalizedLoan,
      canonical,
      buyer_matches: buyerMatches,
      buyer_match_summary: buyerMatchSummary
    }
  };

  return [{ json: result }];

} catch (e) {
  return [{
    json: {
      _error: e?.message || String(e),
      _stack: e?.stack || null,
      _inputs: $input.all().map(i => i.json || {})
    }
  }];
}

