    const buyerMatchSummary = pick(
      root.buyer_match_summary,
      root.summary,
      output.buyer_match_summary,
      output.summary,
      ''
    ) || '';

    const compProperties = Array.isArray(root.comp_properties_report)
      ? root.comp_properties_report
      : Array.isArray(output.comp_properties_report)
        ? output.comp_properties_report
        : [];

    const compsSummary = pick(root.comps_summary, output.comps_summary, '') || '';
    const warnings = Array.isArray(root.warnings) ? [...root.warnings] : [];

    /***** ---------- [2] Locked Baselines ---------- *****/
    const arv = num(pick(
      metrics.arv,
      root.estimated_arv,
      output.estimated_arv,
      property.arv_value
    ));

    const listPrice = num(pick(
      metrics.list_price,
      metrics.price,
      property.list_price,
      property.mls?.price_num,
      root.sale_listing_source?.price,
      root.webhook_custom_data?.list_price,
      root.webhook_custom_data?.['opp.listPrice']
    ));

    const asIsValue = num(pick(
      metrics.as_is_value,
