            pass
          });
        }
      }

      return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
    }

    function buildHybridCandidates() {
      const candidates = [];
      if (loanBalance <= 0 || loanPI <= 0) return candidates;

      const priceBase = listPrice || asIsValue || arv || 0;
      const firstPI = loanPI;

      const priceTrials = uniqRounded([
        priceBase,
        priceBase * 0.97,
        priceBase * 0.94,
        asIsValue
      ]);

      for (const price of priceTrials) {
        for (const ctsTrial of uniqRounded([
          recommendedCTS,
          recommendedCTS * 0.75,
          recommendedCTS * 0.5,
          0
        ])) {
          const cts = Math.min(ctsTrial, Math.round(price * 0.10));
          const carryPrincipal = Math.max(price - loanBalance - cts, 0);

          for (const carryRate of [4.0, 3.5, 3.0]) {
            for (const balloonYrs of [5, 7]) {
              const carryYears = 30;
              const carryPI = carryPrincipal > 0 ? Math.round(pmt(carryRate, carryYears, carryPrincipal)) : 0;
              const combinedPI = firstPI + carryPI;
              const totalDebtMonthly = combinedPI + tiMonthly;
              const ADS = totalDebtMonthly * 12;
              const DSCR = ADS > 0 ? round(noi / ADS, 2) : 0;
              const monthlyCF = round(rentMonthly - totalDebtMonthly, 0);
              const annualCF = monthlyCF * 12;
              const assignment = Math.round(cts * num(config.assignmentPctOfDown || 0.25));
              const totalIn = Math.round(cts + buyerClosingCosts + assignment);
              const coc = totalIn > 0 ? round((annualCF / totalIn) * 100, 1) : 0;
              const entryPct = price > 0 ? (totalIn / price) * 100 : 999;

              const pass =
                cts <= price * 0.10 &&
                DSCR >= 1.20 &&
                monthlyCF >= 200 &&
                coc >= 13 &&
                (entryPct <= 15 || (entryPct <= 20 && monthlyCF >= 500));

              candidates.push({
                id: `hybrid|${price}|${cts}|${carryRate}|${balloonYrs}`,
                family: 'hybrid',
                type: 'Hybrid',
                purchasePrice: price,
                down$: cts,
                downPct: price > 0 ? round((cts / price) * 100, 2) : 0,
                ratePct: carryRate,
                years: 30,
                balloonYrs,
                financed: loanBalance + carryPrincipal,
                firstPI,
                carryPrincipal,
                carryRate,
                carryYears,
                carryPI,
                monthPI: combinedPI,
                ADS,
                DSCR,
                monthlyCF,
                annualCF,
                totalIn,
                coc,
                entryPct,
                assignment,
                cashToSeller: cts,
                justification: pass
                  ? 'Passes Hybrid screen with controlled CTS, acceptable DSCR/cash flow, and compliant CoC.'
                  : 'Closest Hybrid structure under current equity and debt, but not fully investor-compliant.',
                pass
              });
            }
          }
        }
      }

      return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
    }

    /***** ---------- [7] Build / Select Candidates ---------- *****/
    const sfCandidates = buildSellerFinanceCandidates();
    const subtoCandidates = buildSubToCandidates();
    const hybridCandidates = buildHybridCandidates();

    const allCandidates = [...sfCandidates, ...subtoCandidates, ...hybridCandidates];
    const preferredFamily = preferredFamilyForDeal(loanBalance, equityPct);

    const primary = selectCandidate(allCandidates, preferredFamily, 'primary');
    const excluded = new Set(primary ? [primary.id] : []);
    const backup = selectCandidate(allCandidates, preferredFamily, 'backup', excluded);

    if (!primary) warnings.push('Offer Engine: No creative candidates built.');
    if (primary && !primary.pass) warnings.push(`Offer Engine: Primary ${primary.type} is least-bad but not fully viable.`);
    if (backup && !backup.pass) warnings.push(`Offer Engine: Backup ${backup.type} is not fully viable.`);

    /***** ---------- [8] Deal Structure ---------- *****/
    const dealStructure = {
      'Primary Offer': formatOffer(primary, tiMonthly, loanBalance, loanRate, 'Primary Offer'),
      'Backup Offer': formatOffer(backup, tiMonthly, loanBalance, loanRate, 'Backup Offer'),
      'Updated Cash Offer': {
        'Final Cash Offer': money(mao),
        'Final Cash Offer % of ARV': `${cashPctOfArv}% of ARV`,
        'Justification':
          `True MAO used: (ARV ${money(arv)} × 70%) - Repairs ${money(repairEstimate)} - ` +
          `Buyer Closing Costs ${money(buyerClosingCosts)} - Wholesale Fee ${money(wholesaleFee)}. ` +
          `This produces a net cash MAO of ${money(mao)}.`
      }
    };

    /***** ---------- [9] Investors Analysis Mirrors Primary ---------- *****/
    const primaryMonthlyCF = primary ? primary.monthlyCF : 0;
    const primaryAnnualCF = primary ? primary.annualCF : 0;
    const primaryCoc = primary ? primary.coc : 0;
    const primaryADS = primary ? primary.ADS : 0;
    const primaryDSCR = primary ? primary.DSCR : 0;
    const primaryTotalIn = primary ? primary.totalIn : 0;
    const primaryPrice = primary ? primary.purchasePrice : 0;

    const rule2 = (primaryPrice > 0 && rentMonthly / primaryPrice >= 0.02) ? '✅' : '❌';
    const rule50 = (annualRent > 0 && opex <= annualRent * 0.5) ? '✅' : '❌';

    const investorsAnalysis = {
      'Gross Rent': money(rentMonthly),
      'Annual Rent': money(annualRent),
      'Operating Expenses': money(opex),
      NOI: money(noi),
      'Annual Debt Service (ADS)': money(primaryADS),
      DSCR: round(primaryDSCR || 0, 2).toFixed(2),
      'Monthly Cash-flow': money(primaryMonthlyCF),
      'Annual Cash-flow': money(primaryAnnualCF),
      'Total Cash In': money(primaryTotalIn),
      'Cash-on-Cash Return': pct(primaryCoc || 0, 1),
      '2% Rule': rule2,
      '50% Rule': rule50
    };

    let investorsAnalysisInsights = '';
    if (primary) {
      investorsAnalysisInsights =
        `${primary.type} is the current best creative path under locked metrics. ` +
        `DSCR is ${round(primaryDSCR || 0, 2).toFixed(2)}, monthly cash flow is ${money(primaryMonthlyCF)}, ` +
        `and cash-on-cash is ${pct(primaryCoc || 0, 1)}. ` +
        `${primary.pass ? 'This path clears the current rules.' : 'This path is the closest fit but still misses one or more investor targets.'}`;
    } else {
      investorsAnalysisInsights = 'No creative structure could be built from the current metrics.';
    }

    /***** ---------- [10] Assignment Fee Range ---------- *****/
    let assignmentFeeRange = '$3,000–$7,500';
    if (primaryMonthlyCF >= 500) assignmentFeeRange = '$8,000–$15,000';
    else if (primaryMonthlyCF >= 200) assignmentFeeRange = '$5,000–$12,000';

    /***** ---------- [11] Canonical Economics ---------- *****/
    const canonical = {
      economics: {
        grossRentMonthly: rentMonthly,
        annualRent,
        opexAnnual: opex,
        NOI: noi,
        ADS: primaryADS,
        DSCR: round(primaryDSCR || 0, 2),
        monthlyCF: primaryMonthlyCF,
        annualCF: primaryAnnualCF,
        totalCashIn: primaryTotalIn,
