// 2. MAIN LOGIC (Executing on the Webhook Object)
// ==========================================
const webhook = $('Start Webhook1').first().json || {};
const body = webhook.body || {};
const cd = body.customData || {};

const oppName = cleanSpaces(firstNonEmpty(
  cd.opportunityName,
  body.opportunity_name,
  body.opportunityName,
  ''
));

const parsedOppStreet = parseStreetFromOppName(oppName);

// STRICT address hierarchy
let rawAddress = cleanSpaces(firstNonEmpty(
  cd.opportunityAddress,
  cd.oppStreetAddress,
  parsedOppStreet,
  ''
));

if (rawAddress && rawAddress.includes(',')) {
  rawAddress = rawAddress.split(',')[0].trim();
}

const rawCity = cleanSpaces(firstNonEmpty(cd.city, body.city, ''));
const rawState = cleanSpaces(firstNonEmpty(cd.state, body.state, '')).toUpperCase();
const rawZip = normalizeZip(firstNonEmpty(cd.zip, body.postal_code, ''));

const rawPropType = firstNonEmpty(cd.prop_type, cd['opp.propertyStyle'], '');
const rawHouseStyle = firstNonEmpty(cd['opp.propertyStyle'], '');
const rawPropertyTypeField = firstNonEmpty( cd['opp.propertyStyle'], '');

const beds = parseNum(firstNonEmpty(cd.beds,  null));
const baths = parseNum(firstNonEmpty(cd.baths,  null));
const sqft = parseNum(firstNonEmpty(cd.squarefootage, null));
const unitCountExplicit = parseNum(firstNonEmpty(cd['opp.units'], null));

const listPrice = parseMoney(firstNonEmpty(cd['opp.listPrice'], cd.list_price, null));
