const yearBuilt = parseNum(firstNonEmpty(cd.yearBuilt, null));
const lotArea = parseNum(firstNonEmpty(cd['opp.lotArea'], null));

// Additional Custom Fields
const listStatus = cleanSpaces(firstNonEmpty(cd['opp.listStatus'], cd.listStatus, null));
const vacancyFlag = cleanSpaces(firstNonEmpty(cd['opp.vacancy'], cd.vacancy, null));
const ownerOccupied = cleanSpaces(firstNonEmpty(cd['opp.ownerOccupied'], cd.ownerOccupied, null));
