const estEquity = parseMoney(firstNonEmpty(cd['opp.estEquity'], cd.estEquity, null));
const highRentEst = parseMoney(firstNonEmpty(cd['highRentEst'], cd.highRentEst, null));
const lowRentEst = parseMoney(firstNonEmpty(cd['lowRentEst'], cd.lowRentEst, null));

const rawUwLoan1Balance = firstNonEmpty(cd['Loan 1 Balance'], cd['opp.totalAmountOfOpenLoans'], null);
const rawUwLoan1Monthly = firstNonEmpty(cd['Loan 1 Monthly payment'], null);
