const rawUwEstMonthly = firstNonEmpty(body['Uw Est Monthly Payment'], null);
const rawOrigPrincipal = firstNonEmpty(cd['loan 1 original principal'], null);


const transcriptA = cleanSpaces(firstNonEmpty(
  cd.prequalified_phone_transcript,
  cd.contact_pq_transcript,
  ''
));

const precall_mode = !(transcriptA);


const addressHasUnit = hasUnitMarker(rawAddress);
const strippedAddress = stripUnit(rawAddress);
const propertyType = canonicalPropertyType(rawPropType, rawHouseStyle, rawPropertyTypeField);
const is_multifamily = propertyType === 'Multi-Family';

// ==========================================
// NOTE EXTRACTIONS (Rent Roll, Beds/Baths)
// ==========================================
let extractedRentRoll = null;
const totalRentMatch = transcriptA.match(/\$?([\d,]+(?:\.\d{2})?)\/?mo\s*(?:total)?/i) || transcriptA.match(/\$?([\d,]+(?:\.\d{2})?)\s*(?:a|per)\s*month/i);
if (totalRentMatch) {
    extractedRentRoll = parseFloat(totalRentMatch[1].replace(/,/g, ''));
}
if (!extractedRentRoll) {
    const rentRegex = /(?:rent roll|gross rent|monthly rent|rents are)[^\d\$]*\$?([\d,]+(?:\.\d{2})?)/i;
    const rentMatch = transcriptA.match(rentRegex);
    if (rentMatch) {
        extractedRentRoll = parseFloat(rentMatch[1].replace(/,/g, ''));
    }
}

let extractedUnitBeds = null;
let extractedUnitBaths = null;
const directBedBathMatch = transcriptA.match(/(\d+(?:\.\d)?)\s*beds?\s*\/\s*(\d+(?:\.\d)?)\s*baths?/i);
if (directBedBathMatch) {
    extractedUnitBeds = parseFloat(directBedBathMatch[1]);
    extractedUnitBaths = parseFloat(directBedBathMatch[2]);
} else {
    const bedBathMatch = transcriptA.match(/(?:unit beds\/baths|beds\s*\/\s*baths|beds?\/baths?|beds\s*and\s*baths)[^\d]*(\d+(?:\.\d)?)\s*\/\s*(\d+(?:\.\d)?)/i);
    if (bedBathMatch) {
        extractedUnitBeds = parseFloat(bedBathMatch[1]);
        extractedUnitBaths = parseFloat(bedBathMatch[2]);
    }
}

// STRICT unit count logic
let unit_count = null;
if (!is_multifamily) {
  unit_count = 1;
} else if (unitCountExplicit && unitCountExplicit > 0) {
  unit_count = unitCountExplicit;
} else {
  let inferred = inferUnitCount(propertyType, transcriptA, addressHasUnit, sqft);
  if (inferred) unit_count = inferred;
}

let building_sqft = sqft;
let unit_sqft = null;
let building_beds = beds;
let unit_beds = null;
let building_baths = baths;
let unit_baths = null;

if (is_multifamily && unit_count && unit_count > 0) {
  if (extractedUnitBeds !== null) {
      unit_beds = extractedUnitBeds;
      building_beds = Math.round(unit_beds * unit_count);
  } else {
      unit_beds = beds ? +(beds / unit_count).toFixed(2) : null;
  }

  if (extractedUnitBaths !== null) {
      unit_baths = extractedUnitBaths;
      building_baths = Math.round(unit_baths * unit_count);
  } else {
      unit_baths = baths ? +(baths / unit_count).toFixed(2) : null;
  }
  unit_sqft = sqft ? Math.round(sqft / unit_count) : null;
}

const loan_1_balance = parseMoney(rawUwLoan1Balance);
let loan_1_monthly_payment = parseMoney(rawUwLoan1Monthly);
const loan_1_rate = parseMoney(rawLoan1Rate);
const total_open_loans_amount = parseMoney(rawTotalAmountOfOpen);
const est_monthly_payment = parseMoney(rawUwEstMonthly);
const loan_1_original_principal = parseMoney(rawOrigPrincipal);

 // Calculate missing P&I payment using standard 30-year amortization if rate and balance exist
if (loan_1_balance > 0 && loan_1_monthly_payment === 0 && loan_1_rate > 0) {
   const r = (loan_1_rate / 100) / 12;
   const n = 360; // Standard 30 yr default
   loan_1_monthly_payment = loan_1_balance * ( (r * Math.pow(1+r, n)) / (Math.pow(1+r, n) - 1) );
 }



// 🚨 PATCH 2: Debt Signal and Incomplete Logic
let loan_status = 'none';

// Only trigger a debt signal if a value is explicitly greater than zero
const debtSignalExists =
  (loan_1_balance != null && loan_1_balance > 0) || 
  (loan_1_monthly_payment != null && loan_1_monthly_payment > 0) || 
  (loan_1_rate != null && loan_1_rate > 0) ||
  (total_open_loans_amount != null && total_open_loans_amount > 0) || 
  (loan_1_original_principal != null && loan_1_original_principal > 0);

if (debtSignalExists) {
  // A loan is technically usable if we have a Balance AND a Monthly Payment.
  // OR, if we have a Balance AND an Interest Rate, the math engine can amortize the missing payment deterministically.
  const hasPaymentOrAmortization = (loan_1_monthly_payment != null && loan_1_monthly_payment > 0) || (loan_1_rate != null && loan_1_rate > 0);
  loan_status = (loan_1_balance > 0 && hasPaymentOrAmortization) ? 'usable' : 'incomplete';
}


let address_scope_confidence = 'high';
if (!rawAddress || !rawCity || !rawState || !rawZip) address_scope_confidence = 'low';
if (is_multifamily && !unit_count) address_scope_confidence = 'medium';

let package_sale_flag = false;
const ppsf = (lastSaleAmount && sqft) ? lastSaleAmount / sqft : 0;
if (is_multifamily && lastSaleAmount && ((assessedTotal && lastSaleAmount > assessedTotal * 2.5) || ppsf > 450 || lastSaleAmount >= 750000)) {
  package_sale_flag = true;
