  unit_beds: unit_beds || null,
  unit_baths: unit_baths || null,
  extracted_rent_roll: extractedRentRoll,

  loan_data: {
    loan_1_balance,
    loan_1_monthly_payment,
    loan_1_rate,
    total_open_loans_amount,
    est_monthly_payment,
    loan_1_original_principal,
    loan_status
  },

  source_assumptions: {
    sqft_input: sqft || null,
    beds_input: beds || null,
    baths_input: baths || null,
    house_style: rawHouseStyle || null,
    property_type_input: rawPropType || rawPropertyTypeField || null,
    assessed_total_value: assessedTotal || null,
    est_value: estValue || null,
    list_price: listPrice || null,
    last_sale_amount: lastSaleAmount || null,
    year_built: yearBuilt || null,
    lot_area: lotArea || null,
    list_status: listStatus,
    vacancy_flag: vacancyFlag,
    owner_occupied_flag: ownerOccupied,
    is_outreach_property: isOutreachProperty,
    est_equity_raw: estEquity,
    highRentEst: highRentEst,
