  },

  guards: {
    block_if_missing_address: !rawAddress || !rawCity || !rawState || !rawZip,
    block_if_unit_count_unknown: is_multifamily && !unit_count,
    block_if_loan_incomplete: loan_status === 'incomplete',
    block_if_short_sale_like: /short sale|pre-foreclosure/i.test(transcriptA) || "",
  }
};

return [{ json: { ...webhook, resolved } }];

