/******************************************************
 OFFER ENGINE v2.1 (Canonical + Webhook Compatible)
 -----------------------------------------------------
 Purpose:
  - Consume ONE canonical merged input item
  - Trust locked upstream metrics / property / loan data
  - ALSO read raw webhook/customData fields when upstream normalizers miss
  - Build:
      • Cash MAO
      • CTS engine
      • Seller Finance candidates
      • Subject-To candidates
      • Hybrid candidates
  - Always return 3 outputs:
      • Primary Offer
      • Backup Offer
      • Updated Cash Offer
  - Never leave Primary / Backup blank when a creative scenario should still
    be shown for educational / negotiation purposes

 Does NOT own:
  - lead scoring
  - stage routing
  - LOI generation
******************************************************/

function num(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  const n = Number(String(v).replace(/[^\d.-]/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function txt(v) {
  return String(v ?? '').trim();
}

function lower(v) {
  return txt(v).toLowerCase();
}

function pick() {
  for (const v of arguments) {
    if (v === 0) return 0;
    if (v === undefined || v === null) continue;
    if (typeof v === 'string') {
      if (v.trim() !== '') return v;
      continue;
    }
    return v;
  }
  return null;
}

function money(n, digits = 0) {
  const v = Number.isFinite(n) ? n : 0;
  return `$${v.toLocaleString('en-US', {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits
  })}`;
}

function pct(n, digits = 1) {
  const v = Number.isFinite(n) ? n : 0;
  return `${v.toFixed(digits)}%`;
}

function round(n, digits = 0) {
  const p = Math.pow(10, digits);
  return Math.round((Number(n) || 0) * p) / p;
}

function clamp(v, min, max) {
  return Math.min(max, Math.max(min, v));
}

function pmt(rateAnnualPct, years, principal) {
  const P = Number(principal) || 0;
  const y = Number(years) || 0;
  const r = (Number(rateAnnualPct) || 0) / 100 / 12;
  const n = y * 12;
  if (P <= 0 || n <= 0) return 0;
  if (r === 0) return P / n;
  return (P * r) / (1 - Math.pow(1 + r, -n));
}

function uniqRounded(nums) {
  const seen = new Set();
  const out = [];
  for (const raw of nums) {
    const v = Math.round(num(raw));
    if (v > 0 && !seen.has(v)) {
      seen.add(v);
      out.push(v);
    }
  }
  return out;
}

function hasSignal(s, rx) {
  return rx.test(lower(s));
}

function maxBy(arr, fn) {
  if (!arr.length) return null;
  return arr.reduce((best, cur) => (fn(cur) > fn(best) ? cur : best), arr[0]);
}

function deepClone(obj) {
  return JSON.parse(JSON.stringify(obj ?? {}));
}

function safeTranscript(root, output) {
  return (
    root?.transcript?.output ||
    root?.transcript ||
    output?.transcript?.output ||
    output?.transcript ||
    root?.transcript_insights ||
    output?.transcript_insights ||
    {}
  );
}

function safeArray(v) {
  return Array.isArray(v) ? v : [];
}

function candidateFailPenalty(c) {
  let penalty = 0;

  if (c.family === 'seller_finance' || c.family === 'hybrid') {
    if (c.DSCR < 1.2) penalty += (1.2 - c.DSCR) * 1000;
    if (c.monthlyCF < 200) penalty += (200 - c.monthlyCF) * 5;
    if (c.coc < 13) penalty += (13 - c.coc) * 50;
  }

  if (c.family === 'subto') {
    if (c.DSCR < 1.0) penalty += (1.0 - c.DSCR) * 1000;
    if (c.monthlyCF < 150) penalty += (150 - c.monthlyCF) * 4;
  }

  if (c.entryPct > 15) penalty += (c.entryPct - 15) * 20;
  if (c.downPct > 10) penalty += (c.downPct - 10) * 25;
  if (c.balloonYrs !== null && c.balloonYrs < 5) penalty += (5 - c.balloonYrs) * 100;

  return penalty;
}

function candidateScore(c) {
  if (!c) return -1e12;
  const passBoost = c.pass ? 1000000 : 0;
  return (
    passBoost +
    (c.monthlyCF * 25) +
    (c.DSCR * 100) +
    (c.coc * 10) -
    (c.totalIn * 0.01) -
    candidateFailPenalty(c)
  );
}

function preferredFamilyForDeal(loanBalance, equityPct, takeoverSignals) {
  if (takeoverSignals && loanBalance > 0) return 'subto';
  if (loanBalance <= 0) return 'seller_finance';
  if (equityPct < 15) return 'subto';
  if (equityPct <= 80) return 'hybrid';
  return 'seller_finance';
}

function familyOrderForPrimary(preferredFamily) {
  if (preferredFamily === 'subto') return ['subto', 'hybrid', 'seller_finance'];
  if (preferredFamily === 'hybrid') return ['hybrid', 'seller_finance', 'subto'];
  return ['seller_finance', 'hybrid', 'subto'];
}

function familyOrderForBackup(preferredFamily) {
  if (preferredFamily === 'subto') return ['hybrid', 'seller_finance', 'subto'];
  if (preferredFamily === 'hybrid') return ['seller_finance', 'subto', 'hybrid'];
  return ['hybrid', 'subto', 'seller_finance'];
}

function selectCandidate(allCandidates, preferredFamily, mode = 'primary', excludeIds = new Set()) {
  const order = mode === 'backup'
    ? familyOrderForBackup(preferredFamily)
    : familyOrderForPrimary(preferredFamily);

  const pool = allCandidates.filter(c => !excludeIds.has(c.id));

  for (const family of order) {
    const passing = pool.filter(c => c.family === family && c.pass);
    if (passing.length) return maxBy(passing, candidateScore);
  }

  const anyPassing = pool.filter(c => c.pass);
  if (anyPassing.length) return maxBy(anyPassing, candidateScore);

  for (const family of order) {
    const familyPool = pool.filter(c => c.family === family);
    if (familyPool.length) return maxBy(familyPool, candidateScore);
  }

  return pool.length ? maxBy(pool, candidateScore) : null;
}

function formatOffer(candidate, tiMonthly, loanBalance, loanRate, label) {
  if (!candidate) {
    return {
      Type: 'No viable creative offer',
      'Purchase Price': 'N/A',
      'Cash to Seller': 'N/A',
      'Down Payment ($)': 'N/A',
      'Down Payment (%)': 'N/A',
      'Interest Rate (%)': 'N/A',
      'Loan Rate (%)': 'N/A',
      'Amortization (Years)': null,
      'Balloon Term (Years)': null,
      'Monthly Payment (PI)': 'N/A',
      'Monthly Taxes and Insurance (TI)': money(tiMonthly),
      ADS: 'N/A',
      DSCR: 'N/A',
      'Monthly Cash-flow': 'N/A',
      'Cash-on-Cash Return': 'N/A',
      'Total Entry Fee': 'N/A',
      'Deal Viable': false,
      Justification: `${label} not available under current metrics.`
    };
  }

  const out = {
    Type: candidate.type,
    'Purchase Price': money(candidate.purchasePrice),
    'Cash to Seller': money(candidate.cashToSeller || 0),
    'Down Payment ($)': money(candidate.down$ || 0),
    'Down Payment (%)': pct(candidate.downPct || 0, 1),
    'Interest Rate (%)': candidate.ratePct != null ? String(candidate.ratePct) : 'N/A',
    'Loan Rate (%)': candidate.ratePct != null ? String(candidate.ratePct) : 'N/A',
    'Amortization (Years)': candidate.years || candidate.carryYears || null,
    'Balloon Term (Years)': candidate.balloonYrs ?? null,
    'Monthly Payment (PI)': money(candidate.monthPI || 0, 2),
    'Monthly Taxes and Insurance (TI)': money(tiMonthly),
    ADS: money(candidate.ADS || 0),
    DSCR: round(candidate.DSCR || 0, 2).toFixed(2),
    'Monthly Cash-flow': money(candidate.monthlyCF || 0),
    'Cash-on-Cash Return': pct(candidate.coc || 0, 1),
    'Total Entry Fee': money(candidate.totalIn || 0),
    'Deal Viable': !!candidate.pass,
    Justification: candidate.justification
  };

  if (candidate.family === 'seller_finance') {
    out['Financed Amount'] = money(candidate.financed || 0);
    out['Seller Carryback Loan'] = money(candidate.financed || 0);
    out['Seller Carryback Interest Rate'] = candidate.ratePct != null ? String(candidate.ratePct) : 'N/A';
    out['Seller Carryback Monthly Payment (PI)'] = money(candidate.monthPI || 0, 2);
    out['Combined Monthly Payment (PI)'] = money(candidate.monthPI || 0, 2);
    out['Existing Loan Balance'] = money(0);
    out['Existing Loan Interest Rate'] = 'N/A';
    out['Existing Loan Monthly Payment (PI)'] = 'N/A';
  }

  if (candidate.family === 'subto') {
    out['Existing Loan Balance'] = money(loanBalance);
    out['Existing Loan Interest Rate'] = loanRate ? String(loanRate) : 'N/A';
    out['Existing Loan Monthly Payment (PI)'] = money(candidate.firstPI || 0, 2);
    out['Combined Monthly Payment (PI)'] = money(candidate.firstPI || 0, 2);
    out['Financed Amount'] = money(loanBalance);
    out['Seller Carryback Loan'] = money(0);
    out['Seller Carryback Interest Rate'] = 'N/A';
    out['Seller Carryback Monthly Payment (PI)'] = money(0, 2);
  }

  if (candidate.family === 'hybrid') {
    out['Existing Loan Balance'] = money(loanBalance);
    out['Existing Loan Interest Rate'] = loanRate ? String(loanRate) : 'N/A';
    out['Existing Loan Monthly Payment (PI)'] = money(candidate.firstPI || 0, 2);
    out['Seller Carryback Loan'] = money(candidate.carryPrincipal || 0);
    out['Seller Carryback Interest Rate'] = candidate.carryRate != null ? String(candidate.carryRate) : 'N/A';
    out['Seller Carryback Monthly Payment (PI)'] = money(candidate.carryPI || 0, 2);
    out['Combined Monthly Payment (PI)'] = money(candidate.monthPI || 0, 2);
    out['Financed Amount'] = money((loanBalance || 0) + (candidate.carryPrincipal || 0));
  }

  return out;
}

