    if (asIsValue > 0 && arv > 0 && asIsValue > arv) warnings.push(`As-is value (${money(asIsValue)}) is above ARV (${money(arv)}). Check value inputs and condition assumptions.`);

    /***** ---------- [3] Seller / Deal Signals ---------- *****/
    const rawTranscript = [
      txt(transcript.sellerUrgency),
