    ].join(' ');

    const dom = num(pick(property.dom, property.mls?.daysOnMarket, root.sale_listing_source?.daysOnMarket, metrics.dom));

    const motivationHigh =
      hasSignal(rawTranscript, /\b(hard money|refi|refinance|must sell|urgent|asap|one to two weeks|financial stress|probate|inherited|vacant|out of state|downsizing|relocated|short sale)\b/i) ||
      dom >= 90;

    const competitionHigh =
      hasSignal(rawTranscript, /\b(multiple offers|offer in hand|bidding war|interested buyer)\b/i);

    const mlsListStatus = lower(pick(
      lead['opp.mlsListStatus'],
      lead.mlsListStatus,
      lead['opp.listStatus'],
      property.mls?.status,
      property.list_status,
