function parseMoney(x) {
  if (x === undefined || x === null || x === '') return 0;
  if (typeof x === 'number') return Number.isFinite(x) ? x : 0;
  const s = String(x).replace(/[^\d.\-]/g, '');
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
}

function firstNonEmpty(...vals) {
  for (const v of vals) {
    if (v === 0) return 0;
    if (v === null || v === undefined) continue;
    if (typeof v === 'string' && v.trim() !== '') return v;
    if (typeof v === 'number' && Number.isFinite(v)) return v;
  }
  return null;
}

function txt(v) {
  return String(v ?? '').trim();
}

function round(n, digits = 0) {
  const p = Math.pow(10, digits);
  return Math.round((Number(n) || 0) * p) / p;
}

function median(nums) {
  const arr = nums.filter(n => Number.isFinite(n)).sort((a, b) => a - b);
  if (!arr.length) return 0;
  const mid = Math.floor(arr.length / 2);
  return arr.length % 2 ? arr[mid] : (arr[mid - 1] + arr[mid]) / 2;
}

function avg(nums) {
  const arr = nums.filter(n => Number.isFinite(n));
  if (!arr.length) return 0;
  return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function safeNode(name, fallback = {}) {
  try {
    const v = $(name).first().json;
    return v ?? fallback;
  } catch {
    return fallback;
  }
}

function moneyStr(n) {
  if (!Number.isFinite(n) || n <= 0) return null;
  return `$${Math.round(n).toLocaleString(undefined, { maximumFractionDigits: 0 })}.00`;
}

function clamp(n, min, max) {
  return Math.min(max, Math.max(min, n));
}

function amortizedPI(balance, annualRatePct, years = 30) {
  const P = parseMoney(balance);
  const rate = parseMoney(annualRatePct);
  if (P <= 0 || rate <= 0) return 0;
  const r = (rate / 100) / 12;
  const n = years * 12;
  return P * ((r * Math.pow(1 + r, n)) / (Math.pow(1 + r, n) - 1));
}

function isReasonableAsIs(candidate, anchors = {}) {
  const v = parseMoney(candidate);
  if (v <= 0) return false;

  const list = parseMoney(anchors.listPrice);
  const compLow = parseMoney(anchors.compLow);
  const market = parseMoney(anchors.marketValue);

  if (list > 0 && v < list * 0.60) return false;
  if (compLow > 0 && v < compLow * 0.55) return false;
  if (market > 0 && v < market * 0.55) return false;

  return true;
}

function chooseAsIsValue(candidates, anchors, warnings) {
  for (const c of candidates) {
    const value = parseMoney(c.value);
    if (!value) continue;

    if (!c.requiresSanity || isReasonableAsIs(value, anchors)) {
      return {
        value,
        source: c.source,
        confidence: c.confidence
      };
    } else {
      warnings.push(`Rejected ${c.source} for as-is value because it failed sanity checks: $${Math.round(value).toLocaleString()}.`);
    }
  }

  if (parseMoney(anchors.listPrice) > 0) {
    const fallback = Math.round(parseMoney(anchors.listPrice) * 0.90);
    warnings.push('As-is value fell back to 90% of list price because stronger sources were missing or failed sanity checks.');
    return {
      value: fallback,
      source: 'fallback_list_price_90pct',
      confidence: 'low'
    };
  }

  if (parseMoney(anchors.compLow) > 0) {
    warnings.push('As-is value fell back to comp_low because stronger sources were missing.');
    return {
      value: parseMoney(anchors.compLow),
      source: 'fallback_comp_low',
      confidence: 'low'
    };
  }

  return {
    value: 0,
    source: 'missing',
    confidence: 'none'
  };
}

function buildCompReport(comparables) {
  if (!Array.isArray(comparables)) return [];
  return comparables.slice(0, 10).map(c => ({
    address: c.formattedAddress || c.address || null,
    correlation: c.correlation != null ? round(parseMoney(c.correlation) * (parseMoney(c.correlation) <= 1 ? 100 : 1), 1) : null,
    price: parseMoney(c.price) || null,
    beds: parseMoney(c.bedrooms) || null,
    baths: parseMoney(c.bathrooms) || null,
    squareFootage: parseMoney(c.squareFootage) || null,
    daysOnMarket: c.daysOnMarket ?? null,
    distance: parseMoney(c.distance) || null
  }));
}

