    }

    if (beds > 0) score -= Math.abs(compBeds - beds) * 8;
    if (baths > 0) score -= Math.abs(compBaths - baths) * 8;

    if (yearBuilt && compYear) {
      score -= Math.min(Math.abs(compYear - yearBuilt) / 2, 12);
    }

    if (locationCtx.same_building_priority && sameText(c.addressLine1, subjectAddress1)) {
      score += 80;
    }

    if (
      locationCtx.same_subdivision_priority &&
      subjectSubdivision &&
      String(c.subdivision || '').toLowerCase().includes(subjectSubdivision.toLowerCase())
    ) {
      score += 40;
    }

    if (locationCtx.comp_tier_mode === 'tier_1_hyperlocal') {
      if (dist <= 0.10) score += 18;
      else if (dist <= 0.25) score += 10;
    }

    return score;
  }

  let validSaleComps = [];
  let ppsfArv = 0;
  let ppsfArvSource = 'missing';

  if (saleComparables.length) {
    const maxDist = compDistanceLimit(locationCtx);

    validSaleComps = saleComparables.filter(c => {
      const price = parseMoney(c.price);
      const compSqft = parseMoney(c.squareFootage);
      const compBeds = parseMoney(c.bedrooms);
      const compBaths = parseMoney(c.bathrooms);
      const dist = parseMoney(c.distance);

      if (price <= 0 || compSqft <= 0) return false;
      if (dist > maxDist) return false;
      if (beds > 0 && compBeds > 0 && Math.abs(compBeds - beds) > 1) return false;
      if (baths > 0 && compBaths > 0 && Math.abs(compBaths - baths) > 1) return false;

      if (sqft > 0) {
        const ratio = compSqft / sqft;
        if (ratio < 0.75 || ratio > 1.25) return false;
      }

      return true;
    });

    if (locationCtx.comp_tier_mode === 'tier_1_hyperlocal') {
      const sameBuilding = validSaleComps.filter(c =>
        sameText(c.addressLine1, subjectAddress1)
      );

      if (sameBuilding.length >= 2) {
        validSaleComps = sameBuilding;
        ppsfArvSource = 'same_building_weighted_median_ppsf';
        warnings.push('ARV used same-building hyperlocal comp set.');
      } else if (locationCtx.same_subdivision_priority && subjectSubdivision) {
        const sameSubdivision = validSaleComps.filter(c =>
          String(c.subdivision || '').toLowerCase().includes(subjectSubdivision.toLowerCase())
        );

        if (sameSubdivision.length >= 2) {
          validSaleComps = sameSubdivision;
          ppsfArvSource = 'same_subdivision_weighted_median_ppsf';
          warnings.push('ARV used same-subdivision hyperlocal comp set.');
        }
      }
    }

    const scored = validSaleComps
      .map(c => ({
        comp: c,
        score: compScore(c),
        ppsf: parseMoney(c.price) / parseMoney(c.squareFootage)
      }))
      .filter(x => Number.isFinite(x.ppsf) && x.ppsf > 0 && Number.isFinite(x.score))
      .sort((a, b) => b.score - a.score)
      .slice(0, 8);

    if (scored.length) {
      const ppsfValues = scored.map(x => x.ppsf);
      const med = median(ppsfValues);
      const trimmed = scored.filter(x => x.ppsf >= med * 0.70 && x.ppsf <= med * 1.30);

      const finalSet = trimmed.length >= 3 ? trimmed : scored;
      const values = finalSet.map(x => x.ppsf);
      const weights = finalSet.map(x => Math.max(1, x.score));

      const chosenPpsf = weightedMedian(values, weights);

      ppsfArv = Math.round(
        chosenPpsf * (sqft > 0 ? sqft : parseMoney(compsNode.subjectProperty?.squareFootage) || 1500)
      );

      if (ppsfArvSource === 'missing') {
        ppsfArvSource =
          locationCtx.comp_tier_mode === 'tier_1_hyperlocal'
            ? 'hyperlocal_weighted_median_ppsf'
            : locationCtx.comp_tier_mode === 'tier_2_subdivision_sensitive'
              ? 'subdivision_sensitive_weighted_median_ppsf'
              : 'standard_weighted_median_ppsf';
      }
    }
  }

  // ------------------------------------------
  // Market / AVM candidates
  // ------------------------------------------
  const saleAvmEstimate = parseMoney(firstNonEmpty(saleNode.estValue, saleNode.est_value, 0));

  const marketValueEstimate = parseMoney(firstNonEmpty(
    it.market_data_extracted?.estimatedMarketValue,
    it.market_data_trends?.estimatedMarketValue,
    0
  ));

  // ------------------------------------------
  // As-is value selection
  // ------------------------------------------
  const asIsCandidates = [
    { source: 'sale_avm_estimate', value: saleAvmEstimate, confidence: 'medium', requiresSanity: true },
    { source: 'normalized_est_value', value: normalizedEstValue, confidence: 'medium', requiresSanity: true },
    { source: 'comp_low', value: compLow, confidence: 'medium', requiresSanity: true },
    { source: 'market_value_estimate', value: marketValueEstimate, confidence: 'low', requiresSanity: true },
    { source: 'list_price', value: listPrice, confidence: 'low', requiresSanity: false },
    { source: 'tax_assessed_value', value: taxAssessedValue, confidence: 'low', requiresSanity: false }
  ];

  const asIsPick = chooseAsIsValue(asIsCandidates, {
    listPrice,
    compLow,
    marketValue: marketValueEstimate
  }, warnings);

  const as_is_value = asIsPick.value;
  const as_is_value_source = asIsPick.source;
  const as_is_value_confidence = asIsPick.confidence;

  // ------------------------------------------
  // ARV selection
  // ------------------------------------------
  let arv = 0;
  let arv_source = 'missing';

  if (oppArv > 0) {
    arv = oppArv;
    arv_source = 'normalized_est_arv_override';
  } else if (ppsfArv > 0) {
    arv = ppsfArv;
    arv_source = ppsfArvSource || 'weighted_median_ppsf';
  } else if (compMid > 0) {
    arv = compMid;
    arv_source = 'comps_api_price';
  } else if (compHigh > 0) {
    arv = compHigh;
    arv_source = 'comp_high_fallback';
  } else if (marketValueEstimate > 0) {
    arv = Math.round(marketValueEstimate * 1.10);
    arv_source = 'market_value_plus_10pct';
    warnings.push('ARV missing from sale comps API. Derived from market value estimate + 10%.');
  } else if (listPrice > 0) {
    arv = Math.round(listPrice * 1.10);
    arv_source = 'list_price_plus_10pct';
    warnings.push('ARV missing from sale comps API. Derived from list price + 10%.');
  } else if (as_is_value > 0) {
    arv = Math.round(as_is_value * 1.15);
    arv_source = 'as_is_plus_15pct';
    warnings.push('ARV missing from sale comps API. Derived from as-is value + 15%.');
  }

  if (taxAssessedValue > 0 && arv > 0 && arv < taxAssessedValue) {
    warnings.push(`ARV ($${Math.round(arv).toLocaleString()}) came in below county assessed value ($${Math.round(taxAssessedValue).toLocaleString()}). Kept ARV unchanged; assessed value is reference-only.`);
  }

  if (arv > 0 && as_is_value > 0 && as_is_value > arv) {
    warnings.push(`As-is value ($${Math.round(as_is_value).toLocaleString()}) is above ARV ($${Math.round(arv).toLocaleString()}). Check value inputs and condition assumptions.`);
  }

  // ------------------------------------------
  // Repair estimate
  // ------------------------------------------
  let estimatedRepairCost = parseMoney(firstNonEmpty(
    cd.repair_costs,
    cd.repairs,
    cd.EstimatedRepairs,
    cd['PQ | Estimated Repairs $'],
    null
  ));

  if (!estimatedRepairCost) {
    estimatedRepairCost = sqft > 0 ? Math.round(sqft * 20) : 30000;
  }

  // ------------------------------------------
  // Rent
  // ------------------------------------------
  let marketRent = parseMoney(firstNonEmpty(
    res.extracted_rent_roll,
    res.extractedRentRoll,
    canonicalGrossRent
  ));

  if (!res.extracted_rent_roll && Array.isArray(rentalNode.comparables) && rentalNode.comparables.length > 0) {
    let validRents = rentalNode.comparables.filter(c => parseMoney(c.price) > 0);

    validRents = validRents.filter(c => {
      const dist = parseMoney(c.distance);
      const compBeds = parseMoney(c.bedrooms);
      const compBaths = parseMoney(c.bathrooms);
      const compSqft = parseMoney(c.squareFootage);

      if (dist > 2) return false;
      if (rentBeds > 0 && compBeds > 0 && Math.abs(compBeds - rentBeds) > 1) return false;
      if (rentBaths > 0 && compBaths > 0 && Math.abs(compBaths - rentBaths) > 1) return false;

      if (rentSqft > 0 && compSqft > 0) {
        const ratio = compSqft / rentSqft;
        if (ratio < 0.75 || ratio > 1.25) return false;
      }

      return true;
    });

    if (validRents.length > 0) {
      marketRent = Math.round(avg(validRents.map(c => parseMoney(c.price))));
    }
  }

  if (canonicalGrossRent > 0) {
    marketRent = canonicalGrossRent;
  }

  const annualRent = marketRent * 12;
  const proFormaRent = arv > 0 ? Math.round(arv * 0.01) : 0;

  // ------------------------------------------
  // Taxes / insurance / opex
  // ------------------------------------------
  const HIGH_RISK_INS_STATES = new Set(['FL', 'TX', 'LA', 'OK', 'AL', 'MS', 'SC', 'NC', 'GA', 'CA']);
  const insuranceRate = HIGH_RISK_INS_STATES.has(state) ? 0.012 : 0.006;
  const defaultTaxRate = 0.0115;

  let propertyTaxActual = 0;
  try {
    const propData = propNode.propertyTaxes ? propNode : (compsNode.subjectProperty || {});
    if (propData && propData.propertyTaxes) {
      propertyTaxActual =
        parseMoney(propData.propertyTaxes?.['2026']?.total) ||
        parseMoney(propData.propertyTaxes?.['2025']?.total) ||
        parseMoney(propData.propertyTaxes?.['2024']?.total) ||
        parseMoney(propData.propertyTaxes?.['2023']?.total) ||
        0;
    }
  } catch {}

  let taxes = parseMoney(firstNonEmpty(
    res.annual_taxes,
    res.source_assumptions?.annual_taxes,
    cd['annual taxes'],
    cd['anual taxes'],
    cd['PQ | Annual Property Taxes'],
    propertyTaxActual,
    listPrice > 0 ? Math.round(listPrice * defaultTaxRate) : 0,
    as_is_value > 0 ? Math.round(as_is_value * defaultTaxRate) : 0,
    arv > 0 ? Math.round(arv * defaultTaxRate) : 0
  ));

  let insurance = parseMoney(firstNonEmpty(
    cd.insuranceAnnual,
    cd.insuranceMonthly ? Math.round(parseMoney(cd.insuranceMonthly) * 12) : 0,
    0
  ));

  if (!insurance) {
    if (taxes > 0) insurance = Math.round(taxes * (HIGH_RISK_INS_STATES.has(state) ? 1.2 : 0.8));
    else insurance = Math.round((listPrice || as_is_value || arv || 100000) * insuranceRate);
  }

  const isSmallMulti = /(duplex|triplex|fourplex|quad|multi)/.test(propType);
  const isRVPark = /\b(rv park|mobile home park|campground|mhp|rv resort)\b/.test(propType) ||
                   /\b(rv park|mobile home park|campground)\b/i.test(mlsDesc);

  let mgmtRate = rental.assumptions?.mgmtRate ?? (isSmallMulti ? 0.09 : (isRVPark ? 0.12 : 0.08));
  let maintRate = rental.assumptions?.maintRate ?? (isSmallMulti ? 0.07 : (isRVPark ? 0.15 : 0.05));
  let vacancyRate = rental.assumptions?.vacancyRate ?? (isSmallMulti ? 0.07 : (isRVPark ? 0.10 : 0.05));

  if (yearBuilt && yearBuilt < 1980 && !isRVPark) maintRate += 0.02;

  const mgmt = Math.round(mgmtRate * annualRent);
  const maint = Math.round(maintRate * annualRent);
  const vacancy = Math.round(vacancyRate * annualRent);
  const utilitiesRate = rental.assumptions?.utilitiesIncluded ? 0.10 : (isRVPark ? 0.10 : 0);
  const utilities = Math.round(utilitiesRate * annualRent);

  const opex = mgmt + maint + vacancy + utilities + taxes + insurance;
  const noi = annualRent - opex;
  const tiMonthly = (taxes + insurance) / 12;

  // ------------------------------------------
  // Existing loan
  // ------------------------------------------
  const loanData = res.loan_data || {};

  const loanBalance = parseMoney(firstNonEmpty(
    loanData.loan_1_balance,
    loanData.total_open_loans_amount,
    cd['Loan 1 Balance'],
    cd['opp.totalAmountOfOpenLoans'],
    0
  ));

  const loanRate = parseMoney(firstNonEmpty(
    loanData.loan_1_rate,
    cd['Loan 1 rate'],
    cd['Loan 1 Rate'],
    0
  ));

  let sellerMonthlyPaymentPI = parseMoney(firstNonEmpty(
    loanData.loan_1_monthly_payment,
    cd['Loan 1 Monthly payment'],
    0
  ));

  const originalPrincipal = parseMoney(firstNonEmpty(
    loanData.loan_1_original_principal,
    cd['loan 1 original principal'],
    cd['Loan 1 Original Principal'],
    0
  ));

  if (loanBalance > 0 && sellerMonthlyPaymentPI === 0 && loanRate > 0) {
    sellerMonthlyPaymentPI = amortizedPI(loanBalance, loanRate, 30);
  }

  let rawLtv = parseMoney(firstNonEmpty(cd.l_to_v_ratio, null));
  let ltv = null;

  if (rawLtv) ltv = rawLtv > 1 ? rawLtv / 100 : rawLtv;
  if (ltv !== null) ltv = clamp(ltv, 0, 1.25);

  let equity_pct = null;

  if (ltv !== null) {
    equity_pct = (1 - ltv) * 100;
  } else if (as_is_value > 0 && loanBalance > 0) {
    equity_pct = ((as_is_value - loanBalance) / as_is_value) * 100;
  } else if (loanBalance <= 0) {
    equity_pct = 100;
  }

  if (equity_pct !== null) equity_pct = clamp(equity_pct, -100, 100);

  // ------------------------------------------
  // Summaries
  // ------------------------------------------
  const comp_properties_report = buildCompReport(saleComparables);

  let comps_summary = '';
  if (comp_properties_report.length) {
    const prices = comp_properties_report.map(c => parseMoney(c.price)).filter(Boolean);
    const low = prices.length ? Math.min(...prices) : 0;
    const high = prices.length ? Math.max(...prices) : 0;

    comps_summary =
      `Top ${Math.min(comp_properties_report.length, 10)} sale comps support a broad value range of ` +
      `${low > 0 ? `$${Math.round(low).toLocaleString()}` : 'N/A'} to ` +
      `${high > 0 ? `$${Math.round(high).toLocaleString()}` : 'N/A'} for comparable properties. ` +
      `Selected ARV source: ${arv_source}. Selected as-is source: ${as_is_value_source}.`;
  }

  // ------------------------------------------
  // Property object
  // ------------------------------------------
  const property = {
    address,
    city,
    state,
    postal_code: postal,
    list_price: moneyStr(listPrice),
    est_value: as_is_value || null,
    arv_value: arv || null,
    beds,
    baths,
    year_built_mls: yearBuilt,
    dom,
    mls_description: mlsDesc || null,
    mls: {
      number: saleNode.mlsNumber || null,
      name: saleNode.mlsName || null,
      status: saleNode.status || null,
      listedDate: saleNode.listedDate || null,
      lastSeenDate: saleNode.lastSeenDate || null,
      price_num: listPrice || 0
    }
  };

  const existing_loan = {
    balance: loanBalance || 0,
    sellerMonthlyPaymentPI: sellerMonthlyPaymentPI || 0,
    rate: loanRate || 0,
    original_principal: originalPrincipal || 0,
    ltv: ltv !== null ? Number(ltv.toFixed(4)) : null
  };

  const metrics = {
    list_price: listPrice || 0,
    as_is_value,
    arv,
    comp_low: compLow || 0,
    comp_high: compHigh || 0,
    price: listPrice || 0,
    city,
    state,
    bedrooms: beds,
    bathrooms: baths,
    propertyType: propType,
    sqft,
    yearBuilt,
    grossRent: marketRent,
    proFormaRent,
    annualRent,
    estimatedRepairCost,
    taxes,
    insurance,
    mgmt,
    maint,
    vacancy,
    opex,
    noi,
    estValue: as_is_value,
    equity_pct: equity_pct !== null ? round(equity_pct, 2) : null,
    tiMonthly: round(tiMonthly, 2),

    list_price_source: listPriceSource,
    as_is_value_source,
    as_is_value_confidence,
    arv_source,
    raw_value_candidates: {
      normalized_est_arv: oppArv || 0,
      normalized_est_value: normalizedEstValue || 0,
      sale_avm_estimate: saleAvmEstimate || 0,
      market_value_estimate: marketValueEstimate || 0,
      comp_low: compLow || 0,
      comp_mid: compMid || 0,
      comp_high: compHigh || 0,
      tax_assessed_value: taxAssessedValue || 0,
      list_price: listPrice || 0
    }
  };

  const config = {
    insuranceRate,
    mgmtRate,
    maintRate,
    vacancyRate,
    assignmentPctOfDown: 0.25,
    closingCostRate: 0.08,
    taxRate: defaultTaxRate
  };

  const rental_estimates = it.rental_estimates || null;
  const padsplit_current_vs_target = it.rental_models?.padsplit?.debug || {};

  const canonical = {
    rental_model: canonicalKey,
    economics: {
      grossRentMonthly: marketRent,
      annualRent,
      opexAnnual: opex,
      NOI: noi,
      ADS: null,
      DSCR: null,
      monthlyCF: null,
      annualCF: null,
      totalCashIn: null,
      CoC_pct: null
    }
  };

  results.push({
    json: {
      ...it,
      estimated_arv: arv || 0,
      comp_properties_report,
      comps_summary,
      property,
      rental_estimates,
      existing_loan,
      metrics,
      config,
      canonical,
      padsplit_current_vs_target,
      warnings
    }
  });
}

return results;

## 

/******************************************************
 OFFER ENGINE v3.0
 -----------------------------------------------------
 Purpose:
  - Consume ONE canonical merged input item
  - Trust locked upstream metrics / property / loan data
  - Also read normalized subject + raw webhook/customData fallback
  - Build:
      • Cash MAO
      • CTS engine
      • Seller Finance candidates
      • Subject-To candidates
      • Hybrid candidates
  - Always return 3 outputs:
      • Primary Offer
      • Backup Offer
      • Updated Cash Offer
  - Never return blank creative slots
  - Fix cash flow math so OPEX is not ignored and TI is not double-counted
  - Add break-even rent + rent gap + payback metrics

 Does NOT own:
  - lead scoring
  - stage routing
  - LOI generation
******************************************************/

function num(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  const n = Number(String(v).replace(/[^\d.-]/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function txt(v) {
  return String(v ?? '').trim();
}

function lower(v) {
  return txt(v).toLowerCase();
}

function pick() {
  for (const v of arguments) {
    if (v === 0) return 0;
    if (v === false) return false;
    if (v === undefined || v === null) continue;
    if (typeof v === 'string') {
      if (v.trim() !== '') return v;
      continue;
    }
    return v;
  }
  return null;
}

function money(n, digits = 0) {
  const v = Number.isFinite(n) ? n : 0;
  return `$${v.toLocaleString('en-US', {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits
  })}`;
}

function pct(n, digits = 1) {
  const v = Number.isFinite(n) ? n : 0;
  return `${v.toFixed(digits)}%`;
}

function round(n, digits = 0) {
  const p = Math.pow(10, digits);
  return Math.round((Number(n) || 0) * p) / p;
}

function clamp(v, min, max) {
  return Math.min(max, Math.max(min, v));
}

function pmt(rateAnnualPct, years, principal) {
  const P = Number(principal) || 0;
  const y = Number(years) || 0;
  const r = (Number(rateAnnualPct) || 0) / 100 / 12;
  const n = y * 12;
  if (P <= 0 || n <= 0) return 0;
  if (r === 0) return P / n;
  return (P * r) / (1 - Math.pow(1 + r, -n));
}

function uniqRounded(nums) {
  const seen = new Set();
  const out = [];
  for (const raw of nums) {
    const v = Math.round(num(raw));
    if (v > 0 && !seen.has(v)) {
      seen.add(v);
      out.push(v);
    }
  }
  return out;
}

function hasSignal(s, rx) {
  return rx.test(lower(s));
}

function maxBy(arr, fn) {
  if (!arr.length) return null;
  return arr.reduce((best, cur) => (fn(cur) > fn(best) ? cur : best), arr[0]);
}

function deepClone(obj) {
  return JSON.parse(JSON.stringify(obj ?? {}));
}

function safeTranscript(root, output) {
  return (
    root?.transcript?.output ||
    root?.transcript ||
    output?.transcript?.output ||
    output?.transcript ||
    root?.transcript_insights ||
    output?.transcript_insights ||
    {}
  );
}

function yearsToRecaptureCash(totalIn, annualCF) {
  const t = num(totalIn);
  const cf = num(annualCF);
  if (t <= 0 || cf <= 0) return null;
  return round(t / cf, 1);
}

function cashFlowProfile(monthlyCF) {
  const cf = num(monthlyCF);
  if (cf >= 200) return 'positive_cash_flow';
  if (cf >= 0) return 'near_break_even';
  return 'negative_leverage';
}

function preferredFamilyForDeal(loanBalance, equityPct, takeoverSignals) {
  if (takeoverSignals && loanBalance > 0) return 'subto';
  if (loanBalance <= 0) return 'seller_finance';
  if (equityPct < 15) return 'subto';
  if (equityPct <= 80) return 'hybrid';
  return 'seller_finance';
}

function familyOrderForPrimary(preferredFamily) {
  if (preferredFamily === 'subto') return ['subto', 'hybrid', 'seller_finance'];
  if (preferredFamily === 'hybrid') return ['hybrid', 'seller_finance', 'subto'];
  return ['seller_finance', 'hybrid', 'subto'];
}

function familyOrderForBackup(preferredFamily) {
  if (preferredFamily === 'subto') return ['hybrid', 'seller_finance', 'subto'];
  if (preferredFamily === 'hybrid') return ['seller_finance', 'subto', 'hybrid'];
  return ['hybrid', 'subto', 'seller_finance'];
}

function candidateFailPenalty(c) {
  let penalty = 0;

  if (c.family === 'seller_finance' || c.family === 'hybrid') {
    if (c.DSCR < 1.2) penalty += (1.2 - c.DSCR) * 1000;
    if (c.monthlyCF < 200) penalty += (200 - c.monthlyCF) * 5;
    if (c.coc < 13) penalty += (13 - c.coc) * 50;
  }

  if (c.family === 'subto') {
    if (c.DSCR < 1.0) penalty += (1.0 - c.DSCR) * 1000;
    if (c.monthlyCF < 150) penalty += (150 - c.monthlyCF) * 4;
  }

  if (c.entryPct > 15) penalty += (c.entryPct - 15) * 20;
  if (c.downPct > 10) penalty += (c.downPct - 10) * 25;
  if (c.balloonYrs !== null && c.balloonYrs < 5) penalty += (5 - c.balloonYrs) * 100;

  return penalty;
}

function candidateScore(c) {
  if (!c) return -1e12;
  const passBoost = c.pass ? 1000000 : 0;
  return (
    passBoost +
    (c.monthlyCF * 25) +
    (c.DSCR * 100) +
    (c.coc * 10) -
    (c.totalIn * 0.01) -
    candidateFailPenalty(c)
  );
}

function selectCandidate(allCandidates, preferredFamily, mode = 'primary', excludeIds = new Set()) {
  const order = mode === 'backup'
    ? familyOrderForBackup(preferredFamily)
    : familyOrderForPrimary(preferredFamily);

  const pool = allCandidates.filter(c => !excludeIds.has(c.id));

  for (const family of order) {
    const passing = pool.filter(c => c.family === family && c.pass);
    if (passing.length) return maxBy(passing, candidateScore);
  }

  const anyPassing = pool.filter(c => c.pass);
  if (anyPassing.length) return maxBy(anyPassing, candidateScore);

  for (const family of order) {
    const familyPool = pool.filter(c => c.family === family);
    if (familyPool.length) return maxBy(familyPool, candidateScore);
  }

  return pool.length ? maxBy(pool, candidateScore) : null;
}

function formatOffer(candidate, tiMonthly, loanBalance, loanRate, label) {
  if (!candidate) {
    return {
      Type: 'No viable creative offer',
      'Purchase Price': 'N/A',
      'Cash to Seller': 'N/A',
      'Down Payment ($)': 'N/A',
      'Down Payment (%)': 'N/A',
      'Interest Rate (%)': 'N/A',
      'Loan Rate (%)': 'N/A',
      'Amortization (Years)': null,
      'Balloon Term (Years)': null,
      'Monthly Payment (PI)': 'N/A',
      'Monthly Taxes and Insurance (TI)': money(tiMonthly, 2),
      ADS: 'N/A',
      DSCR: 'N/A',
      'Monthly Cash-flow': 'N/A',
      'Annual Cash-flow': 'N/A',
      'Break-even Rent': 'N/A',
      'Rent Gap to Break-even': 'N/A',
      'Cash-on-Cash Return': 'N/A',
      'Total Entry Fee': 'N/A',
      'Years to Recapture Cash In': 'N/A',
      'Cash Flow Profile': 'N/A',
      'Deal Viable': false,
      Justification: `${label} not available under current metrics.`
    };
  }

  const out = {
    Type: candidate.type,
    'Purchase Price': money(candidate.purchasePrice),
    'Cash to Seller': money(candidate.cashToSeller || 0),
    'Down Payment ($)': money(candidate.down$ || 0),
    'Down Payment (%)': pct(candidate.downPct || 0, 1),
    'Interest Rate (%)': candidate.ratePct != null ? String(candidate.ratePct) : 'N/A',
    'Loan Rate (%)': candidate.ratePct != null ? String(candidate.ratePct) : 'N/A',
    'Amortization (Years)': candidate.years || candidate.carryYears || null,
    'Balloon Term (Years)': candidate.balloonYrs ?? null,
    'Monthly Payment (PI)': money(candidate.monthPI || 0, 2),
    'Monthly Taxes and Insurance (TI)': money(tiMonthly, 2),
    ADS: money(candidate.ADS || 0),
    DSCR: round(candidate.DSCR || 0, 2).toFixed(2),
    'Monthly Cash-flow': money(candidate.monthlyCF || 0),
    'Annual Cash-flow': money(candidate.annualCF || 0),
    'Break-even Rent': money(candidate.breakEvenRent || 0, 2),
    'Rent Gap to Break-even': money(candidate.rentGap || 0, 2),
    'Cash-on-Cash Return': pct(candidate.coc || 0, 1),
    'Total Entry Fee': money(candidate.totalIn || 0),
    'Years to Recapture Cash In': candidate.paybackYears != null ? String(candidate.paybackYears) : 'N/A',
    'Cash Flow Profile': candidate.cashFlowProfile || 'N/A',
    'Deal Viable': !!candidate.pass,
    Justification: candidate.justification
  };

  if (candidate.family === 'seller_finance') {
    out['Financed Amount'] = money(candidate.financed || 0);
    out['Seller Carryback Loan'] = money(candidate.financed || 0);
    out['Seller Carryback Interest Rate'] = candidate.ratePct != null ? String(candidate.ratePct) : 'N/A';
    out['Seller Carryback Monthly Payment (PI)'] = money(candidate.monthPI || 0, 2);
    out['Combined Monthly Payment (PI)'] = money(candidate.monthPI || 0, 2);
    out['Existing Loan Balance'] = money(0);
    out['Existing Loan Interest Rate'] = 'N/A';
    out['Existing Loan Monthly Payment (PI)'] = 'N/A';
  }

  if (candidate.family === 'subto') {
    out['Existing Loan Balance'] = money(loanBalance);
    out['Existing Loan Interest Rate'] = loanRate ? String(loanRate) : 'N/A';
    out['Existing Loan Monthly Payment (PI)'] = money(candidate.firstPI || 0, 2);
    out['Combined Monthly Payment (PI)'] = money(candidate.firstPI || 0, 2);
    out['Financed Amount'] = money(loanBalance);
    out['Seller Carryback Loan'] = money(0);
    out['Seller Carryback Interest Rate'] = 'N/A';
    out['Seller Carryback Monthly Payment (PI)'] = money(0, 2);
  }

  if (candidate.family === 'hybrid') {
    out['Existing Loan Balance'] = money(loanBalance);
    out['Existing Loan Interest Rate'] = loanRate ? String(loanRate) : 'N/A';
    out['Existing Loan Monthly Payment (PI)'] = money(candidate.firstPI || 0, 2);
    out['Seller Carryback Loan'] = money(candidate.carryPrincipal || 0);
    out['Seller Carryback Interest Rate'] = candidate.carryRate != null ? String(candidate.carryRate) : 'N/A';
    out['Seller Carryback Monthly Payment (PI)'] = money(candidate.carryPI || 0, 2);
    out['Combined Monthly Payment (PI)'] = money(candidate.monthPI || 0, 2);
    out['Financed Amount'] = money((loanBalance || 0) + (candidate.carryPrincipal || 0));
  }

  return out;
}

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const root = item.json || {};
    const output = (root.output && typeof root.output === 'object' && !Array.isArray(root.output))
      ? root.output
      : {};

    const property = deepClone(root.property || output.property || {});
    const metrics = deepClone(root.metrics || output.metrics || {});
    const config = {
      closingCostRate: 0.08,
      mgmtRate: 0.08,
      maintRate: 0.05,
      vacancyRate: 0.05,
      assignmentPctOfDown: 0.25,
      taxRate: 0.0115,
      insuranceRate: 0.012,
      ...(output.config || {}),
      ...(root.config || {})
    };

    const existingLoan = deepClone(root.existing_loan || output.existing_loan || {});
    const normalizedSubject = deepClone(
      root.normalized_subject ||
      output.normalized_subject ||
      root.resolved ||
      output.resolved ||
      {}
    );

    const transcript = safeTranscript(root, output);
    const locationContext = deepClone(root.location_context || output.location_context || {});
    const marketData = deepClone(root.market_data_trends || output.market_data_trends || root.market_data_extracted || {});
    const lead = root.webhook_custom_data || root.customData || root.body?.customData || root.body || {};

    const buyerMatches =
      Array.isArray(root.buyer_matches) ? root.buyer_matches :
      Array.isArray(root.matches) ? root.matches :
      Array.isArray(output.buyer_matches) ? output.buyer_matches :
      Array.isArray(output.matches) ? output.matches :
      [];

    const buyerMatchSummary = pick(
      root.buyer_match_summary,
      root.summary,
      output.buyer_match_summary,
      output.summary,
      ''
    ) || '';

    const compProperties = Array.isArray(root.comp_properties_report)
      ? root.comp_properties_report
      : Array.isArray(output.comp_properties_report)
        ? output.comp_properties_report
        : [];

    const compsSummary = pick(root.comps_summary, output.comps_summary, '') || '';
    const warnings = Array.isArray(root.warnings) ? [...root.warnings] : [];

    /***** ---------- [1] Core Baselines ---------- *****/
    const arv = num(pick(
      metrics.arv,
      root.estimated_arv,
      output.estimated_arv,
      property.arv_value,
      normalizedSubject.est_arv,
      normalizedSubject.source_assumptions?.est_arv,
      lead['opp.estArv'],
      lead.estArv
    ));

    const listPrice = num(pick(
      metrics.list_price,
      metrics.price,
      property.list_price,
      property.mls?.price_num,
      normalizedSubject.source_assumptions?.list_price,
      lead['opp.listPrice'],
      lead.list_price,
      lead.listPrice
    ));

    const asIsValue = num(pick(
      metrics.as_is_value,
      property.est_value,
      normalizedSubject.source_assumptions?.est_value,
      lead['opp.estValue'],
      lead.estValue,
      lead.est_value,
      lead['opp.assessedTotalValue']
    ));

    const annualRent = num(pick(
      metrics.annualRent,
      metrics.annual_rent,
      num(metrics.grossRent) * 12,
      num(root.standard_rent_monthly) * 12
    ));

    const rentMonthly = num(pick(
      metrics.grossRent,
      metrics.gross_rent_monthly,
      root.standard_rent_monthly,
      annualRent > 0 ? annualRent / 12 : 0
    ));

    const taxes = num(pick(
      metrics.taxes,
      property.annual_taxes,
      normalizedSubject.annual_taxes,
      normalizedSubject.source_assumptions?.annual_taxes,
      lead['annual taxes'],
      lead['anual taxes'],
      0
    ));

    const insurance = num(pick(
      metrics.insurance,
      property.annual_insurance,
      lead.insuranceAnnual,
      0
    ));

    const mgmt = num(pick(
      metrics.mgmt,
      annualRent > 0 ? Math.round(annualRent * num(config.mgmtRate || 0.08)) : 0
    ));

    const maint = num(pick(
      metrics.maint,
      annualRent > 0 ? Math.round(annualRent * num(config.maintRate || 0.05)) : 0
    ));

    const vacancy = num(pick(
      metrics.vacancy,
      annualRent > 0 ? Math.round(annualRent * num(config.vacancyRate || 0.05)) : 0
    ));

    const utilities = num(pick(metrics.utilities, 0));
    const opex = num(pick(
      metrics.opex,
      taxes + insurance + mgmt + maint + vacancy + utilities
    ));

    const noi = num(pick(
      metrics.noi,
      annualRent - opex
    ));

    const tiMonthly = num(pick(
      metrics.tiMonthly,
      (taxes + insurance) / 12
    ));

    const monthlyOpex = annualRent > 0 ? round(opex / 12, 2) : round((taxes + insurance + mgmt + maint + vacancy + utilities) / 12, 2);

    const loanBalance = num(pick(
      existingLoan.balance,
      normalizedSubject.loan_data?.loan_1_balance,
      lead['Loan 1 Balance'],
      lead['opp.totalAmountOfOpenLoans'],
      lead.totalAmountOfOpenLoans
    ));

    const loanRate = num(pick(
      existingLoan.rate,
      normalizedSubject.loan_data?.loan_1_rate,
      lead['Loan 1 rate'],
      lead['Loan 1 Rate']
    ));

    const loanPI = num(pick(
      existingLoan.sellerMonthlyPaymentPI,
      normalizedSubject.loan_data?.loan_1_monthly_payment,
      lead['Loan 1 Monthly payment'],
      lead['Uw Loan 1 Monthly Payment'],
      (loanBalance > 0 && loanRate > 0) ? pmt(loanRate, 30, loanBalance) : 0
    ));

    const originalPrincipal = num(pick(
      existingLoan.original_principal,
      normalizedSubject.loan_data?.loan_1_original_principal,
      lead['loan 1 original principal'],
      lead['Loan 1 Original Principal'],
      0
    ));

    let equityPct = num(metrics.equity_pct);
    if (equityPct > 0 && equityPct <= 1) equityPct = equityPct * 100;

    if (equityPct !== 0 && !equityPct) {
      if (num(existingLoan.ltv) > 0 && num(existingLoan.ltv) <= 1) {
        equityPct = (1 - num(existingLoan.ltv)) * 100;
      } else if (loanBalance > 0 && asIsValue > 0) {
        equityPct = ((asIsValue - loanBalance) / asIsValue) * 100;
      } else if (loanBalance <= 0 && asIsValue > 0) {
        equityPct = 100;
      } else {
        equityPct = 0;
      }
    }
    equityPct = round(clamp(equityPct, -100, 100), 2);

    if (!arv) warnings.push('Offer Engine: ARV missing or zero.');
    if (!asIsValue) warnings.push('Offer Engine: As-is value missing or zero.');
    if (!rentMonthly) warnings.push('Offer Engine: Rent missing or zero.');
    if (loanBalance > 0 && !loanPI) warnings.push('Offer Engine: Existing loan balance present but monthly PI missing / estimated as zero.');
    if (asIsValue > 0 && arv > 0 && asIsValue > arv) warnings.push(`As-is value (${money(asIsValue)}) is above ARV (${money(arv)}). Check value inputs and condition assumptions.`);

    /***** ---------- [2] Seller / Deal Signals ---------- *****/
    const rawTranscript = [
      txt(transcript.sellerUrgency),
      txt(transcript.sellerHardship),
      txt(transcript.price),
      txt(transcript.additionalInsights),
      txt(lead.prequalified_phone_transcript),
      txt(lead.contact_pq_transcript),
      txt(root.prequalified_phone_transcript),
      txt(root.contact_pq_transcript),
      txt(lead['Pq Prequalifier Call Overview']),
      txt(lead['Prequalifier Phone Transcript']),
      txt(lead['Pillar Score Analysis〔P〕'])
    ].join(' ');

    const dom = num(pick(
      property.dom,
      metrics.dom,
      lead['Days on Market'],
      lead.daysOnMarket,
      0
    ));

    const mlsListStatus = lower(pick(
      normalizedSubject.mls_list_status,
      normalizedSubject.source_assumptions?.mls_list_status,
      lead['opp.mlsListStatus'],
      lead['MLS List Status'],
      property.mls?.status,
      property.list_status,
      ''
    ));

    const isShortSale =
      /short sale/.test(mlsListStatus) ||
      hasSignal(rawTranscript, /\bshort sale\b/i);

    const takeoverSignals =
      isShortSale ||
      hasSignal(rawTranscript, /\b(subject to|subto|take over payments|takeover payments|take over the loan|existing financing|existing loan|wrap|wraparound|catch up and take over|crazy low rate|good enough.*rate)\b/i);

    const motivationHigh =
      hasSignal(rawTranscript, /\b(hard money|refi|refinance|must sell|urgent|asap|financial stress|probate|inherited|vacant|out of state|downsizing|relocated|short sale)\b/i) ||
      dom >= 90;

    const competitionHigh =
      hasSignal(rawTranscript, /\b(multiple offers|offer in hand|bidding war)\b/i);

    let motivationBracket = 'neutral';
    if (competitionHigh) motivationBracket = 'aggressive';
    else if (motivationHigh) motivationBracket = 'conservative';

    /***** ---------- [3] Cash-to-Seller Engine ---------- *****/
    const askingPriceForCTS = listPrice || asIsValue || arv || 0;
    const agentCommission = Math.round(askingPriceForCTS * 0.06);
    const sellerClosingCosts = Math.round(askingPriceForCTS * 0.02);

    const sellerRetailNet = Math.round(
      askingPriceForCTS - loanBalance - agentCommission - sellerClosingCosts
    );

    let ctsConservative = 0;
    let ctsStandard = 0;
    let ctsAggressive = 0;

    if (sellerRetailNet < -20000) {
      ctsConservative = 0;
      ctsStandard = 0;
      ctsAggressive = 0;
    } else if (sellerRetailNet <= 0) {
      ctsConservative = 0;
      ctsStandard = 1500;
      ctsAggressive = 4000;
    } else if (sellerRetailNet <= 5000) {
      ctsConservative = 1500;
      ctsStandard = 2000;
      ctsAggressive = Math.min(7000, sellerRetailNet);
    } else {
      ctsConservative = Math.round(Math.min(sellerRetailNet * 0.10, sellerRetailNet));
      ctsStandard = Math.round(Math.min(sellerRetailNet * 0.20, sellerRetailNet));
      ctsAggressive = Math.round(Math.min(sellerRetailNet * 0.30, sellerRetailNet));
    }

    const hardCap15pct = Math.round(askingPriceForCTS * 0.15);

    let recommendedCTS = ctsStandard;
    if (motivationBracket === 'aggressive') recommendedCTS = ctsAggressive;
    if (motivationBracket === 'conservative') recommendedCTS = ctsConservative;
    recommendedCTS = Math.max(0, Math.min(recommendedCTS, hardCap15pct));

    const ctsEngine = {
      seller_retail_net: sellerRetailNet,
      agent_commission: agentCommission,
      seller_closing_costs: sellerClosingCosts,
      cts_conservative: ctsConservative,
      cts_standard: ctsStandard,
      cts_aggressive: ctsAggressive,
      recommended_cts: recommendedCTS,
      motivation_bracket: motivationBracket === 'aggressive' ? 'competition_high' : motivationBracket,
      hard_cap_15pct: hardCap15pct
    };

    /***** ---------- [4] Cash MAO ---------- *****/
    const repairEstimate = num(pick(
      metrics.estimatedRepairCost,
      metrics.repair_estimate,
      root.repair_estimate,
      0
    ));

    const buyerClosingCosts = Math.round(arv * num(config.closingCostRate || 0.08));
    const wholesaleFee = num(pick(config.wholesaleAssignmentFee, metrics.wholesaleFee, root.wholesale_fee, 15000));
    const baseBuyBox = Math.round(arv * 0.70);

    const mao = Math.max(0, Math.round(baseBuyBox - repairEstimate - buyerClosingCosts - wholesaleFee));
    const cashPctOfArv = arv > 0 ? round((mao / arv) * 100, 1) : 0;
    const spreadVsList = listPrice > 0 ? Math.round(mao - listPrice) : 0;

    const acceptableNow = listPrice > 0
      ? mao >= listPrice || ((listPrice - mao) / listPrice) <= 0.05
      : false;

    let negotiationPotential = 'low';
    if (motivationHigh || dom >= 60 || hasSignal(rawTranscript, /\bflexibility|seller financing|creative|cash offer|hard money|subject to|take over payments\b/i)) {
      negotiationPotential = 'high';
    } else if (dom >= 30 || hasSignal(rawTranscript, /\binterested|follow up|open\b/i)) {
      negotiationPotential = 'medium';
    }

    const pursueCashStrategy = mao > 0 && ['medium', 'high'].includes(negotiationPotential);

    const cashOfferObject = {
      type: 'Cash',
      arv,
      buy_box_pct: '70%',
      repair_estimate: repairEstimate,
      buyer_closing_costs: buyerClosingCosts,
      wholesale_fee: wholesaleFee,
      cash_offer: mao,
      cash_offer_pct_of_arv: `${cashPctOfArv}%`,
      spread_vs_list_price: spreadVsList,
      deal_viable: mao > 0,
      acceptable_now: acceptableNow,
      negotiation_potential: negotiationPotential,
      pursue_cash_strategy: pursueCashStrategy
    };

    /***** ---------- [5] Creative Price Anchors ---------- *****/
    const creativePriceFloor = Math.max(listPrice || 0, loanBalance || 0);
    const sfPriceBase = listPrice || asIsValue || arv || 0;

    function buildDerivedMetrics(candidate, monthlyPI, purchasePrice, totalIn) {
      const annualPI = Math.round(monthlyPI * 12);
      const DSCR = annualPI > 0 ? round(noi / annualPI, 2) : 0;
      const annualCF = round(noi - annualPI, 0);
      const monthlyCF = round(annualCF / 12, 0);
      const coc = totalIn > 0 ? round((annualCF / totalIn) * 100, 1) : 0;
      const entryPct = purchasePrice > 0 ? round((totalIn / purchasePrice) * 100, 2) : 999;
      const breakEvenRent = round(monthlyPI + monthlyOpex, 2);
      const rentGap = round(breakEvenRent - rentMonthly, 2);
      const rentGapPct = rentMonthly > 0 ? round((rentGap / rentMonthly) * 100, 1) : 0;
      const paybackYears = yearsToRecaptureCash(totalIn, annualCF);

      return {
        ADS: annualPI,
        DSCR,
        annualCF,
        monthlyCF,
        coc,
        entryPct,
        breakEvenRent,
        rentGap,
        rentGapPct,
        paybackYears,
        cashFlowProfile: cashFlowProfile(monthlyCF)
      };
    }

    /***** ---------- [6] Candidate Builders ---------- *****/
    function buildSellerFinanceCandidates() {
      const candidates = [];
      if (sfPriceBase <= 0) return candidates;

      const priceTrials = uniqRounded([
        sfPriceBase,
        sfPriceBase * 0.97,
        sfPriceBase * 0.94,
        sfPriceBase * 0.90,
        asIsValue,
        asIsValue * 0.97
      ]);

      for (const price of priceTrials) {
        for (const downPct of [10, 8, 5]) {
          const down$ = Math.round(price * downPct / 100);

          if (loanBalance > 0 && down$ < loanBalance) continue;

          for (const ratePct of [4.0, 3.5, 3.0]) {
            for (const balloonYrs of [5, 7]) {
              const years = 30;
              const financed = Math.max(price - down$, 0);
              const monthPI = Math.round(pmt(ratePct, years, financed));
              const assignment = Math.round(down$ * num(config.assignmentPctOfDown || 0.25));
              const totalIn = Math.round(down$ + buyerClosingCosts + assignment);

              const derived = buildDerivedMetrics({}, monthPI, price, totalIn);

              const pass =
                ratePct <= 4 &&
                downPct <= 10 &&
                balloonYrs >= 5 &&
                derived.DSCR >= 1.20 &&
                derived.monthlyCF >= 200 &&
                derived.coc >= 13 &&
                (derived.entryPct <= 15 || (derived.entryPct <= 20 && derived.monthlyCF >= 500));

              candidates.push({
                id: `seller_finance|${price}|${down$}|${ratePct}|${balloonYrs}`,
                family: 'seller_finance',
                type: 'Seller Finance',
                purchasePrice: price,
                down$,
                downPct,
                ratePct,
                years,
                balloonYrs,
                financed,
                monthPI,
                assignment,
                totalIn,
                cashToSeller: down$,
                justification: pass
                  ? 'Passes Seller Finance rules with compliant rate/down/balloon and acceptable DSCR, cash flow, and CoC.'
                  : 'Closest Seller Finance structure under current pricing and rent, but does not fully meet investor thresholds.',
                pass,
                ...derived
              });
            }
          }
        }
      }

      return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
    }

    function buildSubToCandidates() {
      const candidates = [];
      if (loanBalance <= 0 || loanPI <= 0) return candidates;

      const price = creativePriceFloor || asIsValue || arv || 0;
      if (price <= 0) return candidates;

      const firstPI = Math.round(loanPI);

      for (const coverSellerClosing of [false, true]) {
        const sellerCloseCovered = coverSellerClosing ? sellerClosingCosts : 0;
        const buyerSide = buyerClosingCosts + sellerCloseCovered;

        for (const ctsTrial of uniqRounded([
          recommendedCTS,
          recommendedCTS * 0.75,
          recommendedCTS * 0.5,
          0,
          isShortSale ? 500 : 0
        ])) {
          const assignment = Math.round(ctsTrial * num(config.assignmentPctOfDown || 0.25));
          const totalIn = Math.round(ctsTrial + buyerSide + assignment);

          const derived = buildDerivedMetrics({}, firstPI, price, totalIn);

          const lowRateException = loanRate > 0 && loanRate <= 3.5;
          const cfPass = lowRateException ? derived.monthlyCF >= -50 : derived.monthlyCF >= 150;
          const ratePass = (loanBalance > 150000 ? loanRate <= 5 : loanRate <= 8) || loanRate === 0;

          const pass =
            ratePass &&
            derived.DSCR >= 1.0 &&
            cfPass &&
            derived.entryPct <= 15;

          candidates.push({
            id: `subto|${price}|${ctsTrial}|${loanRate}|${coverSellerClosing ? 1 : 0}`,
            family: 'subto',
            type: 'Subject-To',
            purchasePrice: price,
            down$: ctsTrial,
            downPct: price > 0 ? round((ctsTrial / price) * 100, 2) : 0,
            ratePct: loanRate || null,
            years: null,
            balloonYrs: null,
            financed: loanBalance,
            firstPI,
            monthPI: firstPI,
            assignment,
            totalIn,
            cashToSeller: ctsTrial,
            coverSellerClosing,
            justification: pass
              ? 'Passes Subject-To screen with acceptable DSCR/cash flow and controlled entry.'
              : 'Closest Subject-To structure under current debt and entry assumptions, but not fully investor-compliant.',
            pass,
            ...derived
          });
        }
      }

      return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
    }

    function buildHybridCandidates() {
      const candidates = [];
      if (loanBalance <= 0 || loanPI <= 0) return candidates;

      const priceBase = creativePriceFloor || asIsValue || arv || 0;
      if (priceBase <= 0) return candidates;

      const firstPI = Math.round(loanPI);

      const priceTrials = uniqRounded([
        priceBase,
        priceBase * 0.97,
        priceBase * 0.94,
        asIsValue,
        listPrice
      ]);

      for (const price of priceTrials) {
        for (const ctsTrial of uniqRounded([
          recommendedCTS,
          recommendedCTS * 0.75,
          recommendedCTS * 0.5,
          0
        ])) {
          const cts = Math.min(ctsTrial, Math.round(price * 0.10));
          const carryPrincipal = Math.max(price - loanBalance - cts, 0);

          for (const carryRate of [4.0, 3.5, 3.0]) {
            for (const balloonYrs of [5, 7]) {
              const carryYears = 30;
              const carryPI = carryPrincipal > 0 ? Math.round(pmt(carryRate, carryYears, carryPrincipal)) : 0;
              const combinedPI = firstPI + carryPI;
              const assignment = Math.round(cts * num(config.assignmentPctOfDown || 0.25));
              const totalIn = Math.round(cts + buyerClosingCosts + assignment);

              const derived = buildDerivedMetrics({}, combinedPI, price, totalIn);

              const pass =
                cts <= price * 0.10 &&
                derived.DSCR >= 1.20 &&
                derived.monthlyCF >= 200 &&
                derived.coc >= 13 &&
                (derived.entryPct <= 15 || (derived.entryPct <= 20 && derived.monthlyCF >= 500));

              candidates.push({
                id: `hybrid|${price}|${cts}|${carryRate}|${balloonYrs}`,
                family: 'hybrid',
                type: 'Hybrid',
                purchasePrice: price,
                down$: cts,
                downPct: price > 0 ? round((cts / price) * 100, 2) : 0,
                ratePct: carryRate,
                years: 30,
                balloonYrs,
                financed: loanBalance + carryPrincipal,
                firstPI,
                carryPrincipal,
                carryRate,
                carryYears,
                carryPI,
                monthPI: combinedPI,
                assignment,
                totalIn,
                cashToSeller: cts,
                justification: pass
                  ? 'Passes Hybrid screen with controlled CTS, acceptable DSCR/cash flow, and compliant CoC.'
                  : 'Closest Hybrid structure under current equity and debt, but not fully investor-compliant.',
                pass,
                ...derived
              });
            }
          }
        }
      }

      return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
    }

    function buildForcedFallbackCandidates() {
      const forced = [];
      const basePrice = Math.max(listPrice || 0, loanBalance || 0, asIsValue || 0, arv || 0);

      if (loanBalance > 0 && loanPI > 0) {
        const firstPI = Math.round(loanPI);
        const totalInA = Math.round(buyerClosingCosts);
        const derivedA = buildDerivedMetrics({}, firstPI, basePrice, totalInA);

        forced.push({
          id: `forced_subto|${basePrice}|0`,
          family: 'subto',
          type: 'Subject-To',
          purchasePrice: basePrice,
          down$: 0,
          downPct: 0,
          ratePct: loanRate || null,
          years: null,
          balloonYrs: null,
          financed: loanBalance,
          firstPI,
          monthPI: firstPI,
          assignment: 0,
          totalIn: totalInA,
          cashToSeller: 0,
          coverSellerClosing: false,
          justification: 'Educational fallback only. Subject-To structure shown because this is a debt-heavy creative scenario, but current numbers do not meet investor thresholds.',
          pass: false,
          ...derivedA
        });

        const totalInB = Math.round(buyerClosingCosts);
        const derivedB = buildDerivedMetrics({}, firstPI, basePrice, totalInB);

        forced.push({
          id: `forced_hybrid|${basePrice}|0`,
          family: 'hybrid',
          type: 'Hybrid',
          purchasePrice: basePrice,
          down$: 0,
          downPct: 0,
          ratePct: 4.0,
          years: 30,
          balloonYrs: 5,
          financed: loanBalance,
          firstPI,
          carryPrincipal: 0,
          carryRate: 4.0,
          carryYears: 30,
          carryPI: 0,
          monthPI: firstPI,
          assignment: 0,
          totalIn: totalInB,
          cashToSeller: 0,
          justification: 'Educational fallback only. Hybrid shown as second-best creative path, but there is no margin for a true hybrid structure under current numbers.',
          pass: false,
          ...derivedB
        });
      } else {
        const downA = Math.round(basePrice * 0.10);
        const piA = Math.round(pmt(4.0, 30, Math.max(basePrice - downA, 0)));
        const totalInA = Math.round(downA + buyerClosingCosts);
        const derivedA = buildDerivedMetrics({}, piA, basePrice, totalInA);

        forced.push({
          id: `forced_sf_a|${basePrice}|${downA}`,
          family: 'seller_finance',
          type: 'Seller Finance',
          purchasePrice: basePrice,
          down$: downA,
          downPct: 10,
          ratePct: 4.0,
          years: 30,
          balloonYrs: 5,
          financed: Math.max(basePrice - downA, 0),
          monthPI: piA,
          assignment: 0,
          totalIn: totalInA,
          cashToSeller: downA,
          justification: 'Educational fallback only. Seller finance shown because no stronger creative structure was buildable from the current data.',
          pass: false,
          ...derivedA
        });

        const downB = Math.round(basePrice * 0.05);
        const piB = Math.round(pmt(3.5, 30, Math.max(basePrice - downB, 0)));
        const totalInB = Math.round(downB + buyerClosingCosts);
        const derivedB = buildDerivedMetrics({}, piB, basePrice, totalInB);

        forced.push({
          id: `forced_sf_b|${basePrice}|${downB}`,
          family: 'seller_finance',
          type: 'Seller Finance',
          purchasePrice: basePrice,
          down$: downB,
          downPct: 5,
          ratePct: 3.5,
          years: 30,
          balloonYrs: 7,
          financed: Math.max(basePrice - downB, 0),
          monthPI: piB,
          assignment: 0,
          totalIn: totalInB,
          cashToSeller: downB,
          justification: 'Educational fallback only. Alternate seller finance shown because no passing creative structures were available.',
          pass: false,
          ...derivedB
        });
      }

      return forced;
    }

    /***** ---------- [7] Build / Select Candidates ---------- *****/
    const sfCandidates = buildSellerFinanceCandidates();
    const subtoCandidates = buildSubToCandidates();
    const hybridCandidates = buildHybridCandidates();

    const rawCandidates = [...sfCandidates, ...subtoCandidates, ...hybridCandidates];
    const forcedFallbacks = buildForcedFallbackCandidates();
    const creativeCandidates = rawCandidates.length >= 2 ? rawCandidates : [...rawCandidates, ...forcedFallbacks];

    const preferredFamily = preferredFamilyForDeal(loanBalance, equityPct, takeoverSignals);

    const primary = selectCandidate(creativeCandidates, preferredFamily, 'primary');
    const excluded = new Set(primary ? [primary.id] : []);
    let backup = selectCandidate(creativeCandidates, preferredFamily, 'backup', excluded);

    if (!backup && forcedFallbacks.length) {
      const backupExcluded = new Set(primary ? [primary.id] : []);
      backup = selectCandidate(forcedFallbacks, preferredFamily, 'backup', backupExcluded);
    }

    if (!primary) warnings.push('Offer Engine: No creative candidates built.');
    if (primary && !primary.pass) warnings.push(`Offer Engine: Primary ${primary.type} is least-bad but not fully viable.`);
    if (backup && !backup.pass) warnings.push(`Offer Engine: Backup ${backup.type} is not fully viable.`);

    /***** ---------- [8] Deal Structure ---------- *****/
    const dealStructure = {
      'Primary Offer': formatOffer(primary, tiMonthly, loanBalance, loanRate, 'Primary Offer'),
      'Backup Offer': formatOffer(backup, tiMonthly, loanBalance, loanRate, 'Backup Offer'),
      'Updated Cash Offer': {
        'Final Cash Offer': money(mao),
        'Final Cash Offer % of ARV': `${cashPctOfArv}% of ARV`,
        'Justification':
          `True MAO used: (ARV ${money(arv)} × 70%) - Repairs ${money(repairEstimate)} - ` +
          `Buyer Closing Costs ${money(buyerClosingCosts)} - Wholesale Fee ${money(wholesaleFee)}. ` +
          `This produces a net cash MAO of ${money(mao)}.`
      }
    };

    /***** ---------- [9] Investors Analysis Mirrors Primary ---------- *****/
    const primaryMonthlyCF = primary ? primary.monthlyCF : 0;
    const primaryAnnualCF = primary ? primary.annualCF : 0;
    const primaryCoc = primary ? primary.coc : 0;
    const primaryADS = primary ? primary.ADS : 0;
    const primaryDSCR = primary ? primary.DSCR : 0;
    const primaryTotalIn = primary ? primary.totalIn : 0;
    const primaryPrice = primary ? primary.purchasePrice : 0;
    const primaryBreakEvenRent = primary ? primary.breakEvenRent : 0;
    const primaryRentGap = primary ? primary.rentGap : 0;
    const primaryPayback = primary ? primary.paybackYears : null;
    const primaryProfile = primary ? primary.cashFlowProfile : 'unknown';

    const rule2 = (primaryPrice > 0 && rentMonthly / primaryPrice >= 0.02) ? '✅' : '❌';
    const rule50 = (annualRent > 0 && opex <= annualRent * 0.5) ? '✅' : '❌';

    const investorsAnalysis = {
      'Gross Rent': money(rentMonthly),
      'Annual Rent': money(annualRent),
      'Operating Expenses': money(opex),
      NOI: money(noi),
      'Annual Debt Service (ADS)': money(primaryADS),
      DSCR: round(primaryDSCR || 0, 2).toFixed(2),
      'Monthly Cash-flow': money(primaryMonthlyCF),
      'Annual Cash-flow': money(primaryAnnualCF),
      'Break-even Rent': money(primaryBreakEvenRent, 2),
      'Rent Gap to Break-even': money(primaryRentGap, 2),
      'Cash Flow Profile': primaryProfile,
      'Years to Recapture Cash In': primaryPayback != null ? String(primaryPayback) : 'N/A',
      'Total Cash In': money(primaryTotalIn),
      'Cash-on-Cash Return': pct(primaryCoc || 0, 1),
      '2% Rule': rule2,
      '50% Rule': rule50
    };

    let investorsAnalysisInsights = '';
    if (primary) {
      investorsAnalysisInsights =
        `${primary.type} is the current best creative path under locked metrics. ` +
        `DSCR is ${round(primaryDSCR || 0, 2).toFixed(2)}, monthly cash flow is ${money(primaryMonthlyCF)}, ` +
        `break-even rent is ${money(primaryBreakEvenRent, 2)}, and the rent gap is ${money(primaryRentGap, 2)}. ` +
        `${primary.pass ? 'This path clears the current rules.' : 'This path is the closest fit but still misses one or more investor targets.'}`;
    } else {
      investorsAnalysisInsights = 'No creative structure could be built from the current metrics.';
    }

    /***** ---------- [10] Assignment Fee Range ---------- *****/
    let assignmentFeeRange = '$3,000–$7,500';
    if (primaryMonthlyCF >= 500) assignmentFeeRange = '$8,000–$15,000';
    else if (primaryMonthlyCF >= 200) assignmentFeeRange = '$5,000–$12,000';

    /***** ---------- [11] Canonical Economics ---------- *****/
    const canonical = {
      economics: {
        grossRentMonthly: rentMonthly,
        annualRent,
        opexAnnual: opex,
        NOI: noi,
        ADS: primaryADS,
        DSCR: round(primaryDSCR || 0, 2),
        monthlyCF: primaryMonthlyCF,
        annualCF: primaryAnnualCF,
        breakEvenRentMonthly: round(primaryBreakEvenRent || 0, 2),
        rentGapToBreakEven: round(primaryRentGap || 0, 2),
        totalCashIn: primaryTotalIn,
        CoC_pct: round(primaryCoc || 0, 1)
      }
    };

    /***** ---------- [12] Normalized Outputs ---------- *****/
    const normalizedMetrics = {
      ...metrics,
      list_price: listPrice,
      price: listPrice || num(metrics.price),
      as_is_value: asIsValue,
      arv,
      grossRent: rentMonthly,
      annualRent,
      taxes,
      insurance,
      mgmt,
      maint,
      vacancy,
      utilities,
      opex,
      noi,
      tiMonthly: round(tiMonthly, 2),
      monthly_opex: round(monthlyOpex, 2),
      equity_pct: round(equityPct, 2)
    };

    const normalizedLoan = {
      ...existingLoan,
      balance: loanBalance,
      sellerMonthlyPaymentPI: round(loanPI, 2),
      rate: loanRate,
      original_principal: originalPrincipal
    };

    /***** ---------- [13] Debug ---------- *****/
    const offerEngineDebug = {
      version: 'offer-engine-v3.0',
      preferred_family: preferredFamily,
      raw_candidate_counts: {
        seller_finance: sfCandidates.length,
        subto: subtoCandidates.length,
        hybrid: hybridCandidates.length,
        total: rawCandidates.length
      },
      effective_candidate_total: creativeCandidates.length,
      selected: {
        primary_id: primary?.id || null,
        backup_id: backup?.id || null,
        primary_viable: !!primary?.pass,
        backup_viable: !!backup?.pass
      },
      deal_flags: {
        is_short_sale: isShortSale,
        takeover_signals: takeoverSignals,
        motivation_bracket: motivationBracket,
        creative_price_floor: creativePriceFloor
      },
      math_notes: {
        ads_is_pi_only: true,
        ti_not_double_counted_in_ads: true,
        monthly_cf_formula: 'monthlyCF = (NOI - annual_PI_only_debt_service) / 12',
        break_even_formula: 'breakEvenRent = monthlyPI + (annual_opex / 12)'
      },
      warnings
    };

    /***** ---------- [14] Result ---------- *****/
    const result = {
      estimated_arv: arv,
      comp_properties_report: compProperties,
      comps_summary: compsSummary,

      investors_analysis: investorsAnalysis,
      investors_analysis_insights: investorsAnalysisInsights,
      deal_structure: dealStructure,

      cash_offer: cashOfferObject,
      mao,
      wholesale_fee: wholesaleFee,
      repair_estimate: repairEstimate,
      cts_engine: ctsEngine,
      assignment_fee_range: assignmentFeeRange,

      property,
      metrics: normalizedMetrics,
      config,
      existing_loan: normalizedLoan,
      canonical,

      normalized_subject: normalizedSubject,
      transcript: root.transcript || output.transcript || {},
      location_context: locationContext,
      market_data_trends: marketData,

      buyer_matches: buyerMatches,
      buyer_match_summary: buyerMatchSummary,

      offer_engine_debug: offerEngineDebug,

      output: {
        estimated_arv: arv,
        comp_properties_report: compProperties,
        comps_summary: compsSummary,
        investors_analysis: investorsAnalysis,
        investors_analysis_insights: investorsAnalysisInsights,
        deal_structure: dealStructure,

        cash_offer: cashOfferObject,
        mao,
        wholesale_fee: wholesaleFee,
        repair_estimate: repairEstimate,
        cts_engine: ctsEngine,
        assignment_fee_range: assignmentFeeRange,

        property,
        metrics: normalizedMetrics,
        config,
        existing_loan: normalizedLoan,
        canonical,

        normalized_subject: normalizedSubject,
        buyer_matches: buyerMatches,
        buyer_match_summary: buyerMatchSummary,
        offer_engine_debug: offerEngineDebug
      }
    };

    results.push({ json: result });

  } catch (e) {
    results.push({
      json: {
        _error: e?.message || String(e),
        _stack: e?.stack || null,
        _input: item.json || {}
      }
    });
  }
}

return results;

