      seller_carry_amort_years: null,
      seller_carry_balloon_years: null,
      seller_carry_monthly_pi: null,

      combined_monthly_pi: null,
      total_entry_fee: null,

      'Purchase Price': 'N/A',
      'Cash to Seller': 'N/A',
      'Down Payment ($)': 'N/A',
      'Down Payment (%)': 'N/A',
      'Interest Rate (%)': 'N/A',
      'Loan Rate (%)': 'N/A',
      'Amortization (Years)': null,
      'Balloon Term (Years)': null,
      'Monthly Payment (PI)': 'N/A',
      'Monthly Taxes and Insurance (TI)': money(tiMonthly, 2),
      ADS: 'N/A',
      DSCR: 'N/A',
      'Monthly Cash-flow': 'N/A',
      'Annual Cash-flow': 'N/A',
      'Break-even Rent': 'N/A',
      'Rent Gap to Break-even': 'N/A',
      'Cash-on-Cash Return': 'N/A',
      'Total Entry Fee': 'N/A',
      'Years to Recapture Cash In': 'N/A',
      'Cash Flow Profile': 'N/A',
      'Deal Viable': false,
      Justification: `${label} not available under current metrics.`
    };
  }

  const out = {
    Type: candidate.type,
    offer_type: candidate.type,

    cts: moneyOrNull(candidate.cts),
    cts_pct: pctOrNull(candidate.ctsPct, 2),
    down_payment: moneyOrNull(candidate.downPayment),
    down_payment_pct: pctOrNull(candidate.downPaymentPct, 2),

    existing_loan_balance: moneyOrNull(candidate.existingLoanBalance),
    existing_loan_rate: candidate.existingLoanRate != null ? String(candidate.existingLoanRate) : null,
    existing_loan_monthly_pi: moneyOrNull(candidate.existingLoanMonthlyPI, 2),

    seller_carry_principal: moneyOrNull(candidate.sellerCarryPrincipal),
    seller_carry_rate: candidate.sellerCarryRate != null ? String(candidate.sellerCarryRate) : null,
    seller_carry_amort_years: candidate.sellerCarryAmortYears ?? null,
    seller_carry_balloon_years: candidate.sellerCarryBalloonYears ?? null,
    seller_carry_monthly_pi: moneyOrNull(candidate.sellerCarryMonthlyPI, 2),

    combined_monthly_pi: moneyOrNull(candidate.combinedMonthlyPI, 2),
    total_entry_fee: moneyOrNull(candidate.totalIn),

    'Purchase Price': money(candidate.purchasePrice),
    'Cash to Seller': money(candidate.cashToSeller || 0),
    'Down Payment ($)': candidate.downPayment != null ? money(candidate.downPayment) : 'N/A',
    'Down Payment (%)': candidate.downPaymentPct != null ? pct(candidate.downPaymentPct, 1) : 'N/A',
    'CTS ($)': candidate.cts != null ? money(candidate.cts) : 'N/A',
    'CTS (%)': candidate.ctsPct != null ? pct(candidate.ctsPct, 1) : 'N/A',
    'Interest Rate (%)': candidate.ratePct != null ? String(candidate.ratePct) : 'N/A',
    'Loan Rate (%)': candidate.ratePct != null ? String(candidate.ratePct) : 'N/A',
    'Amortization (Years)': candidate.years || candidate.carryYears || candidate.sellerCarryAmortYears || null,
    'Balloon Term (Years)': candidate.balloonYrs ?? candidate.sellerCarryBalloonYears ?? null,
    'Monthly Payment (PI)': money(candidate.monthPI || 0, 2),
    'Monthly Taxes and Insurance (TI)': money(tiMonthly, 2),
    ADS: money(candidate.ADS || 0),
    DSCR: round(candidate.DSCR || 0, 2).toFixed(2),
    'Monthly Cash-flow': money(candidate.monthlyCF || 0),
    'Annual Cash-flow': money(candidate.annualCF || 0),
    'Break-even Rent': money(candidate.breakEvenRent || 0, 2),
    'Rent Gap to Break-even': money(candidate.rentGap || 0, 2),
    'Cash-on-Cash Return': pct(candidate.coc || 0, 1),
    'Total Entry Fee': money(candidate.totalIn || 0),
    'Years to Recapture Cash In': candidate.paybackYears != null ? String(candidate.paybackYears) : 'N/A',
    'Cash Flow Profile': candidate.cashFlowProfile || 'N/A',
    'Deal Viable': !!candidate.pass,
    Justification: candidate.justification
  };

  if (candidate.family === 'seller_finance') {
    out['Financed Amount'] = money(candidate.financed || 0);
    out['Seller Carryback Loan'] = money(candidate.sellerCarryPrincipal || 0);
    out['Seller Carryback Interest Rate'] = candidate.sellerCarryRate != null ? String(candidate.sellerCarryRate) : 'N/A';
    out['Seller Carryback Monthly Payment (PI)'] = money(candidate.sellerCarryMonthlyPI || 0, 2);
    out['Combined Monthly Payment (PI)'] = money(candidate.combinedMonthlyPI || 0, 2);
    out['Existing Loan Balance'] = money(0);
    out['Existing Loan Interest Rate'] = 'N/A';
    out['Existing Loan Monthly Payment (PI)'] = 'N/A';
  }

  if (candidate.family === 'subto') {
    out['Financed Amount'] = money(candidate.existingLoanBalance || loanBalance || 0);
    out['Seller Carryback Loan'] = money(0);
    out['Seller Carryback Interest Rate'] = 'N/A';
    out['Seller Carryback Monthly Payment (PI)'] = money(0, 2);
    out['Combined Monthly Payment (PI)'] = money(candidate.combinedMonthlyPI || candidate.firstPI || 0, 2);
    out['Existing Loan Balance'] = money(candidate.existingLoanBalance || loanBalance || 0);
    out['Existing Loan Interest Rate'] = candidate.existingLoanRate != null ? String(candidate.existingLoanRate) : (loanRate ? String(loanRate) : 'N/A');
    out['Existing Loan Monthly Payment (PI)'] = money(candidate.existingLoanMonthlyPI || candidate.firstPI || 0, 2);
  }

  if (candidate.family === 'hybrid') {
    out['Financed Amount'] = money((candidate.existingLoanBalance || loanBalance || 0) + (candidate.sellerCarryPrincipal || 0));
    out['Seller Carryback Loan'] = money(candidate.sellerCarryPrincipal || 0);
    out['Seller Carryback Interest Rate'] = candidate.sellerCarryRate != null ? String(candidate.sellerCarryRate) : 'N/A';
    out['Seller Carryback Monthly Payment (PI)'] = money(candidate.sellerCarryMonthlyPI || 0, 2);
    out['Combined Monthly Payment (PI)'] = money(candidate.combinedMonthlyPI || candidate.monthPI || 0, 2);
    out['Existing Loan Balance'] = money(candidate.existingLoanBalance || loanBalance || 0);
    out['Existing Loan Interest Rate'] = candidate.existingLoanRate != null ? String(candidate.existingLoanRate) : (loanRate ? String(loanRate) : 'N/A');
    out['Existing Loan Monthly Payment (PI)'] = money(candidate.existingLoanMonthlyPI || candidate.firstPI || 0, 2);
  }

  return out;
}

