      lead['opp.listPrice'],
      lead.list_price,
      lead.listPrice
    ));

    const asIsValue = num(pick(
      metrics.as_is_value,
      property.est_value,
      normalizedSubject.source_assumptions?.est_value,
      lead['opp.estValue'],
      lead.estValue,
      lead.est_value,
      lead['opp.assessedTotalValue']
    ));

    const annualRent = num(pick(
      metrics.annualRent,
      metrics.annual_rent,
      num(metrics.grossRent) * 12,
      num(root.standard_rent_monthly) * 12
    ));

    const rentMonthly = num(pick(
      metrics.grossRent,
      metrics.gross_rent_monthly,
      root.standard_rent_monthly,
      annualRent > 0 ? annualRent / 12 : 0
    ));

    const taxes = num(pick(
      metrics.taxes,
      property.annual_taxes,
      normalizedSubject.annual_taxes,
      normalizedSubject.source_assumptions?.annual_taxes,
      lead['annual taxes'],
      lead['anual taxes'],
      0
    ));

    const insurance = num(pick(
      metrics.insurance,
      property.annual_insurance,
      lead.insuranceAnnual,
      0
    ));

    const mgmt = num(pick(
      metrics.mgmt,
      annualRent > 0 ? Math.round(annualRent * num(config.mgmtRate || 0.08)) : 0
    ));

    const maint = num(pick(
      metrics.maint,
      annualRent > 0 ? Math.round(annualRent * num(config.maintRate || 0.05)) : 0
    ));

    const vacancy = num(pick(
      metrics.vacancy,
      annualRent > 0 ? Math.round(annualRent * num(config.vacancyRate || 0.05)) : 0
    ));

    const utilities = num(pick(metrics.utilities, 0));

    const opex = num(pick(
      metrics.opex,
      taxes + insurance + mgmt + maint + vacancy + utilities
    ));

    const noi = num(pick(
      metrics.noi,
      annualRent - opex
    ));

    const tiMonthly = num(pick(
      metrics.tiMonthly,
      (taxes + insurance) / 12
    ));

    const monthlyOpex = annualRent > 0
      ? round(opex / 12, 2)
      : round((taxes + insurance + mgmt + maint + vacancy + utilities) / 12, 2);

    const loanBalance = num(pick(
      existingLoan.balance,
      normalizedSubject.loan_data?.loan_1_balance,
      lead['Loan 1 Balance'],
      lead['opp.totalAmountOfOpenLoans'],
      lead.totalAmountOfOpenLoans
    ));

    const loanRate = num(pick(
      existingLoan.rate,
      normalizedSubject.loan_data?.loan_1_rate,
      lead['Loan 1 rate'],
      lead['Loan 1 Rate']
    ));

    const loanPI = num(pick(
      existingLoan.sellerMonthlyPaymentPI,
      normalizedSubject.loan_data?.loan_1_monthly_payment,
      lead['Loan 1 Monthly payment'],
      lead['Uw Loan 1 Monthly Payment'],
      (loanBalance > 0 && loanRate > 0) ? pmt(loanRate, 30, loanBalance) : 0
    ));

    const originalPrincipal = num(pick(
      existingLoan.original_principal,
      normalizedSubject.loan_data?.loan_1_original_principal,
      lead['loan 1 original principal'],
      lead['Loan 1 Original Principal'],
      0
    ));

    let equityPct = num(metrics.equity_pct);
    if (equityPct > 0 && equityPct <= 1) equityPct = equityPct * 100;

    if (equityPct !== 0 && !equityPct) {
      if (num(existingLoan.ltv) > 0 && num(existingLoan.ltv) <= 1) {
        equityPct = (1 - num(existingLoan.ltv)) * 100;
      } else if (loanBalance > 0 && asIsValue > 0) {
        equityPct = ((asIsValue - loanBalance) / asIsValue) * 100;
      } else if (loanBalance <= 0 && asIsValue > 0) {
        equityPct = 100;
      } else {
        equityPct = 0;
      }
    }
    equityPct = round(clamp(equityPct, -100, 100), 2);

    if (!arv) warnings.push('Offer Engine: ARV missing or zero.');
    if (!asIsValue) warnings.push('Offer Engine: As-is value missing or zero.');
    if (!rentMonthly) warnings.push('Offer Engine: Rent missing or zero.');
    if (loanBalance > 0 && !loanPI) warnings.push('Offer Engine: Existing loan balance present but monthly PI missing / estimated as zero.');
    if (asIsValue > 0 && arv > 0 && asIsValue > arv) warnings.push(`As-is value (${money(asIsValue)}) is above ARV (${money(arv)}). Check value inputs and condition assumptions.`);

    /***** ---------- [2] Seller / Deal Signals ---------- *****/
    const rawTranscript = [
      txt(transcript.sellerUrgency),
      txt(transcript.sellerHardship),
      txt(transcript.price),
      txt(transcript.additionalInsights),
      txt(lead.prequalified_phone_transcript),
      txt(lead.contact_pq_transcript),
      txt(root.prequalified_phone_transcript),
      txt(root.contact_pq_transcript),
      txt(lead['Pq Prequalifier Call Overview']),
      txt(lead['Prequalifier Phone Transcript']),
      txt(lead['Pillar Score Analysis〔P〕'])
    ].join(' ');

    const dom = num(pick(
      property.dom,
      metrics.dom,
      lead['Days on Market'],
      lead.daysOnMarket,
      0
    ));

    const mlsListStatus = lower(pick(
      normalizedSubject.mls_list_status,
      normalizedSubject.source_assumptions?.mls_list_status,
      lead['opp.mlsListStatus'],
      lead['MLS List Status'],
      property.mls?.status,
      property.list_status,
      ''
    ));

    const isShortSale =
      /short sale/.test(mlsListStatus) ||
      hasSignal(rawTranscript, /\bshort sale\b/i);

    const takeoverSignals =
      isShortSale ||
      hasSignal(rawTranscript, /\b(subject to|subto|take over payments|takeover payments|take over the loan|existing financing|existing loan|wrap|wraparound|catch up and take over|crazy low rate|good enough.*rate)\b/i);

    const motivationHigh =
      hasSignal(rawTranscript, /\b(hard money|refi|refinance|must sell|urgent|asap|financial stress|probate|inherited|vacant|out of state|downsizing|relocated|short sale)\b/i) ||
      dom >= 90;

    const competitionHigh =
      hasSignal(rawTranscript, /\b(multiple offers|offer in hand|bidding war)\b/i);

    let motivationBracket = 'neutral';
    if (competitionHigh) motivationBracket = 'aggressive';
    else if (motivationHigh) motivationBracket = 'conservative';

    /***** ---------- [3] Cash-to-Seller Engine ---------- *****/
    const askingPriceForCTS = listPrice || asIsValue || arv || 0;
    const agentCommission = Math.round(askingPriceForCTS * 0.06);
    const sellerClosingCosts = Math.round(askingPriceForCTS * 0.02);

    const sellerRetailNet = Math.round(
      askingPriceForCTS - loanBalance - agentCommission - sellerClosingCosts
    );

    let ctsConservative = 0;
    let ctsStandard = 0;
    let ctsAggressive = 0;

    if (sellerRetailNet < -20000) {
      ctsConservative = 0;
      ctsStandard = 0;
      ctsAggressive = 0;
    } else if (sellerRetailNet <= 0) {
      ctsConservative = 0;
      ctsStandard = 1500;
      ctsAggressive = 4000;
    } else if (sellerRetailNet <= 5000) {
      ctsConservative = 1500;
      ctsStandard = 2000;
      ctsAggressive = Math.min(7000, sellerRetailNet);
    } else {
      ctsConservative = Math.round(Math.min(sellerRetailNet * 0.10, sellerRetailNet));
      ctsStandard = Math.round(Math.min(sellerRetailNet * 0.20, sellerRetailNet));
      ctsAggressive = Math.round(Math.min(sellerRetailNet * 0.30, sellerRetailNet));
    }

    const hardCap15pct = Math.round(askingPriceForCTS * 0.15);

    let recommendedCTS = ctsStandard;
    if (motivationBracket === 'aggressive') recommendedCTS = ctsAggressive;
    if (motivationBracket === 'conservative') recommendedCTS = ctsConservative;
    recommendedCTS = Math.max(0, Math.min(recommendedCTS, hardCap15pct));

    const ctsEngine = {
      seller_retail_net: sellerRetailNet,
      agent_commission: agentCommission,
      seller_closing_costs: sellerClosingCosts,
      cts_conservative: ctsConservative,
      cts_standard: ctsStandard,
      cts_aggressive: ctsAggressive,
      recommended_cts: recommendedCTS,
      motivation_bracket: motivationBracket === 'aggressive' ? 'competition_high' : motivationBracket,
      hard_cap_15pct: hardCap15pct
    };

    /***** ---------- [4] Cash MAO ---------- *****/
    const repairEstimate = num(pick(
      metrics.estimatedRepairCost,
      metrics.repair_estimate,
      root.repair_estimate,
      0
    ));

    const buyerClosingCosts = Math.round(arv * num(config.closingCostRate || 0.08));
    const wholesaleFee = num(pick(config.wholesaleAssignmentFee, metrics.wholesaleFee, root.wholesale_fee, 15000));
    const baseBuyBox = Math.round(arv * 0.70);

    const mao = Math.max(0, Math.round(baseBuyBox - repairEstimate - buyerClosingCosts - wholesaleFee));
    const cashPctOfArv = arv > 0 ? round((mao / arv) * 100, 1) : 0;
    const spreadVsList = listPrice > 0 ? Math.round(mao - listPrice) : 0;

    const acceptableNow = listPrice > 0
      ? mao >= listPrice || ((listPrice - mao) / listPrice) <= 0.05
      : false;

    let negotiationPotential = 'low';
    if (motivationHigh || dom >= 60 || hasSignal(rawTranscript, /\bflexibility|seller financing|creative|cash offer|hard money|subject to|take over payments\b/i)) {
      negotiationPotential = 'high';
    } else if (dom >= 30 || hasSignal(rawTranscript, /\binterested|follow up|open\b/i)) {
      negotiationPotential = 'medium';
    }

    const pursueCashStrategy = mao > 0 && ['medium', 'high'].includes(negotiationPotential);

    const cashOfferObject = {
      type: 'Cash',
      arv,
      buy_box_pct: '70%',
      repair_estimate: repairEstimate,
      buyer_closing_costs: buyerClosingCosts,
      wholesale_fee: wholesaleFee,
      cash_offer: mao,
      cash_offer_pct_of_arv: `${cashPctOfArv}%`,
      spread_vs_list_price: spreadVsList,
      deal_viable: mao > 0,
      acceptable_now: acceptableNow,
      negotiation_potential: negotiationPotential,
      pursue_cash_strategy: pursueCashStrategy
    };

    /***** ---------- [5] Creative Price Anchors ---------- *****/
    const creativePriceFloor = Math.max(listPrice || 0, loanBalance || 0);
    const sfPriceBase = listPrice || asIsValue || arv || 0;

    function buildDerivedMetrics(monthlyPI, purchasePrice, totalIn) {
      const annualPI = Math.round(monthlyPI * 12);
      const DSCR = annualPI > 0 ? round(noi / annualPI, 2) : 0;
      const annualCF = round(noi - annualPI, 0);
      const monthlyCF = round(annualCF / 12, 0);
      const coc = totalIn > 0 ? round((annualCF / totalIn) * 100, 1) : 0;
      const entryPct = purchasePrice > 0 ? round((totalIn / purchasePrice) * 100, 2) : 999;
      const breakEvenRent = round(monthlyPI + monthlyOpex, 2);
      const rentGap = round(breakEvenRent - rentMonthly, 2);
      const rentGapPct = rentMonthly > 0 ? round((rentGap / rentMonthly) * 100, 1) : 0;
      const paybackYears = yearsToRecaptureCash(totalIn, annualCF);

      return {
        ADS: annualPI,
        DSCR,
        annualCF,
        monthlyCF,
        coc,
        entryPct,
        breakEvenRent,
        rentGap,
        rentGapPct,
        paybackYears,
        cashFlowProfile: cashFlowProfile(monthlyCF)
      };
    }

    /***** ---------- [6] Candidate Builders ---------- *****/
    function buildSellerFinanceCandidates() {
      const candidates = [];
      if (sfPriceBase <= 0) return candidates;

      const priceTrials = uniqRounded([
        sfPriceBase,
        sfPriceBase * 0.97,
        sfPriceBase * 0.94,
        sfPriceBase * 0.90,
        asIsValue,
        asIsValue * 0.97
      ]);

      for (const price of priceTrials) {
        for (const downPct of [10, 8, 5]) {
          const down$ = Math.round(price * downPct / 100);

          // Pure Seller Finance only valid if existing debt is fully retired at close.
          if (loanBalance > 0 && down$ < loanBalance) continue;

          for (const ratePct of [4.0, 3.5, 3.0]) {
            for (const balloonYrs of [5, 7]) {
              const years = 30;
              const financed = Math.max(price - down$, 0);
              const monthPI = Math.round(pmt(ratePct, years, financed));
              const assignment = Math.round(down$ * num(config.assignmentPctOfDown || 0.25));
              const totalIn = Math.round(down$ + buyerClosingCosts + assignment);

              const derived = buildDerivedMetrics(monthPI, price, totalIn);

              const pass =
                ratePct <= 4 &&
                downPct <= 10 &&
                balloonYrs >= 5 &&
                derived.DSCR >= 1.20 &&
                derived.monthlyCF >= 200 &&
                derived.coc >= 13 &&
                (derived.entryPct <= 15 || (derived.entryPct <= 20 && derived.monthlyCF >= 500));

              candidates.push({
                id: `seller_finance|${price}|${down$}|${ratePct}|${balloonYrs}`,
                family: 'seller_finance',
                type: 'Seller Finance',

                purchasePrice: price,
                down$,
                downPct,
                ratePct,
                years,
                balloonYrs,
                financed,
                monthPI,
                assignment,
                totalIn,
                cashToSeller: down$,

                // HARD-CODED FIELD CONTRACT
                cts: null,
                ctsPct: null,
                downPayment: down$,
                downPaymentPct: downPct,
                existingLoanBalance: 0,
                existingLoanRate: null,
                existingLoanMonthlyPI: 0,
                sellerCarryPrincipal: financed,
                sellerCarryRate: ratePct,
                sellerCarryAmortYears: years,
                sellerCarryBalloonYears: balloonYrs,
                sellerCarryMonthlyPI: monthPI,
                combinedMonthlyPI: monthPI,
                loanPaidOffAtClose: loanBalance > 0,

                justification: pass
                  ? 'Passes Seller Finance rules. Existing debt is retired at closing, so the remaining balance becomes true seller carry.'
                  : 'Closest Seller Finance structure under current pricing and rent, but does not fully meet investor thresholds.',
                pass,
                ...derived
              });
            }
          }
        }
      }

      return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
    }

    function buildSubToCandidates() {
      const candidates = [];
      if (loanBalance <= 0 || loanPI <= 0) return candidates;

      const price = creativePriceFloor || asIsValue || arv || 0;
      if (price <= 0) return candidates;

      const firstPI = Math.round(loanPI);

      for (const coverSellerClosing of [false, true]) {
        const sellerCloseCovered = coverSellerClosing ? sellerClosingCosts : 0;
        const buyerSide = buyerClosingCosts + sellerCloseCovered;

        for (const ctsTrial of uniqRounded([
          recommendedCTS,
          recommendedCTS * 0.75,
          recommendedCTS * 0.5,
          0,
          isShortSale ? 500 : 0
        ])) {
          const assignment = Math.round(ctsTrial * num(config.assignmentPctOfDown || 0.25));
          const totalIn = Math.round(ctsTrial + buyerSide + assignment);

          const derived = buildDerivedMetrics(firstPI, price, totalIn);

          const lowRateException = loanRate > 0 && loanRate <= 3.5;
          const cfPass = lowRateException ? derived.monthlyCF >= -50 : derived.monthlyCF >= 150;
          const ratePass = (loanBalance > 150000 ? loanRate <= 5 : loanRate <= 8) || loanRate === 0;

          const pass =
            ratePass &&
            derived.DSCR >= 1.0 &&
            cfPass &&
            derived.entryPct <= 15;

          candidates.push({
            id: `subto|${price}|${ctsTrial}|${loanRate}|${coverSellerClosing ? 1 : 0}`,
            family: 'subto',
            type: 'Subject-To',

            purchasePrice: price,
            down$: ctsTrial,
            downPct: price > 0 ? round((ctsTrial / price) * 100, 2) : 0,
            ratePct: loanRate || null,
            years: null,
            balloonYrs: null,
            financed: loanBalance,
            firstPI,
            monthPI: firstPI,
            assignment,
            totalIn,
            cashToSeller: ctsTrial,
            coverSellerClosing,

            // HARD-CODED FIELD CONTRACT
            cts: ctsTrial,
            ctsPct: price > 0 ? round((ctsTrial / price) * 100, 2) : 0,
            downPayment: null,
            downPaymentPct: null,
            existingLoanBalance: loanBalance,
            existingLoanRate: loanRate || null,
            existingLoanMonthlyPI: firstPI,
            sellerCarryPrincipal: 0,
            sellerCarryRate: null,
            sellerCarryAmortYears: null,
            sellerCarryBalloonYears: null,
            sellerCarryMonthlyPI: 0,
            combinedMonthlyPI: firstPI,
            loanPaidOffAtClose: false,

            justification: pass
              ? 'Passes Subject-To screen with acceptable DSCR/cash flow and controlled entry.'
              : 'Closest Subject-To structure under current debt and entry assumptions, but not fully investor-compliant.',
            pass,
            ...derived
          });
        }
      }

      return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
    }

    function buildHybridCandidates() {
      const candidates = [];
      if (loanBalance <= 0 || loanPI <= 0) return candidates;

      const priceBase = creativePriceFloor || asIsValue || arv || 0;
      if (priceBase <= 0) return candidates;

      const firstPI = Math.round(loanPI);

      const priceTrials = uniqRounded([
        priceBase,
        priceBase * 0.97,
        priceBase * 0.94,
        asIsValue,
        listPrice
      ]);

      for (const price of priceTrials) {
        for (const ctsTrial of uniqRounded([
          recommendedCTS,
          recommendedCTS * 0.75,
          recommendedCTS * 0.5,
          0
        ])) {
          const cts = Math.min(ctsTrial, Math.round(price * 0.10));
          const carryPrincipal = Math.max(price - loanBalance - cts, 0);

          for (const carryRate of [4.0, 3.5, 3.0]) {
            for (const balloonYrs of [5, 7]) {
              const carryYears = 30;
              const carryPI = carryPrincipal > 0 ? Math.round(pmt(carryRate, carryYears, carryPrincipal)) : 0;
              const combinedPI = firstPI + carryPI;
              const assignment = Math.round(cts * num(config.assignmentPctOfDown || 0.25));
              const totalIn = Math.round(cts + buyerClosingCosts + assignment);

              const derived = buildDerivedMetrics(combinedPI, price, totalIn);

              const pass =
                cts <= price * 0.10 &&
                derived.DSCR >= 1.20 &&
                derived.monthlyCF >= 200 &&
                derived.coc >= 13 &&
                (derived.entryPct <= 15 || (derived.entryPct <= 20 && derived.monthlyCF >= 500));

              candidates.push({
                id: `hybrid|${price}|${cts}|${carryRate}|${balloonYrs}`,
                family: 'hybrid',
                type: 'Hybrid',

                purchasePrice: price,
                down$: cts,
                downPct: price > 0 ? round((cts / price) * 100, 2) : 0,
                ratePct: carryRate,
                years: 30,
                balloonYrs,
                financed: loanBalance + carryPrincipal,
                firstPI,
                carryPrincipal,
                carryRate,
                carryYears,
                carryPI,
                monthPI: combinedPI,
                assignment,
                totalIn,
                cashToSeller: cts,

                // HARD-CODED FIELD CONTRACT
                cts,
                ctsPct: price > 0 ? round((cts / price) * 100, 2) : 0,
                downPayment: null,
                downPaymentPct: null,
                existingLoanBalance: loanBalance,
                existingLoanRate: loanRate || null,
                existingLoanMonthlyPI: firstPI,
                sellerCarryPrincipal: carryPrincipal,
                sellerCarryRate: carryRate,
                sellerCarryAmortYears: carryYears,
                sellerCarryBalloonYears: balloonYrs,
                sellerCarryMonthlyPI: carryPI,
                combinedMonthlyPI: combinedPI,
                loanPaidOffAtClose: false,

                justification: pass
                  ? 'Passes Hybrid screen with controlled CTS, acceptable DSCR/cash flow, and compliant CoC.'
                  : 'Closest Hybrid structure under current equity and debt, but not fully investor-compliant.',
                pass,
                ...derived
              });
            }
          }
        }
      }

      return candidates.sort((a, b) => candidateScore(b) - candidateScore(a));
    }

    function buildForcedFallbackCandidates() {
      const forced = [];
      const basePrice = Math.max(listPrice || 0, loanBalance || 0, asIsValue || 0, arv || 0);

      if (loanBalance > 0 && loanPI > 0) {
        const firstPI = Math.round(loanPI);
        const totalInA = Math.round(buyerClosingCosts);
        const derivedA = buildDerivedMetrics(firstPI, basePrice, totalInA);

        forced.push({
          id: `forced_subto|${basePrice}|0`,
          family: 'subto',
          type: 'Subject-To',

          purchasePrice: basePrice,
          down$: 0,
          downPct: 0,
          ratePct: loanRate || null,
          years: null,
          balloonYrs: null,
          financed: loanBalance,
          firstPI,
          monthPI: firstPI,
          assignment: 0,
          totalIn: totalInA,
          cashToSeller: 0,
          coverSellerClosing: false,

          cts: 0,
          ctsPct: 0,
          downPayment: null,
          downPaymentPct: null,
          existingLoanBalance: loanBalance,
          existingLoanRate: loanRate || null,
          existingLoanMonthlyPI: firstPI,
          sellerCarryPrincipal: 0,
          sellerCarryRate: null,
          sellerCarryAmortYears: null,
          sellerCarryBalloonYears: null,
          sellerCarryMonthlyPI: 0,
          combinedMonthlyPI: firstPI,
          loanPaidOffAtClose: false,

          justification: 'Educational fallback only. Subject-To structure shown because this is a debt-heavy creative scenario, but current numbers do not meet investor thresholds.',
          pass: false,
          ...derivedA
        });

        const totalInB = Math.round(buyerClosingCosts);
        const derivedB = buildDerivedMetrics(firstPI, basePrice, totalInB);

        forced.push({
          id: `forced_hybrid|${basePrice}|0`,
          family: 'hybrid',
          type: 'Hybrid',

          purchasePrice: basePrice,
          down$: 0,
          downPct: 0,
          ratePct: 4.0,
          years: 30,
          balloonYrs: 5,
          financed: loanBalance,
          firstPI,
          carryPrincipal: 0,
          carryRate: 4.0,
          carryYears: 30,
          carryPI: 0,
          monthPI: firstPI,
          assignment: 0,
          totalIn: totalInB,
          cashToSeller: 0,

          cts: 0,
          ctsPct: 0,
          downPayment: null,
          downPaymentPct: null,
          existingLoanBalance: loanBalance,
          existingLoanRate: loanRate || null,
          existingLoanMonthlyPI: firstPI,
          sellerCarryPrincipal: 0,
          sellerCarryRate: 4.0,
          sellerCarryAmortYears: 30,
          sellerCarryBalloonYears: 5,
          sellerCarryMonthlyPI: 0,
          combinedMonthlyPI: firstPI,
          loanPaidOffAtClose: false,

          justification: 'Educational fallback only. Hybrid shown as second-best creative path, but there is no margin for a true hybrid structure under current numbers.',
          pass: false,
          ...derivedB
        });
      } else {
        const downA = Math.round(basePrice * 0.10);
        const piA = Math.round(pmt(4.0, 30, Math.max(basePrice - downA, 0)));
        const totalInA = Math.round(downA + buyerClosingCosts);
        const derivedA = buildDerivedMetrics(piA, basePrice, totalInA);

        forced.push({
          id: `forced_sf_a|${basePrice}|${downA}`,
          family: 'seller_finance',
          type: 'Seller Finance',

          purchasePrice: basePrice,
          down$: downA,
          downPct: 10,
          ratePct: 4.0,
          years: 30,
          balloonYrs: 5,
          financed: Math.max(basePrice - downA, 0),
          monthPI: piA,
          assignment: 0,
          totalIn: totalInA,
          cashToSeller: downA,

          cts: null,
          ctsPct: null,
          downPayment: downA,
          downPaymentPct: 10,
          existingLoanBalance: 0,
          existingLoanRate: null,
          existingLoanMonthlyPI: 0,
          sellerCarryPrincipal: Math.max(basePrice - downA, 0),
          sellerCarryRate: 4.0,
          sellerCarryAmortYears: 30,
          sellerCarryBalloonYears: 5,
          sellerCarryMonthlyPI: piA,
          combinedMonthlyPI: piA,
          loanPaidOffAtClose: loanBalance > 0,

          justification: 'Educational fallback only. Seller finance shown because no stronger creative structure was buildable from the current data.',
          pass: false,
          ...derivedA
        });

        const downB = Math.round(basePrice * 0.05);
        const piB = Math.round(pmt(3.5, 30, Math.max(basePrice - downB, 0)));
        const totalInB = Math.round(downB + buyerClosingCosts);
        const derivedB = buildDerivedMetrics(piB, basePrice, totalInB);

        forced.push({
          id: `forced_sf_b|${basePrice}|${downB}`,
          family: 'seller_finance',
          type: 'Seller Finance',

          purchasePrice: basePrice,
          down$: downB,
          downPct: 5,
          ratePct: 3.5,
          years: 30,
