  /******************************************************
 OFFER ENGINE v3.2
 -----------------------------------------------------
 Purpose:
  - Consume ONE canonical merged input item
  - Trust locked upstream metrics / property / loan data
  - Also read normalized subject + raw webhook/customData fallback
  - Build:
      • Cash MAO
      • CTS engine
      • Seller Finance candidates
      • Subject-To candidates
      • Hybrid candidates
  - Always return 3 outputs:
      • Primary Offer
      • Backup Offer
      • Updated Cash Offer
  - Never return blank creative slots
  - Fix cash flow math so OPEX is not ignored and TI is not double-counted
  - Add break-even rent + rent gap + payback metrics
  - Hard-code offer field contract by offer type:
      • Seller Finance => down payment + seller carry, CTS = null
      • Subject-To => CTS + existing debt only, no seller carry
      • Hybrid => CTS + existing debt + seller carry

 HARD FAMILY RULE:
  - Subto: equity < 20%
  - Hybrid: equity >= 20% and <= 85%
  - Seller Finance: equity > 85% OR free/clear

 Does NOT own:
  - lead scoring
  - stage routing
  - LOI generation
******************************************************/

function num(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  const n = Number(String(v).replace(/[^\d.-]/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function txt(v) {
  return String(v ?? '').trim();
}

function lower(v) {
  return txt(v).toLowerCase();
}

function pick() {
  for (const v of arguments) {
    if (v === 0) return 0;
    if (v === false) return false;
    if (v === undefined || v === null) continue;
    if (typeof v === 'string') {
      if (v.trim() !== '') return v;
      continue;
    }
    return v;
  }
  return null;
}

function money(n, digits = 0) {
  const v = Number.isFinite(n) ? n : 0;
  return `$${v.toLocaleString('en-US', {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits
  })}`;
}

function moneyOrNull(n, digits = 0) {
  if (n === null || n === undefined) return null;
  return money(num(n), digits);
}

function pct(n, digits = 1) {
  const v = Number.isFinite(n) ? n : 0;
  return `${v.toFixed(digits)}%`;
}

function pctOrNull(n, digits = 1) {
  if (n === null || n === undefined) return null;
  return pct(num(n), digits);
}

function round(n, digits = 0) {
  const p = Math.pow(10, digits);
  return Math.round((Number(n) || 0) * p) / p;
}

function clamp(v, min, max) {
  return Math.min(max, Math.max(min, v));
}

function pmt(rateAnnualPct, years, principal) {
  const P = Number(principal) || 0;
  const y = Number(years) || 0;
  const r = (Number(rateAnnualPct) || 0) / 100 / 12;
  const n = y * 12;
  if (P <= 0 || n <= 0) return 0;
  if (r === 0) return P / n;
  return (P * r) / (1 - Math.pow(1 + r, -n));
}

function uniqRounded(nums) {
  const seen = new Set();
  const out = [];
  for (const raw of nums) {
    const v = Math.round(num(raw));
    if (v > 0 && !seen.has(v)) {
      seen.add(v);
      out.push(v);
    }
  }
  return out;
}

function hasSignal(s, rx) {
  return rx.test(lower(s));
}

function maxBy(arr, fn) {
  if (!arr.length) return null;
  return arr.reduce((best, cur) => (fn(cur) > fn(best) ? cur : best), arr[0]);
}

function deepClone(obj) {
  return JSON.parse(JSON.stringify(obj ?? {}));
}

function safeTranscript(root, output) {
  return (
    root?.transcript?.output ||
    root?.transcript ||
    output?.transcript?.output ||
    output?.transcript ||
    root?.transcript_insights ||
    output?.transcript_insights ||
    {}
  );
}

function yearsToRecaptureCash(totalIn, annualCF) {
  const t = num(totalIn);
  const cf = num(annualCF);
  if (t <= 0 || cf <= 0) return null;
  return round(t / cf, 1);
}

function cashFlowProfile(monthlyCF) {
  const cf = num(monthlyCF);
  if (cf >= 200) return 'positive_cash_flow';
  if (cf >= 0) return 'near_break_even';
  return 'negative_leverage';
}

/*
  HARD family enforcement:
  - Free/clear => Seller Finance
  - Equity < 20% => Subject-To
  - Equity 20% to 85% => Hybrid
  - Equity > 85% => Seller Finance
*/
function requiredFamilyForDeal(loanBalance, equityPct) {
  if (loanBalance <= 0) return 'seller_finance';
  if (equityPct < 20) return 'subto';
  if (equityPct <= 85) return 'hybrid';
  return 'seller_finance';
}

function candidateFailPenalty(c) {
  let penalty = 0;

  if (c.family === 'seller_finance' || c.family === 'hybrid') {
    if (c.DSCR < 1.2) penalty += (1.2 - c.DSCR) * 1000;
    if (c.monthlyCF < 200) penalty += (200 - c.monthlyCF) * 5;
    if (c.coc < 13) penalty += (13 - c.coc) * 50;
  }

  if (c.family === 'subto') {
    if (c.DSCR < 1.0) penalty += (1.0 - c.DSCR) * 1000;
    if (c.monthlyCF < 150) penalty += (150 - c.monthlyCF) * 4;
    if (num(c.unresolvedEquity) > 2500) penalty += num(c.unresolvedEquity) * 2;
  }

  if (c.entryPct > 15) penalty += (c.entryPct - 15) * 20;
  if (c.downPct > 10) penalty += (c.downPct - 10) * 25;
  if (c.balloonYrs !== null && c.balloonYrs < 5) penalty += (5 - c.balloonYrs) * 100;

  return penalty;
}

function candidateScore(c) {
  if (!c) return -1e12;
  const passBoost = c.pass ? 1000000 : 0;
  const forcedPenalty = c.forcedFallback ? 100000 : 0;

  return (
    passBoost +
    (c.monthlyCF * 25) +
    (c.DSCR * 100) +
    (c.coc * 10) -
    (c.totalIn * 0.01) -
    candidateFailPenalty(c) -
    forcedPenalty
  );
}

function selectCandidateInFamily(allCandidates, requiredFamily, excludeIds = new Set()) {
  const pool = allCandidates.filter(
    c => c.family === requiredFamily && !excludeIds.has(c.id)
  );

  if (!pool.length) return null;

  const realPool = pool.filter(c => !c.forcedFallback);
  const realPassing = realPool.filter(c => c.pass);
  if (realPassing.length) return maxBy(realPassing, candidateScore);

  const anyPassing = pool.filter(c => c.pass);
  if (anyPassing.length) return maxBy(anyPassing, candidateScore);

  if (realPool.length) return maxBy(realPool, candidateScore);

  return maxBy(pool, candidateScore);
}

