function parseMoney(x) {
  if (x === undefined || x === null || x === '') return 0;
  if (typeof x === 'number') return Number.isFinite(x) ? x : 0;
  const s = String(x).replace(/[^\d.\-]/g, '');
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
}

function firstNonEmpty(...vals) {
  for (const v of vals) {
    if (v === 0) return 0;
    if (v === false) return false;
    if (v === null || v === undefined) continue;
    if (typeof v === 'string' && v.trim() !== '') return v;
    if (typeof v === 'number' && Number.isFinite(v)) return v;
    if (typeof v === 'boolean') return v;
  }
  return null;
}

function firstPositive(...vals) {
  for (const v of vals) {
    const n = parseMoney(v);
    if (n > 0) return n;
  }
  return 0;
}

function txt(v) {
  return String(v ?? '').trim();
}

function round(n, digits = 0) {
  const p = Math.pow(10, digits);
  return Math.round((Number(n) || 0) * p) / p;
}

function median(nums) {
  const arr = nums.filter(n => Number.isFinite(n)).sort((a, b) => a - b);
  if (!arr.length) return 0;
  const mid = Math.floor(arr.length / 2);
  return arr.length % 2 ? arr[mid] : (arr[mid - 1] + arr[mid]) / 2;
}

function avg(nums) {
  const arr = nums.filter(n => Number.isFinite(n));
  if (!arr.length) return 0;
  return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function safeNode(name, fallback = {}) {
  try {
    const v = $(name).first().json;
    return v ?? fallback;
  } catch {
    return fallback;
  }
}

function moneyStr(n) {
  if (!Number.isFinite(n) || n <= 0) return null;
  return `$${Math.round(n).toLocaleString(undefined, { maximumFractionDigits: 0 })}.00`;
}

function clamp(n, min, max) {
  return Math.min(max, Math.max(min, n));
}

function amortizedPI(balance, annualRatePct, years = 30) {
  const P = parseMoney(balance);
  const rate = parseMoney(annualRatePct);
  if (P <= 0 || rate <= 0) return 0;
  const r = (rate / 100) / 12;
  const n = years * 12;
  return P * ((r * Math.pow(1 + r, n)) / (Math.pow(1 + r, n) - 1));
}

function isReasonableAsIs(candidate, anchors = {}) {
  const v = parseMoney(candidate);
  if (v <= 0) return false;

  const list = parseMoney(anchors.listPrice);
  const compLow = parseMoney(anchors.compLow);
  const market = parseMoney(anchors.marketValue);

  if (list > 0 && v < list * 0.60) return false;
  if (compLow > 0 && v < compLow * 0.55) return false;
  if (market > 0 && v < market * 0.55) return false;

  return true;
}

function chooseAsIsValue(candidates, anchors, warnings) {
  for (const c of candidates) {
    const value = parseMoney(c.value);
    if (!value) continue;

    if (!c.requiresSanity || isReasonableAsIs(value, anchors)) {
      return {
        value,
        source: c.source,
        confidence: c.confidence
      };
    } else {
      warnings.push(`Rejected ${c.source} for as-is value because it failed sanity checks: $${Math.round(value).toLocaleString()}.`);
    }
  }

  if (parseMoney(anchors.listPrice) > 0) {
    const fallback = Math.round(parseMoney(anchors.listPrice) * 0.90);
    warnings.push('As-is value fell back to 90% of list price because stronger sources were missing or failed sanity checks.');
    return {
      value: fallback,
      source: 'fallback_list_price_90pct',
      confidence: 'low'
    };
  }

  if (parseMoney(anchors.compLow) > 0) {
    warnings.push('As-is value fell back to comp_low because stronger sources were missing.');
    return {
      value: parseMoney(anchors.compLow),
      source: 'fallback_comp_low',
      confidence: 'low'
    };
  }

  return {
    value: 0,
    source: 'missing',
    confidence: 'none'
  };
}

function buildCompReport(comparables) {
  if (!Array.isArray(comparables)) return [];
  return comparables.slice(0, 10).map(c => ({
    address: c.formattedAddress || c.address || null,
    correlation: c.correlation != null
      ? round(parseMoney(c.correlation) * (parseMoney(c.correlation) <= 1 ? 100 : 1), 1)
      : null,
    price: parseMoney(c.price) || null,
    beds: parseMoney(c.bedrooms) || null,
    baths: parseMoney(c.bathrooms) || null,
    squareFootage: parseMoney(c.squareFootage) || null,
    daysOnMarket: c.daysOnMarket ?? null,
    distance: parseMoney(c.distance) || null
  }));
}

function weightedMedian(values, weights) {
  const pairs = values
    .map((v, i) => ({ v, w: weights[i] }))
    .filter(x => Number.isFinite(x.v) && Number.isFinite(x.w) && x.w > 0)
    .sort((a, b) => a.v - b.v);

  if (!pairs.length) return 0;

  const totalWeight = pairs.reduce((sum, x) => sum + x.w, 0);
  let running = 0;

  for (const p of pairs) {
    running += p.w;
    if (running >= totalWeight / 2) return p.v;
  }

  return pairs[pairs.length - 1].v;
}

function sameText(a, b) {
  return String(a || '').trim().toLowerCase() === String(b || '').trim().toLowerCase();
}

function extractPropertyTaxesFromNode(node) {
  if (!node || typeof node !== 'object') return 0;

  const direct = firstPositive(
    node.annualTaxes,
    node.annualTax,
    node.taxAmount,
    node.propertyTax,
    node.propertyTaxesAnnual,
    node.tax
  );
  if (direct > 0) return direct;

  if (node.propertyTaxes && typeof node.propertyTaxes === 'object') {
    return firstPositive(
      node.propertyTaxes?.['2026']?.total,
      node.propertyTaxes?.['2025']?.total,
      node.propertyTaxes?.['2024']?.total,
      node.propertyTaxes?.['2023']?.total,
      node.propertyTaxes?.['2022']?.total
    );
  }

  return 0;
}

function estimateRepairCost({ explicitRepair, sqft, yearBuilt, transcriptText, mlsDesc, warnings }) {
  const explicit = parseMoney(explicitRepair);
  if (explicit > 0) {
    return {
      estimatedRepairCost: explicit,
      repair_estimate_source: 'explicit_input',
      repair_cost_per_sqft: sqft > 0 ? round(explicit / sqft, 2) : null
    };
  }

  const text = `${txt(transcriptText)} ${txt(mlsDesc)}`.toLowerCase();

  const heavyRehabLike = /\b(full gut|gut rehab|foundation|fire damage|structural|needs everything|major rehab|flood damage)\b/.test(text);
  const moderateRehabLike = /\b(needs work|deferred maintenance|dated|cosmetic rehab|updating needed|fixer|handyman)\b/.test(text);
  const recentlyUpdatedLike = /\b(new roof|new hvac|new ac|new plumbing|renovated|updated|move-in ready|turnkey|brand new|new construction|built in 20\d{2})\b/.test(text);

  const currentYear = new Date().getFullYear();
  const age = yearBuilt ? Math.max(0, currentYear - yearBuilt) : null;

  let perSqft = 20;
  let minRepair = 30000;
  let source = 'age_based_default';

  if (heavyRehabLike) {
    perSqft = 30;
    minRepair = 45000;
    source = 'heavy_rehab_signal';
  } else if (moderateRehabLike) {
    perSqft = 15;
    minRepair = 18000;
    source = 'moderate_rehab_signal';
  } else if (recentlyUpdatedLike) {
    perSqft = 5;
    minRepair = 6000;
    source = 'recently_updated_signal';
  } else if (age !== null) {
    if (age <= 3) {
      perSqft = 4;
      minRepair = 5000;
      source = 'very_new_property_age_curve';
    } else if (age <= 10) {
      perSqft = 6;
      minRepair = 7500;
      source = 'newer_property_age_curve';
    } else if (age <= 25) {
      perSqft = 10;
      minRepair = 12000;
      source = 'mid_age_property_age_curve';
    } else if (age <= 45) {
      perSqft = 15;
      minRepair = 18000;
      source = 'older_property_age_curve';
    } else {
      perSqft = 22;
      minRepair = 25000;
      source = 'old_property_age_curve';
    }
  }

  const estimate = sqft > 0 ? Math.max(minRepair, Math.round(sqft * perSqft)) : minRepair;

  if (source === 'very_new_property_age_curve' || source === 'newer_property_age_curve') {
    warnings.push('Repairs were estimated with a newer-property age curve, not the old flat $20/sqft fallback.');
  }

  return {
    estimatedRepairCost: estimate,
    repair_estimate_source: source,
    repair_cost_per_sqft: sqft > 0 ? perSqft : null
  };
}

function compDistanceLimit(ctx) {
  if (ctx.comp_tier_mode === 'tier_1_hyperlocal') {
    return ctx.distance_policy?.tier_1_max_miles || 0.5;
