    0
  ));

  const sqft = Number(firstNonEmpty(
    res.building_sqft,
    res.unit_sqft,
    res.source_assumptions?.sqft_input,
    0
  ));

  // Unit-oriented metrics for rent comp logic
  const rentBeds = Number(firstNonEmpty(
    res.unit_beds,
    res.building_beds,
    res.source_assumptions?.beds_input,
    0
  ));

  const rentBaths = Number(firstNonEmpty(
    res.unit_baths,
    res.building_baths,
    res.source_assumptions?.baths_input,
    0
  ));

  const rentSqft = Number(firstNonEmpty(
    res.unit_sqft,
    res.building_sqft,
    res.source_assumptions?.sqft_input,
    0
  ));

  let yearBuilt = firstNonEmpty(
    propNode.yearBuilt,
    saleNode.yearBuilt,
    compsNode.subjectProperty?.yearBuilt,
    rentalNode.subjectProperty?.yearBuilt,
    cd.year_built_mls,
    cd.yearBuilt,
    res.source_assumptions?.year_built,
    null
  );

  if (typeof yearBuilt === 'string') {
    yearBuilt = parseInt(yearBuilt.replace(/[^\d]/g, ''), 10);
  }

  yearBuilt = Number.isFinite(yearBuilt) && yearBuilt >= 1700 && yearBuilt <= 2100 ? yearBuilt : null;

  const propType = String(
    res.property_type_for_value ||
    compsNode.subjectProperty?.propertyType ||
    rentalNode.subjectProperty?.propertyType ||
    saleNode.propertyType ||
    cd.prop_type ||
    'single family'
  ).toLowerCase();

  const oppArv = parseMoney(firstNonEmpty(
    res.est_arv,
    res.source_assumptions?.est_arv,
    cd['opp.estArv'],
    cd.estArv,
    null
  ));

  const normalizedEstValue = parseMoney(firstNonEmpty(
    res.source_assumptions?.est_value,
    cd['opp.estValue'],
    cd.estValue,
    null
  ));

  const mlsDesc = String(firstNonEmpty(cd.mlsDescription, saleNode.description, '') || '').trim();

  const transcriptText = String(firstNonEmpty(
    cd.prequalified_phone_transcript,
    cd.contact_pq_transcript,
    ''
  ));

  const dom = Number(firstNonEmpty(
    saleNode.daysOnMarket,
    saleNode.dom,
    res.source_assumptions?.days_on_market,
    cd.dom,
    null
  )) || 0;

  // ------------------------------------------
  // List price
  // ------------------------------------------
  const rawListPrice = parseMoney(firstNonEmpty(
    saleNode.price,
    res.source_assumptions?.list_price,
    cd['opp.listPrice'],
    cd.list_price,
    cd.ListPrice,
    0
  ));

  const listPrice = rawListPrice > 0 ? rawListPrice : 0;

  const listPriceSource =
    saleNode.price ? 'sale_listing_price' :
    res.source_assumptions?.list_price ? 'normalized_source_assumptions' :
    cd['opp.listPrice'] || cd.list_price || cd.ListPrice ? 'legacy_custom_data' :
    'missing';

  // ------------------------------------------
  // Tax assessed value (reference only)
  // ------------------------------------------
  let taxAssessedValue = parseMoney(res.source_assumptions?.assessed_total_value);

  if (!taxAssessedValue) {
    try {
      const propData = propNode.taxAssessments ? propNode : (compsNode.subjectProperty || {});
      if (propData && propData.taxAssessments) {
        taxAssessedValue =
          parseMoney(propData.taxAssessments?.['2026']?.value) ||
          parseMoney(propData.taxAssessments?.['2025']?.value) ||
          parseMoney(propData.taxAssessments?.['2024']?.value) ||
          parseMoney(propData.taxAssessments?.['2023']?.value) ||
          0;
      }
    } catch {}
  }

  // ------------------------------------------
  // Sale comp support (tier-aware)
  // ------------------------------------------
  const locationCtx = (() => {
    try {
      return $('Location Context v1').first().json.location_context || {};
    } catch {
      return {};
    }
  })();

  const compLow = parseMoney(compsNode.priceRangeLow);
  const compHigh = parseMoney(compsNode.priceRangeHigh);
  const compMid = parseMoney(compsNode.price);

  const saleComparables = Array.isArray(compsNode.comparables) ? compsNode.comparables : [];

  const subjectAddress1 = txt(compsNode.subjectProperty?.addressLine1 || address);
  const subjectSubdivision = txt(propNode.subdivision || compsNode.subjectProperty?.subdivision || '');

  function compScore(c) {
    const dist = parseMoney(c.distance);
    const compSqft = parseMoney(c.squareFootage);
    const compBeds = parseMoney(c.bedrooms);
    const compBaths = parseMoney(c.bathrooms);
    const compYear = parseMoney(c.yearBuilt);
    const price = parseMoney(c.price);

    if (price <= 0 || compSqft <= 0) return -999999;

    let score = 100;

    score -= dist * 25;

    if (sqft > 0 && compSqft > 0) {
      const sqftDeltaPct = Math.abs(compSqft - sqft) / sqft;
      score -= sqftDeltaPct * 90;
    }

    if (beds > 0) score -= Math.abs(compBeds - beds) * 8;
    if (baths > 0) score -= Math.abs(compBaths - baths) * 8;

    if (yearBuilt && compYear) {
      score -= Math.min(Math.abs(compYear - yearBuilt) / 2, 12);
    }

    if (locationCtx.same_building_priority && sameText(c.addressLine1, subjectAddress1)) {
      score += 80;
    }

    if (
      locationCtx.same_subdivision_priority &&
      subjectSubdivision &&
      String(c.subdivision || '').toLowerCase().includes(subjectSubdivision.toLowerCase())
    ) {
      score += 40;
    }

    if (locationCtx.comp_tier_mode === 'tier_1_hyperlocal') {
      if (dist <= 0.10) score += 18;
      else if (dist <= 0.25) score += 10;
    }

    return score;
  }

  let validSaleComps = [];
  let ppsfArv = 0;
  let ppsfArvSource = 'missing';

  if (saleComparables.length) {
    const maxDist = compDistanceLimit(locationCtx);

    validSaleComps = saleComparables.filter(c => {
      const price = parseMoney(c.price);
      const compSqft = parseMoney(c.squareFootage);
      const compBeds = parseMoney(c.bedrooms);
      const compBaths = parseMoney(c.bathrooms);
      const dist = parseMoney(c.distance);

      if (price <= 0 || compSqft <= 0) return false;
      if (dist > maxDist) return false;
      if (beds > 0 && compBeds > 0 && Math.abs(compBeds - beds) > 1) return false;
      if (baths > 0 && compBaths > 0 && Math.abs(compBaths - baths) > 1) return false;

      if (sqft > 0) {
        const ratio = compSqft / sqft;
        if (ratio < 0.75 || ratio > 1.25) return false;
      }

      return true;
    });

    if (locationCtx.comp_tier_mode === 'tier_1_hyperlocal') {
      const sameBuilding = validSaleComps.filter(c => sameText(c.addressLine1, subjectAddress1));

      if (sameBuilding.length >= 2) {
        validSaleComps = sameBuilding;
        ppsfArvSource = 'same_building_weighted_median_ppsf';
        warnings.push('ARV used same-building hyperlocal comp set.');
      } else if (locationCtx.same_subdivision_priority && subjectSubdivision) {
        const sameSubdivision = validSaleComps.filter(c =>
          String(c.subdivision || '').toLowerCase().includes(subjectSubdivision.toLowerCase())
        );

        if (sameSubdivision.length >= 2) {
          validSaleComps = sameSubdivision;
          ppsfArvSource = 'same_subdivision_weighted_median_ppsf';
          warnings.push('ARV used same-subdivision hyperlocal comp set.');
        }
      }
    }

    const scored = validSaleComps
      .map(c => ({
        comp: c,
        score: compScore(c),
        ppsf: parseMoney(c.price) / parseMoney(c.squareFootage)
      }))
      .filter(x => Number.isFinite(x.ppsf) && x.ppsf > 0 && Number.isFinite(x.score))
      .sort((a, b) => b.score - a.score)
      .slice(0, 8);

    if (scored.length) {
      const ppsfValues = scored.map(x => x.ppsf);
      const med = median(ppsfValues);
      const trimmed = scored.filter(x => x.ppsf >= med * 0.70 && x.ppsf <= med * 1.30);

      const finalSet = trimmed.length >= 3 ? trimmed : scored;
      const values = finalSet.map(x => x.ppsf);
      const weights = finalSet.map(x => Math.max(1, x.score));
      const chosenPpsf = weightedMedian(values, weights);

      ppsfArv = Math.round(
        chosenPpsf * (sqft > 0 ? sqft : parseMoney(compsNode.subjectProperty?.squareFootage) || 1500)
      );

      if (ppsfArvSource === 'missing') {
        ppsfArvSource =
          locationCtx.comp_tier_mode === 'tier_1_hyperlocal'
            ? 'hyperlocal_weighted_median_ppsf'
            : locationCtx.comp_tier_mode === 'tier_2_subdivision_sensitive'
              ? 'subdivision_sensitive_weighted_median_ppsf'
              : 'standard_weighted_median_ppsf';
      }
    }
  }

  // ------------------------------------------
  // Market / AVM candidates
  // ------------------------------------------
  const saleAvmEstimate = parseMoney(firstNonEmpty(
    saleNode.estValue,
    saleNode.est_value,
    0
  ));

  const marketValueEstimate = parseMoney(firstNonEmpty(
    it.market_data_extracted?.estimatedMarketValue,
    it.market_data_trends?.estimatedMarketValue,
    0
  ));

  // ------------------------------------------
  // As-is value selection
  // ------------------------------------------
  const asIsCandidates = [
    { source: 'sale_avm_estimate', value: saleAvmEstimate, confidence: 'medium', requiresSanity: true },
    { source: 'normalized_est_value', value: normalizedEstValue, confidence: 'medium', requiresSanity: true },
    { source: 'comp_low', value: compLow, confidence: 'medium', requiresSanity: true },
    { source: 'market_value_estimate', value: marketValueEstimate, confidence: 'low', requiresSanity: true },
    { source: 'list_price', value: listPrice, confidence: 'low', requiresSanity: false },
    { source: 'tax_assessed_value', value: taxAssessedValue, confidence: 'low', requiresSanity: false }
  ];

  const asIsPick = chooseAsIsValue(asIsCandidates, {
    listPrice,
    compLow,
    marketValue: marketValueEstimate
  }, warnings);

  const as_is_value = asIsPick.value;
  const as_is_value_source = asIsPick.source;
  const as_is_value_confidence = asIsPick.confidence;

  // ------------------------------------------
  // ARV selection
  // ------------------------------------------
  let arv = 0;
  let arv_source = 'missing';

  if (oppArv > 0) {
    arv = oppArv;
    arv_source = 'normalized_est_arv_override';
  } else if (ppsfArv > 0) {
    arv = ppsfArv;
    arv_source = ppsfArvSource || 'weighted_median_ppsf';
  } else if (compMid > 0) {
    arv = compMid;
    arv_source = 'comps_api_price';
  } else if (compHigh > 0) {
    arv = compHigh;
    arv_source = 'comp_high_fallback';
  } else if (marketValueEstimate > 0) {
    arv = Math.round(marketValueEstimate * 1.10);
    arv_source = 'market_value_plus_10pct';
    warnings.push('ARV missing from sale comps API. Derived from market value estimate + 10%.');
  } else if (listPrice > 0) {
    arv = Math.round(listPrice * 1.10);
    arv_source = 'list_price_plus_10pct';
    warnings.push('ARV missing from sale comps API. Derived from list price + 10%.');
  } else if (as_is_value > 0) {
    arv = Math.round(as_is_value * 1.15);
    arv_source = 'as_is_plus_15pct';
    warnings.push('ARV missing from sale comps API. Derived from as-is value + 15%.');
  }

  if (taxAssessedValue > 0 && arv > 0 && arv < taxAssessedValue) {
    warnings.push(`ARV ($${Math.round(arv).toLocaleString()}) came in below county assessed value ($${Math.round(taxAssessedValue).toLocaleString()}). Kept ARV unchanged; assessed value is reference-only.`);
  }

  if (arv > 0 && as_is_value > 0 && as_is_value > arv) {
    warnings.push(`As-is value ($${Math.round(as_is_value).toLocaleString()}) is above ARV ($${Math.round(arv).toLocaleString()}). Check value inputs and condition assumptions.`);
  }

  // ------------------------------------------
  // Repair estimate
  // ------------------------------------------
  const repairResult = estimateRepairCost({
    explicitRepair: firstNonEmpty(
      cd.repair_costs,
      cd.repairs,
      cd.EstimatedRepairs,
      cd['PQ | Estimated Repairs $'],
      null
    ),
    sqft,
    yearBuilt,
    transcriptText,
    mlsDesc,
    warnings
  });

  const estimatedRepairCost = repairResult.estimatedRepairCost;
  const repair_estimate_source = repairResult.repair_estimate_source;
  const repair_cost_per_sqft = repairResult.repair_cost_per_sqft;

  // ------------------------------------------
  // Rent
  // ------------------------------------------
  let marketRent = parseMoney(firstNonEmpty(
    res.extracted_rent_roll,
    res.extractedRentRoll,
    canonicalGrossRent
  ));

  if (!res.extracted_rent_roll && Array.isArray(rentalNode.comparables) && rentalNode.comparables.length > 0) {
    let validRents = rentalNode.comparables.filter(c => parseMoney(c.price) > 0);

    validRents = validRents.filter(c => {
      const dist = parseMoney(c.distance);
      const compBeds = parseMoney(c.bedrooms);
      const compBaths = parseMoney(c.bathrooms);
      const compSqft = parseMoney(c.squareFootage);

      if (dist > 2) return false;
      if (rentBeds > 0 && compBeds > 0 && Math.abs(compBeds - rentBeds) > 1) return false;
      if (rentBaths > 0 && compBaths > 0 && Math.abs(compBaths - rentBaths) > 1) return false;

      if (rentSqft > 0 && compSqft > 0) {
        const ratio = compSqft / rentSqft;
        if (ratio < 0.75 || ratio > 1.25) return false;
      }

      return true;
    });

    if (validRents.length > 0) {
      marketRent = Math.round(avg(validRents.map(c => parseMoney(c.price))));
    }
  }

  if (canonicalGrossRent > 0) {
    marketRent = canonicalGrossRent;
  }

  const annualRent = marketRent * 12;
  const proFormaRent = arv > 0 ? Math.round(arv * 0.01) : 0;

  // ------------------------------------------
  // Taxes / insurance / opex
  // ------------------------------------------
  const HIGH_RISK_INS_STATES = new Set(['FL', 'TX', 'LA', 'OK', 'AL', 'MS', 'SC', 'NC', 'GA', 'CA']);
  const insuranceRate = HIGH_RISK_INS_STATES.has(state) ? 0.012 : 0.006;
  const defaultTaxRate = 0.0115;

  const propertyTaxActual = firstPositive(
    res.annual_taxes,
    res.source_assumptions?.annual_taxes,
    cd['annual taxes'],
    cd['anual taxes'],
    cd['Annual Property Taxes'],
    cd['PQ | Annual Property Taxes'],
    extractPropertyTaxesFromNode(propNode),
    extractPropertyTaxesFromNode(saleNode),
    extractPropertyTaxesFromNode(compsNode.subjectProperty || {})
  );

  let taxes = firstPositive(
    res.annual_taxes,
    res.source_assumptions?.annual_taxes,
    cd['annual taxes'],
    cd['anual taxes'],
    cd['Annual Property Taxes'],
    cd['PQ | Annual Property Taxes'],
    propertyTaxActual
  );

  if (!taxes) {
    taxes = firstPositive(
      listPrice > 0 ? Math.round(listPrice * defaultTaxRate) : 0,
      as_is_value > 0 ? Math.round(as_is_value * defaultTaxRate) : 0,
      arv > 0 ? Math.round(arv * defaultTaxRate) : 0
    );
    warnings.push('Taxes fell back to percentage-based estimate because no actual annual tax figure was found upstream.');
  }

  let insurance = parseMoney(firstNonEmpty(
    cd.insuranceAnnual,
    cd.insuranceMonthly ? Math.round(parseMoney(cd.insuranceMonthly) * 12) : 0,
    0
  ));

  if (!insurance) {
    if (taxes > 0) insurance = Math.round(taxes * (HIGH_RISK_INS_STATES.has(state) ? 1.2 : 0.8));
    else insurance = Math.round((listPrice || as_is_value || arv || 100000) * insuranceRate);
  }

  const isSmallMulti = /(duplex|triplex|fourplex|quad|multi)/.test(propType);
  const isRVPark = /\b(rv park|mobile home park|campground|mhp|rv resort)\b/.test(propType) ||
                   /\b(rv park|mobile home park|campground)\b/i.test(mlsDesc);

  let mgmtRate = rental.assumptions?.mgmtRate ?? (isSmallMulti ? 0.09 : (isRVPark ? 0.12 : 0.08));
  let maintRate = rental.assumptions?.maintRate ?? (isSmallMulti ? 0.07 : (isRVPark ? 0.15 : 0.05));
  let vacancyRate = rental.assumptions?.vacancyRate ?? (isSmallMulti ? 0.07 : (isRVPark ? 0.10 : 0.05));

  if (yearBuilt && yearBuilt < 1980 && !isRVPark) {
    maintRate += 0.02;
  }

  const utilitiesRate = rental.assumptions?.utilitiesIncluded ? 0.10 : (isRVPark ? 0.10 : 0);

  const mgmt = Math.round(mgmtRate * annualRent);
  const maint = Math.round(maintRate * annualRent);
  const vacancy = Math.round(vacancyRate * annualRent);
  const utilities = Math.round(utilitiesRate * annualRent);

  const opex = mgmt + maint + vacancy + utilities + taxes + insurance;
  const noi = annualRent - opex;
  const tiMonthly = (taxes + insurance) / 12;

  // ------------------------------------------
  // Existing loan
  // ------------------------------------------
  const loanData = res.loan_data || {};

  const loanBalance = parseMoney(firstNonEmpty(
    loanData.loan_1_balance,
    loanData.total_open_loans_amount,
    cd['Loan 1 Balance'],
    cd['opp.totalAmountOfOpenLoans'],
    0
  ));

  const loanRate = parseMoney(firstNonEmpty(
    loanData.loan_1_rate,
    cd['Loan 1 rate'],
    cd['Loan 1 Rate'],
    0
  ));

  let sellerMonthlyPaymentPI = parseMoney(firstNonEmpty(
    loanData.loan_1_monthly_payment,
    cd['Loan 1 Monthly payment'],
    0
  ));

  const originalPrincipal = parseMoney(firstNonEmpty(
    loanData.loan_1_original_principal,
    cd['loan 1 original principal'],
    cd['Loan 1 Original Principal'],
    0
  ));

  if (loanBalance > 0 && sellerMonthlyPaymentPI === 0 && loanRate > 0) {
    sellerMonthlyPaymentPI = amortizedPI(loanBalance, loanRate, 30);
  }

  let rawLtv = parseMoney(firstNonEmpty(cd.l_to_v_ratio, null));
  let ltv = null;

  if (rawLtv) ltv = rawLtv > 1 ? rawLtv / 100 : rawLtv;
  if (ltv !== null) ltv = clamp(ltv, 0, 1.25);

  let equity_pct = null;

  if (ltv !== null) {
    equity_pct = (1 - ltv) * 100;
  } else if (as_is_value > 0 && loanBalance > 0) {
    equity_pct = ((as_is_value - loanBalance) / as_is_value) * 100;
  } else if (loanBalance <= 0) {
    equity_pct = 100;
  }

  if (equity_pct !== null) equity_pct = clamp(equity_pct, -100, 100);

  // ------------------------------------------
  // Break-even / rent thresholds
  // ------------------------------------------
  const variableExpenseRate = clamp(mgmtRate + maintRate + vacancyRate + utilitiesRate, 0, 0.95);
  const fixedMonthlyCosts = round(((taxes + insurance) / 12) + sellerMonthlyPaymentPI, 2);

  const breakEvenRentMonthly = variableExpenseRate < 1
    ? round(fixedMonthlyCosts / (1 - variableExpenseRate), 2)
    : null;

  const breakEvenGapMonthly = breakEvenRentMonthly != null
    ? round(marketRent - breakEvenRentMonthly, 2)
    : null;

  const debtServiceAnnualPIOnly = round(sellerMonthlyPaymentPI * 12, 2);
  const fixedOpexAnnual = round(taxes + insurance, 2);

  const rentNeededForDSCR120Existing = variableExpenseRate < 1
    ? round((((debtServiceAnnualPIOnly * 1.20) + fixedOpexAnnual) / 12) / (1 - variableExpenseRate), 2)
    : null;

  const baseDSCRPIOnly = debtServiceAnnualPIOnly > 0
    ? round(noi / debtServiceAnnualPIOnly, 3)
    : null;

  // ------------------------------------------
  // Summaries
  // ------------------------------------------
  const comp_properties_report = buildCompReport(saleComparables);

  let comps_summary = '';
  if (comp_properties_report.length) {
    const prices = comp_properties_report.map(c => parseMoney(c.price)).filter(Boolean);
    const low = prices.length ? Math.min(...prices) : 0;
    const high = prices.length ? Math.max(...prices) : 0;

    comps_summary =
      `Top ${Math.min(comp_properties_report.length, 10)} sale comps support a broad value range of ` +
      `${low > 0 ? `$${Math.round(low).toLocaleString()}` : 'N/A'} to ` +
      `${high > 0 ? `$${Math.round(high).toLocaleString()}` : 'N/A'} for comparable properties. ` +
      `Selected ARV source: ${arv_source}. Selected as-is source: ${as_is_value_source}.`;
  }

  // ------------------------------------------
  // Property object
  // ------------------------------------------
  const property = {
    address,
    city,
    state,
    postal_code: postal,
    list_price: moneyStr(listPrice),
    est_value: as_is_value || null,
    arv_value: arv || null,
    beds,
    baths,
    year_built_mls: yearBuilt,
    dom,
    mls_description: mlsDesc || null,
    mls: {
      number: saleNode.mlsNumber || null,
      name: saleNode.mlsName || null,
      status: saleNode.status || null,
      listedDate: saleNode.listedDate || null,
      lastSeenDate: saleNode.lastSeenDate || null,
      price_num: listPrice || 0
    }
  };

  const existing_loan = {
    balance: loanBalance || 0,
    sellerMonthlyPaymentPI: round(sellerMonthlyPaymentPI || 0, 2),
    rate: loanRate || 0,
    original_principal: originalPrincipal || 0,
    ltv: ltv !== null ? Number(ltv.toFixed(4)) : null
  };

  const metrics = {
    list_price: listPrice || 0,
    as_is_value,
    arv,
    comp_low: compLow || 0,
    comp_high: compHigh || 0,
    price: listPrice || 0,
    city,
    state,
    bedrooms: beds,
    bathrooms: baths,
    propertyType: propType,
    sqft,
    yearBuilt,
    grossRent: marketRent,
    proFormaRent,
    annualRent,
    estimatedRepairCost,
    repair_estimate_source,
    repair_cost_per_sqft,
    taxes,
    insurance,
    mgmt,
    maint,
    vacancy,
    utilities,
    opex,
    noi,
    estValue: as_is_value,
    equity_pct: equity_pct !== null ? round(equity_pct, 2) : null,
    tiMonthly: round(tiMonthly, 2),

    breakEvenRentMonthly,
    breakEvenGapMonthly,
    rentNeededForDSCR120Existing,
    baseDebtServiceAnnualPIOnly: debtServiceAnnualPIOnly,
    baseDSCRPIOnly,

    list_price_source: listPriceSource,
    as_is_value_source,
    as_is_value_confidence,
    arv_source,
    raw_value_candidates: {
      normalized_est_arv: oppArv || 0,
      normalized_est_value: normalizedEstValue || 0,
      sale_avm_estimate: saleAvmEstimate || 0,
      market_value_estimate: marketValueEstimate || 0,
      comp_low: compLow || 0,
      comp_mid: compMid || 0,
      comp_high: compHigh || 0,
      tax_assessed_value: taxAssessedValue || 0,
      list_price: listPrice || 0
    }
  };

  const config = {
    insuranceRate,
    mgmtRate,
    maintRate,
    vacancyRate,
    utilitiesRate,
    assignmentPctOfDown: 0.25,
    closingCostRate: 0.08,
    taxRate: defaultTaxRate
  };

  const rental_estimates = it.rental_estimates || null;
  const padsplit_current_vs_target = it.rental_models?.padsplit?.debug || {};

  const canonical = {
    rental_model: canonicalKey,
    economics: {
      grossRentMonthly: marketRent,
      annualRent,
      opexAnnual: opex,
      NOI: noi,
      ADS: null,
      DSCR: null,
      monthlyCF: null,
      annualCF: null,
      totalCashIn: null,
      CoC_pct: null
    }
  };

  results.push({
    json: {
      ...it,
      estimated_arv: arv || 0,
      comp_properties_report,
      comps_summary,
      property,
      rental_estimates,
      existing_loan,
      metrics,
      config,
      canonical,
      padsplit_current_vs_target,
      warnings
    }
  });
}

return results;

