function isNil(v) {
  return v === null || v === undefined;
}

function num(v) {
  if (isNil(v) || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  if (typeof v === 'boolean') return v ? 1 : 0;
  const n = Number(String(v).replace(/[^\d.-]/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function txt(v) {
  return String(v ?? '').trim();
}

function lower(v) {
  return txt(v).toLowerCase();
}

function round(n, digits = 0) {
  const p = Math.pow(10, digits);
  return Math.round((Number(n) || 0) * p) / p;
}

function clamp(v, min, max) {
  return Math.min(max, Math.max(min, v));
}

function money(n, digits = 0) {
  const v = Number.isFinite(n) ? n : 0;
  return `$${v.toLocaleString('en-US', {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits
  })}`;
}

function moneyOrNull(n, digits = 0) {
  if (n === null || n === undefined) return null;
  return money(num(n), digits);
}

function pct(n, digits = 1) {
  const v = Number.isFinite(n) ? n : 0;
  return `${v.toFixed(digits)}%`;
}

function pctOrNull(n, digits = 1) {
  if (n === null || n === undefined) return null;
  return pct(num(n), digits);
}

function pmt(rateAnnualPct, years, principal) {
  const P = Number(principal) || 0;
  const y = Number(years) || 0;
  const r = (Number(rateAnnualPct) || 0) / 100 / 12;
  const n = y * 12;
  if (P <= 0 || n <= 0) return 0;
  if (r === 0) return P / n;
  return (P * r) / (1 - Math.pow(1 + r, -n));
}

function deepClone(obj) {
  return JSON.parse(JSON.stringify(obj ?? {}));
}

function pick() {
  for (const v of arguments) {
    if (v === 0 || v === false) return v;
    if (v === undefined || v === null) continue;
    if (typeof v === 'string') {
      if (v.trim() !== '') return v;
      continue;
    }
    return v;
  }
  return null;
}

function uniqRounded(nums) {
  const seen = new Set();
  const out = [];
  for (const raw of nums) {
    const v = Math.round(num(raw));
    if (v >= 0 && !seen.has(v)) {
      seen.add(v);
      out.push(v);
    }
  }
  return out;
}

function safeTranscript(root, output) {
  return (
    root?.transcript?.output ||
    root?.transcript ||
    output?.transcript?.output ||
    output?.transcript ||
    root?.transcript_insights ||
    output?.transcript_insights ||
    {}
  );
}

function yearsToRecaptureCash(totalIn, annualCF) {
  const t = num(totalIn);
  const cf = num(annualCF);
  if (t <= 0 || cf <= 0) return null;
  return round(t / cf, 1);
}

function cashFlowProfile(monthlyCF) {
  const cf = num(monthlyCF);
  if (cf >= 200) return 'positive_cash_flow';
  if (cf >= 0) return 'near_break_even';
  return 'negative_leverage';
}

function computeEquityPct(metricsEquityPct, loanBalance, asIsValue, existingLtv) {
  let equityPct = num(metricsEquityPct);
  if (equityPct > 0 && equityPct <= 1) equityPct *= 100;

  if (equityPct !== 0 && !equityPct) {
    if (num(existingLtv) > 0 && num(existingLtv) <= 1) {
      equityPct = (1 - num(existingLtv)) * 100;
    } else if (loanBalance > 0 && asIsValue > 0) {
      equityPct = ((asIsValue - loanBalance) / asIsValue) * 100;
    } else if (loanBalance <= 0 && asIsValue > 0) {
      equityPct = 100;
    } else {
      equityPct = 0;
    }
  }
  return round(clamp(equityPct, -100, 100), 2);
}

function routeFamilies(loanBalance, equityPct) {
  if (loanBalance <= 0) {
    return { primary: 'seller_finance', secondary: [], confidence: 'high', reason: 'free_clear' };
  }
  if (equityPct < 20) {
    return { primary: 'subto', secondary: ['hybrid'], confidence: equityPct < 10 ? 'high' : 'medium', reason: 'equity_below_20' };
  }
  if (equityPct <= 85) {
    return { primary: 'hybrid', secondary: ['subto'], confidence: 'high', reason: 'equity_20_to_85' };
  }
  return { primary: 'seller_finance', secondary: ['hybrid'], confidence: 'high', reason: 'equity_above_85' };
}

function validateCanonicalInput(input) {
  const errors = [];
  const warnings = [];

  if (!input.property.arv) warnings.push({ code: 'MISSING_ARV', message: 'ARV missing or zero.' });
  if (!input.property.asIsValue) warnings.push({ code: 'MISSING_AS_IS_VALUE', message: 'As-is value missing or zero.' });
  if (!input.income.rentMonthly && !input.income.annualRent) warnings.push({ code: 'MISSING_RENT', message: 'Rent missing or zero.' });
  if (input.debt.balance > 0 && !input.debt.monthlyPI) warnings.push({ code: 'MISSING_LOAN_PI', message: 'Debt balance present but monthly PI missing or zero.' });

  const basePriceAvailable = [
    input.property.listPrice,
    input.property.asIsValue,
    input.property.arv,
    input.debt.balance
  ].some(v => Number(v) > 0);

  if (!basePriceAvailable) {
    errors.push({ code: 'NO_PRICE_BASIS', message: 'No valid price basis available.' });
  }

  if (input.padsplit?.feasible && input.padsplit?.grossRentMonthly <= 0 && input.padsplit?.targetRooms <= 0) {
    warnings.push({ code: 'PADSPLIT_RENT_UNDERMODELED', message: 'Padsplit feasible but no usable padsplit rent model was found.' });
  }

  return { valid: errors.length === 0, errors, warnings };
}

function computeEconomics(input, policy) {
  const annualRent = num(input.income.annualRent || num(input.income.rentMonthly) * 12);
  const rentMonthly = num(input.income.rentMonthly || (annualRent > 0 ? annualRent / 12 : 0));

  const taxes = num(input.expenses.taxesAnnual);
  const insurance = num(input.expenses.insuranceAnnual);
  const mgmt = num(input.expenses.mgmtAnnual || annualRent * policy.economics.mgmt_rate);
  const maint = num(input.expenses.maintAnnual || annualRent * policy.economics.maint_rate);
  const vacancy = num(input.expenses.vacancyAnnual || annualRent * policy.economics.vacancy_rate);
  const utilities = num(input.expenses.utilitiesAnnual);
  const opexAnnual = num(input.expenses.opexAnnual || taxes + insurance + mgmt + maint + vacancy + utilities);
  const noi = num(input.expenses.noi || annualRent - opexAnnual);
  const tiMonthly = round((taxes + insurance) / 12, 2);
  const monthlyOpex = round(opexAnnual / 12, 2);

  return {
    annualRent, rentMonthly, taxes, insurance, mgmt, maint, vacancy, utilities,
    opexAnnual, noi, tiMonthly, monthlyOpex
  };
}

function computePadsplitGrossRentMonthly(input, policy) {
  const p = input.padsplit || {};
  const roomRateStandard = num(p.standardRoomRate || policy.mandates.padsplit.standard_room_rate_default);
  const roomRateEnsuite = num(p.ensuiteRoomRate || policy.mandates.padsplit.ensuite_room_rate_default);

  const standardRooms = num(p.standardRoomCount);
  const ensuiteRooms = num(p.ensuiteRoomCount);

  const roomMixGross = (standardRooms * roomRateStandard) + (ensuiteRooms * roomRateEnsuite);
  if (roomMixGross > 0) return roomMixGross;
  if (num(p.grossRentMonthly) > 0) return num(p.grossRentMonthly);

  return 0;
}

function computePadsplitEconomics(input, policy) {
  const annualTaxes = num(input.expenses.taxesAnnual);
  const annualInsurance = num(input.expenses.insuranceAnnual);

  const grossRentMonthly = computePadsplitGrossRentMonthly(input, policy);
  const annualRent = round(grossRentMonthly * 12, 0);

  const vacancy = round(annualRent * num(policy.mandates.padsplit.vacancy_rate), 0);
  const mgmt = round(annualRent * num(policy.mandates.padsplit.mgmt_rate), 0);
  const maint = round(annualRent * num(policy.mandates.padsplit.maint_rate), 0);

  const utilities = round(num(input.padsplit.monthlyUtilities) * 12, 0);
  const cleaning = round(num(input.padsplit.monthlyCleaning) * 12, 0);
  const turnReserve = round(num(input.padsplit.monthlyTurnReserve) * 12, 0);

  const opexAnnual = annualTaxes + annualInsurance + vacancy + mgmt + maint + utilities + cleaning + turnReserve;
  const noi = round(annualRent - opexAnnual, 0);

  return {
    grossRentMonthly, annualRent, taxes: annualTaxes, insurance: annualInsurance,
    vacancy, mgmt, maint, utilities, cleaning, turnReserve, opexAnnual, noi,
    monthlyOpex: round(opexAnnual / 12, 2)
  };
}

function buildDerivedMetrics({ noi, rentMonthly, monthlyOpex, monthlyPI, purchasePrice, totalIn }) {
  const ADS = round(monthlyPI * 12, 0);
  const DSCR = ADS > 0 ? round(noi / ADS, 2) : 0;
  const annualCF = round(noi - ADS, 0);
  const monthlyCF = round(annualCF / 12, 0);
  const coc = totalIn > 0 ? round((annualCF / totalIn) * 100, 1) : 0;
  const entryPct = purchasePrice > 0 ? round((totalIn / purchasePrice) * 100, 2) : 999;
  const breakEvenRent = round(monthlyPI + monthlyOpex, 2);
  const rentGap = round(breakEvenRent - rentMonthly, 2);
  const rentGapPct = rentMonthly > 0 ? round((rentGap / rentMonthly) * 100, 1) : 0;
  const paybackYears = yearsToRecaptureCash(totalIn, annualCF);

  return {
    ADS, DSCR, annualCF, monthlyCF, coc, entryPct, breakEvenRent,
    rentGap, rentGapPct, paybackYears, cashFlowProfile: cashFlowProfile(monthlyCF)
  };
}

function normalizeInput(root, policy) {
  const output = (root.output && typeof root.output === 'object' && !Array.isArray(root.output)) ? root.output : {};
  const property = deepClone(root.property || output.property || {});
  const metrics = deepClone(root.metrics || output.metrics || {});
  const existingLoan = deepClone(root.existing_loan || output.existing_loan || {});
  const normalizedSubject = deepClone(root.normalized_subject || output.normalized_subject || root.resolved || output.resolved || {});
  const transcript = safeTranscript(root, output);
  const lead = root.webhook_custom_data || root.customData || root.body?.customData || root.body || {};

  const arv = num(pick(metrics.arv, root.estimated_arv, output.estimated_arv, property.arv_value, normalizedSubject.est_arv, normalizedSubject.source_assumptions?.est_arv, lead['opp.estArv'], lead.estArv));
  const listPrice = num(pick(metrics.list_price, metrics.price, property.list_price, property.mls?.price_num, normalizedSubject.source_assumptions?.list_price, lead['opp.listPrice'], lead.list_price, lead.listPrice));
  const asIsValue = num(pick(metrics.as_is_value, property.est_value, normalizedSubject.source_assumptions?.est_value, lead['opp.estValue'], lead.estValue, lead.est_value, lead['opp.assessedTotalValue']));

  const annualRent = num(pick(metrics.annualRent, metrics.annual_rent, num(metrics.grossRent) * 12, num(root.standard_rent_monthly) * 12));
  const rentMonthly = num(pick(metrics.grossRent, metrics.gross_rent_monthly, root.standard_rent_monthly, annualRent > 0 ? annualRent / 12 : 0));

  const taxesAnnual = num(pick(metrics.taxes, property.annual_taxes, normalizedSubject.annual_taxes, normalizedSubject.source_assumptions?.annual_taxes, lead['annual taxes'], lead['anual taxes'], 0));
  const insuranceAnnual = num(pick(metrics.insurance, property.annual_insurance, lead.insuranceAnnual, 0));
  const mgmtAnnual = num(pick(metrics.mgmt, annualRent > 0 ? Math.round(annualRent * policy.economics.mgmt_rate) : 0));
  const maintAnnual = num(pick(metrics.maint, annualRent > 0 ? Math.round(annualRent * policy.economics.maint_rate) : 0));
  const vacancyAnnual = num(pick(metrics.vacancy, annualRent > 0 ? Math.round(annualRent * policy.economics.vacancy_rate) : 0));
  const utilitiesAnnual = num(pick(metrics.utilities, 0));
  const opexAnnual = num(pick(metrics.opex, taxesAnnual + insuranceAnnual + mgmtAnnual + maintAnnual + vacancyAnnual + utilitiesAnnual));
  const noi = num(pick(metrics.noi, annualRent - opexAnnual));

  const balance = num(pick(existingLoan.balance, normalizedSubject.loan_data?.loan_1_balance, lead['Loan 1 Balance'], lead['opp.totalAmountOfOpenLoans'], lead.totalAmountOfOpenLoans));
  const ratePct = num(pick(existingLoan.rate, normalizedSubject.loan_data?.loan_1_rate, lead['Loan 1 rate'], lead['Loan 1 Rate']));
  const monthlyPI = num(pick(existingLoan.sellerMonthlyPaymentPI, normalizedSubject.loan_data?.loan_1_monthly_payment, lead['Loan 1 Monthly payment'], lead['Uw Loan 1 Monthly Payment'], (balance > 0 && ratePct > 0) ? pmt(ratePct, 30, balance) : 0));

  return {
    raw: root,
    property_raw: property,
    metrics_raw: metrics,
    existing_loan_raw: existingLoan,
    normalized_subject: normalizedSubject,
    transcript,
    lead,
    property: {
      arv,
      listPrice,
      asIsValue,
      dom: num(pick(property.dom, metrics.dom, lead['Days on Market'], lead.daysOnMarket, 0)),
      mlsStatus: lower(pick(normalizedSubject.mls_list_status, normalizedSubject.source_assumptions?.mls_list_status, lead['opp.mlsListStatus'], lead['MLS List Status'], property.mls?.status, property.list_status, ''))
    },
    income: {
      rentMonthly,
      annualRent
    },
    expenses: {
      taxesAnnual,
      insuranceAnnual,
      mgmtAnnual,
      maintAnnual,
      vacancyAnnual,
      utilitiesAnnual,
      opexAnnual,
      noi
    },
    debt: {
      balance,
      ratePct,
      monthlyPI,
      originalPrincipal: num(pick(existingLoan.original_principal, normalizedSubject.loan_data?.loan_1_original_principal, lead['loan 1 original principal'], lead['Loan 1 Original Principal'], 0)),
      ltv: num(existingLoan.ltv)
    },
    padsplit: {
      allowed: !!root.rental_models?.padsplit?.allowed,
      feasible: !!root.rental_models?.padsplit?.feasible,
      grossRentMonthly: num(root.rental_models?.padsplit?.grossRentMonthly),
      currentRooms: num(root.rental_models?.padsplit?.debug?.currentRooms ?? root.padsplit_current_vs_target?.currentRooms),
      targetRooms: num(root.rental_models?.padsplit?.debug?.targetRooms ?? root.padsplit_current_vs_target?.targetRooms),
      ensuiteRoomCount: num(root.padsplit_room_mix?.ensuiteRoomCount ?? root.body?.padsplit_room_mix?.ensuiteRoomCount ?? 0),
      standardRoomCount: num(root.padsplit_room_mix?.standardRoomCount ?? root.body?.padsplit_room_mix?.standardRoomCount ?? 0),
      standardRoomRate: num(root.padsplit_room_mix?.standardRoomRate ?? root.body?.padsplit_room_mix?.standardRoomRate ?? root.rental_models?.padsplit?.debug?.standardRoomRate ?? policy.mandates.padsplit.standard_room_rate_default),
      ensuiteRoomRate: num(root.padsplit_room_mix?.ensuiteRoomRate ?? root.body?.padsplit_room_mix?.ensuiteRoomRate ?? root.rental_models?.padsplit?.debug?.ensuiteRoomRate ?? policy.mandates.padsplit.ensuite_room_rate_default),
      upliftMonthly: num(root.rental_models?.padsplit?.debug?.upliftMonthly ?? root.padsplit_current_vs_target?.upliftMonthly),
      renoEstimate: num(root.rental_models?.padsplit?.debug?.totalRenoEstimate ?? root.padsplit_current_vs_target?.totalRenoEstimate ?? root.rental_models?.padsplit?.debug?.renoEstimate ?? 0),
      supportedReno: num(root.rental_models?.padsplit?.debug?.supportedReno ?? root.padsplit_current_vs_target?.supportedReno ?? 0),
      monthlyUtilities: num(root.padsplit_expenses?.monthlyUtilities ?? root.body?.padsplit_expenses?.monthlyUtilities ?? policy.mandates.padsplit.default_monthly_utilities),
      monthlyCleaning: num(root.padsplit_expenses?.monthlyCleaning ?? root.body?.padsplit_expenses?.monthlyCleaning ?? policy.mandates.padsplit.default_monthly_cleaning),
      monthlyTurnReserve: num(root.padsplit_expenses?.monthlyTurnReserve ?? root.body?.padsplit_expenses?.monthlyTurnReserve ?? policy.mandates.padsplit.default_monthly_turn_reserve),
      bathroomRisk: root.rental_models?.padsplit?.debug?.bathroomInfrastructureRisk ?? root.padsplit_current_vs_target?.bathroomInfrastructureRisk ?? null,
      upstream: deepClone(root.rental_models?.padsplit || root.padsplit || {})
    },
    marketSignals: {
      motivationHigh: num(pick(property.dom, metrics.dom, lead['Days on Market'], lead.daysOnMarket, 0)) >= 90,
      competitionHigh: false,
      isShortSale: /short sale/.test(lower(pick(normalizedSubject.mls_list_status, property.mls?.status, property.list_status, '')))
    }
  };
}

function computeMotivationBracket(signals) {
  if (signals.competitionHigh) return 'aggressive';
  if (signals.motivationHigh) return 'conservative';
  return 'neutral';
}

function computeCTS(input, policy) {
  const askingPrice = input.property.listPrice || input.property.asIsValue || input.property.arv || 0;
  const agentCommission = Math.round(askingPrice * policy.economics.agent_commission_rate);
  const sellerClosingCosts = Math.round(askingPrice * policy.economics.seller_closing_cost_rate);
  const sellerRetailNet = Math.round(askingPrice - input.debt.balance - agentCommission - sellerClosingCosts);

  let ctsConservative = 0;
  let ctsStandard = 0;
  let ctsAggressive = 0;

  if (sellerRetailNet < -20000) {
    ctsConservative = 0; ctsStandard = 0; ctsAggressive = 0;
  } else if (sellerRetailNet <= 0) {
    ctsConservative = 0; ctsStandard = 1500; ctsAggressive = 4000;
  } else if (sellerRetailNet <= 5000) {
    ctsConservative = 1500; ctsStandard = 2000; ctsAggressive = Math.min(7000, sellerRetailNet);
  } else {
    ctsConservative = Math.round(Math.min(sellerRetailNet * 0.10, sellerRetailNet));
    ctsStandard = Math.round(Math.min(sellerRetailNet * 0.20, sellerRetailNet));
    ctsAggressive = Math.round(Math.min(sellerRetailNet * 0.30, sellerRetailNet));
  }

  const hardCap15pct = Math.round(askingPrice * policy.economics.cts_hard_cap_pct);
  const motivationBracket = computeMotivationBracket(input.marketSignals);

  let recommendedCTS = ctsStandard;
  if (motivationBracket === 'aggressive') recommendedCTS = ctsAggressive;
  if (motivationBracket === 'conservative') recommendedCTS = ctsConservative;
  recommendedCTS = Math.max(0, Math.min(recommendedCTS, hardCap15pct));

  return {
    seller_retail_net: sellerRetailNet,
    agent_commission: agentCommission,
    seller_closing_costs: sellerClosingCosts,
    cts_conservative: ctsConservative,
    cts_standard: ctsStandard,
    cts_aggressive: ctsAggressive,
    recommended_cts: recommendedCTS,
    motivation_bracket: motivationBracket === 'aggressive' ? 'competition_high' : motivationBracket,
    hard_cap_15pct: hardCap15pct
  };
}

function computeCashOffer(input, policy) {
  const repairEstimate = num(pick(input.metrics_raw.estimatedRepairCost, input.metrics_raw.repair_estimate, input.raw.repair_estimate, 0));
  const buyerClosingCosts = Math.round(input.property.arv * policy.economics.closing_cost_rate);
  const wholesaleFee = num(pick(policy.economics.wholesale_assignment_fee, input.metrics_raw.wholesaleFee, input.raw.wholesale_fee, 15000));
  const baseBuyBox = Math.round(input.property.arv * policy.economics.buy_box_pct);
  const mao = Math.max(0, Math.round(baseBuyBox - repairEstimate - buyerClosingCosts - wholesaleFee));
  const cashPctOfArv = input.property.arv > 0 ? round((mao / input.property.arv) * 100, 1) : 0;
  const spreadVsList = input.property.listPrice > 0 ? Math.round(mao - input.property.listPrice) : 0;

  return {
    buyerClosingCosts,
    wholesaleFee,
    repairEstimate,
    mao,
    cashPctOfArv,
    spreadVsList,
    cash_offer: {
      type: 'Cash',
      arv: input.property.arv,
      buy_box_pct: `${round(policy.economics.buy_box_pct * 100, 0)}%`,
      repair_estimate: repairEstimate,
      buyer_closing_costs: buyerClosingCosts,
      wholesale_fee: wholesaleFee,
      cash_offer: mao,
      cash_offer_pct_of_arv: `${cashPctOfArv}%`,
      spread_vs_list_price: spreadVsList,
      deal_viable: mao > 0
    }
  };
}

function withReasons(candidate, hardFails, softFails, forcedFallback = false) {
  return {
    ...candidate,
    hard_fail_reasons: hardFails,
    soft_fail_reasons: softFails,
    forcedFallback,
    pass: hardFails.length === 0 && softFails.length === 0
  };
}

function buildSellerFinanceCandidates(ctx) {
  const { input, econ, policy, cash } = ctx;
  const out = [];
  const priceBase = input.property.listPrice || input.property.asIsValue || input.property.arv || 0;
  if (priceBase <= 0) return out;

  const priceTrials = uniqRounded([priceBase, priceBase * 0.97, priceBase * 0.94, priceBase * 0.90, input.property.asIsValue]);

  for (const price of priceTrials) {
    for (const downPct of policy.families.seller_finance.allowed_down_pcts) {
      const downPayment = Math.round(price * downPct / 100);
      if (input.debt.balance > 0 && downPayment < input.debt.balance) continue;

      for (const ratePct of policy.families.seller_finance.allowed_rates) {
        for (const balloonYrs of policy.families.seller_finance.allowed_balloons) {
          const financed = Math.max(price - downPayment, 0);
          const monthlyPI = Math.round(pmt(ratePct, policy.families.seller_finance.amort_years, financed));
          const assignment = Math.round(downPayment * policy.economics.assignment_pct_of_entry);
          const totalIn = Math.round(downPayment + cash.buyerClosingCosts + assignment);
          const derived = buildDerivedMetrics({
            noi: econ.noi,
            rentMonthly: econ.rentMonthly,
            monthlyOpex: econ.monthlyOpex,
            monthlyPI,
            purchasePrice: price,
            totalIn
          });

          const hardFails = [];
          const softFails = [];

          if (derived.DSCR < policy.families.seller_finance.min_dscr_hard) hardFails.push('DSCR_HARD_FAIL');
          if (derived.monthlyCF < policy.families.seller_finance.min_monthly_cf_hard) hardFails.push('MONTHLY_CF_HARD_FAIL');
          if (downPct > policy.families.seller_finance.max_down_pct) hardFails.push('DOWN_PAYMENT_TOO_HIGH');

          if (derived.DSCR < policy.families.seller_finance.min_dscr_target) softFails.push('DSCR_BELOW_TARGET');
          if (derived.monthlyCF < policy.families.seller_finance.min_monthly_cf_target) softFails.push('MONTHLY_CF_BELOW_TARGET');
          if (derived.coc < policy.families.seller_finance.min_coc_target) softFails.push('COC_BELOW_TARGET');

          out.push(withReasons({
            id: `seller_finance|${price}|${downPct}|${ratePct}|${balloonYrs}`,
            family: 'seller_finance',
            strategy: downPct <= 5 ? 'seller_finance_low_down' : 'seller_finance_standard',
            type: 'Seller Finance',
            purchasePrice: price,
            downPayment,
            downPaymentPct: downPct,
            cts: null,
            ctsPct: null,
            existingLoanBalance: 0,
            existingLoanRate: null,
            existingLoanMonthlyPI: 0,
            sellerCarryPrincipal: financed,
            sellerCarryRate: ratePct,
            sellerCarryAmortYears: policy.families.seller_finance.amort_years,
            sellerCarryBalloonYears: balloonYrs,
            sellerCarryMonthlyPI: monthlyPI,
            combinedMonthlyPI: monthlyPI,
            cashToSeller: downPayment,
            totalIn,
            financed,
            ...derived
          }, hardFails, softFails));
        }
      }
    }
  }
  return out;
}

function buildSubToCandidates(ctx) {
  const { input, econ, policy, cash, cts } = ctx;
  const out = [];
  if (input.debt.balance <= 0 || input.debt.monthlyPI <= 0) return out;

  const price = Math.max(input.property.listPrice || 0, input.debt.balance || 0, input.property.asIsValue || 0);
  if (price <= 0) return out;

  for (const coverSellerClosing of [false, true]) {
    const sellerCloseCovered = coverSellerClosing ? cts.seller_closing_costs : 0;
    const buyerSide = cash.buyerClosingCosts + sellerCloseCovered;

    for (const ctsTrial of uniqRounded([
      cts.recommended_cts,
      cts.recommended_cts * 0.75,
      cts.recommended_cts * 0.5,
      0,
      input.marketSignals.isShortSale ? 500 : 0
    ])) {
      const assignment = Math.round(ctsTrial * policy.economics.assignment_pct_of_entry);
      const totalIn = Math.round(ctsTrial + buyerSide + assignment);
      const unresolvedEquity = Math.max(price - input.debt.balance - ctsTrial, 0);
      const derived = buildDerivedMetrics({
        noi: econ.noi,
        rentMonthly: econ.rentMonthly,
        monthlyOpex: econ.monthlyOpex,
        monthlyPI: input.debt.monthlyPI,
        purchasePrice: price,
        totalIn
      });

      const hardFails = [];
      const softFails = [];
      const maxRate = input.debt.balance > policy.families.subto.large_balance_cutoff
        ? policy.families.subto.max_rate_pct_large_balance
        : policy.families.subto.max_rate_pct_small_balance;

      if (unresolvedEquity > policy.families.subto.max_unresolved_equity) hardFails.push('UNRESOLVED_EQUITY_TOO_HIGH');
      if (derived.DSCR < policy.families.subto.min_dscr_hard) hardFails.push('DSCR_HARD_FAIL');
      if (input.debt.ratePct > maxRate) hardFails.push('RATE_TOO_HIGH');
      if (derived.entryPct > policy.families.subto.max_entry_pct) hardFails.push('ENTRY_TOO_HIGH');

      const monthlyCfTarget = input.debt.ratePct > 0 && input.debt.ratePct <= policy.families.subto.low_rate_exception_pct
        ? -50
        : policy.families.subto.min_monthly_cf_target;

      if (derived.DSCR < policy.families.subto.min_dscr_target) softFails.push('DSCR_BELOW_TARGET');
      if (derived.monthlyCF < monthlyCfTarget) softFails.push('MONTHLY_CF_BELOW_TARGET');

      out.push(withReasons({
        id: `subto|${price}|${ctsTrial}|${coverSellerClosing ? 1 : 0}`,
        family: 'subto',
        strategy: ctsTrial === 0 ? 'subto_zero_entry' : 'subto_low_cts',
        type: 'Subject-To',
        purchasePrice: price,
        downPayment: null,
        downPaymentPct: null,
        cts: ctsTrial,
        ctsPct: price > 0 ? round((ctsTrial / price) * 100, 2) : 0,
        existingLoanBalance: input.debt.balance,
        existingLoanRate: input.debt.ratePct || null,
        existingLoanMonthlyPI: input.debt.monthlyPI,
        sellerCarryPrincipal: 0,
        sellerCarryRate: null,
        sellerCarryAmortYears: null,
        sellerCarryBalloonYears: null,
        sellerCarryMonthlyPI: 0,
        combinedMonthlyPI: input.debt.monthlyPI,
        cashToSeller: ctsTrial,
        totalIn,
        unresolvedEquity,
        ...derived
      }, hardFails, softFails));
    }
  }
  return out;
}

function buildHybridCandidates(ctx) {
  const { input, econ, policy, cash, cts } = ctx;
  const out = [];
  if (input.debt.balance <= 0 || input.debt.monthlyPI <= 0) return out;

  const priceBase = Math.max(input.property.listPrice || 0, input.debt.balance || 0, input.property.asIsValue || 0);
  if (priceBase <= 0) return out;

  const priceTrials = uniqRounded([priceBase, priceBase * 0.97, priceBase * 0.94, input.property.asIsValue, input.property.listPrice]);

  for (const price of priceTrials) {
    for (const ctsTrial of uniqRounded([cts.recommended_cts, cts.recommended_cts * 0.75, cts.recommended_cts * 0.5, 0])) {
      const ctsValue = Math.min(ctsTrial, Math.round(price * policy.families.hybrid.max_cts_pct / 100));
      const carryPrincipal = Math.max(price - input.debt.balance - ctsValue, 0);
      if (carryPrincipal <= 0) continue;

      for (const carryRate of policy.families.hybrid.allowed_rates) {
        for (const balloonYrs of policy.families.hybrid.allowed_balloons) {
          const carryPI = Math.round(pmt(carryRate, policy.families.hybrid.amort_years, carryPrincipal));
          const combinedMonthlyPI = input.debt.monthlyPI + carryPI;
          const assignment = Math.round(ctsValue * policy.economics.assignment_pct_of_entry);
          const totalIn = Math.round(ctsValue + cash.buyerClosingCosts + assignment);
          const derived = buildDerivedMetrics({
            noi: econ.noi,
            rentMonthly: econ.rentMonthly,
            monthlyOpex: econ.monthlyOpex,
            monthlyPI: combinedMonthlyPI,
            purchasePrice: price,
            totalIn
          });

          const hardFails = [];
          const softFails = [];

          if (carryPrincipal <= 0) hardFails.push('NO_TRUE_SELLER_CARRY');
          if (derived.DSCR < policy.families.hybrid.min_dscr_hard) hardFails.push('DSCR_HARD_FAIL');
          if (derived.monthlyCF < policy.families.hybrid.min_monthly_cf_hard) hardFails.push('MONTHLY_CF_HARD_FAIL');

          if (derived.DSCR < policy.families.hybrid.min_dscr_target) softFails.push('DSCR_BELOW_TARGET');
          if (derived.monthlyCF < policy.families.hybrid.min_monthly_cf_target) softFails.push('MONTHLY_CF_BELOW_TARGET');
          if (derived.coc < policy.families.hybrid.min_coc_target) softFails.push('COC_BELOW_TARGET');

          out.push(withReasons({
            id: `hybrid|${price}|${ctsValue}|${carryRate}|${balloonYrs}`,
            family: 'hybrid',
            strategy: ctsValue === 0 ? 'hybrid_zero_cts' : 'hybrid_low_cts',
            type: 'Hybrid',
            purchasePrice: price,
            downPayment: null,
            downPaymentPct: null,
            cts: ctsValue,
            ctsPct: price > 0 ? round((ctsValue / price) * 100, 2) : 0,
            existingLoanBalance: input.debt.balance,
            existingLoanRate: input.debt.ratePct || null,
            existingLoanMonthlyPI: input.debt.monthlyPI,
            sellerCarryPrincipal: carryPrincipal,
            sellerCarryRate: carryRate,
            sellerCarryAmortYears: policy.families.hybrid.amort_years,
            sellerCarryBalloonYears: balloonYrs,
            sellerCarryMonthlyPI: carryPI,
            combinedMonthlyPI,
            cashToSeller: ctsValue,
            totalIn,
            ...derived
          }, hardFails, softFails));
        }
      }
    }
  }
  return out;
}

function buildForcedFallbackCandidates(ctx) {
  const { input, econ, policy, cash } = ctx;
  if (!policy.fallback.enabled) return [];

  const forced = [];
  const basePrice = Math.max(input.property.listPrice || 0, input.debt.balance || 0, input.property.asIsValue || 0, input.property.arv || 0);
  if (basePrice <= 0) return forced;

  if (input.debt.balance > 0 && input.debt.monthlyPI > 0) {
    const derivedSubto = buildDerivedMetrics({
      noi: econ.noi,
      rentMonthly: econ.rentMonthly,
      monthlyOpex: econ.monthlyOpex,
      monthlyPI: input.debt.monthlyPI,
      purchasePrice: basePrice,
      totalIn: cash.buyerClosingCosts
    });

    forced.push(withReasons({
      id: `forced_subto|${basePrice}|0`,
      family: 'subto',
      strategy: 'fallback_subto',
      type: 'Subject-To',
      purchasePrice: basePrice,
      downPayment: null,
      downPaymentPct: null,
      cts: 0,
      ctsPct: 0,
      existingLoanBalance: input.debt.balance,
      existingLoanRate: input.debt.ratePct || null,
      existingLoanMonthlyPI: input.debt.monthlyPI,
      sellerCarryPrincipal: 0,
      sellerCarryRate: null,
      sellerCarryAmortYears: null,
      sellerCarryBalloonYears: null,
      sellerCarryMonthlyPI: 0,
      combinedMonthlyPI: input.debt.monthlyPI,
      cashToSeller: 0,
      totalIn: cash.buyerClosingCosts,
      unresolvedEquity: Math.max(basePrice - input.debt.balance, 0),
      ...derivedSubto
    }, ['FALLBACK_ONLY'], [], true));

    const derivedHybrid = buildDerivedMetrics({
      noi: econ.noi,
      rentMonthly: econ.rentMonthly,
      monthlyOpex: econ.monthlyOpex,
      monthlyPI: input.debt.monthlyPI,
      purchasePrice: basePrice,
      totalIn: cash.buyerClosingCosts
    });

    forced.push(withReasons({
      id: `forced_hybrid|${basePrice}|0`,
      family: 'hybrid',
      strategy: 'fallback_hybrid',
      type: 'Hybrid',
      purchasePrice: basePrice,
      downPayment: null,
      downPaymentPct: null,
      cts: 0,
      ctsPct: 0,
      existingLoanBalance: input.debt.balance,
      existingLoanRate: input.debt.ratePct || null,
      existingLoanMonthlyPI: input.debt.monthlyPI,
      sellerCarryPrincipal: 0,
      sellerCarryRate: 4.0,
      sellerCarryAmortYears: 30,
      sellerCarryBalloonYears: 5,
      sellerCarryMonthlyPI: 0,
      combinedMonthlyPI: input.debt.monthlyPI,
      cashToSeller: 0,
      totalIn: cash.buyerClosingCosts,
      ...derivedHybrid
    }, ['FALLBACK_ONLY'], [], true));
  } else {
    const downPayment = Math.round(basePrice * 0.10);
    const monthlyPI = Math.round(pmt(4.0, 30, Math.max(basePrice - downPayment, 0)));
    const derived = buildDerivedMetrics({
      noi: econ.noi,
      rentMonthly: econ.rentMonthly,
      monthlyOpex: econ.monthlyOpex,
      monthlyPI,
      purchasePrice: basePrice,
      totalIn: downPayment + cash.buyerClosingCosts
    });

    forced.push(withReasons({
      id: `forced_sf|${basePrice}|${downPayment}`,
      family: 'seller_finance',
      strategy: 'fallback_seller_finance',
      type: 'Seller Finance',
      purchasePrice: basePrice,
      downPayment,
      downPaymentPct: 10,
      cts: null,
      ctsPct: null,
      existingLoanBalance: 0,
      existingLoanRate: null,
      existingLoanMonthlyPI: 0,
      sellerCarryPrincipal: Math.max(basePrice - downPayment, 0),
      sellerCarryRate: 4.0,
      sellerCarryAmortYears: 30,
      sellerCarryBalloonYears: 5,
      sellerCarryMonthlyPI: monthlyPI,
      combinedMonthlyPI: monthlyPI,
      cashToSeller: downPayment,
      totalIn: downPayment + cash.buyerClosingCosts,
      financed: Math.max(basePrice - downPayment, 0),
      ...derived
    }, ['FALLBACK_ONLY'], [], true));
  }

  return forced;
}

function attachMandateMetrics(candidate, ctx) {
  const purchasePrice = num(candidate.purchasePrice);
  const repairEstimate = num(ctx.cash.repairEstimate || 0);
  const asIsValue = num(ctx.input.property.asIsValue || 0);
  const arv = num(ctx.input.property.arv || 0);

  const instantEquity = Math.max(asIsValue - purchasePrice, 0);
  const instantEquityPct = purchasePrice > 0 ? round((instantEquity / purchasePrice) * 100, 2) : 0;

  const arvSpread = Math.max(arv - purchasePrice, 0);
  const arvSpreadPct = purchasePrice > 0 ? round((arvSpread / purchasePrice) * 100, 2) : 0;

  const allInBasis = round(
    purchasePrice + repairEstimate + num(candidate.totalIn || 0) + num(ctx.input.padsplit?.renoEstimate || 0),
    0
  );
  const allInToArvPct = arv > 0 ? round(allInBasis / arv, 4) : 999;

  const standardRent = num(ctx.econ.rentMonthly || 0);
  const padsplitRent = num(ctx.padsplitEcon?.grossRentMonthly || 0);
  const padsplitUpside = Math.max(padsplitRent - standardRent, 0);
  const padsplitUpsidePct = standardRent > 0 ? round((padsplitUpside / standardRent) * 100, 2) : 0;

  return {
    ...candidate,
    instantEquity,
    instantEquityPct,
    arvSpread,
    arvSpreadPct,
    allInBasis,
    allInToArvPct,
    padsplitUpside,
    padsplitUpsidePct
  };
}

function attachPadsplitDebtView(candidate, ctx) {
  const noi = num(ctx.padsplitEcon.noi || 0);
  const monthlyPI = num(candidate.combinedMonthlyPI || candidate.monthPI || 0);
  const annualDebtService = round(monthlyPI * 12, 0);

  const padsplitAnnualCF = round(noi - annualDebtService, 0);
  const padsplitMonthlyCF = round(padsplitAnnualCF / 12, 0);
  const padsplitDSCR = annualDebtService > 0 ? round(noi / annualDebtService, 2) : 0;
  const padsplitCoC = num(candidate.totalIn) > 0 ? round((padsplitAnnualCF / num(candidate.totalIn)) * 100, 1) : 0;

  return {
    ...candidate,
    padsplitAnnualCF,
    padsplitMonthlyCF,
    padsplitDSCR,
    padsplitCoC
  };
}

function evaluateCashflowMandate(candidate, policy) {
  const p = policy.mandates.cashflow;
  const hardFails = [];
  const softFails = [];

  if (candidate.DSCR < p.min_dscr_hard) hardFails.push('DSCR_HARD_FAIL');
  if (candidate.monthlyCF < p.min_monthly_cf_hard) hardFails.push('MONTHLY_CF_HARD_FAIL');
  if (candidate.entryPct > p.max_entry_pct) hardFails.push('ENTRY_TOO_HIGH');

  if (candidate.DSCR < p.min_dscr_target) softFails.push('DSCR_BELOW_TARGET');
  if (candidate.monthlyCF < p.min_monthly_cf_target) softFails.push('MONTHLY_CF_BELOW_TARGET');
  if (candidate.coc < p.min_coc_target) softFails.push('COC_BELOW_TARGET');

  return { pass: hardFails.length === 0 && softFails.length === 0, hard_fail_reasons: hardFails, soft_fail_reasons: softFails };
}

function evaluateBrrrrMandate(candidate, policy) {
  const p = policy.mandates.brrrr;
  const hardFails = [];
  const softFails = [];

  if (candidate.DSCR < p.min_dscr_hard) hardFails.push('DSCR_TOO_LOW_FOR_BRRRR');
  if (candidate.monthlyCF < p.min_monthly_cf_hard) hardFails.push('MONTHLY_CF_TOO_NEGATIVE_FOR_BRRRR');
  if (candidate.entryPct > p.max_entry_pct) hardFails.push('ENTRY_TOO_HIGH_FOR_BRRRR');

  if (candidate.instantEquityPct < p.min_instant_equity_pct) softFails.push('INSTANT_EQUITY_TOO_LOW');
  if (candidate.arvSpreadPct < p.min_arv_spread_pct) softFails.push('ARV_SPREAD_TOO_LOW');
  if (candidate.allInToArvPct > p.max_all_in_to_arv_pct) softFails.push('ALL_IN_BASIS_TOO_HIGH');

  return { pass: hardFails.length === 0 && softFails.length === 0, hard_fail_reasons: hardFails, soft_fail_reasons: softFails };
}

function evaluatePadsplitMandate(candidate, ctx, policy) {
  const p = policy.mandates.padsplit;
  const hardFails = [];
  const softFails = [];

  if (p.require_padsplit_viable && !ctx.input.padsplit.feasible) hardFails.push('PADSPLIT_NOT_FEASIBLE_UPSTREAM');
  if (ctx.padsplitEcon.grossRentMonthly <= 0) hardFails.push('NO_PADSPLIT_RENT_MODEL');
  if (candidate.padsplitDSCR < p.min_dscr_hard) hardFails.push('PADSPLIT_DSCR_HARD_FAIL');
  if (candidate.padsplitMonthlyCF < p.min_monthly_cf_hard) hardFails.push('PADSPLIT_CF_HARD_FAIL');
  if (candidate.entryPct > p.max_entry_pct) hardFails.push('ENTRY_TOO_HIGH');

  if (candidate.padsplitDSCR < p.min_dscr_target) softFails.push('PADSPLIT_DSCR_BELOW_TARGET');
  if (candidate.padsplitMonthlyCF < p.min_monthly_cf_target) softFails.push('PADSPLIT_CF_BELOW_TARGET');
  if (candidate.padsplitCoC < p.min_coc_target) softFails.push('PADSPLIT_COC_BELOW_TARGET');
  if (candidate.padsplitUpside <= 0) softFails.push('NO_PADSPLIT_UPSIDE');

  return { pass: hardFails.length === 0 && softFails.length === 0, hard_fail_reasons: hardFails, soft_fail_reasons: softFails };
}

function evaluateMandates(candidate, ctx, policy) {
  let enriched = attachMandateMetrics(candidate, ctx);
  enriched = attachPadsplitDebtView(enriched, ctx);

  const mandate_results = {
    cashflow: evaluateCashflowMandate(enriched, policy),
    brrrr: evaluateBrrrrMandate(enriched, policy),
    padsplit: evaluatePadsplitMandate(enriched, ctx, policy)
  };

  const viable_for = Object.entries(mandate_results)
    .filter(([, result]) => result.pass)
    .map(([name]) => name);

  return { ...enriched, mandate_results, viable_for };
}

function boundedScore(value, min, target, max = null) {
  const v = Number(value) || 0;
  if (v <= min) return 0;
  if (max !== null && v >= max) return 100;
  if (v >= target) return 100;
  if (target === min) return 100;
  return Math.max(0, Math.min(100, ((v - min) / (target - min)) * 100));
}

function inverseScore(value, target, hardMax) {
  const v = Number(value) || 0;
  if (v <= target) return 100;
  if (v >= hardMax) return 0;
  return Math.max(0, Math.min(100, 100 - ((v - target) / (hardMax - target)) * 100));
}

function complexityScore(candidate) {
  if (candidate.family === 'seller_finance') return 85;
  if (candidate.family === 'subto') return 70;
  if (candidate.family === 'hybrid') return 60;
  return 50;
}

function confidenceScore(candidate) {
  let score = 80;
  if (!candidate.pass) score -= 40;
  if (candidate.forcedFallback) score -= 30;
  if ((candidate.hard_fail_reasons || []).length) score -= 30;
  if ((candidate.soft_fail_reasons || []).length) score -= 10;
  return Math.max(0, Math.min(100, score));
}

function rankCandidate(candidate, profile) {
  const mandate = profile.mandate || 'cashflow';
  const mandateResult = candidate.mandate_results?.[mandate];

  const scorecard = {
    dscr: boundedScore(mandate === 'padsplit' ? candidate.padsplitDSCR : candidate.DSCR, 0.8, 1.2),
    cashFlow: boundedScore(mandate === 'padsplit' ? candidate.padsplitMonthlyCF : candidate.monthlyCF, -100, 250),
    coc: boundedScore(mandate === 'padsplit' ? candidate.padsplitCoC : candidate.coc, 0, 15),
    entry: inverseScore(candidate.entryPct, 10, 25),
    complexity: complexityScore(candidate),
    confidence: confidenceScore({
      ...candidate,
      hard_fail_reasons: mandateResult?.hard_fail_reasons || [],
      soft_fail_reasons: mandateResult?.soft_fail_reasons || [],
      pass: !!mandateResult?.pass
    }),
    instantEquity: boundedScore(candidate.instantEquityPct || 0, 0, 12, 25),
    arvSpread: boundedScore(candidate.arvSpreadPct || 0, 0, 20, 35),
    padsplitUpside: boundedScore(candidate.padsplitUpsidePct || 0, 0, 25, 60)
  };

  const w = profile.weights;
  const weightedScore =
    scorecard.dscr * (w.dscr || 0) +
    scorecard.cashFlow * (w.cashFlow || 0) +
    scorecard.coc * (w.coc || 0) +
    scorecard.entry * (w.entry || 0) +
    scorecard.complexity * (w.complexity || 0) +
    scorecard.confidence * (w.confidence || 0) +
    scorecard.instantEquity * (w.instantEquity || 0) +
    scorecard.arvSpread * (w.arvSpread || 0) +
    scorecard.padsplitUpside * (w.padsplitUpside || 0);

  return { weightedScore: round(weightedScore, 2), scorecard };
}

function sortCandidates(candidates, profile) {
  return [...candidates]
    .map(candidate => {
      const rank = rankCandidate(candidate, profile);
      return { ...candidate, weightedScore: rank.weightedScore, scorecard: rank.scorecard };
    })
    .sort((a, b) => {
      if (b.pass !== a.pass) return Number(b.pass) - Number(a.pass);
      if (a.forcedFallback !== b.forcedFallback) return Number(a.forcedFallback) - Number(b.forcedFallback);
      if (b.weightedScore !== a.weightedScore) return b.weightedScore - a.weightedScore;
      if ((b.padsplitMonthlyCF ?? b.monthlyCF) !== (a.padsplitMonthlyCF ?? a.monthlyCF)) return (b.padsplitMonthlyCF ?? b.monthlyCF) - (a.padsplitMonthlyCF ?? a.monthlyCF);
      if ((b.padsplitDSCR ?? b.DSCR) !== (a.padsplitDSCR ?? a.DSCR)) return (b.padsplitDSCR ?? b.DSCR) - (a.padsplitDSCR ?? a.DSCR);
      if (a.totalIn !== b.totalIn) return a.totalIn - b.totalIn;
      return String(a.id).localeCompare(String(b.id));
    });
}

function qualityTier(candidate, profile) {
  if (!candidate) return 'non_marketable';
  if (candidate.forcedFallback) return 'non_marketable';

  const mandate = profile?.mandate || 'cashflow';
  const result = candidate.mandate_results?.[mandate];

  if (mandate === 'brrrr') {
    if (result?.pass && candidate.instantEquityPct >= 20 && candidate.allInToArvPct <= 0.75) return 'brrrr_grade';
    if (result?.pass) return 'value_add_grade';
    return 'speculative';
  }

  if (mandate === 'padsplit') {
    if (result?.pass && candidate.padsplitUpsidePct >= 25) return 'padsplit_grade';
    if (result?.pass) return 'alternative_rent_grade';
    return 'speculative';
  }

  if (result?.pass && candidate.DSCR >= 1.3 && candidate.monthlyCF >= 300 && candidate.coc >= 15) return 'institutional_grade';
  if (result?.pass && candidate.DSCR >= 1.2 && candidate.monthlyCF >= 200) return 'investor_grade';
  if (candidate.DSCR >= 1.0 && candidate.monthlyCF >= 0) return 'thin_margin';
  return 'speculative';
}

function sellerFacingAllowed(candidate, validation, policy, profile) {
  if (!candidate) return false;
  if (!validation.valid) return false;
  if (candidate.forcedFallback && !policy.fallback.seller_facing_allowed) return false;

  const tier = qualityTier(candidate, profile);
  return [
    'institutional_grade',
    'investor_grade',
    'thin_margin',
    'brrrr_grade',
    'value_add_grade',
    'padsplit_grade',
    'alternative_rent_grade'
  ].includes(tier);
}

function selectCandidates(candidates, routing, profile) {
  const primaryPool = sortCandidates(candidates.filter(c => c.family === routing.primary), profile);
  const secondaryPool = sortCandidates(candidates.filter(c => routing.secondary.includes(c.family)), profile);

  const primary = primaryPool[0] || null;
  const challenger = secondaryPool[0] || null;

  const winner = challenger && primary
    ? (challenger.pass && !primary.pass && challenger.weightedScore >= primary.weightedScore + 10 ? challenger : primary)
    : (primary || challenger || null);

  const backup = [
    ...sortCandidates(candidates.filter(c => c.id !== winner?.id && c.family === routing.primary), profile),
    ...sortCandidates(candidates.filter(c => c.id !== winner?.id && routing.secondary.includes(c.family)), profile)
  ][0] || null;

  return { primary: winner, backup };
}

function summarizeDecision(primary, backup, routing) {
  return {
    winning_strategy: primary?.strategy || null,
    winner_id: primary?.id || null,
    backup_id: backup?.id || null,
    why_winner_won: primary ? [
      primary.pass ? 'PASSED_SELECTED_MANDATE' : 'BEST_AVAILABLE',
      `PRIMARY_FAMILY_${routing.primary}`,
      `VIABLE_FOR_${(primary.viable_for || []).join('_') || 'none'}`
    ] : [],
    routing_reason: routing.reason
  };
}

