  pushLine(lines, 'Annual Cash-flow', ia['Annual Cash-flow']);
  pushLine(lines, 'Break-even Rent', ia['Break-even Rent']);
  pushLine(lines, 'Rent Gap to Break-even', ia['Rent Gap to Break-even']);
