    const comps = Array.isArray(output.comp_properties_report) ? output.comp_properties_report : [];
    const transcript =
      output.transcript ||
      root.transcript?.output ||
      root.transcript ||
      {};

    const selectedMandate = L(engine.mandate || mandateDiagnostics.selected_mandate || 'cashflow');
    const primaryViable = !!engine.primary_viable;
    const backupViable = !!engine.backup_viable;
    const sellerFacingAllowed = !!engine.seller_facing_allowed;
    const qualityTier = L(engine.quality_tier || 'speculative');
    const routingConfidence = L(engine.routing_confidence || 'low');

    const viableFor = Array.isArray(primary.viable_for)
      ? primary.viable_for
      : Array.isArray(primaryRaw.viable_for)
        ? primaryRaw.viable_for
        : [];

    const mandateResult = primaryRaw.mandate_results?.[selectedMandate] || null;
    const mandatePass = !!mandateResult?.pass;

    const DSCR =
