      metrics,
      config,
      canonical,
      padsplit_room_mix,
      padsplit_expenses,
      padsplit_current_vs_target,
      warnings
    }
  });
}

return results;

## *
 * Code5 - Pretty Pack v4.1
 *
 * Source of truth split:
 * - OFFER ENGINE1 / deterministic upstream:
 *   all numeric underwriting, investors_analysis, deal_structure numbers,
 *   cash_offer, mao, wholesale_fee, repair_estimate, cts_engine,
 *   assignment_fee_range, buyer_matches dataset, comp_properties_report dataset
 *
 * - AI Agent:
 *   all narrative/explanation fields only
 *   (deal justifications, investors_analysis_insights, lead_score_explanation,
 *    buyer_match_summary, comps_summary, dispoStrategy,
 *    finalRecommendationsAndInsights, loi)
 *
 * Output:
 * {
 *   role_notes: {
 *     prequalifier: { text, html, discord },
 *     closer:       { text, html, discord },
 *     tc:           { text, html, discord },
 *     dispo_manager:{ text, html, discord },
 *     owner:        { text, html, discord },
 *     end_buyer:    { text, html, discord }
 *   },
 *   pretty_summary_one_line,
 *   pretty_json,
 *   ai_underwriting_note,
 *   pretty_note_ghl,
 *   direct_to_agent_loi
 * }
 */

function safeNode(name, fallback = {}) {
  try {
    const v = $(name).first().json;
    return v || fallback;
  } catch {
    return fallback;
  }
}

function firstValue() {
  for (const v of arguments) {
    if (v === 0 || v === false) return v;
    if (v === null || v === undefined) continue;
    if (typeof v === 'string' && v.trim() === '') continue;
    return v;
  }
  return null;
}

function nonEmptyObject() {
  for (const v of arguments) {
    if (v && typeof v === 'object' && !Array.isArray(v) && Object.keys(v).length) {
      return v;
    }
  }
  return {};
}

function hasAnyKey(obj, keys) {
  if (!obj || typeof obj !== 'object') return false;
  return keys.some((k) => obj[k] !== undefined && obj[k] !== null);
}

function toMoneyNumber(x) {
  if (x === null || x === undefined || x === '') return null;
  if (typeof x === 'number') return Number.isFinite(x) ? x : null;
  const n = parseFloat(String(x).replace(/[^\d.\-]/g, ''));
  return Number.isFinite(n) ? n : null;
}

function money(x, digits = 2) {
  const n = toMoneyNumber(x);
  if (n === null) return '—';
  return `$${n.toLocaleString('en-US', {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits
  })}`;
}

function numText(x, digits = 2) {
  const n = toMoneyNumber(x);
  if (n === null) return '—';
  return n.toFixed(digits);
}

function pct(x, digits = 1) {
  if (x === null || x === undefined || x === '') return '—';
  if (typeof x === 'string' && x.includes('%')) return x;
  const n = toMoneyNumber(x);
  if (n === null) return '—';
  return `${n.toFixed(digits)}%`;
}

function clean(s) {
  return String(s == null ? '' : s).replace(/\s+\n/g, '\n').trim();
}

function lower(s) {
  return String(s == null ? '' : s).trim().toLowerCase();
}

function nlToBr(s) {
  return String(s || '').replace(/\n/g, '<br>');
}

function toDiscord(s) {
  return String(s || '')
    .replace(/^🏠/gm, '**🏠**')
    .replace(/^🏦/gm, '**🏦**')
    .replace(/^📊/gm, '**📊**')
    .replace(/^💼/gm, '**💼**')
    .replace(/^🧭/gm, '**🧭**')
    .replace(/^📬/gm, '**📬**')
    .replace(/^📌/gm, '**📌**')
    .replace(/^👤/gm, '**👤**')
    .replace(/^🗒️/gm, '**🗒️**');
}

function isPresent(v) {
  if (v === 0 || v === false) return true;
  if (v === null || v === undefined) return false;
  if (typeof v === 'string') {
    const s = v.trim();
    return s !== '' && s !== 'N/A' && s !== 'null' && s !== 'undefined';
  }
  return true;
}

function pushLine(lines, label, value, formatter) {
  if (!isPresent(value)) return;
  const out = formatter ? formatter(value) : value;
  if (!isPresent(out)) return;
  lines.push(`• ${label}: ${out}`);
}

function offerField(offer) {
  const keys = Array.prototype.slice.call(arguments, 1);
  for (const key of keys) {
    if (offer && offer[key] !== undefined && offer[key] !== null && offer[key] !== '') {
      return offer[key];
    }
  }
  return null;
}

function buildContext(a) {
  const aiNode = safeNode('AI Agent');
  const oeNode = safeNode('OFFER ENGINE v1') || {};

  const current = a || {};
  const currentOut = current.output || {};

  // STRICT SOURCE OWNERSHIP
  const aiOut = nonEmptyObject(
    aiNode.output,
    current.ai_agent && current.ai_agent.output,
    current.aiAgent && current.aiAgent.output,
    {}
  );

  const oeOut = nonEmptyObject(
    oeNode.output,
    current.offer_engine && current.offer_engine.output,
    current.offerEngine && current.offerEngine.output,
    current.offer_generator && current.offer_generator.output,
    {}
  );

  const currentDeal = firstValue(currentOut.deal_structure, current.deal_structure, {});
  const aiDeal = firstValue(aiOut.deal_structure, {});
  const oeDeal = firstValue(oeOut.deal_structure, currentDeal, {});

  function mergeOffer(name) {
    const base = firstValue(oeDeal[name], currentDeal[name], {});
    const ai = firstValue(aiDeal[name], {});
    return {
      ...base,
      Justification: isPresent(ai.Justification) ? ai.Justification : null
    };
  }

  return {
    raw: current,
    currentOut,
    aiOut,
    oeOut,

    // deterministic / upstream first
    property: firstValue(currentOut.property, current.property, oeOut.property, aiOut.property, {}),
    metrics: firstValue(currentOut.metrics, current.metrics, oeOut.metrics, aiOut.metrics, {}),
    existingLoan: firstValue(currentOut.existing_loan, current.existing_loan, oeOut.existing_loan, aiOut.existing_loan, {}),
    config: firstValue(currentOut.config, current.config, oeOut.config, aiOut.config, {}),
    transcript: firstValue(current.transcript, currentOut.transcript, {}),

    // lead score should NOT come from AI unless AI truly owns it upstream
    leadScore: firstValue(currentOut.lead_score, current.lead_score, oeOut.lead_score, null),
    leadScoreExplanation: firstValue(aiOut.lead_score_explanation, null),

    // investor math = deterministic / offer engine
    investorsAnalysis: firstValue(oeOut.investors_analysis, currentOut.investors_analysis, current.investors_analysis, {}),
    investorsAnalysisInsights: firstValue(aiOut.investors_analysis_insights, null),

    // comps dataset != AI; summary = AI
    compsSummary: firstValue(aiOut.comps_summary, null),
    compPropertiesReport: firstValue(currentOut.comp_properties_report, current.comp_properties_report, oeOut.comp_properties_report, []),

    // buyer match dataset != AI; summary = AI
    buyerMatches: firstValue(currentOut.buyer_matches, current.buyer_matches, oeOut.buyer_matches, []),
    buyerMatchSummary: firstValue(aiOut.buyer_match_summary, null),

    // narrative-only blocks = AI only
    dispoStrategy: firstValue(aiOut.dispoStrategy, {}),
    finalRecommendationsAndInsights: firstValue(aiOut.finalRecommendationsAndInsights, null),
    loi: firstValue(aiOut.loi, null),

    // offer numbers = deterministic; justifications = AI only
    dealStructure: {
      'Primary Offer': mergeOffer('Primary Offer'),
      'Backup Offer': mergeOffer('Backup Offer'),
      'Updated Cash Offer': mergeOffer('Updated Cash Offer')
    },

    cashOffer: firstValue(oeOut.cash_offer, currentOut.cash_offer, current.cash_offer, {}),
    mao: firstValue(oeOut.mao, currentOut.mao, current.mao),
    wholesaleFee: firstValue(oeOut.wholesale_fee, currentOut.wholesale_fee, current.wholesale_fee),
    repairEstimate: firstValue(oeOut.repair_estimate, currentOut.repair_estimate, current.repair_estimate),
    ctsEngine: firstValue(oeOut.cts_engine, currentOut.cts_engine, current.cts_engine, {}),
    assignmentFeeRange: firstValue(oeOut.assignment_fee_range, currentOut.assignment_fee_range, current.assignment_fee_range),

    estimatedArv: firstValue(currentOut.estimated_arv, current.estimated_arv, oeOut.estimated_arv, aiOut.estimated_arv)
  };
}

function buildHeader(ctx) {
  const p = ctx.property || {};
  const address = [p.address, p.city, p.state, p.postal_code].filter(Boolean).join(', ') || '—';
  const arv = money(firstValue(ctx.estimatedArv, p.arv_value, ctx.metrics.arv));
  const asIs = money(firstValue(ctx.metrics.as_is_value, ctx.metrics.estValue, p.est_value));
  const asking = money(firstValue(p.mls && p.mls.price_num, ctx.metrics.list_price, ctx.metrics.price, p.list_price));

  const lines = [];
  lines.push(`🏠 Property: ${address}`);
  lines.push(`ARV: ${arv}  |  As-Is: ${asIs}  |  Asking: ${asking}`);
  if (isPresent(ctx.leadScore)) lines.push(`Underwriting Score: ${ctx.leadScore}`);
  return lines.join('\n');
}

