function buildOfferSection(title, offer) {
  if (!offer || !isPresent(offer.Type || offer.offer_type)) {
    return `${title}\n• —`;
  }

  const type = firstValue(offer.offer_type, offer.Type, 'Offer');
  const typeKey = lower(type);
  const lines = [];
  lines.push(`${title}`);
  lines.push(`• Type: ${type}`);

  pushLine(lines, 'Purchase Price', offerField(offer, 'Purchase Price'));

  if (typeKey.includes('subject')) {
    pushLine(lines, 'CTS', offerField(offer, 'cts', 'CTS ($)', 'Cash to Seller'));
    pushLine(lines, 'CTS %', offerField(offer, 'cts_pct', 'CTS (%)'));
    pushLine(lines, 'Existing Loan Balance', offerField(offer, 'existing_loan_balance', 'Existing Loan Balance'));
    pushLine(lines, 'Existing Loan Rate', offerField(offer, 'existing_loan_rate', 'Existing Loan Interest Rate', 'Loan Rate (%)', 'Interest Rate (%)'));
    pushLine(lines, 'Existing Loan Monthly PI', offerField(offer, 'existing_loan_monthly_pi', 'Existing Loan Monthly Payment (PI)', 'Monthly Payment (PI)'));
    pushLine(lines, 'Combined Monthly PI', offerField(offer, 'combined_monthly_pi', 'Combined Monthly Payment (PI)'));
  } else if (typeKey.includes('hybrid')) {
    pushLine(lines, 'CTS', offerField(offer, 'cts', 'CTS ($)', 'Cash to Seller'));
    pushLine(lines, 'CTS %', offerField(offer, 'cts_pct', 'CTS (%)'));
    pushLine(lines, 'Existing Loan Balance', offerField(offer, 'existing_loan_balance', 'Existing Loan Balance'));
    pushLine(lines, 'Existing Loan Rate', offerField(offer, 'existing_loan_rate', 'Existing Loan Interest Rate'));
    pushLine(lines, 'Existing Loan Monthly PI', offerField(offer, 'existing_loan_monthly_pi', 'Existing Loan Monthly Payment (PI)'));
    pushLine(lines, 'Seller Carry Principal', offerField(offer, 'seller_carry_principal', 'Seller Carryback Loan'));
    pushLine(lines, 'Seller Carry Rate', offerField(offer, 'seller_carry_rate', 'Seller Carryback Interest Rate'));
    pushLine(lines, 'Seller Carry Amort Years', offerField(offer, 'seller_carry_amort_years'));
    pushLine(lines, 'Seller Carry Balloon Years', offerField(offer, 'seller_carry_balloon_years', 'Balloon Term (Years)'));
    pushLine(lines, 'Seller Carry Monthly PI', offerField(offer, 'seller_carry_monthly_pi', 'Seller Carryback Monthly Payment (PI)'));
    pushLine(lines, 'Combined Monthly PI', offerField(offer, 'combined_monthly_pi', 'Combined Monthly Payment (PI)'));
  } else {
    pushLine(lines, 'Down Payment', offerField(offer, 'down_payment', 'Down Payment ($)'));
    pushLine(lines, 'Down Payment %', offerField(offer, 'down_payment_pct', 'Down Payment (%)'));
    pushLine(lines, 'Seller Carry Principal', offerField(offer, 'seller_carry_principal', 'Seller Carryback Loan', 'Financed Amount'));
    pushLine(lines, 'Seller Carry Rate', offerField(offer, 'seller_carry_rate', 'Seller Carryback Interest Rate', 'Loan Rate (%)', 'Interest Rate (%)'));
    pushLine(lines, 'Seller Carry Amort Years', offerField(offer, 'seller_carry_amort_years', 'Amortization (Years)'));
    pushLine(lines, 'Seller Carry Balloon Years', offerField(offer, 'seller_carry_balloon_years', 'Balloon Term (Years)'));
    pushLine(lines, 'Seller Carry Monthly PI', offerField(offer, 'seller_carry_monthly_pi', 'Seller Carryback Monthly Payment (PI)', 'Monthly Payment (PI)'));
  }

  pushLine(lines, 'Monthly Taxes and Insurance (TI)', offerField(offer, 'Monthly Taxes and Insurance (TI)', 'Monthly Taxes & Insurance'));
  pushLine(lines, 'ADS', offerField(offer, 'ADS'));
  pushLine(lines, 'DSCR', offerField(offer, 'DSCR'));
  pushLine(lines, 'Monthly Cash-flow', offerField(offer, 'Monthly Cash-flow'));
  pushLine(lines, 'Annual Cash-flow', offerField(offer, 'Annual Cash-flow'));
  pushLine(lines, 'Break-even Rent', offerField(offer, 'Break-even Rent'));
  pushLine(lines, 'Rent Gap to Break-even', offerField(offer, 'Rent Gap to Break-even'));
  pushLine(lines, 'Cash Flow Profile', offerField(offer, 'Cash Flow Profile'));
  pushLine(lines, 'Years to Recapture Cash In', offerField(offer, 'Years to Recapture Cash In'));
  pushLine(lines, 'Total Entry Fee', offerField(offer, 'total_entry_fee', 'Total Entry Fee'));
  pushLine(lines, 'Cash-on-Cash Return', offerField(offer, 'Cash-on-Cash Return'));
  pushLine(lines, 'Traditional Sale Seller Net Spread', offerField(offer, 'Traditional Sale Seller Net Spread'));

  if (isPresent(offer.Justification)) {
    lines.push(`• Justification: ${clean(offer.Justification)}`);
  }

  return lines.join('\n');
}

function buildCashOfferSection(ctx) {
  const updated = ctx.dealStructure['Updated Cash Offer'] || {};
  const cash = ctx.cashOffer || {};
  const lines = [];
  lines.push('All Cash Offer');
  pushLine(lines, 'Final Cash Offer', firstValue(updated['Final Cash Offer'], cash.cash_offer), (v) => {
    if (typeof v === 'string' && v.includes('$')) return v;
    return money(v, 0);
  });
  pushLine(lines, 'Final Cash Offer % of ARV', firstValue(updated['Final Cash Offer % of ARV'], cash.cash_offer_pct_of_arv));
  pushLine(lines, 'ARV', cash.arv, (v) => money(v, 0));
  pushLine(lines, 'Buy Box %', cash.buy_box_pct);
  pushLine(lines, 'Repair Estimate', firstValue(cash.repair_estimate, ctx.repairEstimate), (v) => money(v, 0));
  pushLine(lines, 'Buyer Closing Costs', cash.buyer_closing_costs, (v) => money(v, 0));
  pushLine(lines, 'Wholesale Fee', firstValue(cash.wholesale_fee, ctx.wholesaleFee), (v) => money(v, 0));
  pushLine(lines, 'Spread vs List Price', cash.spread_vs_list_price, (v) => money(v, 0));
  pushLine(lines, 'Deal Viable', cash.deal_viable);
  pushLine(lines, 'Acceptable Now', cash.acceptable_now);
  pushLine(lines, 'Negotiation Potential', cash.negotiation_potential);
  pushLine(lines, 'Pursue Cash Strategy', cash.pursue_cash_strategy);
  if (isPresent(updated.Justification)) {
    lines.push(`• Justification: ${clean(updated.Justification)}`);
