function buildCompsSection(ctx) {
  const comps = Array.isArray(ctx.compPropertiesReport) ? ctx.compPropertiesReport.slice(0, 5) : [];
  const lines = [];
  lines.push('📌 Comps');
  if (isPresent(ctx.compsSummary)) {
    lines.push(`• Summary: ${clean(ctx.compsSummary)}`);
  }
  if (!comps.length) {
    lines.push('• —');
    return lines.join('\n');
  }

  comps.forEach((c, i) => {
    const bits = [];
    bits.push(c.address || '—');
    if (isPresent(c.price)) bits.push(money(c.price, 0));
    if (isPresent(c.beds) || isPresent(c.bedrooms)) bits.push(`${firstValue(c.beds, c.bedrooms)}bd`);
    if (isPresent(c.baths) || isPresent(c.bathrooms)) bits.push(`${firstValue(c.baths, c.bathrooms)}ba`);
    if (isPresent(c.squareFootage)) bits.push(`${c.squareFootage} sf`);
    if (isPresent(c.daysOnMarket)) bits.push(`DOM ${c.daysOnMarket}`);
    if (isPresent(c.distance)) bits.push(`Dist ${c.distance}`);
    if (isPresent(c.correlation)) bits.push(`Corr ${c.correlation}`);
    lines.push(`• Comp ${i + 1}: ${bits.join(', ')}`);
  });

  return lines.join('\n');
}

function buildBuyerMatchesSection(ctx, showContact) {
  const buyers = Array.isArray(ctx.buyerMatches) ? ctx.buyerMatches.slice(0, 5) : [];
  const lines = [];
  lines.push('👤 Buyer Matches');

  if (isPresent(ctx.buyerMatchSummary)) {
    lines.push(`• Summary: ${clean(ctx.buyerMatchSummary)}`);
  }

  if (!buyers.length) {
    lines.push('• —');
    return lines.join('\n');
  }

  buyers.forEach((b) => {
    const head = `${b.buyer || '—'} (${b.score != null ? b.score : '—'}) [${b.level || '—'}]${b.rationale ? ` — ${b.rationale}` : ''}`;
    lines.push(`• ${head}`);
    if (showContact) {
      const contact = b.contact || {};
      const parts = [];
      if (isPresent(contact.name)) parts.push(contact.name);
      if (isPresent(contact.company)) parts.push(contact.company);
      if (isPresent(contact.email)) parts.push(contact.email);
      if (isPresent(contact.phone)) parts.push(String(contact.phone));
      if (parts.length) lines.push(`•   Contact: ${parts.join(' | ')}`);
    }
  });

  return lines.join('\n');
}

function buildDispoSection(ctx) {
  const d = ctx.dispoStrategy || {};
  if (!hasAnyKey(d, ['recommendedDispoStrategy', 'bestEndBuyerType', 'projectedAssignmentFee'])) return null;
  const lines = [];
  lines.push('🧭 Disposition Strategy');
  pushLine(lines, 'Recommended Strategy', d.recommendedDispoStrategy);
  pushLine(lines, 'Best End Buyer Type', d.bestEndBuyerType);
  pushLine(lines, 'Projected Assignment Fee', d.projectedAssignmentFee);
  if (Array.isArray(d.endBuyerExitStrategyProfitProjections) && d.endBuyerExitStrategyProfitProjections.length) {
    lines.push('• End Buyer Exit Strategy Profit Projections:');
    d.endBuyerExitStrategyProfitProjections.forEach((x) => lines.push(`•   • ${x}`));
  }
  return lines.join('\n');
}

function buildRecommendationsSection(ctx) {
  if (!isPresent(ctx.finalRecommendationsAndInsights)) return null;
  return `📬 Final Recommendations and Insights\n• ${clean(ctx.finalRecommendationsAndInsights)}`;
}

function buildTranscriptSection(ctx) {
  const t = firstValue(ctx.transcript && ctx.transcript.output, ctx.transcript, {});
  if (!hasAnyKey(t, ['sellerUrgency', 'sellerHardship', 'conditionOfProperty', 'price', 'additionalInsights'])) return null;
  const lines = [];
  lines.push('🗒️ Transcript Insights');
  pushLine(lines, 'Seller Urgency', t.sellerUrgency);
  pushLine(lines, 'Seller Hardship', t.sellerHardship);
  pushLine(lines, 'Condition', t.conditionOfProperty);
  pushLine(lines, 'Price / Terms', t.price);
  pushLine(lines, 'Additional', t.additionalInsights);
  return lines.join('\n');
}

function buildLeadSection(ctx) {
  const lines = [];
  lines.push('🤖AI Underwriting Scoring');
  pushLine(lines, 'Underwriting Score', ctx.leadScore);
  if (isPresent(ctx.leadScoreExplanation)) {
    lines.push(`• Explanation: ${clean(ctx.leadScoreExplanation)}`);
  }
  return lines.join('\n');
}

function buildLoanSection(ctx) {
  const ex = ctx.existingLoan || {};
  const lines = [];
  if (!hasAnyKey(ex, ['balance', 'rate', 'sellerMonthlyPaymentPI', 'original_principal', 'ltv'])) return null;
  lines.push('🏦 Existing Loan');
  pushLine(lines, 'Balance', ex.balance, (v) => money(v, 0));
  pushLine(lines, 'Rate', ex.rate, (v) => pct(v, 2));
  pushLine(lines, 'Monthly PI', ex.sellerMonthlyPaymentPI, (v) => money(v, 2));
  pushLine(lines, 'Original Principal', ex.original_principal, (v) => money(v, 0));
  pushLine(lines, 'LTV', ex.ltv, (v) => pct(Number(v) <= 1.5 ? Number(v) * 100 : v, 2));
  return lines.join('\n');
}

function buildOffersSection(ctx, includeCtsEngine) {
  const sections = [];
  sections.push('💼 Deal Structure');
  sections.push(buildOfferSection('Primary Offer', ctx.dealStructure['Primary Offer']));
  sections.push(buildOfferSection('Backup Offer', ctx.dealStructure['Backup Offer']));
  sections.push(buildCashOfferSection(ctx));
  if (includeCtsEngine) {
    const cts = buildCtsEngineSection(ctx);
    if (cts) sections.push(cts);
  }
  return sections.join('\n\n');
}

function buildPrequalifier(ctx) {
  return [
    buildHeader(ctx),
    buildLeadSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, false),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, false),
    buildTranscriptSection(ctx)
  ].filter(Boolean).join('\n\n');
}

function buildCloser(ctx) {
  return [
    buildHeader(ctx),
    buildLoanSection(ctx),
    buildLeadSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, true),
    buildDispoSection(ctx),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, false),
    buildRecommendationsSection(ctx),
    '🧰 Closer Checklist\n' + [
      '• Verify payoff, PI, escrow, arrears, HOA, liens, solar, and any loss-mit status',
      '• Reconfirm CTS / cash to seller and who is covering closing costs',
      '• Reconfirm move-out timing and title / attorney / escrow path',
      '• Use the AI justification as the narrative and the OFFER ENGINE numbers as the hard math'
    ].join('\n')
  ].filter(Boolean).join('\n\n');
}

function buildTC(ctx) {
  return [
    buildHeader(ctx),
    buildLoanSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, true),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, true),
    buildRecommendationsSection(ctx)
  ].filter(Boolean).join('\n\n');
}

function buildDispoManager(ctx) {
  return [
    buildHeader(ctx),
    buildLoanSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, true),
    buildDispoSection(ctx),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, true),
    buildRecommendationsSection(ctx)
  ].filter(Boolean).join('\n\n');
}

function buildOwner(ctx) {
  return [
    buildHeader(ctx),
    buildLeadSection(ctx),
    buildLoanSection(ctx),
    buildInvestorsAnalysis(ctx),
    buildOffersSection(ctx, true),
    buildDispoSection(ctx),
    buildCompsSection(ctx),
    buildBuyerMatchesSection(ctx, true),
    buildRecommendationsSection(ctx)
  ].filter(Boolean).join('\n\n');
}

function buildEndBuyer(ctx) {
  return [
    buildHeader(ctx),
    buildInvestorsAnalysis(ctx),
    buildOfferSection('Primary Offer', ctx.dealStructure['Primary Offer']),
    buildCashOfferSection(ctx),
    buildCompsSection(ctx),
    buildDispoSection(ctx)
  ].filter(Boolean).join('\n\n');
}

function buildRoleNotes(ctx) {
  const notes = {
    prequalifier: buildPrequalifier(ctx),
    closer: buildCloser(ctx),
    tc: buildTC(ctx),
    dispo_manager: buildDispoManager(ctx),
    owner: buildOwner(ctx),
    end_buyer: buildEndBuyer(ctx)
  };

  const out = {};
  Object.keys(notes).forEach((key) => {
    out[key] = {
      text: notes[key],
      html: nlToBr(notes[key]),
      discord: toDiscord(notes[key])
    };
  });
  return out;
}

function buildFallbackLoi(ctx) {
  const p = ctx.property || {};
  const addr = [p.address, p.city, p.state, p.postal_code].filter(Boolean).join(', ') || 'the subject property';
  const primary = ctx.dealStructure['Primary Offer'] || {};
  const cash = ctx.dealStructure['Updated Cash Offer'] || {};
  return [
    '<html><body>',
    `<h2>Letter of Intent - ${addr}</h2>`,
    '<p>Please consider the following purchase options:</p>',
    '<h3>Option 1: All Cash</h3>',
    `<p>Purchase Price: ${firstValue(cash['Final Cash Offer'], '—')}</p>`,
    '<h3>Option 2: Creative Offer</h3>',
    `<p>Type: ${firstValue(primary.Type, primary.offer_type, '—')}</p>`,
    `<p>Purchase Price: ${firstValue(primary['Purchase Price'], '—')}</p>`,
    `<p>Cash to Seller / CTS: ${firstValue(primary.cts, primary['CTS ($)'], primary['Cash to Seller'], primary['Down Payment ($)'], '—')}</p>`,
    `<p>Justification: ${clean(primary.Justification || '') || '—'}</p>`,
    '</body></html>'
  ].join('');
}

function buildOutput(a) {
  const ctx = buildContext(a);
  const role_notes = buildRoleNotes(ctx);
  const ownerOneLine = role_notes.owner.text.replace(/\n+/g, ' | ').replace(/\s+/g, ' ').trim();

  return {
    role_notes,
    pretty_summary_one_line: ownerOneLine,
    pretty_json: JSON.stringify(a, null, 2),
    ai_underwriting_note: role_notes.owner.html,
    pretty_note_ghl: role_notes.owner.text,
    direct_to_agent_loi: firstValue(ctx.loi, buildFallbackLoi(ctx))
  };
}

if (typeof item !== 'undefined') {
  return [{ json: buildOutput(item && item.json ? item.json : {}) }];
}

return items.map((it) => ({ json: buildOutput(it && it.json ? it.json : {}) }));

## /**
 * Code5 - Pretty Pack v4.2
 *
 * Updated:
 * - Gracefully explains Cash MAO logic
 * - Clearly states repairs / closing costs / seller agent fees / wholesale fee are reference numbers
 * - Shows closer reference numbers without making them look automatically deducted
 */

function safeNode(name, fallback = {}) {
  try {
    const v = $(name).first().json;
    return v || fallback;
  } catch {
    return fallback;
  }
}

function firstValue() {
  for (const v of arguments) {
    if (v === 0 || v === false) return v;
    if (v === null || v === undefined) continue;
    if (typeof v === 'string' && v.trim() === '') continue;
    return v;
  }
  return null;
}

function nonEmptyObject() {
  for (const v of arguments) {
    if (v && typeof v === 'object' && !Array.isArray(v) && Object.keys(v).length) return v;
  }
  return {};
}

function hasAnyKey(obj, keys) {
  if (!obj || typeof obj !== 'object') return false;
  return keys.some((k) => obj[k] !== undefined && obj[k] !== null);
}

function toMoneyNumber(x) {
  if (x === null || x === undefined || x === '') return null;
  if (typeof x === 'number') return Number.isFinite(x) ? x : null;
  const n = parseFloat(String(x).replace(/[^\d.\-]/g, ''));
  return Number.isFinite(n) ? n : null;
}

function money(x, digits = 2) {
  const n = toMoneyNumber(x);
  if (n === null) return '—';
  return `$${n.toLocaleString('en-US', {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits
  })}`;
}

function pct(x, digits = 1) {
  if (x === null || x === undefined || x === '') return '—';
  if (typeof x === 'string' && x.includes('%')) return x;
  const n = toMoneyNumber(x);
  if (n === null) return '—';
  return `${n.toFixed(digits)}%`;
}

function clean(s) {
  return String(s == null ? '' : s).replace(/\s+\n/g, '\n').trim();
}

function lower(s) {
  return String(s == null ? '' : s).trim().toLowerCase();
}

function nlToBr(s) {
  return String(s || '').replace(/\n/g, '<br>');
}

function toDiscord(s) {
  return String(s || '')
    .replace(/^🏠/gm, '**🏠**')
    .replace(/^🏦/gm, '**🏦**')
    .replace(/^📊/gm, '**📊**')
    .replace(/^💼/gm, '**💼**')
    .replace(/^🧭/gm, '**🧭**')
    .replace(/^📬/gm, '**📬**')
    .replace(/^📌/gm, '**📌**')
    .replace(/^👤/gm, '**👤**')
    .replace(/^🗒️/gm, '**🗒️**')
    .replace(/^🧰/gm, '**🧰**')
    .replace(/^💵/gm, '**💵**');
}

function isPresent(v) {
  if (v === 0 || v === false) return true;
  if (v === null || v === undefined) return false;
  if (typeof v === 'string') {
    const s = v.trim();
    return s !== '' && s !== 'N/A' && s !== 'null' && s !== 'undefined';
  }
  return true;
}

function pushLine(lines, label, value, formatter) {
  if (!isPresent(value)) return;
  const out = formatter ? formatter(value) : value;
  if (!isPresent(out)) return;
  lines.push(`• ${label}: ${out}`);
}

function offerField(offer) {
  const keys = Array.prototype.slice.call(arguments, 1);
  for (const key of keys) {
    if (offer && offer[key] !== undefined && offer[key] !== null && offer[key] !== '') return offer[key];
  }
  return null;
}

function buildContext(a) {
  const aiNode = safeNode('AI Agent');
  const oeNode = safeNode('OFFER ENGINE v1') || {};

  const current = a || {};
  const currentOut = current.output || {};

  const aiOut = nonEmptyObject(
    aiNode.output,
    current.ai_agent && current.ai_agent.output,
    current.aiAgent && current.aiAgent.output,
    {}
  );

  const oeOut = nonEmptyObject(
    oeNode.output,
    current.offer_engine && current.offer_engine.output,
    current.offerEngine && current.offerEngine.output,
    current.offer_generator && current.offer_generator.output,
    {}
  );

  const currentDeal = firstValue(currentOut.deal_structure, current.deal_structure, {});
  const aiDeal = firstValue(aiOut.deal_structure, {});
  const oeDeal = firstValue(oeOut.deal_structure, currentDeal, {});

  function mergeOffer(name) {
    const base = firstValue(oeDeal[name], currentDeal[name], {});
    const ai = firstValue(aiDeal[name], {});
    return {
      ...base,
      Justification: isPresent(ai.Justification) ? ai.Justification : base.Justification
    };
  }

  return {
    raw: current,
    currentOut,
    aiOut,
    oeOut,

    property: firstValue(currentOut.property, current.property, oeOut.property, aiOut.property, {}),
    metrics: firstValue(currentOut.metrics, current.metrics, oeOut.metrics, aiOut.metrics, {}),
    existingLoan: firstValue(currentOut.existing_loan, current.existing_loan, oeOut.existing_loan, aiOut.existing_loan, {}),
    config: firstValue(currentOut.config, current.config, oeOut.config, aiOut.config, {}),
    transcript: firstValue(current.transcript, currentOut.transcript, oeOut.transcript, {}),

    leadScore: firstValue(currentOut.lead_score, current.lead_score, current.leadScore, oeOut.lead_score, null),
    leadScoreExplanation: firstValue(aiOut.lead_score_explanation, current.lead_score_explanation, null),

    investorsAnalysis: firstValue(oeOut.investors_analysis, currentOut.investors_analysis, current.investors_analysis, {}),
    investorsAnalysisInsights: firstValue(aiOut.investors_analysis_insights, oeOut.investors_analysis_insights, currentOut.investors_analysis_insights, null),

    compsSummary: firstValue(aiOut.comps_summary, currentOut.comps_summary, current.comps_summary, null),
    compPropertiesReport: firstValue(currentOut.comp_properties_report, current.comp_properties_report, oeOut.comp_properties_report, []),

    buyerMatches: firstValue(currentOut.buyer_matches, current.buyer_matches, oeOut.buyer_matches, []),
    buyerMatchSummary: firstValue(aiOut.buyer_match_summary, currentOut.buyer_match_summary, current.buyer_match_summary, null),

    dispoStrategy: firstValue(aiOut.dispoStrategy, currentOut.dispoStrategy, current.dispoStrategy, {}),
    finalRecommendationsAndInsights: firstValue(aiOut.finalRecommendationsAndInsights, currentOut.finalRecommendationsAndInsights, null),
    loi: firstValue(aiOut.loi, currentOut.loi, null),

    dealStructure: {
      'Primary Offer': mergeOffer('Primary Offer'),
      'Backup Offer': mergeOffer('Backup Offer'),
      'Updated Cash Offer': mergeOffer('Updated Cash Offer')
    },

    cashOffer: firstValue(oeOut.cash_offer, currentOut.cash_offer, current.cash_offer, {}),
    mao: firstValue(oeOut.mao, currentOut.mao, current.mao),
    wholesaleFee: firstValue(oeOut.wholesale_fee, currentOut.wholesale_fee, current.wholesale_fee),
    repairEstimate: firstValue(oeOut.repair_estimate, currentOut.repair_estimate, current.repair_estimate),
    ctsEngine: firstValue(oeOut.cts_engine, currentOut.cts_engine, current.cts_engine, {}),
    assignmentFeeRange: firstValue(oeOut.assignment_fee_range, currentOut.assignment_fee_range, current.assignment_fee_range),
    estimatedArv: firstValue(currentOut.estimated_arv, current.estimated_arv, oeOut.estimated_arv, aiOut.estimated_arv)
  };
}

function buildHeader(ctx) {
  const p = ctx.property || {};
  const address = [p.address, p.city, p.state, p.postal_code].filter(Boolean).join(', ') || '—';
  const arv = money(firstValue(ctx.estimatedArv, p.arv_value, ctx.metrics.arv));
  const asIs = money(firstValue(ctx.metrics.as_is_value, ctx.metrics.estValue, p.est_value));
  const asking = money(firstValue(p.mls && p.mls.price_num, ctx.metrics.list_price, ctx.metrics.price, p.list_price));

  const lines = [];
  lines.push(`🏠 Property: ${address}`);
  lines.push(`ARV: ${arv}  |  As-Is: ${asIs}  |  Asking: ${asking}`);
  if (isPresent(ctx.leadScore)) lines.push(`Underwriting Score: ${ctx.leadScore}`);
  return lines.join('\n');
}

function buildInvestorsAnalysis(ctx) {
  const ia = ctx.investorsAnalysis || {};
  const lines = [];
  lines.push('📊 Investors Analysis');
  pushLine(lines, 'Gross Rent', ia['Gross Rent']);
  pushLine(lines, 'Annual Rent', ia['Annual Rent']);
  pushLine(lines, 'Operating Expenses', ia['Operating Expenses']);
  pushLine(lines, 'NOI', ia['NOI']);
  pushLine(lines, 'Annual Debt Service (ADS)', ia['Annual Debt Service (ADS)']);
  pushLine(lines, 'DSCR', ia['DSCR']);
  pushLine(lines, 'Monthly Cash-flow', ia['Monthly Cash-flow']);
  pushLine(lines, 'Annual Cash-flow', ia['Annual Cash-flow']);
  pushLine(lines, 'Break-even Rent', ia['Break-even Rent']);
  pushLine(lines, 'Rent Gap to Break-even', ia['Rent Gap to Break-even']);
  pushLine(lines, 'Cash Flow Profile', ia['Cash Flow Profile']);
  pushLine(lines, 'Years to Recapture Cash In', ia['Years to Recapture Cash In']);
  pushLine(lines, 'Total Cash In', ia['Total Cash In']);
