function buildCompsSection(ctx) {
  const comps = Array.isArray(ctx.compPropertiesReport) ? ctx.compPropertiesReport.slice(0, 5) : [];
  const lines = [];
  lines.push('📌 Comps');
  if (isPresent(ctx.compsSummary)) lines.push(`• Summary: ${clean(ctx.compsSummary)}`);
  if (!comps.length) {
