    return lines.join('\n');
  }

  comps.forEach((c, i) => {
    const bits = [];
    bits.push(c.address || '—');
    if (isPresent(c.price)) bits.push(money(c.price, 0));
    if (isPresent(c.beds) || isPresent(c.bedrooms)) bits.push(`${firstValue(c.beds, c.bedrooms)}bd`);
    if (isPresent(c.baths) || isPresent(c.bathrooms)) bits.push(`${firstValue(c.baths, c.bathrooms)}ba`);
    if (isPresent(c.squareFootage)) bits.push(`${c.squareFootage} sf`);
    if (isPresent(c.daysOnMarket)) bits.push(`DOM ${c.daysOnMarket}`);
    if (isPresent(c.distance)) bits.push(`Dist ${c.distance}`);
    if (isPresent(c.correlation)) bits.push(`Corr ${c.correlation}`);
    lines.push(`• Comp ${i + 1}: ${bits.join(', ')}`);
  });

  return lines.join('\n');
}

function buildBuyerMatchesSection(ctx, showContact) {
  const buyers = Array.isArray(ctx.buyerMatches) ? ctx.buyerMatches.slice(0, 5) : [];
  const lines = [];
  lines.push('👤 Buyer Matches');

