    lines.push(`• ${head}`);
    if (showContact) {
      const contact = b.contact || {};
      const parts = [];
      if (isPresent(contact.name)) parts.push(contact.name);
      if (isPresent(contact.company)) parts.push(contact.company);
      if (isPresent(contact.email)) parts.push(contact.email);
      if (isPresent(contact.phone)) parts.push(String(contact.phone));
      if (parts.length) lines.push(`•   Contact: ${parts.join(' | ')}`);
