  return out;
}

function buildFallbackLoi(ctx) {
  const p = ctx.property || {};
  const addr = [p.address, p.city, p.state, p.postal_code].filter(Boolean).join(', ') || 'the subject property';
  const primary = ctx.dealStructure['Primary Offer'] || {};
  const cash = ctx.dealStructure['Updated Cash Offer'] || {};
  return [
    '<html><body>',
    `<h2>Letter of Intent - ${addr}</h2>`,
    '<p>Please consider the following purchase options:</p>',
