    `<p>Cash to Seller / CTS: ${firstValue(primary.cts, primary['CTS ($)'], primary['Cash to Seller'], primary['Down Payment ($)'], '—')}</p>`,
    `<p>Justification: ${clean(primary.Justification || '') || '—'}</p>`,
    '</body></html>'
  ].join('');
}

function buildOutput(a) {
  const ctx = buildContext(a);
  const role_notes = buildRoleNotes(ctx);
  const ownerOneLine = role_notes.owner.text.replace(/\n+/g, ' | ').replace(/\s+/g, ' ').trim();

  return {
    role_notes,
    pretty_summary_one_line: ownerOneLine,
    pretty_json: JSON.stringify(a, null, 2),
    ai_underwriting_note: role_notes.owner.html,
    pretty_note_ghl: role_notes.owner.text,
    direct_to_agent_loi: firstValue(ctx.loi, buildFallbackLoi(ctx))
  };
}

if (typeof item !== 'undefined') {
  return [{ json: buildOutput(item && item.json ? item.json : {}) }];
}

return items.map((it) => ({ json: buildOutput(it && it.json ? it.json : {}) }));

