/**
 * Evaluation & Stage Router v5.0
 * Merged version:
 * - Boss scoring model:
 *   1. Cash Probability: 1-10
 *   2. Creative Probability: 1-10
 *   3. Underwriting Evaluation: derived from max(Cash, Creative)
 *
 * - Pre-call / Post-call distinction:
 *   Pre-call = public/inferred motivation only, capped confidence
 *   Post-call = transcript/seller/agent evidence drives caps and score
 *
 * - Important:
 *   Underwriting Evaluation is NOT an investor quality score.
 *   It answers: "How actionable is this lead from a seller acceptance perspective?"
 */

const SCORING_VERSION = 'acceptance-router-v5.0-boss-merged';

const EVAL = {
  HOT: { label: '🔥 Hot', value: 'hot' },
  WARM: { label: '🌧️ Warm', value: 'warm' },
  FOLLOWUP: { label: '📞 Follow-Up', value: 'followup' },
  COLD: { label: '🥶 Cold', value: 'cold' },
  DEAD: { label: '☠️ Dead', value: 'dead' },
  MANUAL: { label: '🤝 Manual Review', value: 'manual_review' }
};

const STAGES = {
  CLOSER: '3. Closer Call',
  UNDERWRITER: '2. Underwriter Review',
  FOLLOWUP: '1.5 Prequal Answered: Following Up',
  NURTURE: '9. Cold: Long-Term Nurture',
  DEAD: '10. Dead: Inactive',
  NOT_INTERESTED: '11. Cold/Not Interested',
  DNC: '12. DNC: Do Not contact'
};

function T(v) {
  return String(v ?? '').trim();
}

function lower(v) {
  return T(v).toLowerCase();
}

function num(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  if (typeof v === 'boolean') return v ? 1 : 0;

  let s = String(v).trim().toLowerCase();

  // handles "$300k", "300k", "$300,000"
  const isK = /\bk\b/.test(s);
  s = s.replace(/[^\d.-]/g, '');

  let n = Number(s);
  if (!Number.isFinite(n)) return 0;
  if (isK && n < 10000) n *= 1000;
  return n;
}

function round(n, d = 2) {
  const p = Math.pow(10, d);
  return Math.round((Number(n) || 0) * p) / p;
}

function clamp(v, min, max) {
  return Math.min(max, Math.max(min, Number(v) || 0));
}

function clampInt(v, min, max) {
  return Math.round(clamp(v, min, max));
}

function money(n) {
  return `$${Math.round(Number(n) || 0).toLocaleString('en-US')}`;
}

function pct(n, d = 1) {
  return `${round(n, d).toFixed(d)}%`;
}

function firstNum(...vals) {
  for (const v of vals) {
    const n = num(v);
    if (n !== 0) return n;
  }
  return 0;
}

function firstText(...vals) {
  for (const v of vals) {
    const s = T(v);
    if (s) return s;
  }
  return '';
}

function getNode(name, fallback = {}) {
  try {
    return $(name).first().json || fallback;
  } catch {
    return fallback;
  }
}

function isObj(v) {
  return v && typeof v === 'object' && !Array.isArray(v);
}

function extractOffer(root, output, label) {
  const key = lower(label);

  if (label === 'Primary Offer') {
    return (
      root?.deal_structure?.['Primary Offer'] ||
      output?.deal_structure?.['Primary Offer'] ||
      root?.offers?.primary_offer ||
      root?.offers?.primaryOffer ||
      output?.offers?.primary_offer ||
      output?.offers?.primaryOffer ||
      {}
    );
  }

  if (label === 'Updated Cash Offer') {
    return (
      root?.deal_structure?.['Updated Cash Offer'] ||
      output?.deal_structure?.['Updated Cash Offer'] ||
      root?.offers?.cash_offer ||
      root?.offers?.cashOffer ||
      output?.offers?.cash_offer ||
      output?.offers?.cashOffer ||
      {}
    );
  }

  return {};
}

function extractTranscript(root, output) {
  const analyzer = getNode('Phone Transcript analyzer', {});
  const candidates = [
    root?.transcript?.output,
    root?.transcript,
    output?.transcript?.output,
    output?.transcript,
    analyzer?.output,
    analyzer,
    root?.transcript_insights,
    output?.transcript_insights
  ];

  for (const c of candidates) {
    if (isObj(c)) return c;
  }

  return {};
}

function transcriptText(transcript) {
  return lower(JSON.stringify(transcript || {}));
}

function hasRealTranscript(transcript) {
  const blob = transcriptText(transcript);

  if (!blob || blob === '{}' || blob.length < 20) return false;
  if (/no\s+transcript\s+provided|no\s+call\s+transcript|transcript\s+not\s+provided|no\s+transcript/.test(blob)) {
    return false;
  }

  return true;
}

function normalizeExecutionContext(root, output, transcript) {
  const resolved = root.resolved || output.resolved || {};
  const rawMode = lower(
    root.execution_context ||
    output.execution_context ||
    resolved.underwriting_mode ||
    resolved.mode ||
    ''
  );

  if (rawMode.includes('post')) return 'post_call';
  if (rawMode.includes('pre')) return 'pre_call';

  return hasRealTranscript(transcript) ? 'post_call' : 'pre_call';
}

function extractDollarNear(blob, patterns) {
  const text = lower(blob);

  for (const pattern of patterns) {
    const re = new RegExp(`${pattern}[^\\d$]{0,40}\\$?\\s*([\\d,.]+)\\s*(k)?`, 'i');
    const m = text.match(re);
    if (m) {
      let n = num(`${m[1]}${m[2] ? 'k' : ''}`);
      if (n > 0) return n;
    }
  }

  return 0;
}

function extractAnyDollar(blob) {
  const text = lower(blob);
  const m = text.match(/\$?\s*([\d,.]+)\s*(k)?/i);
  if (!m) return 0;
  return num(`${m[1]}${m[2] ? 'k' : ''}`);
}

function inferSellerStance({ transcript, executionContext, publicText }) {
  const blob = `${transcriptText(transcript)} ${lower(publicText)}`;
  const postOnly = transcriptText(transcript);

  const stance = {
    urgency_band: 'unknown',
    price_flexibility: 'unknown',
    terms_openness: 'unknown',
    creative_discussed: false,
    cash_preference: 'unknown',
    cash_need: 'unknown',
    seller_minimum_price: 0,
    seller_minimum_down_payment: 0,
    seller_stated_ask: 0,
    direct_quote_basis: executionContext === 'post_call',
    motivation_confidence: executionContext === 'post_call' ? 70 : 35
  };

  const sourceForFirmStance = executionContext === 'post_call' ? postOnly : blob;

  stance.seller_minimum_price = extractDollarNear(sourceForFirmStance, [
    'minimum',
    'min',
    'lowest',
    'bottom',
    'need',
    'needs',
    'has to get',
    'must get',
    'walk away with',
    'net',
    'take'
  ]);

  stance.seller_stated_ask = extractDollarNear(sourceForFirmStance, [
    'asking',
    'listed at',
    'list price',
    'wants',
    'want',
    'price is',
    'firm at'
  ]);

  stance.seller_minimum_down_payment = extractDollarNear(sourceForFirmStance, [
    'down payment',
    'down',
    'cash to seller',
    'cash upfront',
    'upfront',
    'needs down',
    'minimum down'
  ]);

  if (/foreclosure|pre[-\s]?foreclosure|behind|arrears|urgent|asap|immediately|must\s+sell|need\s+to\s+sell|hardship|desperate/.test(blob)) {
    stance.urgency_band = 'critical';
  } else if (/vacant|inherited|probate|relocat|divorce|out\s+of\s+state|tired\s+landlord/.test(blob)) {
    stance.urgency_band = 'high';
  } else if (/motivated|wants\s+to\s+sell|needs\s+sold|bring\s+offer|bring\s+offers/.test(blob)) {
    stance.urgency_band = 'medium';
  } else if (/no\s+rush|not\s+in\s+a\s+hurry|not\s+motivated|testing\s+the\s+market/.test(blob)) {
    stance.urgency_band = 'none';
  }

  if (/firm|retail|full\s+price|list\s+price|won'?t\s+discount|will\s+not\s+go\s+below|not\s+flexible|price\s+is\s+firm/.test(sourceForFirmStance)) {
    stance.price_flexibility = 'retail_only';
  } else if (/somewhat\s+flexible|slightly\s+flexible|minor\s+discount|small\s+discount|little\s+flexible/.test(blob)) {
    stance.price_flexibility = 'slightly_flexible';
  } else if (/flexible|negotiable|bring\s+offer|bring\s+offers|any\s+offer|open\s+to\s+offer|price\s+drop|price\s+reduc|reduced/.test(blob)) {
    stance.price_flexibility = 'flexible';
  }

  if (/cash\s+only|no\s+creative|not\s+open\s+to\s+terms|no\s+seller\s+finance|no\s+subject|no\s+subto/.test(sourceForFirmStance)) {
    stance.terms_openness = 'no_creative';
    stance.creative_discussed = true;
  } else if (/open\s+to\s+terms|creative|seller\s+finance|subject\s*to|subto|sub\s*to|carry|seller\s+carry|payments/.test(blob)) {
    stance.terms_openness = 'open';
    stance.creative_discussed = true;
  } else if (/maybe|would\s+consider|might\s+consider|possibly|curious/.test(blob)) {
    stance.terms_openness = 'maybe';
    stance.creative_discussed = true;
  }

  if (/cash\s+only|cash\s+buyer|clean\s+close|quick\s+close|prefers\s+cash|prefer\s+cash/.test(blob)) {
    stance.cash_preference = 'prefers_cash';
  }

  if (/cash\s+out|needs\s+cash|payoff|required\s+payoff|walk\s+away\s+with/.test(blob)) {
    stance.cash_need = 'must_cash_out';
  } else if (/some\s+cash|cash\s+to\s+seller|down\s+payment/.test(blob)) {
    stance.cash_need = 'some_cash_needed';
  } else if (/low\s+cash|terms\s+matter|payment\s+matter|monthly\s+income/.test(blob)) {
    stance.cash_need = 'low_cash_need';
  }

  if (executionContext === 'post_call') {
    stance.motivation_confidence = 80;
    if (stance.urgency_band === 'critical' || stance.price_flexibility !== 'unknown' || stance.terms_openness !== 'unknown') {
      stance.motivation_confidence = 90;
    }
    if (stance.urgency_band === 'unknown' && stance.price_flexibility === 'unknown' && stance.terms_openness === 'unknown') {
      stance.motivation_confidence = 60;
    }
  } else {
    stance.motivation_confidence = 35;
    if (/pre[-\s]?foreclosure|foreclosure|tax\s+lien|hoa\s+lien|probate|vacant|absentee|out\s+of\s+state|price\s+reduc|reduced/.test(blob)) {
      stance.motivation_confidence = 55;
    }
  }

  return stance;
}

function publicMotivationScore({ dom, publicText }) {
  let score = 35;
  const text = lower(publicText);

  if (dom >= 180) score += 25;
  else if (dom >= 90) score += 18;
  else if (dom >= 45) score += 8;

  if (/price\s+reduc|reduced|recently\s+lowered|motivated\s+seller|bring\s+offers|as[-\s]?is/.test(text)) score += 12;
  if (/pre[-\s]?foreclosure|foreclosure|tax\s+lien|hoa\s+lien|lis\s+pendens|probate|inherited/.test(text)) score += 20;
  if (/vacant|absentee|out\s+of\s+state|relocat|tired\s+landlord/.test(text)) score += 10;
  if (/multiple\s+offers|highest\s+and\s+best|bidding\s+war/.test(text)) score -= 18;

  return clamp(score, 0, 85);
}

function transcriptMotivationScore({ stance, transcript }) {
  const blob = transcriptText(transcript);
  let score = 45;

  if (stance.urgency_band === 'critical') score += 40;
  else if (stance.urgency_band === 'high') score += 28;
  else if (stance.urgency_band === 'medium') score += 15;
  else if (stance.urgency_band === 'none') score -= 30;

  if (/vacant|inherited|probate|relocat|divorce|out\s+of\s+state|tired\s+landlord/.test(blob)) score += 12;
  if (/multiple\s+offers|highest\s+and\s+best|bidding\s+war/.test(blob)) score -= 20;

  return clamp(score, 0, 100);
}

function estimateSellerFloor({
  stance,
  executionContext,
  listPrice,
  sellerAsk,
  asIsValue,
  arv,
  publicMotivation
}) {
  let floor = 0;
  let source = 'none';
  let confidence = 'none';

  if (stance.seller_minimum_price > 0) {
    return {
      value: stance.seller_minimum_price,
      source: 'explicit_seller_minimum',
      confidence: 'high',
      notes: 'Seller gave an explicit minimum / floor.'
    };
  }

  if (sellerAsk > 0 || stance.seller_stated_ask > 0) {
    const ask = sellerAsk || stance.seller_stated_ask;

    if (stance.price_flexibility === 'retail_only') {
      floor = ask;
      source = 'seller_ask_firm';
      confidence = executionContext === 'post_call' ? 'high' : 'medium';
    } else if (stance.price_flexibility === 'flexible' && stance.urgency_band === 'critical') {
      floor = ask * 0.85;
      source = 'seller_ask_discounted_for_critical_motivation';
      confidence = executionContext === 'post_call' ? 'high' : 'medium';
    } else if (stance.price_flexibility === 'flexible') {
      floor = ask * 0.90;
      source = 'seller_ask_discounted_for_flexibility';
      confidence = executionContext === 'post_call' ? 'high' : 'medium';
    } else if (stance.price_flexibility === 'slightly_flexible') {
      floor = ask * 0.95;
      source = 'seller_ask_slightly_discounted';
      confidence = executionContext === 'post_call' ? 'high' : 'medium';
    } else {
      floor = ask;
      source = 'seller_ask_unknown_flexibility';
      confidence = executionContext === 'post_call' ? 'medium' : 'low';
    }

    return {
      value: round(floor, 0),
      source,
      confidence,
      notes: 'Seller asking price used as primary floor anchor.'
    };
  }

  if (listPrice > 0) {
    if (stance.price_flexibility === 'retail_only') {
      floor = listPrice;
      source = 'mls_list_firm';
      confidence = executionContext === 'post_call' ? 'high' : 'medium';
    } else if (stance.price_flexibility === 'flexible' && stance.urgency_band === 'critical') {
      floor = listPrice * 0.85;
      source = 'mls_list_discounted_for_critical_motivation';
      confidence = executionContext === 'post_call' ? 'high' : 'medium';
    } else if (stance.price_flexibility === 'flexible') {
      floor = listPrice * 0.90;
      source = 'mls_list_discounted_for_flexibility';
      confidence = executionContext === 'post_call' ? 'high' : 'medium';
    } else if (stance.price_flexibility === 'slightly_flexible') {
      floor = listPrice * 0.95;
      source = 'mls_list_slightly_discounted';
      confidence = executionContext === 'post_call' ? 'high' : 'medium';
    } else if (executionContext === 'pre_call' && publicMotivation >= 70) {
      floor = listPrice * 0.90;
      source = 'mls_list_inferred_public_motivation';
      confidence = 'medium';
    } else {
      floor = listPrice;
      source = 'mls_list_no_confirmed_flexibility';
      confidence = executionContext === 'pre_call' ? 'low' : 'medium';
    }

    return {
      value: round(floor, 0),
      source,
      confidence,
      notes: 'MLS list price used as seller floor anchor.'
    };
  }

  if (asIsValue > 0) {
    return {
      value: round(asIsValue, 0),
      source: 'as_is_value_fallback',
      confidence: 'low',
      notes: 'No seller/list price anchor; as-is value used as weak fallback.'
    };
  }

  if (arv > 0) {
    return {
      value: round(arv, 0),
      source: 'arv_fallback',
      confidence: 'low',
      notes: 'No seller/list/as-is anchor; ARV used as weak fallback.'
    };
  }

  return {
    value: 0,
    source: 'missing',
    confidence: 'none',
    notes: 'No reliable price anchor found.'
  };
}

function cashScoreFromRatio(ratio) {
  if (!ratio || ratio <= 0) return null;

  if (ratio < 0.70) return 1;
  if (ratio < 0.80) return 2;
  if (ratio < 0.85) return 3;
  if (ratio < 0.90) return 4;
  if (ratio < 0.95) return 5;
  if (ratio < 1.00) return 6;
  if (ratio < 1.05) return 7;
  if (ratio < 1.10) return 8;
  if (ratio < 1.20) return 9;
  return 10;
}

function scoreCashProbability({
  cashOffer,
  sellerFloor,
  stance,
  executionContext,
  listPrice,
  publicMotivationScore,
  transcriptExists
}) {
  const reasons = [];

  if (!cashOffer || cashOffer <= 0) {
    return {
      score: null,
      ratio: null,
      cap: null,
      reasons: ['Missing or malformed cash offer.']
    };
  }

  if (!sellerFloor.value || sellerFloor.value <= 0) {
    return {
      score: null,
      ratio: null,
      cap: null,
      reasons: ['Missing seller floor / price anchor.']
    };
  }

  const ratio = cashOffer / sellerFloor.value;
  let score = cashScoreFromRatio(ratio);
  let cap = 10;

  reasons.push(`Base cash score ${score}/10 from cash offer ratio ${pct(ratio * 100)} of seller floor.`);

  if (stance.urgency_band === 'critical' || stance.urgency_band === 'high') {
    score += 1;
    reasons.push('+1 urgency/distress/speed motivation.');
  }

  if (stance.price_flexibility === 'flexible') {
    score += 1;
    reasons.push('+1 seller flexibility.');
  }

  if (stance.cash_preference === 'prefers_cash') {
    score += 1;
    reasons.push('+1 seller prefers cash / clean close.');
  }

  if (stance.price_flexibility === 'retail_only') {
    score -= 2;
    reasons.push('-2 seller appears firm / retail-only.');
  } else if (stance.price_flexibility === 'slightly_flexible') {
    score -= 1;
    reasons.push('-1 seller only slightly flexible.');
  }

  if (listPrice > 0 && cashOffer < listPrice * 0.75 && stance.price_flexibility !== 'flexible') {
    score -= 2;
    reasons.push('-2 cash offer is more than 25% below list with no clear flexibility signal.');
  }

  if (stance.seller_minimum_price > 0 && cashOffer < stance.seller_minimum_price) {
    cap = Math.min(cap, 4);
    reasons.push('Cap 4: seller gave a minimum above the cash offer.');
  }

  if (sellerFloor.confidence === 'none') {
    cap = Math.min(cap, 5);
    reasons.push('Cap 5: no reliable floor estimate.');
  } else if (sellerFloor.confidence === 'low') {
    cap = Math.min(cap, 6);
    reasons.push('Cap 6: weak seller floor confidence.');
  }

  if (!transcriptExists && executionContext === 'pre_call') {
    cap = Math.min(cap, 6);
    reasons.push('Cap 6: pre-call execution; seller conversation is not confirmed.');
  }

  if (executionContext === 'pre_call' && publicMotivationScore < 50) {
    cap = Math.min(cap, 6);
    reasons.push('Cap 6: pre-call with weak public motivation signals.');
  }

  score = clampInt(Math.min(score, cap), 1, 10);

  return {
    score,
    ratio: round(ratio, 4),
    cap,
    reasons
  };
}

function creativeOpennessPoints({ stance, executionContext }) {
  if (stance.terms_openness === 'no_creative') {
    return { points: 0, cap: 2, status: 'explicit_rejection' };
  }

  if (stance.terms_openness === 'open') {
    return { points: 3, cap: 10, status: 'open' };
  }

  if (stance.terms_openness === 'maybe') {
    return { points: 2, cap: 6, status: 'maybe' };
  }

  if (executionContext === 'pre_call') {
    return { points: 1, cap: 5, status: 'not_discussed_pre_call' };
  }

  return { points: 1, cap: 5, status: 'not_discussed_post_call' };
}

function creativePricePoints({ creativePrice, listPrice, sellerFloor }) {
  const anchor = listPrice || sellerFloor.value || 0;
  if (!creativePrice || !anchor) {
    return { points: 0, ratio: null, anchor: 0, anchorType: 'missing' };
  }

  const ratio = creativePrice / anchor;

  let points = 0;
  if (ratio >= 1.00) points = 2;
  else if (ratio >= 0.95) points = 1.5;
  else if (ratio >= 0.90) points = 1;
  else if (ratio >= 0.80) points = 0.5;
  else points = 0;

  return {
    points,
    ratio: round(ratio, 4),
    anchor,
    anchorType: listPrice ? 'mls_list_price' : 'seller_floor'
  };
}

function downPaymentPoints({ downPayment, purchasePrice, sellerMinDown }) {
  if (!purchasePrice || purchasePrice <= 0) {
    return { points: 0, ratio: null, basis: 'missing_purchase_price' };
  }

  if (sellerMinDown > 0) {
    const ratio = downPayment / sellerMinDown;

    if (ratio >= 1) return { points: 2, ratio: round(ratio, 4), basis: 'seller_minimum_down_payment' };
    if (ratio >= 0.80) return { points: 1, ratio: round(ratio, 4), basis: 'seller_minimum_down_payment' };
    if (ratio >= 0.50) return { points: 0.5, ratio: round(ratio, 4), basis: 'seller_minimum_down_payment' };
    return { points: 0, ratio: round(ratio, 4), basis: 'seller_minimum_down_payment' };
  }

  const dpPct = downPayment / purchasePrice;

  if (dpPct >= 0.10) return { points: 2, ratio: round(dpPct, 4), basis: 'target_down_pct' };
  if (dpPct >= 0.05) return { points: 1, ratio: round(dpPct, 4), basis: 'target_down_pct' };
  if (dpPct >= 0.01) return { points: 0.5, ratio: round(dpPct, 4), basis: 'target_down_pct' };
  return { points: 0, ratio: round(dpPct, 4), basis: 'target_down_pct' };
}

function balloonPoints(balloonYears) {
  const y = num(balloonYears);

  if (y >= 5) return 1.5;
  if (y >= 3) return 1;
  if (y >= 1) return 0.5;
  return 0;
}

function monthlyTermsPoints({ dscr, monthlyCF, validationPasses }) {
  if (validationPasses === true) return 1;

  if (dscr >= 1.28 && monthlyCF >= 0) return 1;
  if (dscr >= 1.10 && monthlyCF >= -100) return 0.5;
  return 0;
}

function motivationFlexConfidencePoints({ stance, executionContext, sellerFloor }) {
  let points = 0;

  if (stance.urgency_band === 'critical' || stance.urgency_band === 'high') points += 0.2;
  if (stance.price_flexibility === 'flexible') points += 0.2;
  if (sellerFloor.confidence === 'high') points += 0.1;

  if (executionContext === 'pre_call') {
    points = Math.min(points, 0.3);
  }

  return clamp(points, 0, 0.5);
}

function scoreCreativeProbability({
  primaryOffer,
  stance,
  executionContext,
  listPrice,
  sellerFloor,
  transcriptExists
}) {
  const reasons = [];

  const purchasePrice = firstNum(
    primaryOffer['Purchase Price'],
    primaryOffer.purchase_price,
    primaryOffer.purchasePrice,
    primaryOffer.raw?.purchasePrice,
    primaryOffer.raw?.price
  );

  if (!purchasePrice || purchasePrice <= 0) {
    return {
      score: null,
      cap: null,
      reasons: ['Missing or malformed primary creative purchase price.']
    };
  }

  const downPayment = firstNum(
    primaryOffer['Down Payment ($)'],
    primaryOffer.down_payment,
    primaryOffer.downPayment,
    primaryOffer['Cash to Seller'],
    primaryOffer.cts,
    primaryOffer.raw?.downPayment,
    primaryOffer.raw?.cts,
    primaryOffer.raw?.totalIn
  );

  const balloonYears = firstNum(
    primaryOffer['Balloon Term (Years)'],
    primaryOffer.balloon_years,
    primaryOffer.seller_note_balloon_years,
    primaryOffer.raw?.balloonYears
  );

  const dscr = firstNum(
    primaryOffer.DSCR,
    primaryOffer.dscr,
    primaryOffer.raw?.DSCR,
    primaryOffer.raw?.dscr
  );

  const monthlyCF = firstNum(
    primaryOffer['Monthly Cash-flow'],
    primaryOffer.monthly_cash_flow,
    primaryOffer.monthly_cf,
    primaryOffer.raw?.monthlyCF,
    primaryOffer.raw?.monthly_cash_flow
  );

  const validationPasses =
    primaryOffer?._validation?.passes === true ||
    primaryOffer?.validation?.passes === true ||
    primaryOffer?.raw?._validation?.passes === true;

  const validationViolations = [
    ...(Array.isArray(primaryOffer?._validation?.violations) ? primaryOffer._validation.violations : []),
    ...(Array.isArray(primaryOffer?.validation?.violations) ? primaryOffer.validation.violations : [])
  ];

  const openness = creativeOpennessPoints({ stance, executionContext });
  const price = creativePricePoints({ creativePrice: purchasePrice, listPrice, sellerFloor });
  const down = downPaymentPoints({
    downPayment,
    purchasePrice,
    sellerMinDown: stance.seller_minimum_down_payment
  });
  const balloon = balloonPoints(balloonYears);
  const monthly = monthlyTermsPoints({ dscr, monthlyCF, validationPasses });
  const motivation = motivationFlexConfidencePoints({ stance, executionContext, sellerFloor });

  let raw =
    openness.points +
    price.points +
    down.points +
    balloon +
    monthly +
    motivation;

  let cap = openness.cap;

  reasons.push(`Seller openness: ${openness.points}/3 (${openness.status}).`);
  reasons.push(`Creative price fit: ${price.points}/2.`);
  reasons.push(`Down payment fit: ${down.points}/2.`);
  reasons.push(`Balloon quality: ${balloon}/1.5.`);
  reasons.push(`Monthly/terms acceptability: ${monthly}/1.`);
  reasons.push(`Motivation/flex/confidence: ${round(motivation, 2)}/0.5.`);

  if (stance.terms_openness === 'no_creative') {
    cap = Math.min(cap, 2);
    reasons.push('Cap 2: seller explicitly rejected creative / terms.');
  }

  if (!stance.creative_discussed || openness.status.includes('not_discussed')) {
    cap = Math.min(cap, 5);
    reasons.push('Cap 5: creative was not discussed.');
  }

  if (openness.status === 'maybe') {
    cap = Math.min(cap, 6);
    reasons.push('Cap 6: seller is unsure / only maybe open to creative.');
  }

  if (!listPrice && !sellerFloor.value) {
    cap = Math.min(cap, 6);
    reasons.push('Cap 6: no reliable creative price anchor.');
  }

  if (sellerFloor.confidence === 'low') {
    cap = Math.min(cap, 6);
    reasons.push('Cap 6: weak seller floor confidence.');
  }

  if (!transcriptExists && executionContext === 'pre_call') {
    cap = Math.min(cap, 5);
    reasons.push('Cap 5: pre-call execution; creative not confirmed with seller/agent.');
  }

  if (stance.seller_minimum_down_payment > 0 && downPayment < stance.seller_minimum_down_payment) {
    cap = Math.min(cap, 6);
    reasons.push('Cap 6: offered down payment is below seller minimum.');
  }

  if (dscr > 0 && dscr < 1.00) {
    cap = Math.min(cap, 4);
    reasons.push('Cap 4: creative structure appears economically non-viable with DSCR below 1.00.');
  } else if (dscr > 0 && dscr < 1.28) {
    cap = Math.min(cap, 6);
    reasons.push('Cap 6: creative structure is below 1.28 DSCR target.');
  }

  if (validationViolations.length) {
    cap = Math.min(cap, 6);
    reasons.push(`Cap 6: offer validation violations present: ${validationViolations.join('; ')}`);
  }

  let score = clampInt(Math.min(raw, cap), 1, 10);

  return {
    score,
    cap,
    raw_score: round(raw, 2),
    purchase_price: round(purchasePrice, 0),
    down_payment: round(downPayment, 0),
    down_payment_pct: purchasePrice > 0 ? round((downPayment / purchasePrice) * 100, 2) : null,
    balloon_years: balloonYears || null,
    dscr: dscr || null,
    monthly_cf: monthlyCF || null,
    component_scores: {
      seller_openness: openness.points,
      seller_openness_status: openness.status,
      creative_price_fit: price.points,
      creative_price_ratio: price.ratio,
      down_payment_fit: down.points,
      down_payment_ratio: down.ratio,
      down_payment_basis: down.basis,
      balloon_quality: balloon,
      monthly_terms_acceptability: monthly,
      motivation_flexibility_confidence: round(motivation, 2)
    },
    reasons
  };
}

function mapEvaluation(bestScore, manualReview) {
  if (manualReview) return EVAL.MANUAL;

  if (bestScore >= 9) return EVAL.HOT;
  if (bestScore >= 7) return EVAL.WARM;
  if (bestScore >= 5) return EVAL.FOLLOWUP;
  if (bestScore >= 3) return EVAL.COLD;
  return EVAL.DEAD;
}

function routeStage({ evaluation, executionContext, hardStop }) {
  if (hardStop === 'dnc') return STAGES.DNC;
  if (hardStop === 'dead') return STAGES.DEAD;
  if (hardStop === 'not_interested') return STAGES.NOT_INTERESTED;

  if (evaluation.value === 'manual_review') return STAGES.UNDERWRITER;
  if (evaluation.value === 'dead') return STAGES.DEAD;
  if (evaluation.value === 'cold') return STAGES.NURTURE;

  if (executionContext === 'pre_call') {
    // Pre-call should not route straight to closer.
    if (evaluation.value === 'hot') return STAGES.UNDERWRITER;
    if (evaluation.value === 'warm') return STAGES.FOLLOWUP;
    if (evaluation.value === 'followup') return STAGES.FOLLOWUP;
    return STAGES.NURTURE;
  }

  // Post-call can route to closer.
  if (evaluation.value === 'hot') return STAGES.CLOSER;
  if (evaluation.value === 'warm') return STAGES.UNDERWRITER;
  if (evaluation.value === 'followup') return STAGES.FOLLOWUP;

  return STAGES.NURTURE;
}

function getHardStop(blob) {
  if (/do\s*not\s*contact|\bdnc\b/.test(blob)) return 'dnc';
  if (/already\s+sold|\bsold\b|closed\s+already/.test(blob)) return 'dead';
  if (/not\s+interested|no\s+interest|stop\s+calling|remove\s+me|take\s+me\s+off/.test(blob)) return 'not_interested';
  return null;
}

function buyerCount(root, output) {
  const buyers =
    root.buyer_matches ||
    output.buyer_matches ||
    root.matches ||
    output.matches ||
    [];

  if (Array.isArray(buyers)) return buyers.length;
  if (isObj(buyers)) {
    if (Array.isArray(buyers.matches)) return buyers.matches.length;
    return Object.keys(buyers).length;
  }

  return 0;
}

const results = [];

for (const item of $input.all()) {
  try {
    const root = item.json || {};
    const output = isObj(root.output) ? root.output : {};

    const metrics = root.metrics || output.metrics || {};
    const property = root.property || output.property || {};
    const canonical = root.canonical || output.canonical || {};
    const econ = canonical.economics || root.economics || output.economics || {};
    const investors = root.investors_analysis || output.investors_analysis || {};
    const resolved = root.resolved || output.resolved || {};
    const listing = root.listing || output.listing || root.sale_listing_source || output.sale_listing_source || {};

    const webhook = getNode('Start Webhook1', {});
    const customData =
      root.webhook_custom_data ||
      root.customData ||
      root.body?.customData ||
      webhook.body?.customData ||
      {};

    const transcript = extractTranscript(root, output);
    const transcriptExists = hasRealTranscript(transcript);
    const executionContext = normalizeExecutionContext(root, output, transcript);

    const primaryOffer = extractOffer(root, output, 'Primary Offer');
    const cashOfferObj = extractOffer(root, output, 'Updated Cash Offer');

    const listPrice = firstNum(
      metrics.list_price,
      metrics.asking_price,
      metrics.price,
      property.list_price,
      listing.listPrice,
      listing.price,
      customData.listPrice,
      customData.price,
      customData.mlsListPrice,
      root.monetaryValue
    );

    const sellerAsk = firstNum(
      customData.seller_asking_price,
      customData.sellerAsk,
      customData.askingPrice,
      customData.asking_price,
      transcript.price,
      transcript.sellerAskingPrice,
      transcript.seller_asking_price
    );

    const arv = firstNum(
      metrics.arv,
      root.estimated_arv,
      output.estimated_arv,
      property.arv,
      property.arv_value,
      root.ARV,
      output.ARV
    );

    const asIsValue = firstNum(
      metrics.as_is_value,
      property.as_is_value,
      property.est_value,
      root.as_is_value,
      output.as_is_value,
      resolved.source_assumptions?.est_value
    );

    const cashOffer = firstNum(
      cashOfferObj['Final Cash Offer'],
      cashOfferObj.cash_offer,
      cashOfferObj.cashOffer,
      cashOfferObj.offer,
      cashOfferObj.price,
      cashOfferObj.raw?.cashOffer,
      cashOfferObj.raw?.price
    );

    const dom = firstNum(
      property.dom,
      property.daysOnMarket,
      listing.dom,
      listing.daysOnMarket,
      metrics.dom,
      customData.dom,
      resolved.source_assumptions?.dom
    );

    const publicText = [
      property.mls_description,
      property.description,
      listing.description,
      listing.publicRemarks,
      JSON.stringify(customData || {}),
      JSON.stringify(resolved || {})
    ].join(' ');

    const stance = inferSellerStance({
      transcript,
      executionContext,
      publicText
    });

    const publicMotScore = publicMotivationScore({
      dom,
      publicText
    });

    const confirmedMotScore = executionContext === 'post_call'
      ? transcriptMotivationScore({ stance, transcript })
      : publicMotScore;

    const sellerFloor = estimateSellerFloor({
      stance,
      executionContext,
      listPrice,
      sellerAsk,
      asIsValue,
      arv,
      publicMotivation: publicMotScore
    });

    const cashProbability = scoreCashProbability({
      cashOffer,
      sellerFloor,
      stance,
      executionContext,
      listPrice,
      publicMotivationScore: publicMotScore,
      transcriptExists
    });

    const creativeProbability = scoreCreativeProbability({
      primaryOffer,
      stance,
      executionContext,
      listPrice,
      sellerFloor,
      transcriptExists
    });

    const meaningfulPriceAnchorExists = !!(
      sellerFloor.value ||
      listPrice ||
      sellerAsk ||
      stance.seller_minimum_price ||
      asIsValue ||
      arv
    );

    const hasAnyOffer = !!(
      cashOffer ||
      creativeProbability.purchase_price ||
      firstNum(primaryOffer['Purchase Price'], primaryOffer.purchase_price, primaryOffer.purchasePrice)
    );

    const invalidOrConflictingData = false;

    const manualReviewReasons = [];

    if (!hasAnyOffer) manualReviewReasons.push('Missing both usable cash and creative offer values.');
    if (!meaningfulPriceAnchorExists) manualReviewReasons.push('Missing meaningful price anchors.');
    if (cashProbability.score === null && creativeProbability.score === null) {
      manualReviewReasons.push('Could not calculate either cash or creative probability.');
    }
    if (invalidOrConflictingData) manualReviewReasons.push('Conflicting or invalid offer data.');

    // Merge decision:
    // Pre-call missing transcript does NOT automatically force manual review.
    // Instead, pre-call scores are capped because seller motivation is unconfirmed.
    // Post-call with transcript but no seller stance may still be scoreable if price anchors/offers exist.
    const manualReview = manualReviewReasons.length > 0;

    const cashScore = cashProbability.score;
    const creativeScore = creativeProbability.score;

    let bestScore = 0;
    let bestPath = 'none';

    if (cashScore !== null && creativeScore !== null) {
      if (creativeScore >= cashScore) {
        bestScore = creativeScore;
        bestPath = 'creative';
      } else {
        bestScore = cashScore;
        bestPath = 'cash';
      }
    } else if (cashScore !== null) {
      bestScore = cashScore;
      bestPath = 'cash';
    } else if (creativeScore !== null) {
      bestScore = creativeScore;
      bestPath = 'creative';
    }

    let evaluation = mapEvaluation(bestScore, manualReview);

    const hardStopBlob = [
      transcriptText(transcript),
      lower(publicText),
      lower(root.status),
      lower(root.pipeline_status),
      lower(customData.leadStatus),
      lower(customData.status)
    ].join(' ');

    const hardStop = getHardStop(hardStopBlob);

    if (hardStop === 'dnc') evaluation = EVAL.DEAD;
    if (hardStop === 'dead') evaluation = EVAL.DEAD;
    if (hardStop === 'not_interested') evaluation = EVAL.COLD;

    const nextStage = routeStage({
      evaluation,
      executionContext,
      hardStop
    });

    const score100 = manualReview ? null : bestScore * 10;

    const acceptance = {
      scoring_version: SCORING_VERSION,
      execution_context: executionContext,

      cash_probability: cashScore,
      creative_probability: creativeScore,
      best_acceptance_score: manualReview ? null : bestScore,
      best_acceptance_path: manualReview ? 'manual_review' : bestPath,

      underwriting_evaluation: evaluation.value,
      underwriting_evaluation_label: evaluation.label,

      seller_floor: {
        value: sellerFloor.value,
        formatted: sellerFloor.value ? money(sellerFloor.value) : null,
        source: sellerFloor.source,
        confidence: sellerFloor.confidence,
        notes: sellerFloor.notes
      },

      seller_stance: stance,

      public_motivation_score: round(publicMotScore, 1),
      confirmed_or_effective_motivation_score: round(confirmedMotScore, 1),

      cash_probability_breakdown: cashProbability,
      creative_probability_breakdown: creativeProbability,

      manual_review: manualReview,
      manual_review_reasons: manualReviewReasons,

      price_anchors: {
        list_price: listPrice || null,
        seller_ask: sellerAsk || null,
        seller_minimum_price: stance.seller_minimum_price || null,
        as_is_value: asIsValue || null,
        arv: arv || null
      },

      offer_values: {
        cash_offer: cashOffer || null,
        creative_purchase_price: creativeProbability.purchase_price || null,
        creative_down_payment: creativeProbability.down_payment || null,
        creative_down_payment_pct: creativeProbability.down_payment_pct || null,
        creative_balloon_years: creativeProbability.balloon_years || null,
        creative_dscr: creativeProbability.dscr || null,
        creative_monthly_cf: creativeProbability.monthly_cf || null
      }
    };

    const explanationParts = [];

    explanationParts.push(`Context: ${executionContext}.`);
    explanationParts.push(`Cash Probability: ${cashScore ?? 'N/A'}/10.`);
    explanationParts.push(`Creative Probability: ${creativeScore ?? 'N/A'}/10.`);
    explanationParts.push(`Best path: ${acceptance.best_acceptance_path}.`);
    explanationParts.push(`Underwriting Evaluation: ${evaluation.label}.`);

    if (sellerFloor.value) {
      explanationParts.push(`Seller floor estimated at ${money(sellerFloor.value)} from ${sellerFloor.source} (${sellerFloor.confidence} confidence).`);
    } else {
      explanationParts.push('No reliable seller floor was found.');
    }

    if (executionContext === 'pre_call') {
      explanationParts.push('Pre-call scoring is capped because seller motivation and flexibility are not confirmed.');
    } else {
      explanationParts.push('Post-call scoring uses transcript/seller stance evidence.');
    }

    if (manualReviewReasons.length) {
      explanationParts.push(`Manual review reason: ${manualReviewReasons.join(' ')}`);
    }

    root.acceptance_scoring = acceptance;

    root.cash_probability = cashScore;
    root.creative_probability = creativeScore;

    root.underwriting_evaluation = evaluation.value;
    root.underwriting_evaluation_label = evaluation.label;

    root.best_acceptance_score = acceptance.best_acceptance_score;
    root.best_acceptance_path = acceptance.best_acceptance_path;

    root.execution_context = executionContext;
    root.seller_stance = stance;
    root.seller_floor = acceptance.seller_floor;

    // Backward compatibility for existing lead score fields.
    // This is NOT an investor quality score. It is acceptance score scaled to 100.
    root.leadScore = score100;
    root.lead_score = score100;
    root.lead_score_version = SCORING_VERSION;
    root.lead_score_explanation = explanationParts.join(' ');

    root.precall_priority_score = executionContext === 'pre_call' ? score100 : null;
    root.postcall_actionability_score = executionContext === 'post_call' ? score100 : null;

    root.recommendation = {
      evaluation: evaluation.label,
      underwritingEvaluation: evaluation.value,
      nextPipelineStage: nextStage,
      stage_version: SCORING_VERSION,
      readyForCloserCall: nextStage === STAGES.CLOSER,

      execution_context: executionContext,

      cash_probability: cashScore,
      creative_probability: creativeScore,
      best_acceptance_score: acceptance.best_acceptance_score,
      best_acceptance_path: acceptance.best_acceptance_path,

      seller_floor: acceptance.seller_floor,
      seller_stance: stance,

      manual_review: manualReview,
      manual_review_reasons: manualReviewReasons,

      summary: root.lead_score_explanation,

      routingNotes: {
        pre_call_rule: executionContext === 'pre_call'
          ? 'Pre-call leads do not route directly to Closer Call.'
          : null,
        post_call_rule: executionContext === 'post_call'
          ? 'Post-call leads can route to Closer Call when seller acceptance score is Hot.'
          : null,
        hard_stop: hardStop || null
      }
    };

    root.output = {
      ...(root.output || {}),

      acceptance_scoring: acceptance,

      cash_probability: cashScore,
      creative_probability: creativeScore,
      underwriting_evaluation: evaluation.value,
      underwriting_evaluation_label: evaluation.label,

      best_acceptance_score: acceptance.best_acceptance_score,
      best_acceptance_path: acceptance.best_acceptance_path,

      leadScore: score100,
      lead_score: score100,
      lead_score_version: SCORING_VERSION,
      lead_score_explanation: root.lead_score_explanation,

      execution_context: executionContext,
      precall_priority_score: root.precall_priority_score,
      postcall_actionability_score: root.postcall_actionability_score,

      seller_stance: stance,
      seller_floor: acceptance.seller_floor,

      recommendation: root.recommendation
    };

    results.push({ json: root });
  } catch (e) {
    results.push({
      json: {
        ...(item.json || {}),

        cash_probability: null,
        creative_probability: null,
        underwriting_evaluation: EVAL.MANUAL.value,
        underwriting_evaluation_label: EVAL.MANUAL.label,

        leadScore: null,
        lead_score: null,
        lead_score_version: SCORING_VERSION,
        lead_score_explanation: `Scoring error: ${e?.message || String(e)}`,

        acceptance_scoring: {
          scoring_version: SCORING_VERSION,
          manual_review: true,
          manual_review_reasons: [`Scoring error: ${e?.message || String(e)}`]
        },

        recommendation: {
          evaluation: EVAL.MANUAL.label,
          underwritingEvaluation: EVAL.MANUAL.value,
          nextPipelineStage: STAGES.UNDERWRITER,
          stage_version: SCORING_VERSION,
          readyForCloserCall: false,
          routingReason: 'scoring_error',
          summary: `Scoring error: ${e?.message || String(e)}`
        }
      }
    });
  }
}

return results;

## /**
 * Evaluation & Stage Router v5.2
 *
 * Philosophy:
 * - Offer Engine creates the offer that pencils to DSCR.
 * - This node scores likelihood of seller acceptance.
 * - It does NOT suppress, reject, or cap the actual offer.
 *
 * Fixes:
 * - Pre-call executions never route to Dead.
 * - Low probability does not mean Dead.
 * - Dead only comes from confirmed hard-stop evidence.
 * - Seller floor is not rigid list price.
 * - DOM, price reductions, and soft agent language reduce estimated seller floor.
 * - Creative offers far below list/value are still allowed, but seller acceptance probability is reduced.
 */

const SCORING_VERSION = 'acceptance-router-v5.2-acceptance-likelihood';

const EVAL = {
  HOT: { label: '🔥 Hot', value: 'hot' },
  WARM: { label: '🌧️ Warm', value: 'warm' },
  FOLLOWUP: { label: '📞 Follow-Up', value: 'followup' },
  COLD: { label: '🥶 Cold', value: 'cold' },
  DEAD: { label: '☠️ Dead', value: 'dead' },
  MANUAL: { label: '🤝 Manual Review', value: 'manual_review' },
  DNC: { label: '🚫 DNC', value: 'dnc' }
};

const STAGES = {
  CLOSER: '3. Closer Call',
  UNDERWRITER: '2. Underwriter Review',
  FOLLOWUP: '1.5 Prequal Answered: Following Up',
  NURTURE: '9. Cold: Long-Term Nurture',
  DEAD: '10. Dead: Inactive',
  NOT_INTERESTED: '11. Cold/Not Interested',
  DNC: '12. DNC: Do Not contact'
};

function T(v) {
  return String(v ?? '').trim();
}

function lower(v) {
  return T(v).toLowerCase();
}

function num(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  if (typeof v === 'boolean') return v ? 1 : 0;

  let s = String(v).trim().toLowerCase();
  const isK = /\bk\b/.test(s);
  s = s.replace(/[^\d.-]/g, '');

  let n = Number(s);
  if (!Number.isFinite(n)) return 0;
  if (isK && n < 10000) n *= 1000;
  return n;
}

function round(n, d = 2) {
  const p = Math.pow(10, d);
  return Math.round((Number(n) || 0) * p) / p;
}

function clamp(v, min, max) {
  return Math.min(max, Math.max(min, Number(v) || 0));
}

function clampInt(v, min, max) {
  return Math.round(clamp(v, min, max));
}

function money(n) {
  return `$${Math.round(Number(n) || 0).toLocaleString('en-US')}`;
}

function pct(n, d = 1) {
  return `${round(n, d).toFixed(d)}%`;
}

function firstNum(...vals) {
  for (const v of vals) {
    const n = num(v);
    if (n !== 0) return n;
  }
  return 0;
}

function getNode(name, fallback = {}) {
  try {
    return $(name).first().json || fallback;
  } catch {
    return fallback;
  }
}

function isObj(v) {
  return v && typeof v === 'object' && !Array.isArray(v);
}

function extractOffer(root, output, label) {
  if (label === 'Primary Offer') {
    return (
      root?.deal_structure?.['Primary Offer'] ||
      output?.deal_structure?.['Primary Offer'] ||
      root?.offers?.primary_offer ||
      root?.offers?.primaryOffer ||
      output?.offers?.primary_offer ||
      output?.offers?.primaryOffer ||
      {}
    );
  }

  if (label === 'Updated Cash Offer') {
    return (
      root?.deal_structure?.['Updated Cash Offer'] ||
      output?.deal_structure?.['Updated Cash Offer'] ||
      root?.offers?.cash_offer ||
      root?.offers?.cashOffer ||
      output?.offers?.cash_offer ||
      output?.offers?.cashOffer ||
      {}
    );
  }

  return {};
}

function extractTranscript(root, output) {
  const analyzer = getNode('Phone Transcript analyzer', {});
  const candidates = [
    root?.transcript?.output,
    root?.transcript,
    output?.transcript?.output,
    output?.transcript,
    analyzer?.output,
    analyzer,
    root?.transcript_insights,
    output?.transcript_insights
  ];

  for (const c of candidates) {
    if (isObj(c)) return c;
  }

  return {};
}

function transcriptText(transcript) {
  return lower(JSON.stringify(transcript || {}));
}

function hasRealTranscript(transcript) {
  const blob = transcriptText(transcript);

  if (!blob || blob === '{}' || blob.length < 20) return false;
  if (/no\s+transcript\s+provided|no\s+call\s+transcript|transcript\s+not\s+provided|no\s+transcript/.test(blob)) {
    return false;
  }

  return true;
}

function normalizeExecutionContext(root, output, transcript) {
  const resolved = root.resolved || output.resolved || {};
  const rawMode = lower(
    root.execution_context ||
    output.execution_context ||
    resolved.underwriting_mode ||
    resolved.mode ||
    ''
  );

  if (rawMode.includes('post')) return 'post_call';
  if (rawMode.includes('pre')) return 'pre_call';

  return hasRealTranscript(transcript) ? 'post_call' : 'pre_call';
}

function extractDollarNear(blob, patterns) {
  const text = lower(blob);

  for (const pattern of patterns) {
    const re = new RegExp(`${pattern}[^\\d$]{0,40}\\$?\\s*([\\d,.]+)\\s*(k)?`, 'i');
    const m = text.match(re);
    if (m) {
      let n = num(`${m[1]}${m[2] ? 'k' : ''}`);
      if (n > 0) return n;
    }
  }

  return 0;
}

function inferSellerStance({ transcript, executionContext, publicText }) {
  const blob = `${transcriptText(transcript)} ${lower(publicText)}`;
  const postOnly = transcriptText(transcript);

  const stance = {
    urgency_band: 'unknown',
    price_flexibility: 'unknown',
    terms_openness: 'unknown',
    creative_discussed: false,
    cash_preference: 'unknown',
    cash_need: 'unknown',
    seller_minimum_price: 0,
    seller_minimum_down_payment: 0,
    seller_stated_ask: 0,
    direct_quote_basis: executionContext === 'post_call',
    motivation_confidence: executionContext === 'post_call' ? 70 : 35
  };

  const sourceForFirmStance = executionContext === 'post_call' ? postOnly : blob;

  stance.seller_minimum_price = extractDollarNear(sourceForFirmStance, [
    'minimum',
    'min',
    'lowest',
    'bottom',
    'need',
    'needs',
    'has to get',
    'must get',
    'walk away with',
    'net',
    'take'
  ]);

  stance.seller_stated_ask = extractDollarNear(sourceForFirmStance, [
    'asking',
    'listed at',
    'list price',
    'wants',
    'want',
    'price is',
    'firm at'
  ]);

  stance.seller_minimum_down_payment = extractDollarNear(sourceForFirmStance, [
    'down payment',
    'down',
    'cash to seller',
    'cash upfront',
    'upfront',
    'needs down',
    'minimum down'
  ]);

  if (/foreclosure|pre[-\s]?foreclosure|behind|arrears|urgent|asap|immediately|must\s+sell|need\s+to\s+sell|hardship|desperate/.test(blob)) {
    stance.urgency_band = 'critical';
  } else if (/vacant|inherited|probate|relocat|divorce|out\s+of\s+state|tired\s+landlord/.test(blob)) {
    stance.urgency_band = 'high';
  } else if (/motivated|wants\s+to\s+sell|needs\s+sold|bring\s+offer|bring\s+offers/.test(blob)) {
    stance.urgency_band = 'medium';
  } else if (/no\s+rush|not\s+in\s+a\s+hurry|not\s+motivated|testing\s+the\s+market/.test(blob)) {
    stance.urgency_band = 'none';
  }

  if (/firm|retail|full\s+price|list\s+price|won'?t\s+discount|will\s+not\s+go\s+below|not\s+flexible|price\s+is\s+firm/.test(sourceForFirmStance)) {
    stance.price_flexibility = 'retail_only';
  } else if (/somewhat\s+flexible|slightly\s+flexible|minor\s+discount|small\s+discount|little\s+flexible|hesitant/.test(blob)) {
    stance.price_flexibility = 'slightly_flexible';
  } else if (/flexible|negotiable|bring\s+offer|bring\s+offers|any\s+offer|open\s+to\s+offer|price\s+drop|price\s+reduc|reduced|discounted\s+cash\s+offer|entertain\s+offers/.test(blob)) {
    stance.price_flexibility = 'flexible';
  }

  if (/cash\s+only|no\s+creative|not\s+open\s+to\s+terms|no\s+seller\s+finance|no\s+subject|no\s+subto/.test(sourceForFirmStance)) {
    stance.terms_openness = 'no_creative';
    stance.creative_discussed = true;
  } else if (/open\s+to\s+terms|creative|seller\s+finance|subject\s*to|subto|sub\s*to|carry|seller\s+carry|payments/.test(blob)) {
    stance.terms_openness = 'open';
    stance.creative_discussed = true;
  } else if (/maybe|would\s+consider|might\s+consider|possibly|curious/.test(blob)) {
    stance.terms_openness = 'maybe';
    stance.creative_discussed = true;
  }

  if (/cash\s+only|cash\s+buyer|clean\s+close|quick\s+close|prefers\s+cash|prefer\s+cash/.test(blob)) {
    stance.cash_preference = 'prefers_cash';
  }

  if (/cash\s+out|needs\s+cash|payoff|required\s+payoff|walk\s+away\s+with/.test(blob)) {
    stance.cash_need = 'must_cash_out';
  } else if (/some\s+cash|cash\s+to\s+seller|down\s+payment/.test(blob)) {
    stance.cash_need = 'some_cash_needed';
  } else if (/low\s+cash|terms\s+matter|payment\s+matter|monthly\s+income/.test(blob)) {
    stance.cash_need = 'low_cash_need';
  }

  if (executionContext === 'post_call') {
    stance.motivation_confidence = 80;
    if (stance.urgency_band === 'critical' || stance.price_flexibility !== 'unknown' || stance.terms_openness !== 'unknown') {
      stance.motivation_confidence = 90;
    }
    if (stance.urgency_band === 'unknown' && stance.price_flexibility === 'unknown' && stance.terms_openness === 'unknown') {
      stance.motivation_confidence = 60;
    }
  } else {
    stance.motivation_confidence = 35;
    if (/pre[-\s]?foreclosure|foreclosure|tax\s+lien|hoa\s+lien|probate|vacant|absentee|out\s+of\s+state|price\s+reduc|reduced/.test(blob)) {
      stance.motivation_confidence = 55;
    }
  }

  return stance;
}

function publicMotivationScore({ dom, publicText }) {
  let score = 35;
  const text = lower(publicText);

  if (dom >= 180) score += 25;
  else if (dom >= 120) score += 22;
  else if (dom >= 90) score += 18;
  else if (dom >= 45) score += 8;

  if (/price\s+reduc|reduced|recently\s+lowered|motivated\s+seller|bring\s+offers|as[-\s]?is/.test(text)) score += 12;
  if (/pre[-\s]?foreclosure|foreclosure|tax\s+lien|hoa\s+lien|lis\s+pendens|probate|inherited/.test(text)) score += 20;
  if (/vacant|absentee|out\s+of\s+state|relocat|tired\s+landlord/.test(text)) score += 10;
  if (/multiple\s+offers|highest\s+and\s+best|bidding\s+war/.test(text)) score -= 18;

  return clamp(score, 0, 85);
}

function transcriptMotivationScore({ stance, transcript }) {
  const blob = transcriptText(transcript);
  let score = 45;

  if (stance.urgency_band === 'critical') score += 40;
  else if (stance.urgency_band === 'high') score += 28;
  else if (stance.urgency_band === 'medium') score += 15;
  else if (stance.urgency_band === 'none') score -= 30;

  if (/vacant|inherited|probate|relocat|divorce|out\s+of\s+state|tired\s+landlord/.test(blob)) score += 12;
  if (/multiple\s+offers|highest\s+and\s+best|bidding\s+war/.test(blob)) score -= 20;

  return clamp(score, 0, 100);
}

function inferListFloorMultiplier({ dom, publicText, stance, executionContext }) {
  const text = lower(publicText);

  if (executionContext === 'post_call' && stance.price_flexibility === 'retail_only') {
    return {
      multiplier: 1,
      reasons: ['Post-call seller/agent appears firm on retail/list price.']
    };
  }

  let m = 0.99;
  const reasons = [];

  if (dom >= 180) {
    m = 0.86;
    reasons.push('DOM 180+ implies strong listing fatigue.');
  } else if (dom >= 120) {
    m = 0.88;
    reasons.push('DOM 120+ implies meaningful listing fatigue.');
  } else if (dom >= 90) {
    m = 0.90;
    reasons.push('DOM 90+ implies moderate motivation.');
  } else if (dom >= 45) {
    m = 0.94;
    reasons.push('DOM 45+ implies some listing fatigue.');
  } else if (dom >= 21) {
    m = 0.97;
    reasons.push('DOM 21+ is slightly softened.');
  } else {
    m = 0.99;
    reasons.push('Low DOM / no public softness signal.');
  }

  if (/price\s+reduc|price\s+drop|reduced|lowered|recently\s+lowered/.test(text)) {
    m -= 0.03;
    reasons.push('Price reduction signal softened seller floor.');
  }

  if (/significant\s+price\s+reduc|major\s+price\s+reduc|large\s+price\s+drop/.test(text)) {
    m -= 0.03;
    reasons.push('Significant price reduction softened seller floor further.');
  }

  if (/hesitant|discounted\s+cash\s+offer|would\s+entertain|might\s+entertain|bring\s+offer|bring\s+offers/.test(text)) {
    m -= 0.02;
    reasons.push('Agent/seller language suggests some willingness to entertain offers.');
  }

  if (stance.price_flexibility === 'flexible') {
    m -= 0.04;
    reasons.push('Seller/listing signal suggests flexibility.');
  } else if (stance.price_flexibility === 'slightly_flexible') {
    m -= 0.02;
    reasons.push('Seller/listing signal suggests slight flexibility.');
  }

  if (stance.urgency_band === 'critical') {
    m -= 0.05;
    reasons.push('Critical urgency softened seller floor.');
  } else if (stance.urgency_band === 'high') {
    m -= 0.02;
    reasons.push('High urgency softened seller floor.');
  }

  if (/multiple\s+offers|highest\s+and\s+best|bidding\s+war/.test(text)) {
    m += 0.04;
    reasons.push('Competition signal raised seller floor.');
  }

  const minFloor = executionContext === 'post_call' && stance.urgency_band === 'critical' ? 0.75 : 0.80;
  m = clamp(m, minFloor, 1);

  return {
    multiplier: round(m, 4),
    reasons
  };
}

function estimateSellerFloor({
  stance,
  executionContext,
  listPrice,
  sellerAsk,
  asIsValue,
  arv,
  publicMotivation,
  dom,
  publicText
}) {
  if (stance.seller_minimum_price > 0) {
    return {
      value: stance.seller_minimum_price,
      source: 'explicit_seller_minimum',
      confidence: 'high',
      multiplier: null,
      multiplier_reasons: ['Seller gave an explicit minimum / floor.'],
      notes: 'Seller gave an explicit minimum / floor.'
    };
  }

  const softness = inferListFloorMultiplier({
    dom,
    publicText,
    stance,
    executionContext
  });

  if (sellerAsk > 0 || stance.seller_stated_ask > 0) {
    const ask = sellerAsk || stance.seller_stated_ask;
    let floor = 0;
    let source = '';
    let confidence = '';

    if (stance.price_flexibility === 'retail_only' && executionContext === 'post_call') {
      floor = ask;
      source = 'seller_ask_confirmed_firm';
      confidence = 'high';
    } else {
      floor = ask * softness.multiplier;
      source = 'seller_ask_adjusted_for_acceptance_estimate';
      confidence = executionContext === 'post_call' ? 'medium' : 'low';
      if (publicMotivation >= 70) confidence = executionContext === 'post_call' ? 'high' : 'medium';
    }

    return {
      value: round(floor, 0),
      source,
      confidence,
      multiplier: softness.multiplier,
      multiplier_reasons: softness.reasons,
      notes: 'Seller ask used as anchor, then adjusted for DOM, price reductions, and motivation/flexibility signals unless seller is confirmed firm.'
    };
  }

  if (listPrice > 0) {
    let floor = 0;
    let source = '';
    let confidence = '';

    if (stance.price_flexibility === 'retail_only' && executionContext === 'post_call') {
      floor = listPrice;
      source = 'mls_list_confirmed_firm';
      confidence = 'high';
    } else {
      floor = listPrice * softness.multiplier;
      source = 'mls_list_adjusted_for_acceptance_estimate';
      confidence = executionContext === 'post_call' ? 'medium' : 'low';
      if (publicMotivation >= 70) confidence = executionContext === 'post_call' ? 'high' : 'medium';
    }

    return {
      value: round(floor, 0),
      source,
      confidence,
      multiplier: softness.multiplier,
      multiplier_reasons: softness.reasons,
      notes: 'MLS list price used as anchor, but not treated as a rigid seller floor unless seller is confirmed firm.'
    };
  }

  if (asIsValue > 0) {
    return {
      value: round(asIsValue, 0),
      source: 'as_is_value_fallback',
      confidence: 'low',
      multiplier: null,
      multiplier_reasons: ['No seller/list price anchor; as-is value used as weak fallback.'],
      notes: 'No seller/list price anchor; as-is value used as weak fallback.'
    };
  }

  if (arv > 0) {
    return {
      value: round(arv, 0),
      source: 'arv_fallback',
      confidence: 'low',
      multiplier: null,
      multiplier_reasons: ['No seller/list/as-is anchor; ARV used as weak fallback.'],
      notes: 'No seller/list/as-is anchor; ARV used as weak fallback.'
    };
  }

  return {
    value: 0,
    source: 'missing',
    confidence: 'none',
    multiplier: null,
    multiplier_reasons: ['No reliable price anchor found.'],
    notes: 'No reliable price anchor found.'
  };
}

function cashScoreFromRatio(ratio) {
  if (!ratio || ratio <= 0) return null;

  if (ratio < 0.70) return 1;
  if (ratio < 0.80) return 2;
  if (ratio < 0.85) return 3;
  if (ratio < 0.90) return 4;
  if (ratio < 0.95) return 5;
  if (ratio < 1.00) return 6;
  if (ratio < 1.05) return 7;
  if (ratio < 1.10) return 8;
  if (ratio < 1.20) return 9;
  return 10;
}

function scoreCashProbability({
  cashOffer,
  sellerFloor,
  stance,
  executionContext,
  listPrice,
  publicMotivationScore,
  transcriptExists
}) {
  const reasons = [];

  if (!cashOffer || cashOffer <= 0) {
    return {
      score: null,
      ratio: null,
      score_ceiling: null,
      reasons: ['Missing or malformed cash offer.']
    };
  }

  if (!sellerFloor.value || sellerFloor.value <= 0) {
    return {
      score: null,
      ratio: null,
      score_ceiling: null,
      reasons: ['Missing seller floor / price anchor.']
    };
  }

  const ratio = cashOffer / sellerFloor.value;
  let score = cashScoreFromRatio(ratio);
  let scoreCeiling = 10;

  reasons.push(`Base cash probability ${score}/10 from cash offer ratio ${pct(ratio * 100)} of estimated seller floor.`);
  reasons.push(`Seller floor source: ${sellerFloor.source}; confidence: ${sellerFloor.confidence}.`);

  if (Array.isArray(sellerFloor.multiplier_reasons)) {
    sellerFloor.multiplier_reasons.forEach(r => reasons.push(`Seller floor adjustment: ${r}`));
  }

  if (stance.urgency_band === 'critical' || stance.urgency_band === 'high') {
    score += 1;
    reasons.push('+1 acceptance likelihood: urgency/distress/speed motivation.');
  }

  if (stance.price_flexibility === 'flexible') {
    score += 1;
    reasons.push('+1 acceptance likelihood: seller flexibility.');
  }

  if (stance.cash_preference === 'prefers_cash') {
    score += 1;
    reasons.push('+1 acceptance likelihood: seller prefers cash / clean close.');
  }

  if (stance.price_flexibility === 'retail_only') {
    score -= 2;
    reasons.push('-2 acceptance likelihood: seller appears firm / retail-only.');
  } else if (stance.price_flexibility === 'slightly_flexible') {
    score -= 1;
    reasons.push('-1 acceptance likelihood: seller only slightly flexible.');
  }

  if (listPrice > 0 && cashOffer < listPrice * 0.70 && stance.price_flexibility !== 'flexible' && publicMotivationScore < 65) {
    score -= 1;
    reasons.push('-1 acceptance likelihood: cash offer is below 70% of list with weak flexibility/motivation.');
  } else if (listPrice > 0 && cashOffer < listPrice * 0.75 && stance.price_flexibility !== 'flexible' && publicMotivationScore < 50) {
    score -= 1;
    reasons.push('-1 acceptance likelihood: cash offer is more than 25% below list with weak public motivation.');
  }

  if (stance.seller_minimum_price > 0 && cashOffer < stance.seller_minimum_price) {
    scoreCeiling = Math.min(scoreCeiling, 4);
    reasons.push('Acceptance likelihood ceiling 4/10: seller gave a minimum above the cash offer.');
  }

  if (sellerFloor.confidence === 'none') {
    scoreCeiling = Math.min(scoreCeiling, 5);
    reasons.push('Acceptance likelihood ceiling 5/10: no reliable floor estimate.');
  } else if (sellerFloor.confidence === 'low') {
    scoreCeiling = Math.min(scoreCeiling, 6);
    reasons.push('Acceptance likelihood ceiling 6/10: weak seller floor confidence.');
  }

  if (!transcriptExists && executionContext === 'pre_call') {
    scoreCeiling = Math.min(scoreCeiling, 6);
    reasons.push('Acceptance likelihood ceiling 6/10: pre-call execution; seller conversation is not confirmed.');
  }

  if (executionContext === 'pre_call' && publicMotivationScore < 45) {
    scoreCeiling = Math.min(scoreCeiling, 6);
    reasons.push('Acceptance likelihood ceiling 6/10: pre-call with weak public motivation signals.');
  }

  score = clampInt(Math.min(score, scoreCeiling), 1, 10);

  return {
    score,
    ratio: round(ratio, 4),
    score_ceiling: scoreCeiling,
    reasons
  };
}

function creativeOpennessPoints({ stance, executionContext }) {
  if (stance.terms_openness === 'no_creative') {
    return { points: 0, score_ceiling: 2, status: 'explicit_rejection' };
  }

  if (stance.terms_openness === 'open') {
    return { points: 3, score_ceiling: 10, status: 'open' };
  }

  if (stance.terms_openness === 'maybe') {
    return { points: 2, score_ceiling: 6, status: 'maybe' };
  }

  if (executionContext === 'pre_call') {
    return { points: 1, score_ceiling: 5, status: 'not_discussed_pre_call' };
  }

  return { points: 1, score_ceiling: 5, status: 'not_discussed_post_call' };
}

function creativePriceAcceptancePoints({ creativePrice, listPrice, sellerFloor, valueAnchor }) {
  const anchors = [];

  if (listPrice > 0) {
    anchors.push({ type: 'list_price', value: listPrice, ratio: creativePrice / listPrice });
  }

  if (valueAnchor > 0) {
    anchors.push({ type: 'estimated_value_or_arv', value: valueAnchor, ratio: creativePrice / valueAnchor });
  }

  if (sellerFloor && sellerFloor.value > 0) {
    anchors.push({ type: 'seller_floor', value: sellerFloor.value, ratio: creativePrice / sellerFloor.value });
  }

  if (!creativePrice || !anchors.length) {
    return {
      points: 0,
      weakest_ratio: null,
      weakest_anchor: null,
      ratios: [],
      notes: ['No reliable creative price acceptance anchor.']
    };
  }

  const weakest = anchors.reduce((a, b) => (a.ratio < b.ratio ? a : b));
  const ratio = weakest.ratio;

  let points = 0;

  if (ratio >= 1.00) points = 2;
  else if (ratio >= 0.95) points = 1.7;
  else if (ratio >= 0.90) points = 1.3;
  else if (ratio >= 0.85) points = 0.9;
  else if (ratio >= 0.80) points = 0.6;
  else if (ratio >= 0.70) points = 0.3;
  else points = 0.1;

  return {
    points: round(points, 2),
    weakest_ratio: round(ratio, 4),
    weakest_anchor: weakest.type,
    ratios: anchors.map(a => ({
      anchor: a.type,
      value: round(a.value, 0),
      ratio: round(a.ratio, 4)
    })),
    notes: [`DSCR-valid creative offer is ${pct(ratio * 100)} of ${weakest.type}.`]
  };
}

function creativeAcceptanceCeiling({ weakestRatio, stance, executionContext, publicMotivationScore }) {
  if (weakestRatio === null || weakestRatio === undefined) {
    return {
      score_ceiling: 6,
      reasons: ['Acceptance likelihood ceiling 6/10: missing price acceptance anchor.']
    };
  }

  const confirmedExtremeMotivation =
    executionContext === 'post_call' &&
    stance.urgency_band === 'critical' &&
    (stance.price_flexibility === 'flexible' || stance.terms_openness === 'open');

  const confirmedStrongMotivation =
    executionContext === 'post_call' &&
    (stance.urgency_band === 'high' || stance.price_flexibility === 'flexible' || stance.terms_openness === 'open');

  const preCallStrongPublicSignals =
    executionContext === 'pre_call' &&
    publicMotivationScore >= 70;

  const reasons = [];
  let ceiling = 10;

  if (weakestRatio < 0.70) {
    if (confirmedExtremeMotivation) {
      ceiling = 6;
      reasons.push('Acceptance likelihood ceiling 6/10: offer pencils DSCR but requires a very large seller concession; extreme post-call motivation keeps it viable.');
    } else if (confirmedStrongMotivation) {
      ceiling = 5;
      reasons.push('Acceptance likelihood ceiling 5/10: offer pencils DSCR but is below 70% of list/value; strong seller signals prevent a lower score.');
    } else {
      ceiling = 3;
      reasons.push('Acceptance likelihood ceiling 3/10: offer pencils DSCR but is below 70% of list/value with no confirmed extreme motivation.');
    }
  } else if (weakestRatio < 0.80) {
    if (confirmedExtremeMotivation) {
      ceiling = 7;
      reasons.push('Acceptance likelihood ceiling 7/10: offer pencils DSCR and seller has extreme motivation, but price still requires a major concession.');
    } else if (confirmedStrongMotivation || preCallStrongPublicSignals) {
      ceiling = 6;
      reasons.push('Acceptance likelihood ceiling 6/10: offer pencils DSCR but is 70-79% of list/value; motivation signals make it worth pursuing.');
    } else {
      ceiling = 4;
      reasons.push('Acceptance likelihood ceiling 4/10: offer pencils DSCR but is 70-79% of list/value and likely requires a major seller concession.');
    }
  } else if (weakestRatio < 0.90) {
    if (confirmedStrongMotivation || preCallStrongPublicSignals) {
      ceiling = 8;
      reasons.push('Acceptance likelihood ceiling 8/10: offer pencils DSCR and is 80-89% of list/value with supporting motivation/flexibility signals.');
    } else {
      ceiling = 6;
      reasons.push('Acceptance likelihood ceiling 6/10: offer pencils DSCR but is 80-89% of list/value without strong motivation/flexibility.');
    }
  } else if (weakestRatio < 0.95) {
    ceiling = 8;
    reasons.push('Acceptance likelihood ceiling 8/10: offer pencils DSCR and is 90-94% of list/value.');
  } else {
    ceiling = 10;
    reasons.push('No price-based acceptance ceiling: offer is close to list/value or better.');
  }

  return {
    score_ceiling: ceiling,
    reasons
  };
}

function downPaymentPoints({ downPayment, purchasePrice, sellerMinDown }) {
  if (!purchasePrice || purchasePrice <= 0) {
    return { points: 0, ratio: null, basis: 'missing_purchase_price' };
  }

  if (sellerMinDown > 0) {
    const ratio = downPayment / sellerMinDown;

    if (ratio >= 1) return { points: 2, ratio: round(ratio, 4), basis: 'seller_minimum_down_payment' };
    if (ratio >= 0.80) return { points: 1, ratio: round(ratio, 4), basis: 'seller_minimum_down_payment' };
    if (ratio >= 0.50) return { points: 0.5, ratio: round(ratio, 4), basis: 'seller_minimum_down_payment' };
    return { points: 0, ratio: round(ratio, 4), basis: 'seller_minimum_down_payment' };
  }

  const dpPct = downPayment / purchasePrice;

  if (dpPct >= 0.10) return { points: 2, ratio: round(dpPct, 4), basis: 'target_down_pct' };
  if (dpPct >= 0.05) return { points: 1, ratio: round(dpPct, 4), basis: 'target_down_pct' };
  if (dpPct >= 0.01) return { points: 0.5, ratio: round(dpPct, 4), basis: 'target_down_pct' };
  return { points: 0, ratio: round(dpPct, 4), basis: 'target_down_pct' };
}

function balloonPoints(balloonYears) {
  const y = num(balloonYears);

  if (y >= 5) return 1.5;
  if (y >= 3) return 1;
  if (y >= 1) return 0.5;
  return 0;
}

function monthlyTermsPoints({ dscr, monthlyCF, validationPasses }) {
  if (validationPasses === true) return 1;

  if (dscr >= 1.28 && monthlyCF >= 0) return 1;
  if (dscr >= 1.10 && monthlyCF >= -100) return 0.5;
  return 0;
}

function motivationFlexConfidencePoints({ stance, executionContext, sellerFloor, publicMotivationScore }) {
  let points = 0;

  if (stance.urgency_band === 'critical' || stance.urgency_band === 'high') points += 0.2;
  if (stance.price_flexibility === 'flexible') points += 0.2;
  if (sellerFloor.confidence === 'high') points += 0.1;

  if (executionContext === 'pre_call') {
    if (publicMotivationScore >= 70) points += 0.1;
    points = Math.min(points, 0.3);
  }

  return clamp(points, 0, 0.5);
}

function scoreCreativeProbability({
  primaryOffer,
  stance,
  executionContext,
  listPrice,
  sellerFloor,
  transcriptExists,
  valueAnchor,
  publicMotivationScore
}) {
  const reasons = [];

  const purchasePrice = firstNum(
    primaryOffer['Purchase Price'],
    primaryOffer.purchase_price,
    primaryOffer.purchasePrice,
    primaryOffer.raw?.purchasePrice,
    primaryOffer.raw?.price
  );

  if (!purchasePrice || purchasePrice <= 0) {
    return {
      score: null,
      score_ceiling: null,
      reasons: ['Missing or malformed primary creative purchase price.']
    };
  }

  const downPayment = firstNum(
    primaryOffer['Down Payment ($)'],
    primaryOffer.down_payment,
    primaryOffer.downPayment,
    primaryOffer['Cash to Seller'],
    primaryOffer.cts,
    primaryOffer.raw?.downPayment,
    primaryOffer.raw?.cts,
    primaryOffer.raw?.totalIn
  );

  const balloonYears = firstNum(
    primaryOffer['Balloon Term (Years)'],
    primaryOffer.balloon_years,
    primaryOffer.seller_note_balloon_years,
    primaryOffer.raw?.balloonYears
  );

  const dscr = firstNum(
    primaryOffer.DSCR,
    primaryOffer.dscr,
    primaryOffer.raw?.DSCR,
    primaryOffer.raw?.dscr
  );

  const monthlyCF = firstNum(
    primaryOffer['Monthly Cash-flow'],
    primaryOffer.monthly_cash_flow,
    primaryOffer.monthly_cf,
    primaryOffer.raw?.monthlyCF,
    primaryOffer.raw?.monthly_cash_flow
  );

  const validationPasses =
    primaryOffer?._validation?.passes === true ||
    primaryOffer?.validation?.passes === true ||
    primaryOffer?.raw?._validation?.passes === true;

  const validationViolations = [
    ...(Array.isArray(primaryOffer?._validation?.violations) ? primaryOffer._validation.violations : []),
    ...(Array.isArray(primaryOffer?.validation?.violations) ? primaryOffer.validation.violations : [])
  ];

  const openness = creativeOpennessPoints({ stance, executionContext });
  const price = creativePriceAcceptancePoints({
    creativePrice: purchasePrice,
    listPrice,
    sellerFloor,
    valueAnchor
  });
  const down = downPaymentPoints({
    downPayment,
    purchasePrice,
    sellerMinDown: stance.seller_minimum_down_payment
  });
  const balloon = balloonPoints(balloonYears);
  const monthly = monthlyTermsPoints({ dscr, monthlyCF, validationPasses });
  const motivation = motivationFlexConfidencePoints({
    stance,
    executionContext,
    sellerFloor,
    publicMotivationScore
  });

  let raw =
    openness.points +
    price.points +
    down.points +
    balloon +
    monthly +
    motivation;

  let scoreCeiling = openness.score_ceiling;

  const priceCeiling = creativeAcceptanceCeiling({
    weakestRatio: price.weakest_ratio,
    stance,
    executionContext,
    publicMotivationScore
  });

  scoreCeiling = Math.min(scoreCeiling, priceCeiling.score_ceiling);

  reasons.push('Creative offer is still generated because it pencils DSCR; this score only measures seller acceptance likelihood.');
  reasons.push(`Seller openness: ${openness.points}/3 (${openness.status}).`);
  reasons.push(`Creative price acceptance: ${price.points}/2.`);
  reasons.push(`Down payment fit: ${down.points}/2.`);
  reasons.push(`Balloon quality: ${balloon}/1.5.`);
  reasons.push(`Monthly/terms acceptability: ${monthly}/1.`);
  reasons.push(`Motivation/flex/confidence: ${round(motivation, 2)}/0.5.`);

  price.notes.forEach(r => reasons.push(r));
  priceCeiling.reasons.forEach(r => reasons.push(r));

  if (stance.terms_openness === 'no_creative') {
    scoreCeiling = Math.min(scoreCeiling, 2);
    reasons.push('Acceptance likelihood ceiling 2/10: seller explicitly rejected creative / terms.');
  }

  if (!stance.creative_discussed || openness.status.includes('not_discussed')) {
    scoreCeiling = Math.min(scoreCeiling, 5);
    reasons.push('Acceptance likelihood ceiling 5/10: creative was not discussed.');
  }

  if (openness.status === 'maybe') {
    scoreCeiling = Math.min(scoreCeiling, 6);
    reasons.push('Acceptance likelihood ceiling 6/10: seller is unsure / only maybe open to creative.');
  }

  if (!listPrice && !sellerFloor.value && !valueAnchor) {
    scoreCeiling = Math.min(scoreCeiling, 6);
    reasons.push('Acceptance likelihood ceiling 6/10: no reliable creative price anchor.');
  }

  if (sellerFloor.confidence === 'low') {
    scoreCeiling = Math.min(scoreCeiling, 6);
    reasons.push('Acceptance likelihood ceiling 6/10: weak seller floor confidence.');
  }

  if (!transcriptExists && executionContext === 'pre_call') {
    scoreCeiling = Math.min(scoreCeiling, 5);
    reasons.push('Acceptance likelihood ceiling 5/10: pre-call execution; creative acceptance not confirmed with seller/agent.');
  }

  if (stance.seller_minimum_down_payment > 0 && downPayment < stance.seller_minimum_down_payment) {
    scoreCeiling = Math.min(scoreCeiling, 6);
    reasons.push('Acceptance likelihood ceiling 6/10: offered down payment is below seller minimum.');
  }

  if (dscr > 0 && dscr < 1.00) {
    scoreCeiling = Math.min(scoreCeiling, 4);
    reasons.push('Acceptance likelihood ceiling 4/10: creative structure appears economically non-viable with DSCR below 1.00.');
  } else if (dscr > 0 && dscr < 1.28) {
    scoreCeiling = Math.min(scoreCeiling, 6);
    reasons.push('Acceptance likelihood ceiling 6/10: creative structure is below 1.28 DSCR target.');
  }

  if (validationViolations.length) {
    scoreCeiling = Math.min(scoreCeiling, 6);
    reasons.push(`Acceptance likelihood ceiling 6/10: offer validation issues present: ${validationViolations.join('; ')}`);
  }

  let score = clampInt(Math.min(raw, scoreCeiling), 1, 10);

  return {
    score,
    score_ceiling: scoreCeiling,
    raw_score: round(raw, 2),
    purchase_price: round(purchasePrice, 0),
    down_payment: round(downPayment, 0),
    down_payment_pct: purchasePrice > 0 ? round((downPayment / purchasePrice) * 100, 2) : null,
    balloon_years: balloonYears || null,
    dscr: dscr || null,
    monthly_cf: monthlyCF || null,
    weakest_price_ratio: price.weakest_ratio,
    weakest_price_anchor: price.weakest_anchor,
    price_ratios: price.ratios,
    component_scores: {
      seller_openness: openness.points,
      seller_openness_status: openness.status,
      creative_price_acceptance: price.points,
      creative_weakest_price_ratio: price.weakest_ratio,
      down_payment_fit: down.points,
      down_payment_ratio: down.ratio,
      down_payment_basis: down.basis,
      balloon_quality: balloon,
      monthly_terms_acceptability: monthly,
      motivation_flexibility_confidence: round(motivation, 2)
    },
    reasons
  };
}

function mapEvaluation(bestScore, manualReview) {
  if (manualReview) return EVAL.MANUAL;

  if (bestScore >= 9) return EVAL.HOT;
  if (bestScore >= 7) return EVAL.WARM;
  if (bestScore >= 5) return EVAL.FOLLOWUP;

  // Low probability is Cold/Nurture, not Dead.
  // Dead requires confirmed hard-stop evidence.
  return EVAL.COLD;
}

function routeStage({ evaluation, executionContext, hardStop }) {
  if (hardStop === 'dnc') return STAGES.DNC;

  // Pre-call can never route to Dead.
  if (executionContext === 'pre_call') {
    if (hardStop === 'dead' || hardStop === 'not_interested') {
      return STAGES.UNDERWRITER;
    }

    if (evaluation.value === 'manual_review') return STAGES.UNDERWRITER;
    if (evaluation.value === 'hot') return STAGES.UNDERWRITER;
    if (evaluation.value === 'warm') return STAGES.FOLLOWUP;
    if (evaluation.value === 'followup') return STAGES.FOLLOWUP;
    if (evaluation.value === 'cold') return STAGES.NURTURE;

    return STAGES.NURTURE;
  }

  // Post-call can route to Dead only with confirmed hard-stop evidence.
  if (executionContext === 'post_call') {
    if (hardStop === 'dead') return STAGES.DEAD;
    if (hardStop === 'not_interested') return STAGES.NOT_INTERESTED;

    if (evaluation.value === 'manual_review') return STAGES.UNDERWRITER;
    if (evaluation.value === 'dead') return STAGES.DEAD;
    if (evaluation.value === 'cold') return STAGES.NURTURE;
    if (evaluation.value === 'hot') return STAGES.CLOSER;
    if (evaluation.value === 'warm') return STAGES.UNDERWRITER;
    if (evaluation.value === 'followup') return STAGES.FOLLOWUP;
  }

  return STAGES.UNDERWRITER;
}

function getHardStop(blob) {
  if (/do\s*not\s*contact|\bdnc\b/.test(blob)) return 'dnc';
  if (/already\s+sold|closed\s+already|property\s+sold|went\s+under\s+contract/.test(blob)) return 'dead';
  if (/not\s+interested|no\s+interest|stop\s+calling|remove\s+me|take\s+me\s+off/.test(blob)) return 'not_interested';
  return null;
}

