      property.estimated_value,
      root.as_is_value,
      output.as_is_value,
      resolved.source_assumptions?.est_value
    );

    const valueAnchor = firstNum(
      asIsValue,
      property.estimatedValue,
      property.estimated_value,
      property.propwireValue,
      property.propwire_value,
      metrics.est_value,
      metrics.estimated_value,
      metrics.propwire_value,
      customData.estimatedValue,
      customData.estimated_value,
      customData.propwireValue,
      customData.propwire_value,
      customData.propwire_estimated_value,
      root.estimated_property_value,
      root.propwire_value,
      output.estimated_property_value,
      output.propwire_value,
      arv
    );

    const cashOffer = firstNum(
      cashOfferObj['Final Cash Offer'],
      cashOfferObj.cash_offer,
      cashOfferObj.cashOffer,
      cashOfferObj.offer,
      cashOfferObj.price,
      cashOfferObj.raw?.cashOffer,
      cashOfferObj.raw?.price
    );

    const dom = firstNum(
      property.dom,
      property.daysOnMarket,
      listing.dom,
      listing.daysOnMarket,
      metrics.dom,
      customData.dom,
      resolved.source_assumptions?.dom
    );

    const publicText = [
      property.mls_description,
      property.description,
      listing.description,
      listing.publicRemarks,
      JSON.stringify(customData || {}),
      JSON.stringify(resolved || {})
    ].join(' ');

    const stance = inferSellerStance({
      transcript,
      executionContext,
      publicText
    });

    const publicMotScore = publicMotivationScore({
      dom,
      publicText
    });

    const confirmedMotScore = executionContext === 'post_call'
      ? transcriptMotivationScore({ stance, transcript })
      : publicMotScore;

    const sellerFloor = estimateSellerFloor({
      stance,
      executionContext,
      listPrice,
      sellerAsk,
      asIsValue,
      arv,
      publicMotivation: publicMotScore,
      dom,
      publicText
    });

    const cashProbability = scoreCashProbability({
      cashOffer,
      sellerFloor,
      stance,
      executionContext,
      listPrice,
      publicMotivationScore: publicMotScore,
      transcriptExists
    });

    const creativeProbability = scoreCreativeProbability({
      primaryOffer,
      stance,
      executionContext,
      listPrice,
      sellerFloor,
      transcriptExists,
      valueAnchor,
      publicMotivationScore: publicMotScore
    });

    const meaningfulPriceAnchorExists = !!(
      sellerFloor.value ||
      listPrice ||
      sellerAsk ||
      stance.seller_minimum_price ||
      asIsValue ||
      arv ||
      valueAnchor
    );

    const hasAnyOffer = !!(
      cashOffer ||
      creativeProbability.purchase_price ||
      firstNum(primaryOffer['Purchase Price'], primaryOffer.purchase_price, primaryOffer.purchasePrice)
    );

    const manualReviewReasons = [];

    if (!hasAnyOffer) manualReviewReasons.push('Missing both usable cash and creative offer values.');
    if (!meaningfulPriceAnchorExists) manualReviewReasons.push('Missing meaningful price anchors.');
    if (cashProbability.score === null && creativeProbability.score === null) {
      manualReviewReasons.push('Could not calculate either cash or creative probability.');
    }

    let manualReview = manualReviewReasons.length > 0;

    const cashScore = cashProbability.score;
    const creativeScore = creativeProbability.score;

    let bestScore = 0;
    let bestPath = 'none';

    if (cashScore !== null && creativeScore !== null) {
      if (creativeScore >= cashScore) {
        bestScore = creativeScore;
        bestPath = 'creative';
      } else {
        bestScore = cashScore;
        bestPath = 'cash';
      }
    } else if (cashScore !== null) {
      bestScore = cashScore;
      bestPath = 'cash';
    } else if (creativeScore !== null) {
      bestScore = creativeScore;
      bestPath = 'creative';
    }

    let evaluation = mapEvaluation(bestScore, manualReview);

    const hardStopBlob = [
      transcriptText(transcript),
      lower(publicText),
      lower(root.status),
      lower(root.pipeline_status),
      lower(customData.leadStatus),
      lower(customData.status)
    ].join(' ');

    const hardStop = getHardStop(hardStopBlob);

    if (hardStop === 'dnc') {
      evaluation = EVAL.DNC;
    } else if (executionContext === 'post_call' && hardStop === 'dead') {
      evaluation = EVAL.DEAD;
    } else if (executionContext === 'post_call' && hardStop === 'not_interested') {
      evaluation = EVAL.COLD;
    } else if (executionContext === 'pre_call' && (hardStop === 'dead' || hardStop === 'not_interested')) {
      evaluation = EVAL.MANUAL;
      manualReview = true;
      manualReviewReasons.push('Pre-call had possible hard-stop language, but pre-call executions cannot be routed Dead without confirmation.');
    }

    const nextStage = routeStage({
      evaluation,
      executionContext,
      hardStop
    });

    let score100 = manualReview ? null : bestScore * 10;
    if (hardStop === 'dnc') score100 = 0;

    const acceptance = {
      scoring_version: SCORING_VERSION,
      execution_context: executionContext,

      cash_probability: cashScore,
      creative_probability: creativeScore,
      best_acceptance_score: manualReview ? null : bestScore,
      best_acceptance_path: manualReview ? 'manual_review' : bestPath,

      underwriting_evaluation: evaluation.value,
      underwriting_evaluation_label: evaluation.label,

      seller_floor: {
        value: sellerFloor.value,
        formatted: sellerFloor.value ? money(sellerFloor.value) : null,
        source: sellerFloor.source,
        confidence: sellerFloor.confidence,
        multiplier: sellerFloor.multiplier,
        multiplier_reasons: sellerFloor.multiplier_reasons || [],
        notes: sellerFloor.notes
      },

      seller_stance: stance,

      public_motivation_score: round(publicMotScore, 1),
      confirmed_or_effective_motivation_score: round(confirmedMotScore, 1),

      cash_probability_breakdown: cashProbability,
      creative_probability_breakdown: creativeProbability,

      manual_review: manualReview,
      manual_review_reasons: manualReviewReasons,

      price_anchors: {
        list_price: listPrice || null,
        seller_ask: sellerAsk || null,
        seller_minimum_price: stance.seller_minimum_price || null,
        as_is_value: asIsValue || null,
        arv: arv || null,
        value_anchor: valueAnchor || null,
        dom: dom || null
      },

      offer_values: {
        cash_offer: cashOffer || null,
        creative_purchase_price: creativeProbability.purchase_price || null,
        creative_down_payment: creativeProbability.down_payment || null,
        creative_down_payment_pct: creativeProbability.down_payment_pct || null,
        creative_balloon_years: creativeProbability.balloon_years || null,
        creative_dscr: creativeProbability.dscr || null,
        creative_monthly_cf: creativeProbability.monthly_cf || null,
        creative_weakest_price_ratio: creativeProbability.weakest_price_ratio || null,
        creative_weakest_price_anchor: creativeProbability.weakest_price_anchor || null,
        creative_price_ratios: creativeProbability.price_ratios || []
      }
    };

    const explanationParts = [];

    explanationParts.push(`Context: ${executionContext}.`);
    explanationParts.push(`Cash Probability: ${cashScore ?? 'N/A'}/10.`);
    explanationParts.push(`Creative Probability: ${creativeScore ?? 'N/A'}/10.`);
    explanationParts.push(`Best path: ${acceptance.best_acceptance_path}.`);
    explanationParts.push(`Underwriting Evaluation: ${evaluation.label}.`);

    if (sellerFloor.value) {
      explanationParts.push(`Seller floor estimated at ${money(sellerFloor.value)} from ${sellerFloor.source} (${sellerFloor.confidence} confidence).`);
      if (sellerFloor.multiplier) explanationParts.push(`Seller floor multiplier: ${pct(sellerFloor.multiplier * 100)} of anchor.`);
    } else {
      explanationParts.push('No reliable seller floor was found.');
    }

    if (executionContext === 'pre_call') {
      explanationParts.push('Pre-call scoring is capped because seller motivation and flexibility are not confirmed. Pre-call can never route to Dead.');
    } else {
      explanationParts.push('Post-call scoring uses transcript/seller stance evidence.');
    }

    explanationParts.push('Offer Engine still creates the DSCR-valid offer; this router only scores seller acceptance likelihood.');

    if (manualReviewReasons.length) {
      explanationParts.push(`Manual review reason: ${manualReviewReasons.join(' ')}`);
    }

    root.acceptance_scoring = acceptance;

    root.cash_probability = cashScore;
    root.creative_probability = creativeScore;

    root.underwriting_evaluation = evaluation.value;
    root.underwriting_evaluation_label = evaluation.label;

    root.best_acceptance_score = acceptance.best_acceptance_score;
    root.best_acceptance_path = acceptance.best_acceptance_path;

    root.execution_context = executionContext;
    root.seller_stance = stance;
    root.seller_floor = acceptance.seller_floor;

    root.leadScore = score100;
    root.lead_score = score100;
    root.lead_score_version = SCORING_VERSION;
    root.lead_score_explanation = explanationParts.join(' ');

    root.precall_priority_score = executionContext === 'pre_call' ? score100 : null;
    root.postcall_actionability_score = executionContext === 'post_call' ? score100 : null;

    root.recommendation = {
      evaluation: evaluation.label,
      underwritingEvaluation: evaluation.value,
      nextPipelineStage: nextStage,
      stage_version: SCORING_VERSION,
      readyForCloserCall: nextStage === STAGES.CLOSER,

      execution_context: executionContext,

      cash_probability: cashScore,
      creative_probability: creativeScore,
      best_acceptance_score: acceptance.best_acceptance_score,
      best_acceptance_path: acceptance.best_acceptance_path,

      seller_floor: acceptance.seller_floor,
      seller_stance: stance,

      manual_review: manualReview,
      manual_review_reasons: manualReviewReasons,

      summary: root.lead_score_explanation,

      routingNotes: {
        pre_call_rule: executionContext === 'pre_call'
          ? 'Pre-call leads do not route directly to Closer Call and can never route to Dead.'
          : null,
        post_call_rule: executionContext === 'post_call'
          ? 'Post-call leads can route to Closer Call when seller acceptance score is Hot and no hard stop exists.'
          : null,
        offer_engine_rule: 'Offer Engine should still generate the offer that pencils DSCR. This router only scores likelihood of seller acceptance.',
        hard_stop: hardStop || null
      }
    };

    root.output = {
      ...(root.output || {}),

      acceptance_scoring: acceptance,

      cash_probability: cashScore,
      creative_probability: creativeScore,
      underwriting_evaluation: evaluation.value,
      underwriting_evaluation_label: evaluation.label,

      best_acceptance_score: acceptance.best_acceptance_score,
      best_acceptance_path: acceptance.best_acceptance_path,

      leadScore: score100,
      lead_score: score100,
      lead_score_version: SCORING_VERSION,
      lead_score_explanation: root.lead_score_explanation,

      execution_context: executionContext,
      precall_priority_score: root.precall_priority_score,
      postcall_actionability_score: root.postcall_actionability_score,

      seller_stance: stance,
      seller_floor: acceptance.seller_floor,

      recommendation: root.recommendation
    };

    results.push({ json: root });
  } catch (e) {
    results.push({
      json: {
        ...(item.json || {}),

        cash_probability: null,
        creative_probability: null,
        underwriting_evaluation: EVAL.MANUAL.value,
        underwriting_evaluation_label: EVAL.MANUAL.label,

        leadScore: null,
        lead_score: null,
        lead_score_version: SCORING_VERSION,
        lead_score_explanation: `Scoring error: ${e?.message || String(e)}`,

        acceptance_scoring: {
          scoring_version: SCORING_VERSION,
          manual_review: true,
          manual_review_reasons: [`Scoring error: ${e?.message || String(e)}`]
        },

        recommendation: {
          evaluation: EVAL.MANUAL.label,
          underwritingEvaluation: EVAL.MANUAL.value,
          nextPipelineStage: STAGES.UNDERWRITER,
          stage_version: SCORING_VERSION,
          readyForCloserCall: false,
          routingReason: 'scoring_error',
          summary: `Scoring error: ${e?.message || String(e)}`
        }
      }
    });
  }
}

return results;

## function num(v) {
  if (v === null || v === undefined || v === '') return 0;
  const n = Number(String(v).replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : 0;
}

function txt(v) {
  return String(v ?? '').trim();
}

function lower(v) {
  return txt(v).toLowerCase();
}

function get(obj, keys) {
  for (const k of keys) {
    if (obj && obj[k] !== undefined && obj[k] !== null && obj[k] !== '') return obj[k];
  }
  return null;
}

function normalizeType(v) {
  const s = lower(v);

  if (!s) return '';

  if (s.includes('multi')) return 'multi-family';
  if (s.includes('duplex')) return 'multi-family';
  if (s.includes('triplex')) return 'multi-family';
  if (s.includes('fourplex')) return 'multi-family';
  if (s.includes('apartment')) return 'apartment';
  if (s.includes('single')) return 'single-family';
  if (s.includes('sfr')) return 'single-family';
  if (s.includes('residential')) return 'single-family';
  if (s.includes('detached')) return 'single-family';
  if (s.includes('town')) return 'townhouse';
  if (s.includes('condo')) return 'condo';

  return s;
}

function propertyTypeMatches(compType, subjectType) {
  const c = normalizeType(compType);
  const s = normalizeType(subjectType);

  if (!c || !s) return true;
  if (c === s) return true;

  if (s === 'multi-family' && /(multi|duplex|triplex|fourplex|apartment)/i.test(c)) return true;
  if (s === 'single-family' && /(single|sfr|residential|detached)/i.test(c)) return true;

  return false;
}

function classifyCompStatus(c) {
  const status = lower(get(c, [
    'status',
    'listingStatus',
    'mlsStatus',
    'propertyStatus',
    'standardStatus',
    'listing_status',
    'mls_status',
    'standard_status'
  ]));

  const soldDate = get(c, [
    'soldDate',
    'dateSold',
    'removedDate',
    'closedDate',
    'lastSaleDate',
    'sold_date',
    'date_sold',
    'removed_date',
    'closed_date',
    'last_sale_date'
  ]);

  if (soldDate) return 'sold';

  if (/(sold|closed)/i.test(status)) return 'sold';

  if (/(pending|under contract|under_contract|contingent|active under contract)/i.test(status)) {
    return 'pending';
  }

  if (/(active|for sale|listed|coming soon)/i.test(status)) {
    return 'active';
  }

  if (/(withdrawn|cancelled|canceled|expired)/i.test(status)) {
    return 'excluded';
  }

  // Do not automatically kill "Inactive".
  // RentCast often uses inactive for removed/sold-ish comps.
  if (/inactive|off market|off-market/i.test(status)) {
    return 'unknown';
  }

  return 'unknown';
}

function isAllowedCompStatus(c) {
  const group = classifyCompStatus(c);
  return ['sold', 'pending', 'active', 'unknown'].includes(group);
}

function getCompPrice(c) {
  const group = classifyCompStatus(c);

  if (group === 'sold') {
    return num(get(c, [
      'soldPrice',
      'closePrice',
      'salePrice',
      'lastSalePrice',
      'price',
      'listPrice',
      'sold_price',
      'close_price',
      'sale_price',
      'last_sale_price',
      'list_price'
    ]));
  }

  return num(get(c, [
    'listPrice',
    'price',
    'askingPrice',
    'currentPrice',
    'listingPrice',
    'list_price',
    'asking_price',
    'current_price',
    'listing_price'
  ]));
}

function getPriceBasis(c) {
  const group = classifyCompStatus(c);

  if (group === 'sold') return 'sold_price';
  if (group === 'pending') return 'pending_or_contract_price';
  if (group === 'active') return 'list_price';
  return 'unknown_price_basis';
}

function normalizeComp(c) {
  const statusGroup = classifyCompStatus(c);

  return {
    ...c,
    _price: getCompPrice(c),
    _priceBasis: getPriceBasis(c),
    _statusGroup: statusGroup,
    _sqft: num(get(c, [
      'squareFootage',
      'livingArea',
      'sqft',
      'buildingSqft',
      'buildingArea',
      'square_footage',
      'living_area',
      'building_sqft',
      'building_area'
    ])),
    _beds: num(get(c, [
      'bedrooms',
      'beds',
      'bed',
      'numBedrooms',
      'bed_count',
      'bedroom_count'
    ])),
    _baths: num(get(c, [
      'bathrooms',
      'baths',
      'bath',
      'totalBathrooms',
      'numBathrooms',
      'bath_count',
      'bathroom_count',
      'total_bathrooms'
    ])),
    _distance: num(get(c, [
      'distance',
      'distanceMiles',
      'distance_miles',
      'distanceMi',
      'distance_mi',
      'miles'
    ])),
    _yearBuilt: num(get(c, [
      'yearBuilt',
      'yrBuilt',
      'year_built',
      'yr_built'
    ])),
    _propertyType: get(c, [
      'propertyType',
      'propType',
      'type',
      'property_type',
      'prop_type'
    ])
  };
}

function rejectionReason(c, subject, rules) {
  if (!isAllowedCompStatus(c)) return 'bad_status';

  if (c._price <= 0) return 'missing_or_zero_price';
  if (c._sqft <= 0) return 'missing_or_zero_sqft';

  if (rules.requireBeds && c._beds <= 0) return 'missing_or_zero_beds';
  if (rules.requireBaths && c._baths <= 0) return 'missing_or_zero_baths';

  if (rules.requireTypeMatch && !propertyTypeMatches(c._propertyType, subject.propType)) {
    return 'property_type_mismatch';
  }

  if (rules.maxDistance > 0 && c._distance > rules.maxDistance) {
    return 'distance_too_far';
  }

  if (subject.beds > 0 && c._beds > 0 && Math.abs(c._beds - subject.beds) > rules.bedTolerance) {
    return 'bed_mismatch';
  }

  if (subject.baths > 0 && c._baths > 0 && Math.abs(c._baths - subject.baths) > rules.bathTolerance) {
    return 'bath_mismatch';
  }

  if (subject.sqft > 0 && c._sqft > 0) {
    const sqftRatio = c._sqft / subject.sqft;

    if (sqftRatio < rules.minSqftRatio) return 'sqft_too_small';
    if (sqftRatio > rules.maxSqftRatio) return 'sqft_too_large';
  }

  if (subject.yearBuilt > 0 && c._yearBuilt > 0 && rules.yearTolerance > 0) {
    if (Math.abs(c._yearBuilt - subject.yearBuilt) > rules.yearTolerance) {
      return 'year_built_mismatch';
    }
  }

  return null;
}

function summarizeRejections(normalizedComps, subject, rules) {
  const summary = {};

  for (const c of normalizedComps) {
    const reason = rejectionReason(c, subject, rules);
    if (reason) summary[reason] = (summary[reason] || 0) + 1;
  }

  return summary;
}

function applyRules(normalizedComps, subject, rules) {
  return normalizedComps.filter(c => !rejectionReason(c, subject, rules));
}

function sortComps(comps) {
  const rank = {
    sold: 1,
    pending: 2,
    active: 3,
    unknown: 4
  };

  return comps.sort((a, b) => {
    const ar = rank[a._statusGroup] || 9;
    const br = rank[b._statusGroup] || 9;

    if (ar !== br) return ar - br;

    const ac = num(a.correlation);
    const bc = num(b.correlation);

    if (bc !== ac) return bc - ac;

    if (a._distance !== b._distance) return a._distance - b._distance;

    return num(a.daysOld) - num(b.daysOld);
  });
}

function filterComps(comps, subject) {
  if (!Array.isArray(comps) || !comps.length) {
    return {
      safeComps: [],
      passUsed: 'none',
      rejectionSummary: {},
      debugRejectedSamples: []
    };
  }

  const normalizedComps = comps.map(normalizeComp);

  const isLuxuryOrLarge = subject.sqft >= 3500 || subject.baths >= 5 || subject.beds >= 5;

  const passes = [
    {
      name: 'strict',
      maxDistance: 2,
      minSqftRatio: 0.65,
      maxSqftRatio: 1.35,
      bedTolerance: 2,
      bathTolerance: 2,
      yearTolerance: 25,
      requireBeds: true,
      requireBaths: true,
      requireTypeMatch: true
    },
    {
      name: isLuxuryOrLarge ? 'relaxed_luxury' : 'relaxed',
      maxDistance: isLuxuryOrLarge ? 5 : 3,
      minSqftRatio: isLuxuryOrLarge ? 0.45 : 0.55,
      maxSqftRatio: isLuxuryOrLarge ? 1.75 : 1.50,
      bedTolerance: isLuxuryOrLarge ? 3 : 2,
      bathTolerance: isLuxuryOrLarge ? 3.5 : 2.5,
      yearTolerance: 40,
      requireBeds: true,
      requireBaths: true,
      requireTypeMatch: true
    },
    {
      name: 'salvage_market_context',
      maxDistance: isLuxuryOrLarge ? 10 : 5,
      minSqftRatio: isLuxuryOrLarge ? 0.35 : 0.45,
      maxSqftRatio: isLuxuryOrLarge ? 2.25 : 1.75,
      bedTolerance: isLuxuryOrLarge ? 99 : 3,
      bathTolerance: isLuxuryOrLarge ? 99 : 3.5,
      yearTolerance: 0,
      requireBeds: false,
      requireBaths: false,
      requireTypeMatch: false
    }
  ];

  let selected = [];
  let passUsed = 'none';
  let rejectionSummary = {};

  for (const rules of passes) {
    selected = applyRules(normalizedComps, subject, rules);
    rejectionSummary = summarizeRejections(normalizedComps, subject, rules);

    if (selected.length >= 3) {
      passUsed = rules.name;
      break;
    }

    // If there are only 1-2 usable comps, keep them on salvage instead of returning zero.
    if (rules.name === 'salvage_market_context' && selected.length > 0) {
      passUsed = rules.name;
      break;
    }
  }

  selected = sortComps(selected);

  const debugRejectedSamples = normalizedComps
    .map(c => {
      const finalRules = passes.find(p => p.name === passUsed) || passes[passes.length - 1];
      return {
        address: c.formattedAddress || c.address || c.formatted_address || null,
        price: c._price,
        sqft: c._sqft,
        beds: c._beds,
        baths: c._baths,
        distance: c._distance,
        statusGroup: c._statusGroup,
        rawStatus: get(c, [
          'status',
          'listingStatus',
          'mlsStatus',
          'propertyStatus',
          'standardStatus',
          'listing_status',
          'mls_status',
          'standard_status'
        ]) || null,
        propertyType: c._propertyType || null,
        rejectionReason: rejectionReason(c, subject, finalRules)
      };
    })
    .filter(x => x.rejectionReason)
    .slice(0, 10);

  return {
    safeComps: selected,
    passUsed,
    rejectionSummary,
    debugRejectedSamples
  };
}

const s = $input.first().json;
const comps = s.comparables || s.comps || s.saleComps || [];

const res = (() => {
  try {
    const r = $('Normalize Subject + Mode').first().json;
    if (r && r.resolved) return r.resolved;
  } catch {}

  try {
    const r = $('Deduplicate Opportunities').first().json;
    if (r && r.resolved) return r.resolved;
  } catch {}

  return $input.first().json.resolved || {};
})();

const subject = {
  sqft: num(res.building_sqft || res.sqft || res.squareFootage || res.source_assumptions?.sqft_input),
  beds: num(res.building_beds || res.beds || res.bedrooms || res.source_assumptions?.beds_input),
  baths: num(res.building_baths || res.baths || res.bathrooms || res.source_assumptions?.baths_input),
  yearBuilt: num(res.yearBuilt || res.year_built || res.source_assumptions?.yearBuilt),
  propType: res.property_type_for_value || res.propertyType || res.propType || res.mode || 'Single Family'
};

const filtered = filterComps(comps, subject);
const safeComps = filtered.safeComps;
const top = safeComps.slice(0, 10);

const ppsfValues = safeComps
  .filter(c => c._price > 0 && c._sqft > 0)
  .map(c => c._price / c._sqft);

const avgPPSF = ppsfValues.length
  ? ppsfValues.reduce((a, b) => a + b, 0) / ppsfValues.length
  : 0;

const estARV = subject.sqft > 0 && avgPPSF > 0
  ? Math.round(avgPPSF * subject.sqft)
  : 0;

const adjusted = top.map(c => ({
  formattedAddress: c.formattedAddress || c.address || c.formatted_address || null,
  price: c._price,
  priceBasis: c._priceBasis,
  compStatusGroup: c._statusGroup,
  rawStatus: get(c, [
    'status',
    'listingStatus',
    'mlsStatus',
    'propertyStatus',
    'standardStatus',
    'listing_status',
    'mls_status',
    'standard_status'
  ]) || null,
  propType: c._propertyType || null,
  bedrooms: c._beds,
  bathrooms: c._baths,
  squareFootage: c._sqft,
  pricePerSqFt: c._sqft > 0 ? Number((c._price / c._sqft).toFixed(2)) : 0,
  yrBuilt: c._yearBuilt || null,
  dateListed: get(c, ['listedDate', 'dateListed', 'listed_date', 'date_listed']) || null,
  dateSold: get(c, [
    'soldDate',
    'dateSold',
    'removedDate',
    'closedDate',
    'lastSaleDate',
    'sold_date',
    'date_sold',
    'removed_date',
    'closed_date',
    'last_sale_date'
  ]) || null,
  daysOnMarket: num(get(c, ['daysOnMarket', 'dom', 'days_on_market'])),
  daysOld: num(get(c, ['daysOld', 'days_old'])),
  distance: c._distance,
  correlation: c.correlation != null
    ? Number((num(c.correlation) * (num(c.correlation) <= 1 ? 100 : 1)).toFixed(1))
    : null
}));

const compCounts = safeComps.reduce((acc, c) => {
  acc[c._statusGroup] = (acc[c._statusGroup] || 0) + 1;
  return acc;
}, {});

return [{
  json: {
    estARV,
    arv_source: filtered.passUsed === 'strict'
      ? 'filtered_market_comps_avg_ppsf_strict'
      : `filtered_market_comps_avg_ppsf_${filtered.passUsed}`,
    priceRangeLow: s.priceRangeLow,
    priceRangeHigh: s.priceRangeHigh,
    selected_comps: adjusted,
    address: s.address || $json.address,
    analysis: {
      totalCompsEvaluated: comps.length,
      validMarketCompsFound: safeComps.length,
      validSoldCompsFound: compCounts.sold || 0,
      validPendingCompsFound: compCounts.pending || 0,
      validActiveCompsFound: compCounts.active || 0,
      validUnknownStatusCompsFound: compCounts.unknown || 0,
      averagePpsqft: Number(avgPPSF.toFixed(2)),
      subjectSqft: subject.sqft,
      subjectBeds: subject.beds,
      subjectBaths: subject.baths,
      subjectYearBuilt: subject.yearBuilt,
      subjectPropType: subject.propType,
      filterPassUsed: filtered.passUsed,
      rejectionSummary: filtered.rejectionSummary,
      debugRejectedSamples: filtered.debugRejectedSamples
    }
  }

parameters.jsCode:
/**
 * FINAL GHL MAPPING NODE - FULL REPLACEMENT
 *
 * Source of truth:
 * - Offer Engine1 / Deterministic Deal Math = ALL numeric underwriting
 * - AI Agent = ALL narrative/explanation fields
 * - Evaluation & Stage Router = stage / eval / lead score routing
 * - Transcript analyzer = seller urgency / hardship / condition / next steps
 * - Code5 = pretty notes / pretty json / LOI packaging
 *
 * This node also returns debug/meta so you can see:
 * - how many contact/opportunity fields were actually mapped
 * - which mapped friendly names had no field ID in the dictionary
 * - which dictionary keys exist but were never used by this code
 */

function safeNode(name, fallback = {}) {
  try {
    const v = $(name).first().json;
    return v ?? fallback;
  } catch {
    return fallback;
  }
}

function parseMaybeJson(v) {
  if (v == null) return {};
  if (typeof v === 'object') return v;
  if (typeof v !== 'string') return {};
  const s = v.trim();
  if (!s) return {};
  if (
    (s.startsWith('{') && s.endsWith('}')) ||
    (s.startsWith('[') && s.endsWith(']'))
  ) {
    try {
      return JSON.parse(s);
    } catch {
      return {};
    }
  }
  return {};
}

function normalizeNode(v) {
  if (v == null) return {};
  if (typeof v === 'object') {
    if (v.output != null) {
      const parsed = parseMaybeJson(v.output);
      if (parsed && typeof parsed === 'object' && Object.keys(parsed).length) return parsed;
      if (typeof v.output === 'object') return v.output || {};
    }
    return v;
  }
  return parseMaybeJson(v);
}

function firstValue() {
  for (const v of arguments) {
    if (v === 0 || v === false) return v;
    if (v === null || v === undefined) continue;
    if (typeof v === 'string' && v.trim() === '') continue;
    return v;
  }
  return null;
}

function isBlank(v) {
  return (
    v === undefined ||
    v === null ||
    (typeof v === 'string' && (
      v.trim() === '' ||
      v.trim().toLowerCase() === 'undefined' ||
      v.trim().toLowerCase() === 'null' ||
      v.trim() === 'NaN%' ||
      v.trim() === 'NaN'
    )) ||
    (Array.isArray(v) && v.length === 0)
  );
}

function toNumber(v) {
  if (v === null || v === undefined || v === '') return null;
  if (typeof v === 'number') return Number.isFinite(v) ? v : null;
  const n = Number(String(v).replace(/[^\d.\-]/g, ''));
  return Number.isFinite(n) ? n : null;
}

function money(v, digits = 0) {
  if (v == null || v === '') return '';
  if (typeof v === 'string' && v.trim().startsWith('$')) return v.trim();
  const n = toNumber(v);
  if (n == null) return String(v);
  return `$${n.toLocaleString('en-US', {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits
  })}`;
}

function percent(v, digits = 1) {
  if (v == null || v === '') return '';
  const s = String(v).trim();
  if (s.includes('%')) return s;
  const n = toNumber(v);
  if (n == null) return s;
  return `${n.toFixed(digits)}%`;
}

function cleanText(v) {
  return String(v == null ? '' : v)
    .replace(/\r/g, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function joinBlocks() {
  return Array.from(arguments)
    .filter((x) => !isBlank(x))
    .map((x) => cleanText(x))
    .filter(Boolean)
    .join('\n\n');
}

function nlList(arr) {
  return (Array.isArray(arr) ? arr : [])
    .filter((x) => !isBlank(x))
    .map((x) => String(x).trim())
    .join('\n');
}

function formatCompLine(c) {
  if (!c || typeof c !== 'object') return '';
  return cleanText(
`Address: ${c.address || ''}
Correlation: ${c.correlation || ''}%
Sale Price: ${money(c.price, 0)}
Beds: ${c.beds || ''} Baths: ${c.baths || ''}
Sqft: ${c.squareFootage || c.sqft || ''}
DOM: ${c.daysOnMarket || c.dom || ''}
Distance: ${c.distance || ''}`
  );
}

// --------------------------------------------------
// OFFER HELPERS - MAKE MAPPING ROBUST ACROSS OFFER TYPES
// --------------------------------------------------

function normalizeOfferType(v) {
  return String(v || '')
    .toLowerCase()
    .replace(/[^a-z0-9]/g, '');
}

function offerTypeUsesCts(typeRaw) {
  const t = normalizeOfferType(typeRaw);
  return ['subto', 'subjectto', 'hybrid'].includes(t);
}

function offerTypeNeedsTermFields(typeRaw) {
  const t = normalizeOfferType(typeRaw);

  return (
    t === 'hybrid' ||
    t === 'sellerfi' ||
    t === 'sellerfinance' ||
    t === 'sellerfinancing' ||
    t === 'ownerfi' ||
    t === 'ownerfinance' ||
    t === 'ownerfinancing'
  );
}

function getOfferType(offerObj) {
  return firstValue(
    offerObj?.Type,
    offerObj?.['Offer Type'],
    offerObj?.offer_type
  );
}

function getOfferPurchasePrice(offerObj) {
  return firstValue(
    offerObj?.['Purchase Price'],
    offerObj?.purchase_price,
    offerObj?.price
  );
}

function getOfferDownPaymentDollar(offerObj) {
  const typeRaw = getOfferType(offerObj);

  if (offerTypeUsesCts(typeRaw)) {
    return firstValue(
      offerObj?.cts,
      offerObj?.['Down Payment ($)'],
      offerObj?.['Down Payment'],
      offerObj?.down_payment
    );
  }

  return firstValue(
    offerObj?.['Down Payment ($)'],
    offerObj?.['Down Payment'],
    offerObj?.down_payment,
    offerObj?.cts
  );
}

function getOfferDownPaymentPct(offerObj) {
  const typeRaw = getOfferType(offerObj);

  if (offerTypeUsesCts(typeRaw)) {
    return firstValue(
      offerObj?.cts_pct,
      offerObj?.['Down Payment (%)'],
      offerObj?.['Down Payment %'],
      offerObj?.down_payment_pct
    );
  }

  return firstValue(
    offerObj?.['Down Payment (%)'],
    offerObj?.['Down Payment %'],
    offerObj?.down_payment_pct,
    offerObj?.cts_pct
  );
}

function getOfferLoanRate(offerObj) {
  return firstValue(
    offerObj?.['Loan Rate (%)'],
    offerObj?.['Interest Rate (%)'],
    offerObj?.['Loan Rate %'],
    offerObj?.['Interest Rate %'],
    offerObj?.loan_rate_pct,
    offerObj?.interest_rate_pct
  );
}

function getOfferAmortizationYears(offerObj) {
  return firstValue(
    offerObj?.['Amortization (Years)'],
    offerObj?.['Amortization Years'],
    offerObj?.['Amortization'],
    offerObj?.amortization_years
  );
}

function getOfferBalloonTermYears(offerObj) {
  return firstValue(
    offerObj?.['Balloon Term (Years)'],
    offerObj?.['Balloon Term Years'],
    offerObj?.['Balloon Term'],
    offerObj?.balloon_term_years
  );
}

function getOfferMonthlyPaymentPI(offerObj) {
  return firstValue(
    offerObj?.['Monthly Payment (PI)'],
    offerObj?.['Monthly Payment PI'],
    offerObj?.monthly_payment_pi
  );
}

function getOfferTotalEntryFee(offerObj) {
  return firstValue(
    offerObj?.['Total Entry Fee'],
    offerObj?.total_entry_fee,
    offerObj?.['Total Cash In']
  );
}

function getOfferJustification(numObj, narrObj) {
  return firstValue(
    narrObj?.Justification,
    narrObj?.justification,
    numObj?.Justification,
    numObj?.justification
  );
}

// --------------------------------------------------
// GHL SAFE FIELD NORMALIZATION
// --------------------------------------------------

function normalizeFieldValue(value) {
  if (isBlank(value)) return null;

  if (Array.isArray(value)) {
    const flattened = value
      .flat(Infinity)
      .filter((v) => !isBlank(v))
      .map((v) => {
        if (typeof v === 'object') {
          try {
            return JSON.stringify(v);
          } catch {
            return String(v);
          }
        }
        return String(v);
      })
      .map((v) => v.replace(/\u0000/g, '').trim())
      .filter(Boolean);

    if (!flattened.length) return null;
    return flattened.join('\n\n');
  }

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch {
      return String(value);
    }
  }

  return String(value).replace(/\u0000/g, '').trim();
}

const stageRaw = safeNode('Evaluation & Stage Router', {});
const stage = normalizeNode(stageRaw);

const offerRaw = safeNode('OFFER ENGINE v1', {});
const offer = normalizeNode(offerRaw);

const aiRaw = safeNode('AI Agent', {});
const ai = normalizeNode(aiRaw);

const pretty = normalizeNode(safeNode('Code5', {}));
const compApi = normalizeNode(safeNode('Fetch Comps API', {}));
const rentApi = normalizeNode(safeNode('Fetch rental comps', {}));

const transcriptNode = normalizeNode(safeNode('Pack Agent Input', {}));
const transcriptOut = transcriptNode.transcript?.output || {};

const idNode = normalizeNode(safeNode('Build GHL ID Dictionary', {}));
const fieldIdsOpp = idNode.fieldIdsOpp || {};
const fieldIdsContact = idNode.fieldIdsContact || {};

const contactFields = [];
const opportunityFields = [];

const usedOppKeys = new Set();
const usedContactKeys = new Set();

const skippedNoFieldId = {
  opportunity: [],
  contact: []
};

const skippedNoValue = {
  opportunity: [],
  contact: []
};

function mapField(bucket, dict, usedSet, friendlyName, value, options = {}) {
  const fieldId = dict[friendlyName];
  const skipBlankAudit = options.skipBlankAudit === true;

  if (!fieldId) {
    skippedNoFieldId[bucket].push(friendlyName);
    return;
  }

  usedSet.add(friendlyName);

  const normalizedValue = normalizeFieldValue(value);

  if (isBlank(normalizedValue)) {
    if (!skipBlankAudit) {
      skippedNoValue[bucket].push(friendlyName);
    }
    return;
  }

  const payload = {
    id: String(fieldId).trim(),
    field_value: normalizedValue
  };

  if (bucket === 'opportunity') {
    opportunityFields.push(payload);
  } else {
    contactFields.push(payload);
  }
}

function mapOpp(name, value, options = {}) {
  mapField('opportunity', fieldIdsOpp, usedOppKeys, name, value, options);
}

function mapContact(name, value, options = {}) {
  mapField('contact', fieldIdsContact, usedContactKeys, name, value, options);
}

// --------------------------------------------------
// PRIMARY DATA SOURCING
// --------------------------------------------------

// stage / score / routing
const leadScore = firstValue(
  stageRaw.leadScore,
  stage.leadScore,
  stageRaw.lead_score,
  stage.lead_score,
  ai.lead_score,
  offer.lead_score
);

const evaluation = firstValue(
  stageRaw.recommendation?.evaluation,
  stage.recommendation?.evaluation
);

const nextPipelineStage = firstValue(
  stageRaw.recommendation?.nextPipelineStage,
  stage.recommendation?.nextPipelineStage
);

const stageLeadExplanation = firstValue(
  ai.lead_score_explanation,
  stage.lead_score_explanation
);

// all numbers from offer engine
const investors = offer.investors_analysis || {};
const primaryOfferNum = offer.deal_structure?.['Primary Offer'] || {};
const backupOfferNum = offer.deal_structure?.['Backup Offer'] || {};
const cashOfferNum = offer.deal_structure?.['Updated Cash Offer'] || offer.deal_structure?.['Updated Cash offer'] || {};
const compReport = Array.isArray(offer.comp_properties_report) ? offer.comp_properties_report : [];

// all narrative from AI Agent where available
const primaryOfferNarr = ai.deal_structure?.['Primary Offer'] || {};
const backupOfferNarr = ai.deal_structure?.['Backup Offer'] || {};
const cashOfferNarr = ai.deal_structure?.['Updated Cash Offer'] || ai.deal_structure?.['Updated Cash offer'] || {};
const dispoNarr = ai.dispoStrategy || {};
const buyerMatchSummary = firstValue(ai.buyer_match_summary, offer.buyer_match_summary);
const compsSummaryNarr = firstValue(ai.comps_summary, offer.comps_summary);
const investorInsightNarr = firstValue(ai.investors_analysis_insights, offer.investors_analysis_insights);
const finalRecsNarr = firstValue(ai.finalRecommendationsAndInsights, offer.finalRecommendationsAndInsights);
const loiHtml = firstValue(pretty.direct_to_agent_loi, ai.loi, offer.loi);

// offer-type logic
const primaryOfferType = getOfferType(primaryOfferNum);
const backupOfferType = getOfferType(backupOfferNum);

const primaryNeedsTermFields = offerTypeNeedsTermFields(primaryOfferType);
const backupNeedsTermFields = offerTypeNeedsTermFields(backupOfferType);

const primaryAmortizationYears = primaryNeedsTermFields ? getOfferAmortizationYears(primaryOfferNum) : undefined;
const primaryBalloonTermYears = primaryNeedsTermFields ? getOfferBalloonTermYears(primaryOfferNum) : undefined;

const backupAmortizationYears = backupNeedsTermFields ? getOfferAmortizationYears(backupOfferNum) : undefined;
const backupBalloonTermYears = backupNeedsTermFields ? getOfferBalloonTermYears(backupOfferNum) : undefined;

// --------------------------------------------------
// COMPLEX TEXT BLOCKS
// --------------------------------------------------

const leadScoreExp = cleanText(
`Underwriting Score: ${leadScore ?? ''}
Monthly Cash Flow: ${firstValue(investors['Monthly Cash-flow'], offer.canonical?.economics?.monthlyCF) ?? ''}
Cash on Cash: ${firstValue(investors['Cash-on-Cash Return'], offer.canonical?.economics?.CoC_pct) ?? ''}
DSCR: ${firstValue(investors.DSCR, offer.canonical?.economics?.DSCR) ?? ''}

Therefore; the recommended next stage is: ${nextPipelineStage || ''}

Quick Notes: ${firstValue(
  investorInsightNarr,
  ai.lead_score_explanation,
  stageLeadExplanation,
  transcriptOut.additionalInsights,
  pretty.pretty_summary_one_line
) || ''}

Lead Score Explanation: ${firstValue(ai.lead_score_explanation, stageLeadExplanation) || ''}`
);

let compsContext = cleanText(compsSummaryNarr || '');
for (let i = 0; i < Math.min(3, compReport.length); i++) {
  compsContext = joinBlocks(compsContext, formatCompLine(compReport[i]));
}

const urgencySummary = cleanText(
`Seller Urgency: ${firstValue(transcriptOut.sellerUrgency, ai.sellerUrgency, 'No seller urgency summary available')}

Seller Hardship: ${firstValue(transcriptOut.sellerHardship, ai.sellerHardship, 'No seller hardship summary available')}

Property Condition: ${firstValue(transcriptOut.conditionOfProperty, ai.conditionOfProperty, 'No property condition summary available')}

Price: ${firstValue(transcriptOut.price, ai.price, 'No pricing narrative available')}

Additional Insights: ${firstValue(transcriptOut.additionalInsights, ai.additionalInsights, investorInsightNarr, 'No additional insights available')}

Next Steps: ${firstValue(transcriptOut.nextSteps, ai.nextSteps, 'No next steps available')}

Suggested Follow-Up Script (if necessary): ${firstValue(
  transcriptOut['Suggested Follow up Script'],
  transcriptOut['Suggested Follow-Up Script'],
  ai['Suggested Follow up Script'],
  ai['Suggested Follow-Up Script'],
  'No follow-up script available'
)}`
);

let zillowLinks = cleanText(
`Sales and Rental Comp Zillow Links:

Subject Property Link:
https://www.zillow.com/homes/${compApi.subjectProperty?.id || ''}_rb

Sales Comps:
ARV: ${compApi.price || ''}
Price Range: ${compApi.priceRangeLow || ''} - ${compApi.priceRangeHigh || ''}`
);

const sComps = Array.isArray(compApi.comparables) ? compApi.comparables : [];
for (let i = 0; i < Math.min(6, sComps.length); i++) {
  zillowLinks += `\n${i + 1}: https://www.zillow.com/homes/${sComps[i].id}_rb`;
}

zillowLinks += `\n\nRental Comps:\nAverage Rent: $${rentApi.rent || ''}\nRental Range: $${rentApi.rentRangeLow || ''}-$${rentApi.rentRangeHigh || ''}`;

const rComps = Array.isArray(rentApi.comparables) ? rentApi.comparables : [];
for (let i = 0; i < Math.min(6, rComps.length); i++) {
  zillowLinks += `\n${i + 1}: https://www.zillow.com/homes/${rComps[i].id}_rb`;
}

const dispoText = cleanText(
`Recommended Disposition Strategy: ${firstValue(dispoNarr.recommendedDispoStrategy, 'No disposition strategy available')}

Best Type of Investor to Market this deal to: ${firstValue(dispoNarr.bestEndBuyerType, 'No buyer type available')}

Projected Assignment Fee: ${firstValue(dispoNarr.projectedAssignmentFee, offer.assignment_fee_range, 'No assignment fee available')}

Profit Projection Insights: ${firstValue(
  Array.isArray(dispoNarr.endBuyerExitStrategyProfitProjections) ? dispoNarr.endBuyerExitStrategyProfitProjections[0] : null,
  'No profit projection available'
)}

Final Recommendations: ${firstValue(finalRecsNarr, 'No final recommendations available')}`
);

const cashAmount = firstValue(
  cashOfferNum['Final Cash Offer Amount'],
  cashOfferNum['Final Cash Offer'],
  cashOfferNarr['Final Cash Offer Amount'],
  cashOfferNarr['Final Cash Offer']
);

const cashPct = firstValue(
  cashOfferNum['Final Cash Offer % of ARV'],
  cashOfferNarr['Final Cash Offer % of ARV']
);

const combinedCashOffer = cleanText(
  cashAmount && cashPct ? `${cashAmount} (${cashPct})` : firstValue(cashAmount, '')
);

const prequalNotes = firstValue(
  pretty.role_notes?.prequalifier?.text,
  pretty.ai_underwriting_note,
  pretty.pretty_note_ghl,
  null
);

const fullJsonText = firstValue(
  pretty.pretty_json,
  JSON.stringify({
    offer_engine: offer,
    ai_agent: ai,
    stage_router: stageRaw
  })
);

// --------------------------------------------------
// MAP TO OPPORTUNITY FIELDS
// --------------------------------------------------

mapOpp('Lead Score - Number', leadScore);
mapOpp('Lead Score Explanation & Target Stage / Quick Notes', leadScoreExp);
mapOpp('Prequalifier Notes', prequalNotes);
mapOpp('Estimated ARV', firstValue(offer.estimated_arv, offer.metrics?.arv, offer.property?.arv_value));
mapOpp('Comps Summary Context', compsContext);

mapOpp('Gross Rent', investors['Gross Rent']);
mapOpp('Annual Rent', investors['Annual Rent']);
mapOpp('Operating Expenses', investors['Operating Expenses']);
mapOpp('NOI', investors.NOI);
mapOpp('Annual Debt Service - ADS', investors['Annual Debt Service (ADS)']);
mapOpp('DSCR', investors.DSCR);
mapOpp('Annual Cash Flow', investors['Annual Cash-flow']);
mapOpp('Monthly Cash Flow', investors['Monthly Cash-flow']);
mapOpp('Total Cash In / Entry Fee', investors['Total Cash In']);
mapOpp('Cash-on-Cash Return', investors['Cash-on-Cash Return']);
mapOpp('Cash-on-Cash Return - Alternate ID', investors['Cash-on-Cash Return']);
mapOpp('2% Rule Pass/Fail', investors['2% Rule']);
mapOpp('50% Rule PassFail', investors['50% Rule']);

mapOpp('primary.Offer Type', primaryOfferType);
mapOpp('primary.Purchase Price', getOfferPurchasePrice(primaryOfferNum));
mapOpp('primary.Down Payment $', getOfferDownPaymentDollar(primaryOfferNum));
mapOpp('primary.Down Payment %', percent(getOfferDownPaymentPct(primaryOfferNum)));
mapOpp('primary.Loan Rate %', getOfferLoanRate(primaryOfferNum));
mapOpp('primary.Amortization Years', primaryAmortizationYears, { skipBlankAudit: !primaryNeedsTermFields });
mapOpp('primary.Balloon Term Years', primaryBalloonTermYears, { skipBlankAudit: !primaryNeedsTermFields });
mapOpp('primary.Monthly Payment PI', getOfferMonthlyPaymentPI(primaryOfferNum));
mapOpp('primary.Total Entry Fee', getOfferTotalEntryFee(primaryOfferNum));
mapOpp('primary.Justification', getOfferJustification(primaryOfferNum, primaryOfferNarr));

mapOpp('backup.Offer Type', backupOfferType);
mapOpp('backup.Purchase Price', getOfferPurchasePrice(backupOfferNum));
mapOpp('backup.Down Payment $', getOfferDownPaymentDollar(backupOfferNum));
mapOpp('backup.Down Payment %', percent(getOfferDownPaymentPct(backupOfferNum)));
mapOpp('backup.Loan Rate %', getOfferLoanRate(backupOfferNum));
mapOpp('backup.Amortization Years', backupAmortizationYears, { skipBlankAudit: !backupNeedsTermFields });
mapOpp('backup.Balloon Term Years', backupBalloonTermYears, { skipBlankAudit: !backupNeedsTermFields });
mapOpp('backup.Monthly Payment PI', getOfferMonthlyPaymentPI(backupOfferNum));
mapOpp('backup.Total Entry Fee', getOfferTotalEntryFee(backupOfferNum));
