mapOpp('Cash Offer Justification', firstValue(cashOfferNarr.Justification, cashOfferNum.Justification));
mapOpp('Subjective Additional Insights', firstValue(investorInsightNarr, transcriptOut.additionalInsights));
mapOpp('Seller Urgency / Condition Summary', urgencySummary);
mapOpp('Zillow Links for Comps', zillowLinks);
mapOpp('Average Rent', rentApi.rent);
mapOpp('Rent Range Low', rentApi.rentRangeLow);
mapOpp('Rent Range High', rentApi.rentRangeHigh);
mapOpp('Average Sale Price Comps', compApi.price);
mapOpp('Sale Price Low', compApi.priceRangeLow);
mapOpp('Sale Price High', compApi.priceRangeHigh);
mapOpp('Next Pipeline Stage', nextPipelineStage);
mapOpp('Cold/Warm/Hot Evaluation', evaluation);
mapOpp('Current Timestamp', new Date().toISOString());
mapOpp('Disposition Strategy & Best Buyer Type', dispoText);
mapOpp('Direct to Agent LOI text', loiHtml);
mapOpp('Buyer Match Summary', buyerMatchSummary ? buyerMatchSummary.replace(/\s*\|\s*/g, '\n') : undefined);

// --------------------------------------------------
// MAP TO CONTACT FIELDS
// --------------------------------------------------

mapContact('Lead Score Explanation & Target Stage / Quick Notes', leadScoreExp);
mapContact('underwriter notes', prequalNotes);
mapContact('Estimated ARV', firstValue(offer.estimated_arv, offer.metrics?.arv, offer.property?.arv_value));
mapContact('Comps Summary Context', compsContext);

mapContact('Gross Rent', investors['Gross Rent']);
mapContact('Annual Rent', investors['Annual Rent']);
mapContact('Operating Expenses', investors['Operating Expenses']);
mapContact('Annual Debt Service - ADS', investors['Annual Debt Service (ADS)']);
